add_psalom {
  ["номер"] = 1,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 1,
  ["текст_ру"] = "Блаже́н муж, и́же не и́де на сове́т нечести́вых и на пути́ гре́шных не ста, и на седа́лищи губи́телей не се́де, но в зако́не Госпо́дни во́ля eго́, и в зако́не Его́ поучи́тся день и нощь. И бу́дет я́ко дре́во насажде́нное при исхо́дищих вод, е́же плод свой даст во вре́мя свое́, и лист eго́ не отпаде́т, и вся, ели́ка а́ще твори́т, успе́ет. Не та́ко нечести́вии, не та́ко, но я́ко прах, eго́же возмета́ет ветр от лица́ земли́. Сего́ ра́ди не воскре́снут нечести́вии на суд, ниже́ гре́шницы в сове́т пра́ведных. Я́ко весть Госпо́дь путь пра́ведных, и путь нечести́вых поги́бнет.",
  ["текст_цс"] = "Бл҃же́нъ мꙋ́жъ, и҆́же не и҆́де на совѣ́тъ нечести́выхъ, и҆ на пꙋтѝ грѣ́шныхъ не ста̀, и҆ на сѣда́лищи гꙋби́телей не сѣ́де: Но въ зако́нѣ гдⷭ҇ни во́лѧ є҆гѡ̀, и҆ въ зако́нѣ є҆гѡ̀ поꙋчи́тсѧ де́нь и҆ но́щь. И҆ бꙋ́детъ ꙗ҆́кѡ дре́во насажде́ное при и҆схо́дищихъ во́дъ, є҆́же пло́дъ сво́й да́стъ во вре́мѧ своѐ, и҆ ли́стъ є҆гѡ̀ не ѿпаде́тъ: и҆ всѧ̑, є҆ли̑ка а҆́ще твори́тъ, ᲂу҆спѣ́етъ. Не та́кѡ нечести́вїи, не та́кѡ: но ꙗ҆́кѡ пра́хъ, є҆го́же возмета́етъ вѣ́тръ ѿ лица̀ землѝ. Сегѡ̀ ра́ди не воскре́снꙋтъ нечести́вїи на сꙋ́дъ, нижѐ грѣ̑шницы въ совѣ́тъ првⷣныхъ. Ꙗ҆́кѡ вѣ́сть гдⷭ҇ь пꙋ́ть првⷣныхъ, и҆ пꙋ́ть нечести́выхъ поги́бнетъ.",
  ["заголовок_ру"] = "Псало́м Дави́ду, не надпи́сан у евре́й.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, не надпи́санъ ᲂу҆ є҆врє́й."
}

add_psalom {
  ["номер"] = 2,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 1,
  ["текст_ру"] = "Вску́ю шата́шася язы́цы, и лю́дие поучи́шася тще́тным? Предста́ша ца́рие зе́мстии, и кня́зи собра́шася вку́пе на Го́спода и на Христа́ Его́. Расто́ргнем у́зы их и отве́ржем от нас и́го их. Живы́й на Небесе́х посмее́тся им, и Госпо́дь поруга́ется им. Тогда́ возглаго́лет к ним гне́вом свои́м и я́ростию Свое́ю смяте́т я́. Аз же поста́влен есмь Царь от Него́ над Сио́ном, горо́ю свято́ю Его́, возвеща́яй повеле́ние Госпо́дне. Госпо́дь рече́ ко Мне: Сын Мой еси́ Ты, Аз днесь роди́х Тя. Проси́ от Мене́, и дам Ти язы́ки достоя́ние Твое́, и одержа́ние Твое́ концы́ земли́. Упасе́ши я́ жезло́м желе́зным, я́ко сосу́ды скуде́льничи сокруши́ши я́. И ны́не, ца́рие, разуме́йте, накажи́теся вси судя́щии земли́. Рабо́тайте Го́сподеви со стра́хом и ра́дуйтеся Ему́ с тре́петом. Приими́те наказа́ние, да не когда́ прогне́вается Госпо́дь и поги́бнете от пути́ пра́веднаго, егда́ возгори́тся вско́ре я́рость Его́. Блаже́ни вси наде́ющиися Нань.",
  ["текст_цс"] = "Вскꙋ́ю шата́шасѧ ꙗ҆зы́цы, и҆ лю́дїе поꙋчи́шасѧ тщє́тнымъ; Предста́ша ца́рїе зе́мстїи, и҆ кнѧ̑зи собра́шасѧ вкꙋ́пѣ на гдⷭ҇а и҆ на хрⷭ҇та̀ є҆гѡ̀. Расто́рггемъ ᲂу҆́зы и҆́хъ и҆ ѿве́ржемъ ѿ на́съ и҆́го и҆́хъ. Живы́й на нб҃сѣ́хъ посмѣе́тсѧ и҆̀мъ, и҆ гдⷭ҇ь порꙋга́етсѧ и҆̀мъ. Тогда̀ возглаго́летъ къ ни̑мъ гнѣ́вомъ свои́мъ и҆ ꙗ҆́ростїю свое́ю смѧте́тъ ѧ҆̀: А҆́зъ же поста́вленъ є҆́смь цр҃ь ѿ негѡ̀ над̾ сїѡ́номъ, горо́ю ст҃о́ю є҆гѡ̀, Возвѣща́ѧй повелѣ́нїе гдⷭ҇не. Гдⷭ҇ь речѐ ко мнѣ̀: сн҃ъ мо́й є҆сѝ ты̀, а҆́зъ дне́сь роди́хъ тѧ̀: Просѝ ѿ менѐ, и҆ да́мъ тѝ ꙗ҆зы́ки достоѧ́нїе твоѐ, и҆ ѡ҆держа́нїе твоѐ концы̀ землѝ: Оу҆пасе́ши ѧ҆̀ жезло́мъ желѣ́знымъ, ꙗ҆́кѡ сосꙋ́ды скꙋдє́льничи сокрꙋши́ши ѧ҆̀. И҆ ны́нѣ, ца́рїе, разꙋмѣ́йте, накажи́тесѧ всѝ сꙋдѧ́щїи землѝ. Рабо́тайте гдⷭ҇еви со стра́хомъ, и҆ ра́дꙋйтесѧ є҆мꙋ̀ со тре́петомъ. Прїими́те наказа́нїе, да не когда̀ прогнѣ́ваетсѧ гдⷭ҇ь, и҆ поги́бнете ѿ пꙋтѝ првⷣнагѡ, є҆гда̀ возгори́тсѧ вско́рѣ ꙗ҆́рость є҆гѡ̀: бл҃же́ни всѝ надѣ́ющїисѧ на́нь.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 3,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 1,
  ["текст_ру"] = "Го́споди, что ся умно́жиша стужа́ющии ми? Мно́зи востаю́т на мя, мно́зи глаго́лют души́ мое́й: несть спасе́ния eму́ в Бо́зе eго́. Ты же, Го́споди, Засту́пник мой еси́, сла́ва моя́ и вознося́й главу́ мою́. Гла́сом мои́м ко Го́споду воззва́х, и услы́ша мя от горы́ святы́я Своея́. Аз усну́х, и спах, воста́х, я́ко Госпо́дь засту́пит мя. Не убою́ся от тем люде́й, о́крест напа́дающих на мя. Воскресни́, Го́споди, спаси́ мя, Бо́же мой, я́ко Ты порази́л еси́ вся вражду́ющыя ми всу́е: зу́бы гре́шников сокруши́л еси́. Госпо́дне есть спасе́ние, и на лю́дех Твои́х благослове́ние Твое́.",
  ["текст_цс"] = "Гдⷭ҇и, что́ сѧ ᲂу҆мно́жиша стꙋжа́ющїи мѝ; мно́зи востаю́тъ на мѧ̀, Мно́зи глаго́лютъ дꙋшѝ мое́й: нѣ́сть сп҃се́нїѧ є҆мꙋ̀ въ бз҃ѣ є҆гѡ̀. Ты́ же, гдⷭ҇и, застꙋ́пникъ мо́й є҆сѝ, сла́ва моѧ̀, и҆ возносѧ́й главꙋ̀ мою̀. Гла́сомъ мои́мъ ко гдⷭ҇ꙋ воззва́хъ, и҆ ᲂу҆слы́ша мѧ̀ ѿ горы̀ ст҃ы́ѧ своеѧ̀. А҆́зъ ᲂу҆снꙋ́хъ, и҆ спа́хъ, воста́хъ, ꙗ҆́кѡ гдⷭ҇ь застꙋ́питъ мѧ̀. Не ᲂу҆бою́сѧ ѿ тє́мъ люде́й, ѡ҆́крестъ напа́дающихъ на мѧ̀. Воскрⷭ҇нѝ, гдⷭ҇и, сп҃си́ мѧ, бж҃е мо́й: ꙗ҆́кѡ ты̀ порази́лъ є҆сѝ всѧ̑ враждꙋ́ющыѧ мѝ всꙋ́е, зꙋ́бы грѣ́шникѡвъ сокрꙋши́лъ є҆сѝ. Гдⷭ҇не є҆́сть сп҃се́нїе, и҆ на лю́дехъ твои́хъ бл҃гослове́нїе твоѐ.",
  ["заголовок_ру"] = "Псало́м Дави́ду, внегда́ отбега́ше от лица́ Авессало́ма, сы́на своего́.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, внегда̀ ѿбѣга́ше ѿ лица̀ а҆вессалѡ́ма сы́на своегѡ̀."
}

add_psalom {
  ["номер"] = 4,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 2,
  ["текст_ру"] = "Внегда́ призва́ти ми, услы́ша мя Бог пра́вды моея́, в ско́рби распространи́л мя еси́, уще́дри мя и услы́ши моли́тву мою́. Сы́нове челове́честии, доко́ле тяжкосе́рдии? Вску́ю лю́бите суету́ и и́щете лжи? И уве́дите, я́ко удиви́ Госпо́дь преподо́бнаго Своего́: Госпо́дь услы́шит мя, внегда́ воззва́ти ми к Нему́. Гне́вайтеся, и не согреша́йте, я́же глаго́лете в сердца́х ва́ших, на ло́жах ва́ших умили́теся. Пожри́те же́ртву пра́вды и упова́йте на Го́спода. Мно́зи глаго́лют: кто яви́т нам блага́я? Зна́менася на нас свет лица́ Твоего́, Го́споди. Дал еси́ весе́лие в се́рдце мое́м: от плода́ пшени́цы, вина́ и еле́а своего́ умно́жишася. В ми́ре вку́пе усну́ и почи́ю, я́ко Ты, Го́споди, еди́наго на упова́нии всели́л мя еси́.",
  ["текст_цс"] = "Внегда̀ призва́ти мѝ, ᲂу҆слы́ша мѧ̀ бг҃ъ пра́вды моеѧ̀: въ ско́рби распространи́лъ мѧ̀ є҆сѝ: ᲂу҆ще́дри мѧ̀ и҆ ᲂу҆слы́ши моли́твꙋ мою̀. Сы́нове человѣ́честїи, доко́лѣ тѧжкосе́рдїи; вскꙋ́ю лю́бите сꙋетꙋ̀ и҆ и҆́щете лжѝ; И҆ ᲂу҆вѣ́дите, ꙗ҆́кѡ ᲂу҆дивѝ гдⷭ҇ь прпⷣбнаго своего̀. Гдⷭ҇ь ᲂу҆слы́шитъ мѧ̀, внегда̀ воззва́ти мѝ къ немꙋ̀. Гнѣ́вайтесѧ, и҆ не согрѣша́йте, ꙗ҆̀же глаго́лете въ сердца́хъ ва́шихъ, на ло́жахъ ва́шихъ ᲂу҆мили́тесѧ: Пожри́те же́ртвꙋ пра́вды и҆ ᲂу҆пова́йте на гдⷭ҇а. Мно́зи глаго́лютъ: кто̀ ꙗ҆ви́тъ на́мъ бл҃га̑ѧ; зна́менасѧ на на́съ свѣ́тъ лица̀ твоегѡ̀, гдⷭ҇и. Да́лъ є҆сѝ весе́лїе въ се́рдцы мое́мъ: ѿ плода̀ пшени́цы, вїна̀ и҆ є҆ле́а своегѡ̀ ᲂу҆мно́жишасѧ: Въ ми́рѣ вкꙋ́пѣ ᲂу҆снꙋ̀ и҆ почі́ю, ꙗ҆́кѡ ты̀, гдⷭ҇и, є҆ди́наго на ᲂу҆пова́нїи всели́лъ мѧ̀ є҆сѝ.",
  ["заголовок_ру"] = "В коне́ц, в пе́снех псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, въ пѣ́снехъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 5,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 2,
  ["текст_ру"] = "Глаго́лы моя́ внуши́, Го́споди, разуме́й зва́ние мое́. Вонми́ гла́су моле́ния моего́, Царю́ мой и Бо́же мой, я́ко к Тебе́ помолю́ся, Го́споди. Зау́тра услы́ши глас мой, зау́тра предста́ну Ти, и у́зриши мя. Я́ко Бог не хотя́й беззако́ния, Ты еси́: не присели́тся к Тебе́ лука́внуяй, ниже́ пребу́дут беззако́нницы пред очи́ма Твои́ма: возненави́дел еси́ вся де́лающыя беззако́ние. Погуби́ши вся глаго́лющыя лжу: му́жа крове́й и льсти́ва гнуша́ется Госпо́дь. Аз же мно́жеством ми́лости Твоея́, вни́ду в дом Твой, поклоню́ся ко хра́му свято́му Твоему́, в стра́се Твое́м. Го́споди, наста́ви мя пра́вдою Твое́ю, враг мои́х ра́ди испра́ви пред Тобо́ю путь мой. Я́ко несть во усте́х их и́стины, се́рдце их су́етно, гроб отве́рст горта́нь их: язы́ки свои́ми льща́ху. Суди́ им, Бо́же, да отпаду́т от мы́слей свои́х, по мно́жеству нече́стия их изри́ни я́, я́ко преогорчи́ша Тя, Го́споди. И да возвеселя́тся вси упова́ющии на Тя, во век возра́дуются, и всели́шися в них, и похва́лятся о Тебе́ лю́бящии и́мя Твое́. Я́ко Ты благослови́ши пра́ведника, Го́споди: я́ко ору́жием благоволе́ния венча́л еси́ нас.",
  ["текст_цс"] = "Глаго́лы моѧ̑ внꙋшѝ, гдⷭ҇и, разꙋмѣ́й зва́нїе моѐ. Вонмѝ гла́сꙋ моле́нїѧ моегѡ̀, цр҃ю̀ мо́й и҆ бж҃е мо́й: ꙗ҆́кѡ къ тебѣ̀ помолю́сѧ, гдⷭ҇и. Заꙋ́тра ᲂу҆слы́ши гла́съ мо́й: заꙋ́тра предста́нꙋ тѝ, и҆ ᲂу҆́зриши мѧ̀: Ꙗ҆́кѡ бг҃ъ не хотѧ́й беззако́нїѧ ты̀ є҆сѝ: не присели́тсѧ къ тебѣ̀ лꙋка́внꙋѧй, Нижѐ пребꙋ́дꙋтъ беззакѡ́нницы пред̾ ѻ҆чи́ма твои́ма: возненави́дѣлъ є҆сѝ всѧ̑ дѣ́лающыѧ беззако́нїе, Погꙋби́ши всѧ̑ глаго́лющыѧ лжꙋ̀: мꙋ́жа крове́й и҆ льсти́ва гнꙋша́етсѧ гдⷭ҇ь. А҆́зъ же мно́жествомъ млⷭ҇ти твоеѧ̀ вни́дꙋ въ до́мъ тво́й, поклоню́сѧ ко хра́мꙋ ст҃о́мꙋ твоемꙋ̀, въ стра́сѣ твое́мъ. Гдⷭ҇и, наста́ви мѧ̀ пра́вдою твое́ю, вра̑гъ мои́хъ ра́ди и҆спра́ви пред̾ тобо́ю пꙋ́ть мо́й. Ꙗ҆́кѡ нѣ́сть во ᲂу҆стѣ́хъ и҆́хъ и҆́стины, се́рдце и҆́хъ сꙋ́етно, гро́бъ ѿве́рстъ горта́нь и҆́хъ, ѧ҆зы́ки свои́ми льща́хꙋ. Сꙋдѝ и҆̀мъ, бж҃е, да ѿпадꙋ́тъ ѿ мы́слей свои́хъ: по мно́жествꙋ нече́стїѧ и҆́хъ и҆зри́ни ѧ҆̀, ꙗ҆́кѡ преѡгорчи́ша тѧ̀, гдⷭ҇и. И҆ да возвеселѧ́тсѧ всѝ ᲂу҆пова́ющїи на тѧ̀, во вѣ́къ возра́дꙋютсѧ, и҆ всели́шисѧ въ ни́хъ: и҆ похва́лѧтсѧ ѡ҆ тебѣ̀ лю́бѧщїи и҆́мѧ твоѐ. Ꙗ҆́кѡ ты̀ бл҃гослови́ши првⷣника, гдⷭ҇и, ꙗ҆́кѡ ѻ҆рꙋ́жїемъ бл҃говоле́нїѧ вѣнча́лъ є҆сѝ на́съ.",
  ["заголовок_ру"] = "О насле́дствующем, псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѡ҆ наслѣ́дствꙋющемъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 6,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 2,
  ["текст_ру"] = "Го́споди, да не я́ростию Твое́ю обличи́ши мене́, ниже́ гне́вом Твои́м нака́жеши мене́. Поми́луй мя, Го́споди, я́ко не́мощен есмь, исцели́ мя, Го́споди, я́ко смято́шася ко́сти моя́. И душа́ моя́ смяте́ся зело́: и Ты, Го́споди, доко́ле? Обрати́ся, Го́споди, изба́ви ду́шу мою́: спаси́ мя ра́ди ми́лости Твоея́. Я́ко несть в сме́рти помина́яй Тебе́: во а́де же кто испове́стся Тебе́? Утруди́хся воздыха́нием мои́м, измы́ю на вся́ку нощь ло́же мое́, слеза́ми мои́ми посте́лю мою́ омочу́. Смяте́ся от я́рости о́ко мое́, обетша́х во всех вразе́х мои́х. Отступи́те от мене́, вси де́лающии беззако́ние, я́ко услы́ша Госпо́дь глас пла́ча моего́: услы́ша Госпо́дь моле́ние мое́, Госпо́дь моли́тву мою́ прия́т. Да постыдя́тся и смяту́тся вси врази́ мои́, да возвратя́тся и устыдя́тся зело́ вско́ре.",
  ["текст_цс"] = "Гдⷭ҇и, да не ꙗ҆́ростїю твое́ю ѡ҆бличи́ши менѐ, нижѐ гнѣ́вомъ твои́мъ нака́жеши менѐ. Поми́лꙋй мѧ̀, гдⷭ҇и, ꙗ҆́кѡ не́мощенъ є҆́смь: и҆сцѣли́ мѧ, гдⷭ҇и, ꙗ҆́кѡ смѧто́шасѧ кѡ́сти моѧ̑, И҆ дꙋша̀ моѧ̀ смѧте́сѧ ѕѣлѡ̀: и҆ ты̀, гдⷭ҇и, доко́лѣ; Ѡ҆брати́сѧ, гдⷭ҇и, и҆зба́ви дꙋ́шꙋ мою̀, сп҃си́ мѧ ра́ди млⷭ҇ти твоеѧ̀: Ꙗ҆́кѡ нѣ́сть въ сме́рти помина́ѧй тебѐ, во а҆́дѣ же кто̀ и҆сповѣ́стсѧ тебѣ̀; Оу҆трꙋди́хсѧ воздыха́нїемъ мои́мъ, и҆змы́ю на всѧ́кꙋ но́щь ло́же моѐ, слеза́ми мои́ми посте́лю мою̀ ѡ҆мочꙋ̀. Смѧте́сѧ ѿ ꙗ҆́рости ѻ҆́ко моѐ, ѡ҆бетша́хъ во всѣ́хъ вразѣ́хъ мои́хъ. Ѿстꙋпи́те ѿ менѐ, всѝ дѣ́лающїи беззако́нїе, ꙗ҆́кѡ ᲂу҆слы́ша гдⷭ҇ь гла́съ пла́ча моегѡ̀, Оу҆слы́ша гдⷭ҇ь моле́нїе моѐ, гдⷭ҇ь моли́твꙋ мою̀ прїѧ́тъ. Да постыдѧ́тсѧ и҆ смѧтꙋ́тсѧ всѝ вразѝ моѝ, да возвратѧ́тсѧ и҆ ᲂу҆стыдѧ́тсѧ ѕѣлѡ̀ вско́рѣ.",
  ["заголовок_ру"] = "В коне́ц, в пе́снех о осмо́м, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, въ пѣ́снехъ ѡ҆ ѻ҆смо́мъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 7,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 3,
  ["текст_ру"] = "Го́споди Бо́же мой, на Тя упова́х, спаси́ мя от всех гоня́щих мя и изба́ви мя: да не когда́ похи́тит я́ко лев ду́шу мою́, не су́щу избавля́ющу, ниже́ спаса́ющу. Го́споди Бо́же мой, а́ще сотвори́х сие́, а́ще есть непра́вда в руку́ мое́ю, а́ще возда́х воздаю́щым ми зла, да отпаду́ у́бо от враг мои́х тощ. Да пожене́т у́бо враг ду́шу мою́ и да пости́гнет, и попере́т в зе́млю живо́т мой, и сла́ву мою́ в персть всели́т. Воскресни́, Го́споди, гне́вом Твои́м, вознеси́ся в конца́х враг Твои́х, и воста́ни, Го́споди Бо́же мой, повеле́нием, и́мже запове́дал еси́. И сонм люде́й обы́дет Тя, и о том на высоту́ обрати́ся. Госпо́дь су́дит лю́дем: суди́ ми, Го́споди, по пра́вде мое́й, и по незло́бе мое́й на мя. Да сконча́ется зло́ба гре́шных, и испра́виши пра́веднаго, испыта́яй сердца́ и утро́бы, Бо́же, пра́ведно. По́мощь моя́ от Бо́га, спаса́ющаго пра́выя се́рдцем. Бог суди́тель пра́веден и кре́пок, и долготерпели́в, и не гнев наводя́й на всяк день. А́ще не обратите́ся, ору́жие Свое́ очи́стит, лук Свой напряже́ и угото́ва и́ и в нем угото́ва сосу́ды сме́ртныя, стре́лы Своя́ сгара́емым соде́ла. Се боле́ непра́вдою, зача́т боле́знь, и роди́ беззако́ние: ров изры́, и ископа́ и́, и паде́т в я́му, ю́же соде́ла. Обрати́тся боле́знь eго́ на главу́ eго́, и на верх eго́ непра́вда eго́ сни́дет. Испове́мся Го́сподеви по пра́вде Его́ и пою́ и́мени Го́спода Вы́шняго.",
  ["текст_цс"] = "Гдⷭ҇и бж҃е мо́й, на тѧ̀ ᲂу҆пова́хъ, сп҃си́ мѧ ѿ всѣ́хъ гонѧ́щихъ мѧ̀ и҆ и҆зба́ви мѧ̀: Да не когда̀ похи́титъ ꙗ҆́кѡ ле́въ дꙋ́шꙋ мою̀, не сꙋ́щꙋ и҆збавлѧ́ющꙋ, нижѐ спаса́ющꙋ. Гдⷭ҇и бж҃е мо́й, а҆́ще сотвори́хъ сїѐ, а҆́ще є҆́сть непра́вда въ рꙋкꙋ̀ моє́ю, А҆́ще возда́хъ воздаю́щымъ мѝ ѕла̑, да ѿпадꙋ̀ ᲂу҆̀бо ѿ вра̑гъ мои́хъ то́щъ: Да пожене́тъ ᲂу҆́бѡ вра́гъ дꙋ́шꙋ мою̀, и҆ да пости́гнетъ, и҆ попере́тъ въ зе́млю живо́тъ мо́й, и҆ сла́вꙋ мою̀ въ пе́рсть всели́тъ. Воскрⷭ҇нѝ, гдⷭ҇и, гнѣ́вомъ твои́мъ, вознеси́сѧ въ конца́хъ вра̑гъ твои́хъ, и҆ воста́ни, гдⷭ҇и бж҃е мо́й, повелѣ́нїемъ, и҆́мже заповѣ́далъ є҆сѝ, И҆ со́нмъ люде́й ѡ҆бы́детъ тѧ̀: и҆ ѡ҆ то́мъ на высотꙋ̀ ѡ҆брати́сѧ. Гдⷭ҇ь сꙋ́дитъ лю́демъ: сꙋди́ ми, гдⷭ҇и, по пра́вдѣ мое́й и҆ по неѕло́бѣ мое́й на мѧ̀. Да сконча́етсѧ ѕло́ба грѣ́шныхъ, и҆ и҆спра́виши првⷣнаго, и҆спыта́ѧй сердца̀ и҆ ᲂу҆трѡ́бы, бж҃е, првⷣнѡ. По́мощь моѧ̀ ѿ бг҃а, сп҃са́ющагѡ пра̑выѧ се́рдцемъ. Бг҃ъ сꙋди́тель првⷣнъ, и҆ крѣ́покъ, и҆ долготерпѣли́въ, и҆ не гнѣ́въ наводѧ́й на всѧ́къ де́нь. А҆́ще не ѡ҆братите́сѧ, ѻ҆рꙋ́жїе своѐ ѡ҆чи́ститъ, лꙋ́къ сво́й напрѧжѐ, и҆ ᲂу҆гото́ва и҆̀, И҆ въ не́мъ ᲂу҆гото́ва сосꙋ́ды смє́ртныѧ, стрѣ́лы своѧ̑ сгара́ємымъ содѣ́ла. Сѐ, болѣ̀ непра́вдою, зача́тъ болѣ́знь и҆ родѝ беззако́нїе: Ро́въ и҆зры̀ и҆ и҆скопа̀ и҆̀, и҆ паде́тъ въ ꙗ҆́мꙋ, ю҆́же содѣ́ла. Ѡ҆брати́тсѧ болѣ́знь є҆гѡ̀ на главꙋ̀ є҆гѡ̀, и҆ на ве́рхъ є҆гѡ̀ непра́вда є҆гѡ̀ сни́детъ. И҆сповѣ́мсѧ гдⷭ҇еви по пра́вдѣ є҆гѡ̀ и҆ пою̀ и҆́мени гдⷭ҇а вы́шнѧгѡ.",
  ["заголовок_ру"] = "Псало́м Дави́ду, его́же воспе́т Го́сподеви о словесе́х Хуси́евых, сы́на Иемени́ина.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, є҆го́же воспѣ́тъ гдⷭ҇еви ѡ҆ словесѣ́хъ хꙋсі́евыхъ, сы́на і҆емені́ина."
}

add_psalom {
  ["номер"] = 8,
  ["часть"] = 1,
  ["кафизма"] = 1,
  ["слава"] = 3,
  ["текст_ру"] = "Го́споди, Госпо́дь наш, я́ко чу́дно и́мя Твое́ по всей земли́, я́ко взя́тся великоле́пие Твое́ превы́ше небе́с. Из уст младе́нец и ссу́щих соверши́л еси́ хвалу́, враг Твои́х ра́ди, е́же разруши́ти врага́ и ме́стника. Я́ко узрю́ небеса́, дела́ перст Твои́х, луну́ и зве́зды, я́же Ты основа́л еси́. Что есть челове́к, я́ко по́мниши eго́? или́ сын челове́чь, я́ко посеща́еши eго́? Ума́лил еси́ eго́ ма́лым чим от а́нгел, сла́вою и че́стию венча́л еси́ eго́. И поста́вил еси́ eго́ над де́лы руку́ Твое́ю, вся покори́л еси́ под но́зе eго́. О́вцы и волы́ вся, еще́ же и скоты́ польски́я, пти́цы небе́сныя, и ры́бы морски́я, преходя́щыя стези́ морски́я. Го́споди, Госпо́дь наш, я́ко чу́дно и́мя Твое́ по всей земли́.",
  ["текст_цс"] = "Гдⷭ҇и гдⷭ҇ь на́шъ, ꙗ҆́кѡ чꙋ́дно и҆́мѧ твоѐ по все́й землѝ, ꙗ҆́кѡ взѧ́тсѧ великолѣ́пїе твоѐ превы́ше нб҃съ. И҆з̾ ᲂу҆́стъ младе́нєцъ и҆ ссꙋ́щихъ соверши́лъ є҆сѝ хвалꙋ̀, вра̑гъ твои́хъ ра́ди, є҆́же разрꙋши́ти врага̀ и҆ ме́стника. Ꙗ҆́кѡ ᲂу҆зрю̀ небеса̀, дѣла̀ пє́рстъ твои́хъ, лꙋнꙋ̀ и҆ ѕвѣ́зды, ꙗ҆̀же ты̀ ѡ҆снова́лъ є҆сѝ: что̀ є҆́сть человѣ́къ, ꙗ҆́кѡ по́мниши є҆го̀; и҆лѝ сы́нъ человѣ́чь, ꙗ҆́кѡ посѣща́еши є҆го̀; Оу҆ма́лилъ є҆сѝ є҆го̀ ма́лымъ чи́мъ ѿ а҆́гг҃лъ, сла́вою и҆ че́стїю вѣнча́лъ є҆сѝ є҆го̀: И҆ поста́вилъ є҆сѝ є҆го̀ над̾ дѣ́лы рꙋкꙋ̀ твоє́ю, всѧ̑ покори́лъ є҆сѝ под̾ но́зѣ є҆гѡ̀: Ѻ҆́вцы и҆ волы̀ всѧ̑, є҆ще́ же и҆ скоты̀ пѡльскі́ѧ, Пти̑цы небє́сныѧ и҆ ры̑бы морскі̑ѧ, преходѧ́щыѧ стєзѝ морскі̑ѧ. Гдⷭ҇и гдⷭ҇ь на́шъ, ꙗ҆́кѡ чꙋ́дно и҆́мѧ твоѐ по все́й землѝ.",
  ["заголовок_ру"] = "В коне́ц, о точи́лех, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ точи́лѣхъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 9,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 1,
  ["текст_ру"] = "Испове́мся Тебе́, Го́споди, всем се́рдцем мои́м, пове́м вся чудеса́ Твоя́. Возвеселю́ся и возра́дуюся о Тебе́, пою́ и́мени Твоему́, Вы́шний. Внегда́ возврати́тися врагу́ моему́ вспять, изнемо́гут и поги́бнут от лица́ Твоего́. Я́ко сотвори́л eси́ суд мой и прю мою́, сел eси́ на Престо́ле, судя́й пра́вду. Запрети́л eси́ язы́ком, и поги́бе нечести́вый, и́мя eго́ потреби́л eси́ в век и в век ве́ка. Врагу́ оскуде́ша oру́жия в коне́ц, и гра́ды разруши́л eси́, поги́бе па́мять eго́ с шу́мом. И Госпо́дь во век пребыва́ет, угото́ва на суд престо́л Свой, и Той суди́ти и́мать вселе́нней в пра́вду, суди́ти и́мать лю́дем в правоте́. И бысть Госпо́дь прибе́жище убо́гому, помо́щник во благовре́мениих, в ско́рбех. И да упова́ют на Тя зна́ющии и́мя Твое́, я́ко не оста́вил eси́ взыска́ющих Тя, Го́споди. По́йте Го́сподеви, живу́щему в Сио́не, возвести́те во язы́цех начина́ния Его́, я́ко взыска́яй кро́ви их помяну́, не забы́ зва́ния убо́гих. Поми́луй мя, Го́споди, виждь смире́ние мое́ от враг мои́х, вознося́й мя от врат сме́ртных, Я́ко да возвещу́ вся хвалы́ Твоя́ во врате́х дще́ре Сио́ни, возра́дуемся о спасе́нии Твое́м. Углебо́ша язы́цы в па́губе, ю́же сотвори́ша, в се́ти сей, ю́же скры́ша, увязе́ нога́ их. Зна́емь eсть Госпо́дь судьбы́ творя́й, в де́лех руку́ своeю увязе́ гре́шник. Да возвратя́тся гре́шницы во ад, вси язы́цы забыва́ющии Бо́га. Я́ко не до конца́ забве́н бу́дет ни́щий, терпе́ние убо́гих не поги́бнет до конца́. Воскресни́, Го́споди, да не крепи́тся челове́к, да су́дятся язы́цы пред Тобо́ю. Поста́ви, Го́споди, законоположи́теля над ни́ми, да разуме́ют язы́цы, я́ко челове́цы суть. Вску́ю, Го́споди, отстоя́ дале́че, презира́еши во благовре́мениих, в ско́рбех? Внегда́ горди́тися нечести́вому, возгара́ется ни́щий, увяза́ют в сове́тех, я́же помышля́ют. Я́ко хвали́мь eсть гре́шный в по́хотех души́ своея́, и оби́дяй благослови́мь eсть. Раздражи́ Го́спода гре́шный, по мно́жеству гне́ва своего́ не взы́щет, несть Бо́га пред ним. Оскверня́ются путие́ eго́ на вся́ко вре́мя, отъе́млются судьбы́ Твоя́ от лица́ eго́, все́ми враги́ свои́ми облада́ет. Рече́ бо в се́рдце свое́м, не подви́жуся от ро́да в род без зла, eго́же кля́твы уста́ eго́ по́лна суть, и го́рести и льсти, под язы́ком eго́ труд и боле́знь. Приседи́т в лови́тельстве с бога́тыми в та́йных, eже уби́ти непови́ннаго, oчи eго́ на ни́щаго призира́ете. Лови́т в та́йне я́ко лев во огра́де свое́й, лови́т eже восхи́тити ни́щаго, восхи́тити ни́щаго, внегда́ привлещи́ и́. В се́ти свое́й смири́т eго́, прекло́нится и паде́т, внегда́ eму́ облада́ти убо́гими. Рече́ бо в се́рдце свое́м: забы́ Бог, отврати́ лице́ Свое́, да не ви́дит до конца́. Воскресни́, Го́споди Бо́же мой, да вознесе́тся рука́ Твоя́, не забу́ди убо́гих Твои́х до конца́. Чесо́ ра́ди прогне́ва нечести́вый Бо́га? Рече́ бо в се́рдце свое́м: не взы́щет. Ви́диши, я́ко Ты боле́знь и я́рость смотря́еши, да пре́дан бу́дет в ру́це Твои́, Тебе́ оста́влен eсть ни́щий, си́ру Ты бу́ди помо́щник. Сокруши́ мы́шцу гре́шному и лука́вому, взы́щется грех eго́ и не обря́щется. Госпо́дь Царь во век и в век ве́ка, поги́бнете, язы́цы, от земли́ Его́. Жела́ние убо́гих услы́шал eси́, Го́споди, угото́ванию се́рдца их внят у́хо Твое́. Суди́ си́ру и смире́ну, да не приложи́т ктому́ велича́тися челове́к на земли́.",
  ["текст_цс"] = "И҆сповѣ́мсѧ тебѣ̀, гдⷭ҇и, всѣ́мъ се́рдцемъ мои́мъ, повѣ́мъ всѧ̑ чꙋдеса̀ твоѧ̑. Возвеселю́сѧ и҆ возра́дꙋюсѧ ѡ҆ тебѣ̀, пою̀ и҆́мени твоемꙋ̀, вы́шнїй. Внегда̀ возврати́тисѧ врагꙋ̀ моемꙋ̀ вспѧ́ть, и҆знемо́гꙋтъ и҆ поги́бнꙋтъ ѿ лица̀ твоегѡ̀. Ꙗ҆́кѡ сотвори́лъ є҆сѝ сꙋ́дъ мо́й и҆ прю̀ мою̀: сѣ́лъ є҆сѝ на прⷭ҇то́лѣ, сꙋдѧ́й пра́вдꙋ. Запрети́лъ є҆сѝ ꙗ҆зы́кѡмъ, и҆ поги́бе нечести́вый: и҆́мѧ є҆гѡ̀ потреби́лъ є҆сѝ въ вѣ́къ и҆ въ вѣ́къ вѣ́ка. Врагꙋ̀ ѡ҆скꙋдѣ́ша ѻ҆рꙋ̑жїѧ въ коне́цъ, и҆ гра́ды разрꙋши́лъ є҆сѝ: поги́бе па́мѧть є҆гѡ̀ съ шꙋ́момъ. И҆ гдⷭ҇ь во вѣ́къ пребыва́етъ, ᲂу҆гото́ва на сꙋ́дъ прⷭ҇то́лъ сво́й: И҆ то́й сꙋди́ти и҆́мать вселе́ннѣй въ пра́вдꙋ, сꙋди́ти и҆́мать лю́демъ въ правотѣ̀. И҆ бы́сть гдⷭ҇ь прибѣ́жище ᲂу҆бо́гомꙋ, помо́щникъ во бл҃говре́менїихъ, въ ско́рбехъ. И҆ да ᲂу҆пова́ютъ на тѧ̀ зна́ющїи и҆́мѧ твоѐ, ꙗ҆́кѡ не ѡ҆ста́вилъ є҆сѝ взыска́ющихъ тѧ̀, гдⷭ҇и. По́йте гдⷭ҇еви, живꙋ́щемꙋ въ сїѡ́нѣ, возвѣсти́те во ꙗ҆зы́цѣхъ начина̑нїѧ є҆гѡ̀: Ꙗ҆́кѡ взыска́ѧй крѡ́ви и҆́хъ помѧнꙋ̀, не забы̀ зва́нїѧ ᲂу҆бо́гихъ. Поми́лꙋй мѧ̀, гдⷭ҇и, ви́ждь смире́нїе моѐ ѿ вра̑гъ мои́хъ, возносѧ́й мѧ̀ ѿ вра́тъ сме́ртныхъ: Ꙗ҆́кѡ да возвѣщꙋ̀ всѧ̑ хвалы̑ твоѧ̑ во вратѣ́хъ дще́ре сїѡ́ни: возра́дꙋемсѧ ѡ҆ сп҃се́нїи твое́мъ. Оу҆глѣбо́ша ꙗ҆зы́цы въ па́гꙋбѣ, ю҆́же сотвори́ша: въ сѣ́ти се́й, ю҆́же скры́ша, ᲂу҆вѧзѐ нога̀ и҆́хъ. Зна́емь є҆́сть гдⷭ҇ь сꙋдьбы̑ творѧ́й: въ дѣ́лѣхъ рꙋкꙋ̀ своє́ю ᲂу҆вѧзѐ грѣ́шникъ. Да возвратѧ́тсѧ грѣ̑шницы во а҆́дъ, всѝ ꙗ҆зы́цы забыва́ющїи бг҃а. Ꙗ҆́кѡ не до конца̀ забве́нъ бꙋ́детъ ни́щїй, терпѣ́нїе ᲂу҆бо́гихъ не поги́бнетъ до конца̀. Воскрⷭ҇нѝ, гдⷭ҇и, да не крѣпи́тсѧ человѣ́къ, да сꙋ́дѧтсѧ ꙗ҆зы́цы пред̾ тобо́ю. Поста́ви, гдⷭ҇и, законоположи́телѧ над̾ ни́ми, да разꙋмѣ́ютъ ꙗ҆зы́цы, ꙗ҆́кѡ человѣ́цы сꙋ́ть. Вскꙋ́ю, гдⷭ҇и, ѿстоѧ̀ дале́че, презира́еши во бл҃говре́менїихъ, въ ско́рбехъ; Внегда̀ горди́тисѧ нечести́вомꙋ, возгара́етсѧ ни́щїй: ᲂу҆вѧза́ютъ въ совѣ́тѣхъ, ꙗ҆̀же помышлѧ́ютъ. Ꙗ҆́кѡ хвали́мь є҆́сть грѣ́шный въ по́хотехъ дꙋшѝ своеѧ̀, и҆ ѡ҆би́дѧй бл҃гослови́мь є҆́сть. Раздражѝ гдⷭ҇а грѣ́шный: по мно́жествꙋ гнѣ́ва своегѡ̀ не взы́щетъ: нѣ́сть бг҃а пред̾ ни́мъ. Ѡ҆сквернѧ́ютсѧ пꙋтїѐ є҆гѡ̀ на всѧ́ко вре́мѧ: ѿе́млютсѧ сꙋдьбы̑ твоѧ̑ ѿ лица̀ є҆гѡ̀: всѣ́ми врагѝ свои́ми ѡ҆блада́етъ. Рече́ бо въ се́рдцы свое́мъ: не подви́жꙋсѧ ѿ ро́да въ ро́дъ без̾ ѕла̀: Є҆гѡ́же клѧ́твы ᲂу҆ста̀ є҆гѡ̀ пѡ́лна сꙋ́ть, и҆ го́рести и҆ льстѝ: под̾ ѧ҆зы́комъ є҆гѡ̀ трꙋ́дъ и҆ болѣ́знь. Присѣди́тъ въ лови́тельствѣ съ бога́тыми въ та́йныхъ, є҆́же ᲂу҆би́ти непови́ннаго: ѻ҆́чи є҆гѡ̀ на ни́щаго призира́етѣ. Лови́тъ въ та́йнѣ ꙗ҆́кѡ ле́въ во ѡ҆гра́дѣ свое́й, лови́тъ є҆́же восхи́тити ни́щаго, восхи́тити ни́щаго, внегда̀ привлещѝ и҆̀ въ сѣ́ти свое́й. Смири́тъ є҆го̀: преклони́тсѧ и҆ паде́тъ, внегда̀ є҆мꙋ̀ ѡ҆блада́ти ᲂу҆бо́гими. Рече́ бо въ се́рдцы свое́мъ: забы̀ бг҃ъ, ѿвратѝ лицѐ своѐ, да не ви́дитъ до конца̀. Воскрⷭ҇нѝ, гдⷭ҇и бж҃е мо́й, да вознесе́тсѧ рꙋка̀ твоѧ̀, не забꙋ́ди ᲂу҆бо́гихъ твои́хъ до конца̀. Чесѡ̀ ра́ди прогнѣ́ва нечести́вый бг҃а; рече́ бо въ се́рдцы свое́мъ: не взы́щетъ. Ви́диши, ꙗ҆́кѡ ты̀ болѣ́знь и҆ ꙗ҆́рость смотрѧ́еши, да пре́данъ бꙋ́детъ въ рꙋ́цѣ твоѝ: тебѣ̀ ѡ҆ста́вленъ є҆́сть ни́щїй, си́рꙋ ты̀ бꙋ́ди помо́щникъ. Сокрꙋшѝ мы́шцꙋ грѣ́шномꙋ и҆ лꙋка́вомꙋ: взы́щетсѧ грѣ́хъ є҆гѡ̀ и҆ не ѡ҆брѧ́щетсѧ. Гдⷭ҇ь цр҃ь во вѣ́къ и҆ въ вѣ́къ вѣ́ка: поги́бнете, ꙗ҆зы́цы, ѿ землѝ є҆гѡ̀. Жела́нїе ᲂу҆бо́гихъ ᲂу҆слы́шалъ є҆сѝ, гдⷭ҇и, ᲂу҆гото́ванїю се́рдца и҆́хъ внѧ́тъ ᲂу҆́хо твоѐ. Сꙋдѝ си́рꙋ и҆ смире́нꙋ, да не приложи́тъ ктомꙋ̀ велича́тисѧ человѣ́къ на землѝ.",
  ["заголовок_ру"] = "В коне́ц, о та́йных Сы́на, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ та́йныхъ сы́на, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 10,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 1,
  ["текст_ру"] = "На Го́спода упова́х, ка́ко рече́те души́ мое́й: превита́й по гора́м, я́ко пти́ца? Я́ко се, гре́шницы наляко́ша лук, угото́ваша стре́лы в ту́ле, состреля́ти во мра́це пра́выя се́рдцем. Зане́ я́же Ты соверши́л eси́, oни́ разруши́ша, пра́ведник же что сотвори́? Госпо́дь во хра́ме святе́м Свое́м. Госпо́дь, на небеси́ престо́л Его́, oчи Его́ на ни́щаго призира́ете, ве́жди Его́ испыта́ете сы́ны челове́чeския. Госпо́дь испыта́ет пра́веднаго и нечести́ваго, любя́й же непра́вду ненави́дит свою́ ду́шу. Одожди́т на гре́шники се́ти, oгнь и жу́пел, и дух бу́рен часть ча́ши их. Я́ко пра́веден Госпо́дь, и пра́вды возлюби́, правоты́ ви́де лице́ Его́.",
  ["текст_цс"] = "На гдⷭ҇а ᲂу҆пова́хъ, ка́кѡ рече́те дꙋшѝ мое́й: превита́й по гора́мъ, ꙗ҆́кѡ пти́ца; Ꙗ҆́кѡ сѐ, грѣ̑шницы налѧко́ша лꙋ́къ, ᲂу҆гото́ваша стрѣ́лы въ тꙋ́лѣ, сострѣлѧ́ти во мра́цѣ пра̑выѧ се́рдцемъ. Занѐ ꙗ҆̀же ты̀ соверши́лъ є҆сѝ, ѻ҆нѝ разрꙋши́ша: првⷣникъ же что̀ сотворѝ; Гдⷭ҇ь во хра́мѣ ст҃ѣ́мъ свое́мъ. Гдⷭ҇ь, на нб҃сѝ прⷭ҇то́лъ є҆гѡ̀: ѻ҆́чи є҆гѡ̀ на ни́щаго призира́етѣ, вѣ́жди є҆гѡ̀ и҆спыта́етѣ сы́ны человѣ́чєскїѧ. Гдⷭ҇ь и҆спыта́етъ првⷣнаго и҆ нечести́ваго: любѧ́й же непра́вдꙋ ненави́дитъ свою̀ дꙋ́шꙋ. Ѡ҆дожди́тъ на грѣ́шники сѣ̑ти: ѻ҆́гнь и҆ жꙋ́пелъ, и҆ дꙋ́хъ бꙋ́ренъ ча́сть ча́ши и҆́хъ. Ꙗ҆́кѡ првⷣнъ гдⷭ҇ь и҆ пра̑вды возлюбѝ: правѡты̀ ви́дѣ лицѐ є҆гѡ̀.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ"
}

add_psalom {
  ["номер"] = 11,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 2,
  ["текст_ру"] = "Спаси́ мя, Го́споди, я́ко оскуде́ преподо́бный, я́ко ума́лишася и́стины от сыно́в челове́ческих. Су́eтная глаго́ла ки́йждо ко и́скреннему своему́, устне́ льсти́выя в се́рдце, и в се́рдце глаго́лаша зла́я. Потреби́т Госпо́дь вся устны́ льсти́выя, язы́к велере́чивый, ре́кшыя: язы́к наш возвели́чим, устны́ на́ша при нас суть, кто нам Госпо́дь eсть? Стра́сти ра́ди ни́щих и воздыха́ния убо́гих ны́не воскресну́, глаго́лет Госпо́дь, положу́ся во спасе́ние, не обиню́ся о нем. Словеса́ Госпо́дня словеса́ чи́ста, сребро́ разжже́но, искуше́но земли́, очище́но седмери́цею. Ты, Го́споди, сохрани́ши ны и соблюде́ши ны от ро́да сего́ и во век. О́крест нечести́вии хо́дят, по высоте́ Твое́й умно́жил eси́ сы́ны челове́чeския.",
  ["текст_цс"] = "Сп҃си́ мѧ, гдⷭ҇и, ꙗ҆́кѡ ѡ҆скꙋдѣ̀ прпⷣбный: ꙗ҆́кѡ ᲂу҆ма́лишасѧ и҆́стины ѿ сынѡ́въ человѣ́ческихъ. Сꙋ́єтнаѧ глаго́ла кі́йждо ко и҆́скреннемꙋ своемꙋ̀: ᲂу҆стнѣ̀ льсти̑выѧ въ се́рдцы, и҆ въ се́рдцы глаго́лаша ѕла̑ѧ. Потреби́тъ гдⷭ҇ь всѧ̑ ᲂу҆стны̀ льсти̑выѧ, ѧ҆зы́къ велерѣ́чивый, Ре́кшыѧ: ѧ҆зы́къ на́шъ возвели́чимъ, ᲂу҆стны̀ на̑ша при на́съ сꙋ́ть: кто̀ на́мъ гдⷭ҇ь є҆́сть; Стра́сти ра́ди ни́щихъ и҆ воздыха́нїѧ ᲂу҆бо́гихъ ны́нѣ воскрⷭ҇нꙋ̀, гл҃етъ гдⷭ҇ь: положꙋ́сѧ во сп҃се́нїе, не ѡ҆биню́сѧ ѡ҆ не́мъ. Словеса̀ гдⷭ҇нѧ словеса̀ чи̑ста, сребро̀ разжже́но, и҆скꙋше́но землѝ, ѡ҆чище́но седмери́цею. Ты̀, гдⷭ҇и, сохрани́ши ны̀ и҆ соблюде́ши ны̀ ѿ ро́да сегѡ̀ и҆ во вѣ́къ. Ѡ҆́крестъ нечести́вїи хо́дѧтъ: по высотѣ̀ твое́й ᲂу҆мно́жилъ є҆сѝ сы́ны человѣ́чєскїѧ.",
  ["заголовок_ру"] = "В коне́ц, о осме́й, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ ѻ҆смѣ́й, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 12,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 2,
  ["текст_ру"] = "Доко́ле, Го́споди, забу́деши мя до конца́? Доко́ле отвраща́еши лице́ Твое́ от менe? Доко́ле положу́ сове́ты в души́ мое́й, боле́зни в се́рдце мое́м день и нощь? Доко́ле вознесе́тся враг мой на мя? При́зри, услы́ши мя, Го́споди Бо́же мой, просвети́ oчи мои́, да не когда́ усну́ в смерть, да не когда́ рече́т враг мой, укрепи́хся на него́. Стужа́ющии ми возра́дуются, а́ще подви́жуся. Аз же на ми́лость Твою́ упова́х, возра́дуется се́рдце мое́ о спасе́нии Твое́м, воспою́ Го́сподеви благоде́явшему мне и пою́ и́мени Го́спода Вы́шняго.",
  ["текст_цс"] = "Доко́лѣ, гдⷭ҇и, забꙋ́деши мѧ̀ до конца̀; доко́лѣ ѿвраща́еши лицѐ твоѐ ѿ менѐ; Доко́лѣ положꙋ̀ совѣ́ты въ дꙋшѝ мое́й, бѡлѣ́зни въ се́рдцы мое́мъ де́нь и҆ но́щь; доко́лѣ вознесе́тсѧ вра́гъ мо́й на мѧ̀; При́зри, ᲂу҆слы́ши мѧ̀, гдⷭ҇и бж҃е мо́й: просвѣтѝ ѻ҆́чи моѝ, да не когда̀ ᲂу҆снꙋ̀ въ сме́рть: Да не когда̀ рече́тъ вра́гъ мо́й: ᲂу҆крѣпи́хсѧ на него̀. Стꙋжа́ющїи мѝ возра́дꙋютсѧ, а҆́ще подви́жꙋсѧ. А҆́зъ же на млⷭ҇ть твою̀ ᲂу҆пова́хъ: возра́дꙋетсѧ се́рдце моѐ ѡ҆ сп҃се́нїи твое́мъ: воспою̀ гдⷭ҇еви бл҃годѣ́ѧвшемꙋ мнѣ̀ и҆ пою̀ и҆́мени гдⷭ҇а вы́шнѧгѡ.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 13,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 2,
  ["текст_ру"] = "Рече́ безу́мен в се́рдце свое́м: несть Бог. Растле́ша и омерзи́шася в начина́ниих, несть творя́й благосты́ню. Госпо́дь с небесе́ прини́че на сы́ны челове́чeския, ви́дети, а́ще eсть разумева́яй или́ взыска́яй Бо́га. Вси уклони́шася, вку́пе неключи́ми бы́ша: несть творя́й благосты́ню, несть до eди́наго. Ни ли́ уразуме́ют вси де́лающии беззако́ние, снеда́ющии лю́ди моя́ в снедь хле́ба? Го́спода не призва́ша. Та́мо убоя́шася стра́ха, иде́же не бе страх, я́ко Госпо́дь в ро́де пра́ведных. Сове́т ни́щаго посрами́сте, Госпо́дь же упова́ние eго́ eсть. Кто даст от Сио́на спасе́ние Изра́илево? Внегда́ возврати́т Госпо́дь плене́ние люде́й Свои́х, возра́дуется Иа́ков, и возвесели́тся Изра́иль.",
  ["текст_цс"] = "Речѐ безꙋ́менъ въ се́рдцы свое́мъ: нѣ́сть бг҃ъ. Растлѣ́ша и҆ ѡ҆мерзи́шасѧ въ начина́нїихъ: нѣ́сть творѧ́й бл҃госты́ню. Гдⷭ҇ь съ нб҃сѐ прини́че на сы́ны человѣ́чєскїѧ, ви́дѣти, а҆́ще є҆́сть разꙋмѣва́ѧй, и҆лѝ взыска́ѧй бг҃а. Всѝ ᲂу҆клони́шасѧ, вкꙋ́пѣ неключи́ми бы́ша: нѣ́сть творѧ́й бл҃госты́ню, нѣ́сть до є҆ди́нагѡ. Ни лѝ ᲂу҆разꙋмѣ́ютъ всѝ дѣ́лающїи беззако́нїе, снѣда́ющїи лю́ди моѧ̑ въ снѣ́дь хлѣ́ба; гдⷭ҇а не призва́ша. Та́мѡ ᲂу҆боѧ́шасѧ стра́ха, и҆дѣ́же не бѣ̀ стра́хъ: ꙗ҆́кѡ гдⷭ҇ь въ ро́дѣ првⷣныхъ. Совѣ́тъ ни́щагѡ посрами́сте: гдⷭ҇ь же ᲂу҆пова́нїе є҆гѡ̀ є҆́сть. Кто̀ да́стъ ѿ сїѡ́на сп҃се́нїе і҆и҃лево; Внегда̀ возврати́тъ гдⷭ҇ь плѣне́нїе люде́й свои́хъ, возра́дꙋетсѧ і҆а́кѡвъ, и҆ возвесели́тсѧ і҆и҃ль.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 14,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 3,
  ["текст_ру"] = "Го́споди, кто обита́ет в жили́щи Твое́м? Или́ кто всели́тся во святу́ю го́ру Твою́? Ходя́й непоро́чен и де́лаяй пра́вду, глаго́ляй и́стину в се́рдце свое́м. И́же не ульсти́ язы́ком свои́м и не сотвори́ и́скреннему своему́ зла, и поноше́ния не прия́т на бли́жния своя́. Уничиже́н eсть пред ним лука́внуяй, боя́щыя же ся Го́спода сла́вит, клены́йся и́скреннему свое́му и не отмета́яся. Сребра́ своего́ не даде́ в ли́хву и мзды на непови́нных не прия́т. Творя́й сия́ не подви́жится во век.",
  ["текст_цс"] = "Гдⷭ҇и, кто̀ ѡ҆бита́етъ въ жили́щи твое́мъ; и҆лѝ кто̀ всели́тсѧ во ст҃ꙋ́ю го́рꙋ твою̀; Ходѧ́й непоро́ченъ и҆ дѣ́лаѧй пра́вдꙋ, глаго́лѧй и҆́стинꙋ въ се́рдцы свое́мъ: И҆́же не ᲂу҆льстѝ ѧ҆зы́комъ свои́мъ и҆ не сотворѝ и҆́скреннемꙋ своемꙋ̀ ѕла̀, и҆ поноше́нїѧ не прїѧ́тъ на бли̑жнїѧ своѧ̑: Оу҆ничиже́нъ є҆́сть пред̾ ни́мъ лꙋка́внꙋѧй, боѧ́щыѧжесѧ гдⷭ҇а сла́витъ: клены́йсѧ и҆́скреннемꙋ своемꙋ̀ и҆ не ѿмета́ѧсѧ: Сребра̀ своегѡ̀ не дадѐ въ ли́хвꙋ и҆ мзды̀ на непови́нныхъ не прїѧ́тъ. Творѧ́й сїѧ̑ не подви́житсѧ во вѣ́къ.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 15,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 3,
  ["текст_ру"] = "Сохрани́ мя, Го́споди, я́ко на Тя упова́х. Рех Го́сподеви: Госпо́дь мой eси́ Ты, я́ко благи́х мои́х не тре́буеши. Святы́м, и́же суть на земли́ Его́, удиви́ Госпо́дь вся хоте́ния Своя́ в них. Умно́жишася не́мощи их, по сих ускори́ша: не соберу́ собо́ры их от крове́й, ни помяну́ же име́н их устна́ма мои́ма. Госпо́дь часть достоя́ния моего́ и ча́ши моея́, Ты eси́ устроя́яй достоя́ние мое́ мне. У́жя нападо́ша ми в держа́вных мои́х, и́бо достоя́ние мое́ держа́вно eсть мне. Благословлю́ Го́спода, вразуми́вшаго мя, eще́ же и до но́щи нака́заша мя утро́бы моя́. Предзре́х Го́спода предо мно́ю вы́ну, я́ко одесну́ю менe eсть, да не подви́жуся. Сего́ ра́ди возвесели́ся се́рдце мое́, и возра́довася язы́к мой, eще́ же и плоть моя́ всели́тся на упова́нии. Я́ко не оста́виши ду́шу мою́ во а́де, ниже́ да́си преподо́бному Твоему́ ви́дети истле́ния. Сказа́л ми eси́ пути́ живота́, испо́лниши мя весе́лия с лице́м Твои́м, красота́ в десни́це Твое́й в коне́ц.",
  ["текст_цс"] = "Сохрани́ мѧ, гдⷭ҇и, ꙗ҆́кѡ на тѧ̀ ᲂу҆пова́хъ. Рѣ́хъ гдⷭ҇еви: гдⷭ҇ь мо́й є҆сѝ ты̀, ꙗ҆́кѡ благи́хъ мои́хъ не тре́бꙋеши. Ст҃ы̑мъ, и҆̀же сꙋ́ть на землѝ є҆гѡ̀, ᲂу҆дивѝ гдⷭ҇ь всѧ̑ хотѣ̑нїѧ своѧ̑ въ ни́хъ. Оу҆мно́жишасѧ не́мѡщи и҆́хъ, по си́хъ ᲂу҆скори́ша: не соберꙋ̀ собо́ры и҆́хъ ѿ крове́й, ни помѧнꙋ́ же и҆ме́нъ и҆́хъ ᲂу҆стна́ма мои́ма. Гдⷭ҇ь ча́сть достоѧ́нїѧ моегѡ̀ и҆ ча́ши моеѧ̀: ты̀ є҆сѝ ᲂу҆строѧ́ѧй достоѧ́нїе моѐ мнѣ̀. Оу҆́жѧ нападо́ша мѝ въ держа́вныхъ мои́хъ: и҆́бо достоѧ́нїе моѐ держа́вно є҆́сть мнѣ̀. Бл҃гословлю̀ гдⷭ҇а вразꙋми́вшаго мѧ̀: є҆ще́ же и҆ до но́щи наказа́ша мѧ̀ ᲂу҆трѡ́бы моѧ̑. Предзрѣ́хъ гдⷭ҇а предо мно́ю вы́нꙋ, ꙗ҆́кѡ ѡ҆деснꙋ́ю менѐ є҆́сть, да не подви́жꙋсѧ. Сегѡ̀ ра́ди возвесели́сѧ се́рдце моѐ, и҆ возра́довасѧ ѧ҆зы́къ мо́й: є҆ще́ же и҆ пло́ть моѧ̀ всели́тсѧ на ᲂу҆пова́нїи. Ꙗ҆́кѡ не ѡ҆ста́виши дꙋ́шꙋ мою̀ во а҆́дѣ, нижѐ да́си прпⷣбномꙋ твоемꙋ̀ ви́дѣти и҆стлѣ́нїѧ. Сказа́лъ мѝ є҆сѝ пꙋти̑ живота̀: и҆спо́лниши мѧ̀ весе́лїѧ съ лице́мъ твои́мъ: красота̀ въ десни́цѣ твое́й въ коне́цъ.",
  ["заголовок_ру"] = "Столпописа́ние, Дави́ду.",
  ["заголовок_цс"] = "Столпописа́нїе, дв҃дꙋ."
}

add_psalom {
  ["номер"] = 16,
  ["часть"] = 1,
  ["кафизма"] = 2,
  ["слава"] = 3,
  ["текст_ру"] = "Услы́ши, Го́споди, пра́вду мою́, вонми́ моле́нию моему́, внуши́ моли́тву мою́ не во устна́х льсти́вых. От лица́ Твоего́ судьба́ моя́ изы́дет, oчи мои́ да ви́дита правоты́. Искуси́л eси́ се́рдце мое́, посети́л eси́ но́щию, искуси́л мя eси́, и не обре́теся во мне непра́вда. Я́ко да не возглаго́лют уста́ моя́ дел челове́ческих, за словеса́ усте́н Твои́х аз сохрани́х пути́ же́стоки. Соверши́ стопы́ моя́ во стезя́х Твои́х, да не подви́жутся стопы́ моя́. Аз воззва́х, я́ко услы́шал мя eси́, Бо́же, приклони́ у́хо Твое́ мне и услы́ши глаго́лы моя́. Удиви́ ми́лости Твоя́, спаса́яй упова́ющыя на Тя от проти́вящихся десни́це Твое́й. Сохрани́ мя, Го́споди, я́ко зе́ницу oка, в кро́ве крилу́ Твоeю покры́еши мя. От лица́ нечести́вых остра́стших мя, врази́ мои́ ду́шу мою́ одержа́ша. Тук свой затвори́ша, уста́ их глаго́лаша горды́ню. Изгоня́щии мя ны́не обыдо́ша мя, oчи свои́ возложи́ша уклони́ти на зе́млю. Объя́ша мя я́ко лев гото́в на лов и я́ко ски́мен обита́яй в та́йных. Воскресни́, Го́споди, предвари́ я́ и запни́ им, изба́ви ду́шу мою́ от нечести́ваго, oру́жие Твое́ от враг руки́ Твоея́, Го́споди, от ма́лых от земли́, раздели́ я́ в животе́ их, и сокрове́нных Твои́х испо́лнися чре́во их, насы́тишася сыно́в, и оста́виша оста́нки младе́нцeм свои́м. Аз же пра́вдою явлю́ся лицу́ Твоему́, насы́щуся, внегда́ яви́ти ми ся сла́ве Твое́й.",
  ["текст_цс"] = "Оу҆слы́ши, гдⷭ҇и, пра́вдꙋ мою̀, вонмѝ моле́нїю моемꙋ̀, внꙋшѝ моли́твꙋ мою̀ не во ᲂу҆стна́хъ льсти́выхъ. Ѿ лица̀ твоегѡ̀ сꙋдьба̀ моѧ̀ и҆зы́детъ: ѻ҆́чи моѝ да ви́дита правоты̑. И҆скꙋси́лъ є҆сѝ се́рдце моѐ, посѣти́лъ є҆сѝ но́щїю: и҆скꙋси́лъ мѧ̀ є҆сѝ, и҆ не ѡ҆брѣ́тесѧ во мнѣ̀ непра́вда. Ꙗ҆́кѡ да не возглаго́лютъ ᲂу҆ста̀ моѧ̑ дѣ́лъ человѣ́ческихъ, за словеса̀ ᲂу҆сте́нъ твои́хъ а҆́зъ сохрани́хъ пꙋти̑ же́стѡки. Совершѝ стѡпы̀ моѧ̑ во стезѧ́хъ твои́хъ, да не подви́жꙋтсѧ стѡпы̀ моѧ̑. А҆́зъ воззва́хъ, ꙗ҆́кѡ ᲂу҆слы́шалъ мѧ̀ є҆сѝ, бж҃е: приклонѝ ᲂу҆́хо твоѐ мнѣ̀ и҆ ᲂу҆слы́ши глаго́лы моѧ̑. Оу҆дивѝ млⷭ҇ти твоѧ̑, сп҃са́ѧй ᲂу҆пова́ющыѧ на тѧ̀ ѿ проти́вѧщихсѧ десни́цѣ твое́й: Сохрани́ мѧ, гдⷭ҇и, ꙗ҆́кѡ зѣ́ницꙋ ѻ҆́ка: въ кро́вѣ крилꙋ̑ твоє́ю покры́еши мѧ̀ Ѿ лица̀ нечести́выхъ ѡ҆стра́стшихъ мѧ̀: вразѝ моѝ дꙋ́шꙋ мою̀ ѡ҆держа́ша Тꙋ́къ сво́й затвори́ша, ᲂу҆ста̀ и҆́хъ глаго́лаша горды́ню. И҆згонѧ́щїи мѧ̀ ны́нѣ ѡ҆быдо́ша мѧ̀, ѻ҆́чи своѝ возложи́ша ᲂу҆клони́ти на зе́млю. Ѡ҆б̾ѧ́ша мѧ̀ ꙗ҆́кѡ ле́въ гото́въ на ло́въ и҆ ꙗ҆́кѡ скѵ́менъ ѡ҆бита́ѧй въ та́йныхъ. Воскрⷭ҇нѝ, гдⷭ҇и, предварѝ ѧ҆̀ и҆ запнѝ и҆̀мъ: и҆зба́ви дꙋ́шꙋ мою̀ ѿ нечести́вагѡ, ѻ҆рꙋ́жїе твоѐ Ѿ вра̑гъ рꙋкѝ твоеѧ̀, гдⷭ҇и, ѿ ма́лыхъ ѿ землѝ: раздѣлѝ ѧ҆̀ въ животѣ̀ и҆́хъ, и҆ сокрове́нныхъ твои́хъ и҆спо́лнисѧ чре́во и҆́хъ: насы́тишасѧ сынѡ́въ, и҆ ѡ҆ста́виша ѡ҆ста́нки младе́нцємъ свои̑мъ. А҆́зъ же пра́вдою ꙗ҆влю́сѧ лицꙋ̀ твоемꙋ̀, насы́щꙋсѧ, внегда̀ ꙗ҆ви́тимисѧ сла́вѣ твое́й.",
  ["заголовок_ру"] = "Моли́тва Дави́ду.",
  ["заголовок_цс"] = "Моли́тва дв҃дꙋ."
}

add_psalom {
  ["номер"] = 17,
  ["часть"] = 1,
  ["кафизма"] = 3,
  ["слава"] = 1,
  ["текст_ру"] = "Возлюблю́ Тя, Го́споди, кре́посте моя́. Госпо́дь утвержде́ние мое́, и прибе́жище мое́, и Изба́витель Moй, Бог мой, Помо́щник мой, и упова́ю на Него́, Защи́титель мой, и рог спасе́ния моего́, и Засту́пник мой. Хваля́ призову́ Го́спода и от враг мои́х спасу́ся. Одержа́ша мя боле́зни сме́ртныя, и пото́цы беззако́ния смято́ша мя, боле́зни а́довы обыдо́ша мя, предвари́ша мя се́ти сме́ртныя. И внегда́ скорбе́ти ми, призва́х Го́спода, и к Бо́гу моему́ воззва́х, услы́ша от хра́ма Свята́го Своего́ глас мой, и вопль мой пред Ним вни́дет во у́ши Его́. И подви́жеся, и тре́петна бысть земля́, и основа́ния гор смято́шася и подвиго́шася, я́ко прогне́вася на ня Бог. Взы́де дым гне́вом Его́, и огнь от лица́ Его́ воспла́менится, у́глие возгоре́ся от Него́. И приклони́ небеса́, и сни́де, и мрак под нога́ма Его́. И взы́де на Херуви́мы, и лете́, лете́ на крилу́ ве́треню. И положи́ тму закро́в Свой, о́крест Его́ селе́ние Его́, темна́ вода́ во о́блацех возду́шных. От облиста́ния пред Ним о́блацы проидо́ша, град и у́глие о́гненное. И возгреме́ с небесе́ Госпо́дь и Вы́шний даде́ глас Свой. Низпосла́ стре́лы и разгна́ я́, и мо́лнии умно́жи и смяте́ я́. И яви́шася исто́чницы водни́и, и откры́шася основа́ния вселе́нныя, от запреще́ния Твоего́, Го́споди, от дохнове́ния ду́ха гне́ва Твоего́. Низпосла́ с высоты́, и прия́т мя, восприя́т мя от вод мно́гих. Изба́вит мя от враго́в мои́х си́льных и от ненави́дящих мя, я́ко утверди́шася па́че мене́. Предвари́ша мя в день озлобле́ния моего́, и бысть Госпо́дь утверже́ние мое́. И изведе́ мя на широту́, изба́вит мя, я́ко восхоте́ мя. И возда́ст ми Госпо́дь по пра́вде мое́й и по чистоте́ руку́ мое́ю возда́ст ми. Я́ко сохрани́х пути́ Госпо́дни и не нече́ствовах от Бо́га моего́. Я́ко вся судьбы́ Его́ предо мно́ю и оправда́ния Его́ не отступи́ша от мене́. И бу́ду непоро́чен с Ним, и сохраню́ся от беззако́ния моего́. И возда́ст ми Госпо́дь по пра́вде мое́й и по чистоте́ руку́ мое́ю пред очи́ма Его́. С преподо́бным преподо́бен бу́деши, и с му́жем непови́нным непови́нен бу́деши, и со избра́нным избра́н бу́деши, и со стропти́вым разврати́шися. Я́ко Ты лю́ди смире́нныя спасе́ши и о́чи го́рдых смири́ши. Я́ко Ты просвети́ши свети́льник мой, Го́споди, Бо́же мой, просвети́ши тму мою́. Я́ко Тобо́ю изба́влюся от искуше́ния и Богом мои́м прейду́ сте́ну. Бог мой, непоро́чен путь Его́, словеса́ Госпо́дня разжже́на, Защи́титель есть всех упова́ющих на Него́. Я́ко кто бог, ра́зве Го́спода? или́ кто бог, ра́зве Бо́га на́шего? Бог препоясу́яй мя си́лою, и положи́ непоро́чен путь мой. Соверша́яй но́зе мои́, я́ко еле́ни, и на высо́ких поставля́яй мя. Науча́яй ру́це мои́ на брань, и положи́л еси́ лук ме́дян мы́шца моя́. И дал ми еси́ защище́ние спасе́ния, и десни́ца Твоя́ восприя́т мя, и наказа́ние Твое́ испра́вит мя в коне́ц, и наказа́ние Твое́ то мя научи́т. Ушири́л еси́ стопы́ моя́ подо мно́ю, и не изнемого́сте плесне́ мои́. Пожену́ враги́ моя́, и пости́гну я́, и не возвращу́ся, до́ндеже сконча́ются. Оскорблю́ их, и не возмо́гут ста́ти, паду́т под нога́ма мои́ма. И препоя́сал мя еси́ си́лою на брань, спял еси́ вся востаю́щыя на мя под мя. И враго́в мои́х дал ми еси́ хребе́т, и ненави́дящыя мя потреби́л еси́. Воззва́ша, и не бе спаса́яй: ко Го́споду, и не услы́ша их. И истню́ я́ я́ко прах пред лице́м ве́тра, я́ко бре́ние путе́й погла́жду я́. Изба́виши мя от пререка́ния люде́й, поста́виши мя во главу́ язы́ков. Лю́дие, и́хже не ве́дех, рабо́таша ми. В слух у́ха послу́шаша мя. Сы́нове чужди́и солга́ша ми. Сы́нове чужди́и обетша́ша и охромо́ша от стезь свои́х. Жив Госпо́дь, и благослове́н Бог, и да вознесе́тся Бог спасе́ния моего́. Бог дая́й отмще́ние мне и покори́вый лю́ди под мя. Изба́витель мой от враг мои́х гневли́вых, от востаю́щих на мя вознесе́ши мя, от му́жа непра́ведна изба́виши мя. Сего́ ра́ди испове́мся Тебе́ во язы́цех, Го́споди, и и́мени Твоему́ пою́: велича́яй спасе́ния царе́ва, и творя́й ми́лость христу́ Своему́ Дави́ду, и се́мени eго́ до ве́ка.",
  ["текст_цс"] = "Возлюблю́ тѧ, гдⷭ҇и, крѣ́посте моѧ̀: Гдⷭ҇ь ᲂу҆твержде́нїе моѐ, и҆ прибѣ́жище моѐ, и҆ и҆зба́витель мо́й, бг҃ъ мо́й, помо́щникъ мо́й, и҆ ᲂу҆пова́ю на него̀: защи́титель мо́й, и҆ ро́гъ сп҃се́нїѧ моегѡ̀, и҆ застꙋ́пникъ мо́й. Хвалѧ̀ призовꙋ̀ гдⷭ҇а и҆ ѿ вра̑гъ мои́хъ спасꙋ́сѧ. Ѡ҆держа́ша мѧ̀ бѡлѣ́зни смє́ртныѧ, и҆ пото́цы беззако́нїѧ смѧто́ша мѧ̀: Бѡлѣ́зни а҆́дѡвы ѡ҆быдо́ша мѧ̀, предвари́ша мѧ̀ сѣ̑ти смє́ртныѧ. И҆ внегда̀ скорбѣ́ти мѝ, призва́хъ гдⷭ҇а и҆ къ бг҃ꙋ моемꙋ̀ воззва́хъ: ᲂу҆слы́ша ѿ хра́ма ст҃а́гѡ своегѡ̀ гла́съ мо́й, и҆ во́пль мо́й пред̾ ни́мъ вни́детъ во ᲂу҆́шы є҆гѡ̀. И҆ подви́жесѧ и҆ тре́петна бы́сть землѧ̀, и҆ ѡ҆снова̑нїѧ го́ръ смѧто́шасѧ и҆ подвиго́шасѧ, ꙗ҆́кѡ прогнѣ́васѧ на нѧ̀ бг҃ъ. Взы́де ды́мъ гнѣ́вомъ є҆гѡ̀, и҆ ѻ҆́гнь ѿ лица̀ є҆гѡ̀ воспла́менитсѧ: ᲂу҆́глїе возгорѣ́сѧ ѿ негѡ̀. И҆ приклонѝ нб҃са̀ и҆ сни́де, и҆ мра́къ под̾ нога́ма є҆гѡ̀. И҆ взы́де на херꙋві́мы и҆ летѣ̀, летѣ̀ на крилꙋ̑ вѣ́трєню. И҆ положѝ тмꙋ̀ закро́въ сво́й: ѡ҆́крестъ є҆гѡ̀ селе́нїе є҆гѡ̀: темна̀ вода̀ во ѻ҆́блацѣхъ воздꙋ́шныхъ. Ѿ ѡ҆блиста́нїѧ пред̾ ни́мъ ѻ҆́блацы проидо́ша, гра́дъ и҆ ᲂу҆́глїе ѻ҆́гненное. И҆ возгремѣ̀ съ нб҃сѐ гдⷭ҇ь, и҆ вы́шнїй дадѐ гла́съ сво́й. Низпосла̀ стрѣ́лы и҆ разгна̀ ѧ҆̀, и҆ мѡ́лнїи ᲂу҆мно́жи и҆ смѧтѐ ѧ҆̀. И҆ ꙗ҆ви́шасѧ и҆сто́чницы водні́и, и҆ ѿкры́шасѧ ѡ҆снова̑нїѧ вселе́нныѧ ѿ запреще́нїѧ твоегѡ̀, гдⷭ҇и, ѿ дохнове́нїѧ дꙋ́ха гнѣ́ва твоегѡ̀. Низпосла̀ съ высоты̀ и҆ прїѧ́тъ мѧ̀, воспрїѧ́тъ мѧ̀ ѿ во́дъ мно́гихъ. И҆зба́витъ мѧ̀ ѿ врагѡ́въ мои́хъ си́льныхъ и҆ ѿ ненави́дѧщихъ мѧ̀: ꙗ҆́кѡ ᲂу҆тверди́шасѧ па́че менѐ. Предвари́ша мѧ̀ въ де́нь ѡ҆ѕлобле́нїѧ моегѡ̀: и҆ бы́сть гдⷭ҇ь ᲂу҆твержде́нїе моѐ. И҆ и҆зведе́ мѧ на широтꙋ̀: и҆зба́витъ мѧ̀, ꙗ҆́кѡ восхотѣ́ мѧ. И҆ возда́стъ мѝ гдⷭ҇ь по пра́вдѣ мое́й, и҆ по чистотѣ̀ рꙋкꙋ̀ моє́ю возда́стъ мѝ, Ꙗ҆́кѡ сохрани́хъ пꙋти̑ гдⷭ҇ни и҆ не нече́ствовахъ ѿ бг҃а моегѡ̀. Ꙗ҆́кѡ всѧ̑ сꙋдьбы̑ є҆гѡ̀ предо мно́ю, и҆ ѡ҆правда̑нїѧ є҆гѡ̀ не ѿстꙋпи́ша ѿ менѐ. И҆ бꙋ́дꙋ непоро́ченъ съ ни́мъ и҆ сохраню́сѧ ѿ беззако́нїѧ моегѡ̀. И҆ возда́стъ мѝ гдⷭ҇ь по пра́вдѣ мое́й и҆ по чистотѣ̀ рꙋкꙋ̀ моє́ю пред̾ ѻ҆чи́ма є҆гѡ̀. Съ прпⷣбнымъ прпⷣбенъ бꙋ́деши, и҆ съ мꙋ́жемъ непови́ннымъ непови́ненъ бꙋ́деши, И҆ со и҆збра́ннымъ и҆збра́нъ бꙋ́деши, и҆ со стропти́вымъ разврати́шисѧ. Ꙗ҆́кѡ ты̀ лю́ди смирє́нныѧ сп҃се́ши и҆ ѻ҆́чи го́рдыхъ смири́ши. Ꙗ҆́кѡ ты̀ просвѣти́ши свѣти́льникъ мо́й, гдⷭ҇и: бж҃е мо́й, просвѣти́ши тмꙋ̀ мою̀. Ꙗ҆́кѡ тобо́ю и҆зба́влюсѧ ѿ и҆скꙋше́нїѧ, и҆ бг҃омъ мои́мъ прейдꙋ̀ стѣ́нꙋ. Бг҃ъ мо́й, непоро́ченъ пꙋ́ть є҆гѡ̀: словеса̀ гдⷭ҇нѧ разжжє́на. Защи́титель є҆́сть всѣ́хъ ᲂу҆пова́ющихъ на него̀. Ꙗ҆́кѡ кто̀ бг҃ъ, ра́звѣ гдⷭ҇а; и҆лѝ кто̀ бг҃ъ, ра́звѣ бг҃а на́шегѡ; Бг҃ъ препоѧсꙋ́ѧй мѧ̀ си́лою, и҆ положѝ непоро́ченъ пꙋ́ть мо́й: Соверша́ѧй но́зѣ моѝ ꙗ҆́кѡ є҆ле́ни, и҆ на высо́кихъ поставлѧ́ѧй мѧ̀: Наꙋча́ѧй рꙋ́цѣ моѝ на бра́нь, и҆ положи́лъ є҆сѝ лꙋ́къ мѣ́дѧнъ мы̑шца моѧ̑: И҆ да́лъ мѝ є҆сѝ защище́нїе сп҃се́нїѧ, и҆ десни́ца твоѧ̀ воспрїѧ́тъ мѧ̀: и҆ наказа́нїе твоѐ и҆спра́витъ мѧ̀ въ коне́цъ, и҆ наказа́нїе твоѐ то̀ мѧ̀ наꙋчи́тъ. Оу҆шири́лъ є҆сѝ стѡпы̀ моѧ̑ подо мно́ю, и҆ не и҆знемого́стѣ плеснѣ̀ моѝ. Поженꙋ̀ врагѝ моѧ̑, и҆ пости́гнꙋ ѧ҆̀, и҆ не возвращꙋ́сѧ, до́ндеже сконча́ютсѧ: Ѡ҆скорблю̀ и҆̀хъ, и҆ не возмо́гꙋтъ ста́ти, падꙋ́тъ под̾ нога́ма мои́ма. И҆ препоѧ́салъ мѧ̀ є҆сѝ си́лою на бра́нь, спѧ́лъ є҆сѝ всѧ̑ востаю́щыѧ на мѧ̀ под̾ мѧ̀. И҆ врагѡ́въ мои́хъ да́лъ мѝ є҆сѝ хребе́тъ и҆ ненави́дѧщыѧ мѧ̀ потреби́лъ є҆сѝ. Воззва́ша, и҆ не бѣ̀ спаса́ѧй: ко гдⷭ҇ꙋ, и҆ не ᲂу҆слы́ша и҆́хъ. И҆ и҆стню̀ ѧ҆̀ ꙗ҆́кѡ пра́хъ пред̾ лице́мъ вѣ́тра, ꙗ҆́кѡ бре́нїе пꙋте́й погла́ждꙋ ѧ҆̀. И҆зба́виши мѧ̀ ѿ прерѣка́нїѧ люде́й: поста́виши мѧ̀ во главꙋ̀ ꙗ҆зы́кѡвъ: лю́дїе, и҆́хже не вѣ́дѣхъ, рабо́таша мѝ, Въ слꙋ́хъ ᲂу҆́ха послꙋ́шаша мѧ̀. Сы́нове чꙋжді́и солга́ша мѝ, Сы́нове чꙋжді́и ѡ҆бетша́ша и҆ ѡ҆хромо́ша ѿ сте́зь свои́хъ. Жи́въ гдⷭ҇ь, и҆ бл҃гослове́нъ бг҃ъ, и҆ да вознесе́тсѧ бг҃ъ сп҃се́нїѧ моегѡ̀, Бг҃ъ даѧ́й ѿмще́нїе мнѣ̀ и҆ покори́вый лю́ди под̾ мѧ̀, И҆зба́витель мо́й ѿ вра̑гъ мои́хъ гнѣвли́выхъ: ѿ востаю́щихъ на мѧ̀ вознесе́ши мѧ̀, ѿ мꙋ́жа непра́ведна и҆зба́виши мѧ̀. Сегѡ̀ ра́ди и҆сповѣ́мсѧ тебѣ̀ во ꙗ҆зы́цѣхъ, гдⷭ҇и, и҆ и҆́мени твоемꙋ̀ пою̀: Велича́ѧй спасє́нїѧ царє́ва и҆ творѧ́й млⷭ҇ть хрїстꙋ̀ своемꙋ̀ дв҃дꙋ и҆ сѣ́мени є҆гѡ̀ до вѣ́ка.",
  ["заголовок_ру"] = "В коне́ц, о́троку Госпо́дню Дави́ду, я́же глаго́ла Го́сподеви словеса́ пе́сни сея́, в день, во́ньже изба́ви его́ Госпо́дь от ру́ки всех враг его́, и из ру́ки Сау́ли, и рече́:",
  ["заголовок_цс"] = "Въ коне́цъ, ѻ҆́трокꙋ гдⷭ҇ню дв҃дꙋ, ꙗ҆̀же глаго́ла гдⷭ҇еви словеса̀ пѣ́сни сеѧ̀, въ де́нь, во́ньже и҆зба́ви є҆го̀ гдⷭ҇ь ѿ рꙋкѝ всѣ́хъ вра̑гъ є҆гѡ и҆ и҆з̾ рꙋкѝ саꙋ́ли: и҆ речѐ:"
}

add_psalom {
  ["номер"] = 18,
  ["часть"] = 1,
  ["кафизма"] = 3,
  ["слава"] = 2,
  ["текст_ру"] = "Небеса́ пове́дают сла́ву Бо́жию, творе́ние же руку́ Его́ возвеща́ет твердь. День дни отрыга́ет глаго́л, и нощь но́щи возвеща́ет ра́зум. Не суть ре́чи, ниже́ словеса́, и́хже не слы́шатся гла́си их. Во всю зе́млю изы́де веща́ние их и в концы́ вселе́нныя глаго́лы их. В со́лнце положи́ селе́ние Свое́, и той, я́ко жени́х исходя́й от черто́га своего́, возра́дуется, я́ко исполи́н тещи́ путь. От кра́я небесе́ исхо́д его́, и сре́тение его́ до кра́я небесе́, и несть и́же укры́ется теплоты́ его́. Зако́н Госпо́день непоро́чен, обраща́яй ду́шы, свиде́тельство Госпо́дне ве́рно, умудря́ющее младе́нцы. Оправда́ния Госпо́дня пра́ва, веселя́щая се́рдце, за́поведь Госпо́дня светла́, просвеща́ющая о́чи. Страх Госпо́день чист, пребыва́яй в век ве́ка: судьбы́ Госпо́дни и́стинны, оправда́ны вку́пе, вожделе́нны па́че зла́та и ка́мене че́стна мно́га, и сла́ждша па́че ме́да и со́та. И́бо раб Твой храни́т я́, внегда́ сохрани́ти я́, воздая́ние мно́го. Грехопаде́ния кто разуме́ет? От та́йных мои́х очи́сти мя, и от чужди́х пощади́ раба́ Твоего́, а́ще не облада́ют мно́ю, тогда́ непоро́чен бу́ду и очи́щуся от греха́ вели́ка. И бу́дут во благоволе́ние словеса́ уст мои́х, и поуче́ние се́рдца моего́ пред Тобо́ю вы́ну, Го́споди, Помо́щниче мой и Изба́вителю мой.",
  ["текст_цс"] = "Небеса̀ повѣ́даютъ сла́вꙋ бж҃їю, творе́нїе же рꙋкꙋ̀ є҆гѡ̀ возвѣща́етъ тве́рдь. Де́нь днѝ ѿрыга́етъ глаго́лъ, и҆ но́щь но́щи возвѣща́етъ ра́зꙋмъ. Не сꙋ́ть рѣ̑чи, нижѐ словеса̀, и҆́хже не слы́шатсѧ гла́си и҆́хъ. Во всю̀ зе́млю и҆зы́де вѣща́нїе и҆́хъ, и҆ въ концы̀ вселе́нныѧ глаго́лы и҆́хъ: въ со́лнцѣ положѝ селе́нїе своѐ: И҆ то́й ꙗ҆́кѡ жени́хъ и҆сходѧ́й ѿ черто́га своегѡ̀, возра́дꙋетсѧ ꙗ҆́кѡ и҆споли́нъ тещѝ пꙋ́ть. Ѿ кра́ѧ небесѐ и҆схо́дъ є҆гѡ̀, и҆ срѣ́тенїе є҆гѡ̀ до кра́ѧ небесѐ: и҆ нѣ́сть, и҆́же ᲂу҆кры́етсѧ теплоты̀ є҆гѡ̀. Зако́нъ гдⷭ҇ень непоро́ченъ, ѡ҆браща́ѧй дꙋ́шы: свидѣ́тельство гдⷭ҇не вѣ́рно, ᲂу҆мꙋдрѧ́ющее младе́нцы. Ѡ҆правда̑нїѧ гдⷭ҇нѧ пра̑ва, веселѧ̑щаѧ се́рдце: за́повѣдь гдⷭ҇нѧ свѣтла̀, просвѣща́ющаѧ ѻ҆́чи. Стра́хъ гдⷭ҇ень чи́стъ, пребыва́ѧй въ вѣ́къ вѣ́ка: сꙋдьбы̑ гдⷭ҇ни и҆́стинны, ѡ҆правда̑нны вкꙋ́пѣ, Вожделѣ̑нны па́че зла́та и҆ ка́мене че́стна мно́га, и҆ сла́ждшѧ па́че ме́да и҆ со́та. И҆́бо ра́бъ тво́й храни́тъ ѧ҆̀: внегда̀ сохрани́ти ѧ҆̀, воздаѧ́нїе мно́го. Грѣхопадє́нїѧ кто̀ разꙋмѣ́етъ; ѿ та́йныхъ мои́хъ ѡ҆чи́сти мѧ̀, И҆ ѿ чꙋжди́хъ пощадѝ раба̀ твоего̀: а҆́ще не ѡ҆блада́ютъ мно́ю, тогда̀ непоро́ченъ бꙋ́дꙋ, и҆ ѡ҆чи́щꙋсѧ ѿ грѣха̀ вели́ка. И҆ бꙋ́дꙋтъ во бл҃говоле́нїе словеса̀ ᲂу҆́стъ мои́хъ, и҆ поꙋче́нїе се́рдца моегѡ̀ пред̾ тобо́ю вы́нꙋ, гдⷭ҇и, помо́щниче мо́й и҆ и҆зба́вителю мо́й.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 19,
  ["часть"] = 1,
  ["кафизма"] = 3,
  ["слава"] = 2,
  ["текст_ру"] = "Услы́шит тя Госпо́дь в день печа́ли, защи́тит тя и́мя Бо́га Иа́ковля. По́слет ти по́мощь от Свята́го и от Сио́на засту́пит тя. Помяне́т вся́ку же́ртву твою́, и всесожже́ние твое́ ту́чно бу́ди. Даст ти Госпо́дь по се́рдцу твоему́ и весь сове́т твой испо́лнит. Возра́дуемся о спасе́нии твое́м и во и́мя Го́спода Бо́га на́шего возвели́чимся. Испо́лнит Госпо́дь вся проше́ния твоя́. Ны́не позна́х, я́ко спасе́ Госпо́дь христа́ Своего́, услы́шит eго́ с небесе́ свята́го Своего́, в си́лах спасе́ние десни́цы Его́. Си́и на колесни́цах, и си́и на ко́нех, мы же во и́мя Го́спода Бо́га на́шего призове́м. Ти́и спя́ти бы́ша и падо́ша, мы же воста́хом и испра́вихомся. Го́споди, спаси́ царя́ и услы́ши ны, во́ньже а́ще день призове́м Тя.",
  ["текст_цс"] = "Оу҆слы́шитъ тѧ̀ гдⷭ҇ь въ де́нь печа́ли, защи́титъ тѧ̀ и҆́мѧ бг҃а і҆а́кѡвлѧ. По́слетъ тѝ по́мощь ѿ ст҃а́гѡ, и҆ ѿ сїѡ́на застꙋ́питъ тѧ̀. Помѧне́тъ всѧ́кꙋ же́ртвꙋ твою̀, и҆ всесожже́нїе твоѐ тꙋ́чно бꙋ́ди. Да́стъ тѝ гдⷭ҇ь по се́рдцꙋ твоемꙋ̀, и҆ ве́сь совѣ́тъ тво́й и҆спо́лнитъ. Возра́дꙋемсѧ ѡ҆ сп҃се́нїи твое́мъ, и҆ во и҆́мѧ гдⷭ҇а бг҃а на́шегѡ возвели́чимсѧ: и҆спо́лнитъ гдⷭ҇ь всѧ̑ прошє́нїѧ твоѧ̑. Ны́нѣ позна́хъ, ꙗ҆́кѡ сп҃сѐ гдⷭ҇ь хрїста̀ своего̀: ᲂу҆слы́шитъ є҆го̀ съ нб҃сѐ ст҃а́гѡ своегѡ̀: въ си́лахъ сп҃се́нїе десни́цы є҆гѡ̀. Сі́и на колесни́цахъ, и҆ сі́и на ко́нехъ: мы́ же во и҆́мѧ гдⷭ҇а бг҃а на́шегѡ призове́мъ. Ті́и спѧ́ти бы́ша и҆ падо́ша: мы́ же воста́хомъ и҆ и҆спра́вихомсѧ. Гдⷭ҇и, спасѝ царѧ̀, и҆ ᲂу҆слы́ши ны̀, во́ньже а҆́ще де́нь призове́мъ тѧ̀.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 20,
  ["часть"] = 1,
  ["кафизма"] = 3,
  ["слава"] = 2,
  ["текст_ру"] = "Го́споди, си́лою Твое́ю возвесели́тся царь и о спасе́нии Твое́м возра́дуется зело́. Жела́ние се́рдца eго́ дал еси́ eму́, и хоте́ния устну́ eго́ не́си лиши́л eго́. Я́ко предвари́л еси́ eго́ благослове́нием благосты́нным, положи́л еси́ на главе́ eго́ вене́ц от ка́мене че́стна. Живота́ проси́л есть у Тебе́, и дал еси́ eму́ долготу́ дний во век ве́ка. Ве́лия сла́ва eго́ спасе́нием Твои́м, сла́ву и велеле́пие возложи́ши на него́. Я́ко да́си eму́ благослове́ние во век ве́ка, возвесели́ши eго́ ра́достию с лице́м Твои́м. Я́ко царь упова́ет на Го́спода, и ми́лостию Вы́шняго не подви́жится. Да обря́щется рука́ Твоя́ всем враго́м Твои́м, десни́ца Твоя́ да обря́щет вся ненави́дящыя Тебе́. Я́ко положи́ши их я́ко пещь о́гненную во вре́мя лица́ Твоего́, Госпо́дь гне́вом Свои́м смяте́т я́, и сне́сть их огнь. Плод их от земли́ погуби́ши, и се́мя их от сыно́в челове́ческих. Я́ко уклони́ша на Тя зла́я, помы́слиша сове́ты, и́хже не возмо́гут соста́вити. Я́ко положи́ши я́ хребе́т, во избы́тцех Твои́х угото́виши лице́ их. Вознеси́ся, Го́споди, си́лою Твое́ю, воспое́м и пое́м си́лы Твоя́.",
  ["текст_цс"] = "Гдⷭ҇и, си́лою твое́ю возвесели́тсѧ ца́рь, и҆ ѡ҆ сп҃се́нїи твое́мъ возра́дꙋетсѧ ѕѣлѡ̀. Жела́нїе се́рдца є҆гѡ̀ да́лъ є҆сѝ є҆мꙋ̀, и҆ хотѣ́нїѧ ᲂу҆стнꙋ̀ є҆гѡ̀ нѣ́си лиши́лъ є҆го̀. Ꙗ҆́кѡ предвари́лъ є҆сѝ є҆го̀ бл҃гослове́нїемъ бл҃госты́ннымъ, положи́лъ є҆сѝ на главѣ̀ є҆гѡ̀ вѣне́цъ ѿ ка́мене че́стна. Живота̀ проси́лъ є҆́сть ᲂу҆ тебє̀, и҆ да́лъ є҆сѝ є҆мꙋ̀ долготꙋ̀ дні́й во вѣ́къ вѣ́ка. Ве́лїѧ сла́ва є҆гѡ̀ сп҃се́нїемъ твои́мъ: сла́вꙋ и҆ велелѣ́пїе возложи́ши на него̀. Ꙗ҆́кѡ да́си є҆мꙋ̀ бл҃гослове́нїе во вѣ́къ вѣ́ка: возвесели́ши є҆гѡ̀ ра́достїю съ лице́мъ твои́мъ. Ꙗ҆́кѡ ца́рь ᲂу҆пова́етъ на гдⷭ҇а, и҆ млⷭ҇тїю вы́шнѧгѡ не подви́житсѧ. Да ѡ҆брѧ́щетсѧ рꙋка̀ твоѧ̀ всѣ̑мъ врагѡ́мъ твои̑мъ, десни́ца твоѧ̀ да ѡ҆брѧ́щетъ всѧ̑ ненави́дѧщыѧ тебѐ. Ꙗ҆́кѡ положи́ши и҆̀хъ ꙗ҆́кѡ пе́щь ѻ҆́гненнꙋю во вре́мѧ лица̀ твоегѡ̀: гдⷭ҇ь гнѣ́вомъ свои́мъ смѧте́тъ ѧ҆̀, и҆ снѣ́сть и҆̀хъ ѻ҆́гнь. Пло́дъ и҆́хъ ѿ землѝ погꙋби́ши, и҆ сѣ́мѧ и҆́хъ ѿ сынѡ́въ человѣ́ческихъ. Ꙗ҆́кѡ ᲂу҆клони́ша на тѧ̀ ѕла̑ѧ, помы́слиша совѣ́ты, и҆̀хже не возмо́гꙋтъ соста́вити. Ꙗ҆́кѡ положи́ши ѧ҆̀ хребе́тъ: во и҆збы́тцѣхъ твои́хъ ᲂу҆гото́виши лицѐ и҆́хъ. Вознеси́сѧ, гдⷭ҇и, си́лою твое́ю: воспое́мъ и҆ пое́мъ си̑лы твоѧ̑.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 21,
  ["часть"] = 1,
  ["кафизма"] = 3,
  ["слава"] = 3,
  ["текст_ру"] = "Бо́же, Бо́же мой, вонми́ ми, вску́ю оста́вил мя еси́? Дале́че от спасе́ния моего́ словеса́ грехопаде́ний мои́х. Бо́же мой, воззову́ во дни, и не услы́шиши, и в нощи́, и не в безу́мие мне. Ты же во Святе́м живе́ши, хвало́ Изра́илева. На Тя упова́ша отцы́ на́ши, упова́ша и изба́вил еси́ я́. К Тебе́ воззва́ша, и спасо́шася, на Тя упова́ша, и не постыде́шася. Аз же есмь червь, а не челове́к, поноше́ние челове́ков и уничиже́ние люде́й. Вси ви́дящии мя поруга́ша ми ся, глаго́лаша устна́ми, покива́ша главо́ю: упова́ на Го́спода, да изба́вит eго́, да спасе́т eго́, я́ко хо́щет eго́. Я́ко Ты еси́ исто́ргий мя из чре́ва, упова́ние мое́ от сосцу́ ма́тере моея́. К Тебе́ приве́ржен есмь от ложе́сн, от чре́ва ма́тере моея́ Бог мой еси́ Ты. Да не отсту́пиши от мене́, я́ко скорбь близ, я́ко несть помога́яй ми. Обыдо́ша мя тельцы́ мно́зи, юнцы́ ту́чнии одержа́ша мя. Отверзо́ша на мя уста́ своя́, я́ко лев восхища́яй и рыка́яй. Я́ко вода́ излия́хся, и разсы́пашася вся ко́сти моя́, бысть се́рдце мое́ я́ко воск, та́яй посреде́ чре́ва моего́. И́зсше я́ко скуде́ль кре́пость моя́, и язы́к мой прильпе́ горта́ни моему́, и в персть сме́рти свел мя еси́. Я́ко обыдо́ша мя пси мно́зи, сонм лука́вых одержа́ша мя, ископа́ша ру́це мои́ и но́зе мои́. Исчето́ша вся ко́сти моя́, ти́и же смотри́ша и презре́ша мя. Раздели́ша ри́зы моя́ себе́, и о оде́жди мое́й мета́ша жре́бий. Ты же, Го́споди, не удали́ по́мощь Твою́ от мене́, на заступле́ние мое́ вонми́. Изба́ви от ору́жия ду́шу мою́, и из руки́ пе́сии единоро́дную мою́. Спаси́ мя от уст льво́вых и от рог единоро́жь смире́ние мое́. Пове́м и́мя Твое́ бра́тии мое́й, посреде́ це́ркве воспою́ Тя. Боя́щиися Го́спода, восхвали́те Его́, все се́мя Иа́ковле, просла́вите Его́, да убои́тся же от Него́ все се́мя Изра́илево. Я́ко не уничижи́, ниже́ негодова́ моли́твы ни́щаго, ниже́ отврати́ лице́ Свое́ от мене́, и егда́ воззва́х к Нему́, услы́ша мя. От Тебе́ похвала́ моя́, в це́ркви вели́цей испове́мся Тебе́, моли́твы моя́ возда́м пред боя́щимися Его́. Ядя́т убо́зии и насы́тятся, и восхва́лят Го́спода взыска́ющии Его́, жива́ бу́дут сердца́ их в век ве́ка. Помяну́тся и обратя́тся ко Го́споду вси концы́ земли́, и покло́нятся пред Ним вся оте́чествия язы́к. Я́ко Госпо́дне есть Ца́рствие, и Той облада́ет язы́ки. Ядо́ша и поклони́шася вси ту́чнии земли́, пред Ним припаду́т вси низходя́щии в зе́млю, и душа́ моя́ Тому́ живе́т. И се́мя мое́ порабо́тает Ему́, возвести́т Го́сподеви род гряду́щий. И возвестя́т пра́вду Его́ лю́дем ро́ждшымся, я́же сотвори́ Госпо́дь.",
  ["текст_цс"] = "Бж҃е, бж҃е мо́й, вонми́ ми, вскꙋ́ю ѡ҆ста́вилъ мѧ̀ є҆сѝ; дале́че ѿ сп҃се́нїѧ моегѡ̀ словеса̀ грѣхопаде́нїй мои́хъ. Бж҃е мо́й, воззовꙋ̀ во днѝ, и҆ не ᲂу҆слы́шиши, и҆ въ нощѝ, и҆ не въ безꙋ́мїе мнѣ̀. Ты́ же во ст҃ѣ́мъ живе́ши, хвало̀ і҆и҃лева. На тѧ̀ ᲂу҆пова́ша ѻ҆тцы̀ на́ши: ᲂу҆пова́ша, и҆ и҆зба́вилъ є҆сѝ ѧ҆̀: Къ тебѣ̀ воззва́ша, и҆ спасо́шасѧ: на тѧ̀ ᲂу҆пова́ша, и҆ не постыдѣ́шасѧ. А҆́зъ же є҆́смь че́рвь, а҆ не человѣ́къ, поноше́нїе человѣ́кѡвъ и҆ ᲂу҆ничиже́нїе люде́й. Всѝ ви́дѧщїи мѧ̀ порꙋга́шамисѧ, глаго́лаша ᲂу҆стна́ми, покива́ша главо́ю: Оу҆пова̀ на гдⷭ҇а, да и҆зба́витъ є҆го̀, да сп҃се́тъ є҆го̀, ꙗ҆́кѡ хо́щетъ є҆го̀. Ꙗ҆́кѡ ты̀ є҆сѝ и҆сто́ргїй мѧ̀ и҆з̾ чре́ва, ᲂу҆пова́нїе моѐ ѿ сѡсцꙋ̀ ма́тере моеѧ̀. Къ тебѣ̀ приве́рженъ є҆́смь ѿ ложе́снъ, ѿ чре́ва ма́тере моеѧ̀ бг҃ъ мо́й є҆сѝ ты̀. Да не ѿстꙋ́пиши ѿ менѐ, ꙗ҆́кѡ ско́рбь бли́з̾, ꙗ҆́кѡ нѣ́сть помога́ѧй мѝ. Ѡ҆быдо́ша мѧ̀ тельцы̀ мно́зи, ю҆нцы̀ тꙋ́чнїи ѡ҆держа́ша мѧ̀: Ѿверзо́ша на мѧ̀ ᲂу҆ста̀ своѧ̑, ꙗ҆́кѡ ле́въ восхища́ѧй и҆ рыка́ѧй. Ꙗ҆́кѡ вода̀ и҆злїѧ́хсѧ, и҆ разсы́пашасѧ всѧ̑ кѡ́сти моѧ̑: бы́сть се́рдце моѐ ꙗ҆́кѡ во́скъ та́ѧй посредѣ̀ чре́ва моегѡ̀. И҆́зсше ꙗ҆́кѡ скꙋде́ль крѣ́пость моѧ̀, и҆ ѧ҆зы́къ мо́й прильпѐ горта́ни моемꙋ̀, и҆ въ пе́рсть сме́рти све́лъ мѧ̀ є҆сѝ. Ꙗ҆́кѡ ѡ҆быдо́ша мѧ̀ псѝ мно́зи, со́нмъ лꙋка́выхъ ѡ҆держа́ша мѧ̀: и҆скопа́ша рꙋ́цѣ моѝ и҆ но́зѣ моѝ. И҆счето́ша всѧ̑ кѡ́сти моѧ̑: ті́и же смотри́ша и҆ презрѣ́ша мѧ̀. Раздѣли́ша ри̑зы моѧ̑ себѣ̀, и҆ ѡ҆ ѻ҆де́жди мое́й мета́ша жре́бїй. Ты́ же, гдⷭ҇и, не ᲂу҆далѝ по́мощь твою̀ ѿ менѐ: на застꙋпле́нїе моѐ вонмѝ. И҆зба́ви ѿ ѻ҆рꙋ́жїѧ дꙋ́шꙋ мою̀, и҆ и҆з̾ рꙋкѝ пе́сїи є҆диноро́днꙋю мою̀. Сп҃си́ мѧ ѿ ᲂу҆́стъ льво́выхъ, и҆ ѿ рѡ́гъ є҆динорѡ́жъ смире́нїе моѐ. Повѣ́мъ и҆́мѧ твоѐ бра́тїи мое́й, посредѣ̀ цр҃кве воспою̀ тѧ̀. Боѧ́щїисѧ гдⷭ҇а, восхвали́те є҆го̀, всѐ сѣ́мѧ і҆а́кѡвле, просла́вите є҆го̀, да ᲂу҆бои́тсѧ же ѿ негѡ̀ всѐ сѣ́мѧ і҆и҃лево: Ꙗ҆́кѡ не ᲂу҆ничижѝ, нижѐ негодова̀ моли́твы ни́щагѡ, нижѐ ѿвратѝ лицѐ своѐ ѿ менѐ, и҆ є҆гда̀ воззва́хъ къ немꙋ̀, ᲂу҆слы́ша мѧ̀. Ѿ тебє̀ похвала̀ моѧ̀, въ цр҃кви вели́цѣй и҆сповѣ́мсѧ тебѣ̀: моли̑твы моѧ̑ возда́мъ пред̾ боѧ́щимисѧ є҆гѡ̀. Ꙗ҆дѧ́тъ ᲂу҆бо́зїи, и҆ насы́тѧтсѧ, и҆ восхва́лѧтъ гдⷭ҇а взыска́ющїи є҆го̀: жива̑ бꙋ́дꙋтъ сердца̀ и҆́хъ въ вѣ́къ вѣ́ка. Помѧнꙋ́тсѧ и҆ ѡ҆братѧ́тсѧ ко гдⷭ҇ꙋ всѝ концы̀ землѝ, и҆ покло́нѧтсѧ пред̾ ни́мъ всѧ̑ ѻ҆те́чєствїѧ ꙗ҆зы̑къ: Ꙗ҆́кѡ гдⷭ҇не є҆́сть црⷭ҇твїе, и҆ то́й ѡ҆блада́етъ ꙗ҆зы́ки. Ꙗ҆до́ша и҆ поклони́шасѧ всѝ тꙋ́чнїи землѝ: пред̾ ни́мъ припадꙋ́тъ всѝ низходѧ́щїи въ зе́млю: и҆ дꙋша̀ моѧ̀ томꙋ̀ живе́тъ. И҆ сѣ́мѧ моѐ порабо́таетъ є҆мꙋ̀: возвѣсти́тъ гдⷭ҇еви ро́дъ грѧдꙋ́щїй: И҆ возвѣстѧ́тъ пра́вдꙋ є҆гѡ̀ лю́демъ ро́ждшымсѧ, ꙗ҆̀же сотворѝ гдⷭ҇ь.",
  ["заголовок_ру"] = "В коне́ц, о заступле́нии у́треннем, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ застꙋпле́нїи ᲂу҆́треннѣмъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 22,
  ["часть"] = 1,
  ["кафизма"] = 3,
  ["слава"] = 3,
  ["текст_ру"] = "Госпо́дь пасе́т мя, и ничто́же мя лиши́т. На ме́сте зла́чне, та́мо всели́ мя, на воде́ поко́йне воспита́ мя. Ду́шу мою́ обрати́, наста́ви мя на стези́ пра́вды, и́мене ра́ди Своего́. А́ще бо и пойду́ посреде́ се́ни сме́ртныя, не убою́ся зла, я́ко Ты со мно́ю еси́, жезл Твой и па́лица Твоя́, та мя уте́шиста. Угото́вал еси́ предо мно́ю трапе́зу сопроти́в стужа́ющым мне, ума́стил еси́ еле́ом главу́ мою́, и ча́ша Твоя́ упоява́ющи мя, я́ко держа́вна. И ми́лость Твоя́ пожене́т мя вся дни живота́ моего́, и е́же всели́ти ми ся в дом Госпо́день, в долготу́ дний.",
  ["текст_цс"] = "Гдⷭ҇ь пасе́тъ мѧ̀, и҆ ничто́же мѧ̀ лиши́тъ. На мѣ́сте ѕла́чнѣ, та́мѡ всели́ мѧ, на водѣ̀ поко́йнѣ воспита́ мѧ. Дꙋ́шꙋ мою̀ ѡ҆братѝ, наста́ви мѧ̀ на стєзѝ пра́вды, и҆́мене ра́ди своегѡ̀. А҆́ще бо и҆ пойдꙋ̀ посредѣ̀ сѣ́ни сме́ртныѧ, не ᲂу҆бою́сѧ ѕла̀, ꙗ҆́кѡ ты̀ со мно́ю є҆сѝ: же́злъ тво́й и҆ па́лица твоѧ̀, та̑ мѧ̀ ᲂу҆тѣ́шиста. Оу҆гото́валъ є҆сѝ предо мно́ю трапе́зꙋ сопроти́въ стꙋжа́ющымъ мнѣ̀: ᲂу҆ма́стилъ є҆сѝ є҆ле́омъ главꙋ̀ мою̀, и҆ ча́ша твоѧ̀ ᲂу҆поѧва́ющи мѧ̀, ꙗ҆́кѡ держа́вна. И҆ млⷭ҇ть твоѧ̀ пожене́тъ мѧ̀ всѧ̑ дни̑ живота̀ моегѡ̀, и҆ є҆́же всели́тимисѧ въ до́мъ гдⷭ҇ень въ долготꙋ̀ дні́й.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 23,
  ["часть"] = 1,
  ["кафизма"] = 3,
  ["слава"] = 3,
  ["текст_ру"] = "Госпо́дня земля́, и исполне́ние ея́, вселе́нная и вси живу́щии на ней. Той на моря́х основа́л ю есть, и на река́х угото́вал ю есть. Кто взы́дет на го́ру Госпо́дню? или́ кто ста́нет на ме́сте святе́м Его́? Непови́нен рука́ма и чист се́рдцем, и́же не прия́т всу́е ду́шу свою́, и не кля́тся ле́стию и́скреннему своему́. Сей прии́мет благослове́ние от Го́спода, и ми́лостыню от Бо́га, Спа́са своего́. Сей род и́щущих Го́спода, и́щущих лице́ Бо́га Иа́ковля. Возми́те врата́ кня́зи ва́ша, и возми́теся врата́ ве́чная, и вни́дет Царь Сла́вы. Кто есть се́й Царь Сла́вы? Госпо́дь кре́пок и си́лен, Госпо́дь си́лен в бра́ни. Возми́те врата́ кня́зи ва́ша, и возми́теся врата́ ве́чная, и вни́дет Царь Сла́вы. Кто есть се́й Царь Сла́вы? Госпо́дь Сил, Той есть Царь Сла́вы.",
  ["текст_цс"] = "Гдⷭ҇нѧ землѧ̀, и҆ и҆сполне́нїе є҆ѧ̀, вселе́ннаѧ и҆ всѝ живꙋ́щїи на не́й. То́й на морѧ́хъ ѡ҆снова́лъ ю҆̀ є҆́сть и҆ на рѣка́хъ ᲂу҆гото́валъ ю҆̀ є҆́сть. Кто̀ взы́детъ на го́рꙋ гдⷭ҇ню; и҆лѝ кто̀ ста́нетъ на мѣ́стѣ ст҃ѣ́мъ є҆гѡ̀; Непови́ненъ рꙋка́ма и҆ чи́стъ се́рдцемъ, и҆́же не прїѧ́тъ всꙋ́е дꙋ́шꙋ свою̀ и҆ не клѧ́тсѧ ле́стїю и҆́скреннемꙋ своемꙋ̀: Се́й прїи́метъ бл҃гослове́нїе ѿ гдⷭ҇а и҆ млⷭ҇тыню ѿ бг҃а сп҃са своегѡ̀. Се́й ро́дъ и҆́щꙋщихъ гдⷭ҇а, и҆́щꙋщихъ лицѐ бг҃а і҆а́кѡвлѧ. Возми́те врата̀ кнѧ̑зи ва̑ша, и҆ возми́тесѧ врата̀ вѣ̑чнаѧ: и҆ вни́детъ цр҃ь сла́вы. Кто́ є҆сть се́й цр҃ь сла́вы; гдⷭ҇ь крѣ́покъ и҆ си́ленъ, гдⷭ҇ь си́ленъ въ бра́ни. Возми́те врата̀ кнѧ̑зи ва̑ша, и҆ возми́тесѧ врата̀ вѣ̑чнаѧ: и҆ вни́детъ цр҃ь сла́вы. Кто́ є҆сть се́й цр҃ь сла́вы; гдⷭ҇ь си́лъ, то́й є҆́сть цр҃ь сла́вы.",
  ["заголовок_ру"] = "Псало́м Дави́ду, еди́ныя от суббо́т.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, є҆ди́ныѧ ѿ сꙋббѡ́тъ."
}

add_psalom {
