  ["кафизма"] = 4,
  ["слава"] = 1,
  ["текст_ру"] = "К Тебе́, Го́споди, воздвиго́х ду́шу мою́, Бо́же мой, на Тя упова́х, да не постыжу́ся во век, ниже́ да посмею́т ми ся врази́ мои́, и́бо вси терпя́щии Тя не постыдя́тся. Да постыдя́тся беззако́ннующии вотще́. Пути́ Твоя́, Го́споди, скажи́ ми, и стезя́м Твои́м научи́ мя. Наста́ви мя на и́стину Твою́, и научи́ мя, я́ко Ты еси́ Бог Спас мой, и Тебе́ терпе́х весь день. Помяни́ щедро́ты Твоя́, Го́споди, и ми́лости Твоя́, я́ко от ве́ка суть. Грех ю́ности моея́, и неве́дения моего́ не помяни́, по ми́лости Твое́й помяни́ мя Ты, ра́ди бла́гости Твоея́, Го́споди. Благ и прав Госпо́дь, сего́ ра́ди законоположи́т согреша́ющым на пути́. Наста́вит кро́ткия на суд, научи́т кро́ткия путе́м Свои́м. Вси путие́ Госпо́дни ми́лость и и́стина, взыска́ющым заве́та Его́, и свиде́ния Его́. Ра́ди и́мене Твоего́, Го́споди, и очи́сти грех мой, мног бо есть. Кто есть челове́к боя́йся Го́спода? Законоположи́т eму́ на пути́, eго́же изво́ли. Душа́ eго́ во благи́х водвори́тся, и се́мя eго́ насле́дит зе́млю. Держа́ва Госпо́дь боя́щихся Его́, и заве́т Его́ яви́т им. О́чи мои́ вы́ну ко Го́споду, я́ко Той исто́ргнет от се́ти но́зе мои́. При́зри на мя и поми́луй мя, я́ко единоро́д и нищ есмь аз. Ско́рби се́рдца моего́ умно́жишася, от нужд мои́х изведи́ мя. Виждь смире́ние мое́, и труд мой, и оста́ви вся грехи́ моя́. Виждь враги́ моя́, я́ко умно́жишася, и ненавиде́нием непра́ведным возненави́деша мя. Сохрани́ ду́шу мою́, и изба́ви мя, да не постыжу́ся, я́ко упова́х на Тя. Незло́бивии и пра́вии прилепля́хуся мне, я́ко потерпе́х Тя, Го́споди. Изба́ви, Бо́же, Изра́иля от всех скорбе́й eго́.",
  ["текст_цс"] = "Къ тебѣ̀, гдⷭ҇и, воздвиго́хъ дꙋ́шꙋ мою̀, бж҃е мо́й, на тѧ̀ ᲂу҆пова́хъ, да не постыжꙋ́сѧ во вѣ́къ, нижѐ да посмѣю́тъ ми сѧ вразѝ моѝ: И҆́бо всѝ терпѧ́щїи тѧ̀ не постыдѧ́тсѧ. Да постыдѧ́тсѧ беззако́ннꙋющїи вотщѐ. Пꙋти̑ твоѧ̑, гдⷭ҇и, скажи́ ми и҆ стезѧ́мъ твои̑мъ наꙋчи́ мѧ. Наста́ви мѧ̀ на и҆́стинꙋ твою̀ и҆ наꙋчи́ мѧ: ꙗ҆́кѡ ты̀ є҆сѝ бг҃ъ сп҃съ мо́й, и҆ тебѐ терпѣ́хъ ве́сь де́нь. Помѧнѝ щедрѡ́ты твоѧ̑, гдⷭ҇и, и҆ млⷭ҇ти твоѧ̑, ꙗ҆́кѡ ѿ вѣ́ка сꙋ́ть. Грѣ̑хъ ю҆́ности моеѧ̀ и҆ невѣ́дѣнїѧ моегѡ̀ не помѧнѝ: по млⷭ҇ти твое́й помѧни́ мѧ ты̀, ра́ди бл҃гости твоеѧ̀, гдⷭ҇и. Бл҃гъ и҆ пра́въ гдⷭ҇ь, сегѡ̀ ра́ди законоположи́тъ согрѣша́ющымъ на пꙋтѝ. Наста́витъ крѡ́ткїѧ на сꙋ́дъ, наꙋчи́тъ крѡ́ткїѧ пꙋтє́мъ свои̑мъ. Всѝ пꙋтїѐ гдⷭ҇ни млⷭ҇ть и҆ и҆́стина, взыска́ющымъ завѣ́та є҆гѡ̀ и҆ свидѣ́нїѧ є҆гѡ̀. Ра́ди и҆́мене твоегѡ̀, гдⷭ҇и, и҆ ѡ҆чи́сти грѣ́хъ мо́й, мно́гъ бо є҆́сть. Кто́ є҆сть человѣ́къ боѧ́йсѧ гдⷭ҇а; законоположи́тъ є҆мꙋ̀ на пꙋтѝ, є҆го́же и҆зво́ли. Дꙋша̀ є҆гѡ̀ во благи́хъ водвори́тсѧ, и҆ сѣ́мѧ є҆гѡ̀ наслѣ́дитъ зе́млю. Держа́ва гдⷭ҇ь боѧ́щихсѧ є҆гѡ̀, и҆ завѣ́тъ є҆гѡ̀ ꙗ҆ви́тъ и҆̀мъ. Ѻ҆́чи моѝ вы́нꙋ ко гдⷭ҇ꙋ, ꙗ҆́кѡ то́й и҆сто́ргнетъ ѿ сѣ́ти но́зѣ моѝ. При́зри на мѧ̀ и҆ поми́лꙋй мѧ̀, ꙗ҆́кѡ є҆диноро́дъ и҆ ни́щь є҆́смь а҆́зъ. Скѡ́рби се́рдца моегѡ̀ ᲂу҆мно́жишасѧ, ѿ нꙋ́ждъ мои́хъ и҆зведи́ мѧ. Ви́ждь смире́нїе моѐ и҆ трꙋ́дъ мо́й, и҆ ѡ҆ста́ви всѧ̑ грѣхѝ моѧ̑. Ви́ждь врагѝ моѧ̑, ꙗ҆́кѡ ᲂу҆мно́жишасѧ, и҆ ненавидѣ́нїемъ непра́веднымъ возненави́дѣша мѧ̀. Сохранѝ дꙋ́шꙋ мою̀ и҆ и҆зба́ви мѧ̀, да не постыжꙋ́сѧ, ꙗ҆́кѡ ᲂу҆пова́хъ на тѧ̀. Неѕло́бивїи и҆ пра́вїи прилѣплѧ́хꙋсѧ мнѣ̀, ꙗ҆́кѡ потерпѣ́хъ тѧ̀, гдⷭ҇и. И҆зба́ви, бж҃е, і҆и҃лѧ ѿ всѣ́хъ скорбе́й є҆гѡ̀.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 25,
  ["часть"] = 1,
  ["кафизма"] = 4,
  ["слава"] = 1,
  ["текст_ру"] = "Суди́ ми, Го́споди, я́ко аз незло́бою мое́ю ходи́х, и на Го́спода упова́я, не изнемогу́. Искуси́ мя, Го́споди, и испыта́й мя, разжзи́ утро́бы моя́, и се́рдце мое́. Я́ко ми́лость Твоя́ пред очи́ма мои́ма есть, и благоугоди́х во и́стине Твое́й. Не седо́х с со́нмом су́етным, и со законопресту́пными не вни́ду. Возненави́дех це́рковь лука́внующих, и с нечести́выми не ся́ду. Умы́ю в непови́нных ру́це мои́, и обы́ду же́ртвенник Твой, Го́споди. Е́же услы́шати ми глас хвалы́ Твоея́, и пове́дати вся чудеса́ Твоя́. Го́споди, возлюби́х благоле́пие до́му Твоего́ и ме́сто селе́ния сла́вы Твоея́. Да не погуби́ши с нечести́выми ду́шу мою́, и с му́жи крове́й живо́т мой. И́хже в руку́ беззако́ния, десни́ца их испо́лнися мзды. Аз же незло́бою мое́ю ходи́х, изба́ви мя, Го́споди, и поми́луй мя. Нога́ моя́ ста на правоте́: в це́рквах благословлю́ Тя, Го́споди.",
  ["текст_цс"] = "Сꙋди́ ми, гдⷭ҇и, ꙗ҆́кѡ а҆́зъ неѕло́бою мое́ю ходи́хъ: и҆ на гдⷭ҇а ᲂу҆пова́ѧ не и҆знемогꙋ̀. И҆скꙋси́ мѧ, гдⷭ҇и, и҆ и҆спыта́й мѧ̀, разжжѝ ᲂу҆трѡ́бы моѧ̑ и҆ се́рдце моѐ. Ꙗ҆́кѡ млⷭ҇ть твоѧ̀ пред̾ ѻ҆чи́ма мои́ма є҆́сть, и҆ бл҃гоꙋгоди́хъ во и҆́стинѣ твое́й. Не сѣдо́хъ съ со́нмомъ сꙋ́етнымъ, и҆ со законопрестꙋ́пными не вни́дꙋ. Возненави́дѣхъ це́рковь лꙋка́внꙋющихъ, и҆ съ нечести́выми не сѧ́дꙋ. Оу҆мы́ю въ непови́нныхъ рꙋ́цѣ моѝ, и҆ ѡ҆бы́дꙋ же́ртвенникъ тво́й, гдⷭ҇и, Є҆́же ᲂу҆слы́шати мѝ гла́съ хвалы̀ твоеѧ̀ и҆ повѣ́дати всѧ̑ чꙋдеса̀ твоѧ̑. Гдⷭ҇и, возлюби́хъ бл҃голѣ́пїе до́мꙋ твоегѡ̀ и҆ мѣ́сто селе́нїѧ сла́вы твоеѧ̀. Да не погꙋби́ши съ нечести́выми дꙋ́шꙋ мою̀ и҆ съ мꙋ̑жи крове́й живо́тъ мо́й, И҆́хже въ рꙋкꙋ̀ беззакѡ́нїѧ, десни́ца и҆́хъ и҆спо́лнисѧ мзды̀. А҆́зъ же неѕло́бою мое́ю ходи́хъ: и҆зба́ви мѧ̀, гдⷭ҇и, и҆ поми́лꙋй мѧ̀. Нога̀ моѧ̀ ста̀ на правотѣ̀: въ цр҃квахъ бл҃гословлю́ тѧ, гдⷭ҇и.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 26,
  ["часть"] = 1,
  ["кафизма"] = 4,
  ["слава"] = 1,
  ["текст_ру"] = "Госпо́дь просвеще́ние мое́ и Спаси́тель мой, кого́ убою́ся? Госпо́дь Защи́титель живота́ моего́, от кого́ устрашу́ся? Внегда́ приближа́тися на мя зло́бующым, е́же сне́сти пло́ти моя́, оскорбля́юшии мя, и врази́ мои́, ти́и изнемо́гоша и падо́ша. А́ще ополчи́тся на мя полк, не убои́тся се́рдце мое́, а́ще воста́нет на мя брань, на Него́ аз упова́ю. Еди́но проси́х от Го́спода, то взыщу́: е́же жи́ти ми в дому́ Госпо́дни вся дни живота́ моего́, зре́ти ми красоту́ Госпо́дню и посеща́ти храм святы́й Его́. Я́ко скры мя в селе́нии Свое́м в день зол мои́х, покры́ мя в та́йне селе́ния Своего́, на ка́мень вознесе́ мя. И ны́не се вознесе́ главу́ мою́, на враги́ моя́: обыдо́х и пожро́х в селе́нии Его́ же́ртву хвале́ния и воскликнове́ния, пою́ и воспою́ Го́сподеви. Услы́ши, Го́споди, глас мой, и́мже воззва́х: поми́луй мя и услы́ши мя. Тебе́ рече́ се́рдце мое́, Го́спода взыщу́. Взыска́ Тебе́ лице́ мое́, лица́ Твоего́, Го́споди, взыщу́. Не отврати́ лица́ Твоего́ от мене́ и не уклони́ся гне́вом от раба́ Твоего́: помо́щник мой бу́ди, не отри́ни мене́, и не оста́ви мене́, Бо́же Спаси́телю мой. Я́ко оте́ц мой и ма́ти моя́ оста́виста мя, Госпо́дь же восприя́т мя. Законоположи́ ми, Го́споди, в пути́ Твое́м и наста́ви мя на стезю́ пра́вую враг мои́х ра́ди. Не преда́ждь мене́ в ду́шы стужа́ющих ми, я́ко воста́ша на мя свиде́теле непра́веднии и солга́ непра́вда себе́. Ве́рую ви́дети блага́я Госпо́дня на земли́ живы́х. Потерпи́ Го́спода, мужа́йся и да крепи́тся се́рдце твое́, и потерпи́ Го́спода.",
  ["текст_цс"] = "Гдⷭ҇ь просвѣще́нїе моѐ и҆ сп҃си́тель мо́й, когѡ̀ ᲂу҆бою́сѧ; гдⷭ҇ь защи́титель живота̀ моегѡ̀, ѿ когѡ̀ ᲂу҆страшꙋ́сѧ; Внегда̀ приближа́тисѧ на мѧ̀ ѕло́бꙋющымъ, є҆́же снѣ́сти плѡ́ти моѧ̑, ѡ҆скорблѧ́ющїи мѧ̀ и҆ вразѝ моѝ, ті́и и҆знемого́ша и҆ падо́ша. А҆́ще ѡ҆полчи́тсѧ на мѧ̀ по́лкъ, не ᲂу҆бои́тсѧ се́рдце моѐ: а҆́ще воста́нетъ на мѧ̀ бра́нь, на него̀ а҆́зъ ᲂу҆пова́ю. Є҆ди́но проси́хъ ѿ гдⷭ҇а, то̀ взыщꙋ̀: є҆́же жи́ти мѝ въ домꙋ̀ гдⷭ҇ни всѧ̑ дни̑ живота̀ моегѡ̀, зрѣ́ти мѝ красотꙋ̀ гдⷭ҇ню и҆ посѣща́ти хра́мъ ст҃ы́й є҆гѡ̀. Ꙗ҆́кѡ скры́ мѧ въ селе́нїи свое́мъ въ де́нь ѕѡ́лъ мои́хъ, покры́ мѧ въ та́йнѣ селе́нїѧ своегѡ̀, на ка́мень вознесе́ мѧ. И҆ ны́нѣ сѐ, вознесѐ главꙋ̀ мою̀ на врагѝ моѧ̑: ѡ҆быдо́хъ и҆ пожро́хъ въ селе́нїи є҆гѡ̀ же́ртвꙋ хвале́нїѧ и҆ воскликнове́нїѧ: пою̀ и҆ воспою̀ гдⷭ҇еви. Оу҆слы́ши, гдⷭ҇и, гла́съ мо́й, и҆́мже воззва́хъ, поми́лꙋй мѧ̀ и҆ ᲂу҆слы́ши мѧ̀. Тебѣ̀ речѐ се́рдце моѐ: гдⷭ҇а взыщꙋ̀, взыска̀ тебѐ лицѐ моѐ, лица̀ твоегѡ̀, гдⷭ҇и, взыщꙋ̀. Не ѿвратѝ лица̀ твоегѡ̀ ѿ менѐ и҆ не ᲂу҆клони́сѧ гнѣ́вомъ ѿ раба̀ твоегѡ̀: помо́щникъ мо́й бꙋ́ди, не ѿри́ни менѐ и҆ не ѡ҆ста́ви менѐ, бж҃е, сп҃си́телю мо́й. Ꙗ҆́кѡ ѻ҆те́цъ мо́й и҆ ма́ти моѧ̀ ѡ҆ста́виста мѧ̀, гдⷭ҇ь же воспрїѧ́тъ мѧ̀. Законоположи́ ми, гдⷭ҇и, въ пꙋтѝ твое́мъ, и҆ наста́ви мѧ̀ на стезю̀ пра́вꙋю вра̑гъ мои́хъ ра́ди. Не преда́ждь менѐ въ дꙋ́шы стꙋжа́ющихъ мѝ: ꙗ҆́кѡ воста́ша на мѧ̀ свидѣ́телє непра́веднїи, и҆ солга̀ непра́вда себѣ̀. Вѣ́рꙋю ви́дѣти бл҃га̑ѧ гдⷭ҇нѧ на землѝ живы́хъ. Потерпѝ гдⷭ҇а, мꙋжа́йсѧ, и҆ да крѣпи́тсѧ се́рдце твоѐ, и҆ потерпѝ гдⷭ҇а.",
  ["заголовок_ру"] = "Псало́м Дави́ду, пре́жде пома́зания.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, пре́жде пома́занїѧ."
}

add_psalom {
  ["номер"] = 27,
