  ["кафизма"] = 4,
  ["слава"] = 2,
  ["текст_ру"] = "К Тебе́, Го́споди, воззову́, Бо́же мой, да не премолчи́ши от мене́, да не когда́ премолчи́ши от мене́: и уподо́блюся низходя́щым в ров. Услы́ши, Го́споди, глас моле́ния моего́, внегда́ моли́ти ми ся к Тебе́, внегда́ возде́ти ми ру́це мои́ ко хра́му свято́му Твоему́. Не привлецы́ мене́ со гре́шники и с де́лающими непра́вду не погуби́ мене́, глаго́лющими мир с бли́жними свои́ми, зла́я же в сердца́х свои́х. Даждь им, Го́споди, по дело́м их, и по лука́вству начина́ний их: по дело́м руку́ их даждь им: возда́ждь воздая́ние их им. Я́ко не разуме́ша в дела́ Госпо́дня и в дела́ руку́ Его́: разори́ши я́, и не сози́ждеши я́. Благослове́н Госпо́дь, я́ко услы́ша глас моле́ния моего́. Госпо́дь Помо́щник мой, и Защи́титель мой: на Него́ упова́ се́рдце мое́, и помо́же ми, и процвете́ плоть моя́, и во́лею мое́ю испове́мся Ему́. Госпо́дь утвержде́ние люде́й Свои́х, и Защи́титель спасе́ний христа́ Своего́ есть. Спаси́ лю́ди Твоя́ и благослови достоя́ние Твое́, и упаси́ я́, и возми́ я́ до ве́ка.",
  ["текст_цс"] = "Къ тебѣ̀, гдⷭ҇и, воззовꙋ̀, бж҃е мо́й: да не премолчи́ши ѿ менѐ: да не когда̀ премолчи́ши ѿ менѐ, и҆ ᲂу҆подо́блюсѧ низходѧ́щымъ въ ро́въ. Оу҆слы́ши, гдⷭ҇и, гла́съ моле́нїѧ моегѡ̀, внегда̀ моли́ти ми сѧ къ тебѣ̀, внегда̀ воздѣ́ти мѝ рꙋ́цѣ моѝ ко хра́мꙋ ст҃о́мꙋ твоемꙋ̀. Не привлецы̀ менѐ со грѣ̑шники, и҆ съ дѣ́лающими непра́вдꙋ не погꙋбѝ менѐ, глаго́лющими ми́ръ съ бли́жними свои́ми, ѕла̑ѧ же въ сердца́хъ свои́хъ. Да́ждь и҆̀мъ, гдⷭ҇и, по дѣлѡ́мъ и҆́хъ и҆ по лꙋка́вствꙋ начина́нїй и҆́хъ, по дѣлѡ́мъ рꙋкꙋ̀ и҆́хъ да́ждь и҆̀мъ, возда́ждь воздаѧ́нїе и҆́хъ и҆̀мъ. Ꙗ҆́кѡ не разꙋмѣ́ша въ дѣла̀ гдⷭ҇нѧ и҆ въ дѣла̀ рꙋкꙋ̀ є҆гѡ̀: разори́ши ѧ҆̀ и҆ не сози́ждеши ѧ҆̀. Бл҃гослове́нъ гдⷭ҇ь, ꙗ҆́кѡ ᲂу҆слы́ша гла́съ моле́нїѧ моегѡ̀. Гдⷭ҇ь помо́щникъ мо́й и҆ защи́титель мо́й: на него̀ ᲂу҆пова̀ се́рдце моѐ, и҆ помо́же мѝ, и҆ процвѣтѐ пло́ть моѧ̀: и҆ во́лею мое́ю и҆сповѣ́мсѧ є҆мꙋ̀. Гдⷭ҇ь ᲂу҆твержде́нїе люде́й свои́хъ и҆ защи́титель спасе́нїй хрїста̀ своегѡ̀ є҆́сть. Сп҃сѝ лю́ди твоѧ̑, и҆ блгⷭ҇вѝ достоѧ́нїе твоѐ, и҆ ᲂу҆пасѝ ѧ҆̀, и҆ возмѝ ѧ҆̀ до вѣ́ка.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 28,
  ["часть"] = 1,
  ["кафизма"] = 4,
  ["слава"] = 2,
  ["текст_ру"] = "Принеси́те Го́сподеви сы́нове Бо́жии, принеси́те Го́сподеви, сы́ны о́вни, принеси́те Го́сподеви сла́ву и честь. Принеси́те Го́сподеви сла́ву и́мени Его́, поклони́теся Го́сподеви во дворе́ святе́м Его́. Глас Госпо́день на вода́х, Бог сла́вы возгреме́, Госпо́дь на вода́х мно́гих. Глас Госпо́день в кре́пости, глас Госпо́день в великоле́пии. Глас Го́спода, сокруша́ющаго ке́дры, и стры́ет Госпо́дь ке́дры лива́нския: и истни́т я́ я́ко тельца́ лива́нска, и возлю́бленный я́ко сын единоро́жь. Глас Го́спода, пресеца́ющаго пла́мень огня́. Глас Го́спода, стряса́ющаго пусты́ню, и стрясе́т Госпо́дь пусты́ню Кадди́йскую. Глас Госпо́день сверша́ющий еле́ни, и откры́ет дубра́вы, и в хра́ме Его́ вся́кий глаго́лет сла́ву. Госпо́дь пото́п населя́ет, и ся́дет Госпо́дь Царь в век. Госпо́дь кре́пость лю́дем Свои́м даст, Госпо́дь благослови́т лю́ди Своя́ ми́ром.",
  ["текст_цс"] = "Принеси́те гдⷭ҇еви, сы́нове бж҃їи, принеси́те гдⷭ҇еви сы́ны ѻ҆́вни, принеси́те гдⷭ҇еви сла́вꙋ и҆ че́сть: Принеси́те гдⷭ҇еви сла́вꙋ и҆́мени є҆гѡ̀: поклони́тесѧ гдⷭ҇еви во дворѣ̀ ст҃ѣ́мъ є҆гѡ̀. Гла́съ гдⷭ҇ень на вода́хъ, бг҃ъ сла́вы возгремѣ̀, гдⷭ҇ь на вода́хъ мно́гихъ. Гла́съ гдⷭ҇ень въ крѣ́пости, гла́съ гдⷭ҇ень въ великолѣ́пїи. Гла́съ гдⷭ҇а, сокрꙋша́ющагѡ ке́дры: и҆ стры́етъ гдⷭ҇ь ке́дры лїва̑нскїѧ, И҆ и҆стни́тъ ѧ҆̀ ꙗ҆́кѡ тельца̀ лїва́нска: и҆ возлю́бленный ꙗ҆́кѡ сы́нъ є҆диноро́жь. Гла́съ гдⷭ҇а, пресѣца́ющагѡ пла́мень ѻ҆гнѧ̀. Гла́съ гдⷭ҇а, стрѧса́ющагѡ пꙋсты́ню: и҆ стрѧсе́тъ гдⷭ҇ь пꙋсты́ню кадді́йскꙋю. Гла́съ гдⷭ҇ень, сверша́ющїй є҆лє́ни, и҆ ѿкры́етъ дꙋбра̑вы: и҆ въ хра́мѣ є҆гѡ̀ всѧ́кїй глаго́летъ сла́вꙋ. Гдⷭ҇ь пото́пъ населѧ́етъ, и҆ сѧ́детъ гдⷭ҇ь цр҃ь въ вѣ́къ. Гдⷭ҇ь крѣ́пость лю́демъ свои̑мъ да́стъ, гдⷭ҇ь бл҃гослови́тъ лю́ди своѧ̑ ми́ромъ.",
  ["заголовок_ру"] = "Псало́м Дави́ду, исхо́да ски́нии.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, и҆схо́да ски́нїи."
}

add_psalom {
  ["номер"] = 29,
  ["часть"] = 1,
  ["кафизма"] = 4,
  ["слава"] = 2,
  ["текст_ру"] = "Вознесу́ Тя, Го́споди, я́ко подъя́л мя еси́, и не возвесели́л еси́ враго́в мои́х о мне. Го́споди Бо́же мой, воззва́х к Тебе́, и исцели́л мя еси́. Го́споди, возве́л еси́ от а́да ду́шу мою́, спасл мя еси́ от низходя́щих в ров. По́йте Го́сподеви, преподо́бнии Его́, и испове́дайте па́мять святы́ни Его́. Я́ко гнев в я́рости Его́, и живо́т в во́ли Его́: ве́чер водвори́тся плачь, и зау́тра ра́дость. Аз же рех во оби́лии мое́м: не подви́жуся во век. Го́споди, во́лею Твое́ю пода́ждь добро́те мое́й си́лу. Отврати́л же еси́ лице́ Твое́, и бых смуще́н. К Тебе́, Го́споди, воззову́, и к Бо́гу моему́ помолю́ся. Ка́я по́льза в кро́ви мое́й, внегда́ сходи́ти ми во истле́ние? Еда́ испове́стся Тебе́ персть, или́ возвести́т и́стину Твою́? Слы́ша Госпо́дь и поми́лова мя: Госпо́дь бысть помо́щник мой. Обрати́л еси́ плачь мой в ра́дость мне: растерза́л еси́ вре́тище мое́, и препоя́сал мя еси́ весе́лием. Я́ко да воспое́т Тебе́ сла́ва моя́, и не умилю́ся: Го́споди Бо́же мой, во век испове́мся Тебе́.",
  ["текст_цс"] = "Вознесꙋ́ тѧ, гдⷭ҇и, ꙗ҆́кѡ под̾ѧ́лъ мѧ̀ є҆сѝ, и҆ не возвесели́лъ є҆сѝ врагѡ́въ мои́хъ ѡ҆ мнѣ̀. Гдⷭ҇и бж҃е мо́й, воззва́хъ къ тебѣ̀, и҆ и҆сцѣли́лъ мѧ̀ є҆сѝ. Гдⷭ҇и, возве́лъ є҆сѝ ѿ а҆́да дꙋ́шꙋ мою̀, сп҃слъ мѧ̀ є҆сѝ ѿ низходѧ́щихъ въ ро́въ. По́йте гдⷭ҇еви, прпⷣбнїи є҆гѡ̀, и҆ и҆сповѣ́дайте па́мѧть ст҃ы́ни є҆гѡ̀: Ꙗ҆́кѡ гнѣ́въ въ ꙗ҆́рости є҆гѡ̀, и҆ живо́тъ въ во́ли є҆гѡ̀: ве́черъ водвори́тсѧ пла́чь, и҆ заꙋ́тра ра́дость. А҆́зъ же рѣ́хъ во ѻ҆би́лїи мое́мъ: не подви́жꙋсѧ во вѣ́къ. Гдⷭ҇и, во́лею твое́ю пода́ждь добро́тѣ мое́й си́лꙋ: ѿврати́лъ же є҆сѝ лицѐ твоѐ, и҆ бы́хъ смꙋще́нъ. Къ тебѣ̀, гдⷭ҇и, воззовꙋ̀, и҆ къ бг҃ꙋ моемꙋ̀ помолю́сѧ. Ка́ѧ по́льза въ кро́ви мое́й, внегда̀ сходи́ти мѝ во и҆стлѣ́нїе; є҆да̀ и҆сповѣ́стсѧ тебѣ̀ пе́рсть; и҆лѝ возвѣсти́тъ и҆́стинꙋ твою̀; Слы́ша гдⷭ҇ь и҆ поми́лова мѧ̀: гдⷭ҇ь бы́сть помо́щникъ мо́й. Ѡ҆брати́лъ є҆сѝ пла́чь мо́й въ ра́дость мнѣ̀, растерза́лъ є҆сѝ вре́тище моѐ и҆ препоѧ́салъ мѧ̀ є҆сѝ весе́лїемъ, Ꙗ҆́кѡ да воспое́тъ тебѣ̀ сла́ва моѧ̀, и҆ не ᲂу҆милю́сѧ. Гдⷭ҇и бж҃е мо́й, во вѣ́къ и҆сповѣ́мсѧ тебѣ̀.",
  ["заголовок_ру"] = "Псало́м пе́сни, обновле́ния до́му Дави́дова.",
  ["заголовок_цс"] = "Ѱало́мъ пѣ́сни ѡ҆бновле́нїѧ до́мꙋ дв҃дова."
}

add_psalom {
  ["номер"] = 30,
  ["часть"] = 1,
  ["кафизма"] = 4,
  ["слава"] = 3,
  ["текст_ру"] = "На Тя, Го́споди, упова́х, да не постыжу́ся во век: пра́вдою Твое́ю изба́ви мя и изми́ мя. Приклони́ ко мне у́хо Твое́, ускори́ изъя́ти мя, бу́ди ми в Бо́га Защи́тителя, и в дом прибе́жища, е́же спасти́ мя. Я́ко держа́ва моя́ и прибе́жище мое́ еси́ Ты, и и́мене Твоего́ ра́ди наста́виши мя, и препита́еши мя. Изведе́ши мя от се́ти сея́, ю́же скры́ша ми, я́ко Ты еси́ Защи́титель мой, Го́споди. В ру́це Твои́ предложу́ дух мой: изба́вил мя еси́, Го́споди Бо́же и́стины. Возненави́дел еси́ храня́щыя суеты́ вотще́: аз же на Го́спода упова́х. Возра́дуюся и возвеселю́ся о ми́лости Твое́й, я́ко призре́л еси́ на смире́ние мое́, спасл еси́ от нужд ду́шу мою́, и не́си мене́ затвори́л в рука́х вра́жиих, поста́вил еси́ на простра́нне но́зе мои́. Поми́луй мя, Го́споди, я́ко скорблю́: смяте́ся я́ростию о́ко мое́, душа́ моя́ и утро́ба моя́. Я́ко исчезе́ в боле́зни живо́т мой и ле́та моя́ в воздыха́ниих, изнемо́же нището́ю кре́пость моя́ и ко́сти моя́ смято́шася. От всех враг мои́х бых поноше́ние, и сосе́дом мои́м зело́, и страх зна́емым мои́м: ви́дящии мя вон бежа́ша от мене́. Забве́н бых я́ко мертв от се́рдца, бых я́ко сосу́д погубле́н. Я́ко слы́шах гажде́ние мно́гих, живу́щих о́крест, внегда́ собра́тися им вку́пе на мя, прия́ти ду́шу мою́ совеща́ша. Аз же на Тя, Го́споди, упова́х, рех: Ты еси́ Бог мой. В руку́ Твое́ю жре́бии мои́: изба́ви мя из руки́ враг мои́х и от гоня́щих мя. Просвети́ лице́ Твое́ на раба́ Твоего́, спаси́ мя ми́лостию Твое́ю. Го́споди, да не постыжу́ся, я́ко призва́х Тя: да постыдя́тся нечести́вии и сни́дут во ад. Не́мы да бу́дут устны́ льсти́выя, глаго́лющыя на пра́веднаго беззако́ние, горды́нею и уничиже́нием. Коль мно́гое мно́жество бла́гости Твоея́, Го́споди, ю́же скрыл еси́ боя́щымся Тебе́, соде́лал еси́ упова́ющым на Тя пред сы́ны челове́ческими. Скры́еши их в та́йне лица́ Твоего́ от мяте́жа челове́ческа, покры́еши их в кро́ве от пререка́ния язы́к. Благослове́н Госпо́дь, я́ко удиви́ ми́лость Свою́ во гра́де огражде́ния. Аз же рех во изступле́нии мое́м: отве́ржен есмь от лица́ о́чию Твое́ю: сего́ ра́ди услы́шал еси́ глас моли́твы моея́, внегда́ воззва́х к Тебе́. Возлюби́те Го́спода, вси преподо́бнии Его́, я́ко и́стины взыска́ет Госпо́дь, и воздае́т изли́ше творя́щым горды́ню. Мужа́йтеся, и да крепи́тся се́рдце ва́ше, вси упова́ющии на Го́спода.",
  ["текст_цс"] = "На тѧ̀, гдⷭ҇и, ᲂу҆пова́хъ, да не постыжꙋ́сѧ во вѣ́къ: пра́вдою твое́ю и҆зба́ви мѧ̀ и҆ и҆зми́ мѧ. Приклонѝ ко мнѣ̀ ᲂу҆́хо твоѐ, ᲂу҆скорѝ и҆з̾ѧ́ти мѧ̀: бꙋ́ди мѝ въ бг҃а защи́тителѧ и҆ въ до́мъ прибѣ́жища, є҆́же сп҃сти́ мѧ. Ꙗ҆́кѡ держа́ва моѧ̀ и҆ прибѣ́жище моѐ є҆сѝ ты̀: и҆ и҆́мене твоегѡ̀ ра́ди наста́виши мѧ̀ и҆ препита́еши мѧ̀. И҆зведе́ши мѧ̀ ѿ сѣ́ти сеѧ̀, ю҆́же скры́ша мѝ: ꙗ҆́кѡ ты̀ є҆сѝ защи́титель мо́й, гдⷭ҇и. Въ рꙋ́цѣ твоѝ предложꙋ̀ дꙋ́хъ мо́й: и҆зба́вилъ мѧ̀ є҆сѝ, гдⷭ҇и бж҃е и҆́стины. Возненави́дѣлъ є҆сѝ хранѧ́щыѧ сꙋєты̀ вотщѐ: а҆́зъ же на гдⷭ҇а ᲂу҆пова́хъ. Возра́дꙋюсѧ и҆ возвеселю́сѧ ѡ҆ млⷭ҇ти твое́й, ꙗ҆́кѡ призрѣ́лъ є҆сѝ на смире́нїе моѐ, сп҃слъ є҆сѝ ѿ нꙋ́ждъ дꙋ́шꙋ мою̀ И҆ нѣ́си менѐ затвори́лъ въ рꙋка́хъ вра́жїихъ, поста́вилъ є҆сѝ на простра́ннѣ но́зѣ моѝ. Поми́лꙋй мѧ̀, гдⷭ҇и, ꙗ҆́кѡ скорблю̀: смѧте́сѧ ꙗ҆́ростїю ѻ҆́ко моѐ, дꙋша̀ моѧ̀ и҆ ᲂу҆тро́ба моѧ̀. Ꙗ҆́кѡ и҆счезѐ въ болѣ́зни живо́тъ мо́й, и҆ лѣ̑та моѧ̑ въ воздыха́нїихъ: и҆знемо́же нището́ю крѣ́пость моѧ̀, и҆ кѡ́сти моѧ̑ смѧто́шасѧ. Ѿ всѣ́хъ вра̑гъ мои́хъ бы́хъ поноше́нїе, и҆ сосѣ́дѡмъ мои̑мъ ѕѣлѡ̀, и҆ стра́хъ зна́ємымъ мои̑мъ: ви́дѧщїи мѧ̀ во́нъ бѣжа́ша ѿ менѐ. Забве́нъ бы́хъ ꙗ҆́кѡ ме́ртвъ ѿ се́рдца: бы́хъ ꙗ҆́кѡ сосꙋ́дъ погꙋбле́нъ. Ꙗ҆́кѡ слы́шахъ гажде́нїе мно́гихъ живꙋ́щихъ ѡ҆́крестъ: внегда̀ собра́тисѧ и҆̀мъ вкꙋ́пѣ на мѧ̀, прїѧ́ти дꙋ́шꙋ мою̀ совѣща́ша. А҆́зъ же на тѧ̀, гдⷭ҇и, ᲂу҆пова́хъ, рѣ́хъ: ты̀ є҆сѝ бг҃ъ мо́й. Въ рꙋкꙋ̀ твоє́ю жрє́бїи моѝ: и҆зба́ви мѧ̀ и҆з̾ рꙋкѝ вра̑гъ мои́хъ и҆ ѿ гонѧ́щихъ мѧ̀. Просвѣтѝ лицѐ твоѐ на раба̀ твоего̀: сп҃си́ мѧ млⷭ҇тїю твое́ю. Гдⷭ҇и, да не постыжꙋ́сѧ, ꙗ҆́кѡ призва́хъ тѧ̀: да постыдѧ́тсѧ нечести́вїи, и҆ сни́дꙋтъ во а҆́дъ. Нѣ̑мы да бꙋ́дꙋтъ ᲂу҆стны̀ льсти̑выѧ, глаго́лющыѧ на првⷣнаго беззако́нїе, горды́нею и҆ ᲂу҆ничиже́нїемъ. Ко́ль мно́гое мно́жество бл҃гости твоеѧ̀, гдⷭ҇и, ю҆́же скры́лъ є҆сѝ боѧ́щымсѧ тебє̀, содѣ́лалъ є҆сѝ ᲂу҆пова́ющымъ на тѧ̀, пред̾ сы́ны человѣ́ческими: Скры́еши и҆̀хъ въ та́йнѣ лица̀ твоегѡ̀ ѿ мѧте́жа человѣ́ческа, покры́еши и҆̀хъ въ кро́вѣ ѿ прерѣка́нїѧ ѧ҆зы̑къ. Бл҃гослове́нъ гдⷭ҇ь, ꙗ҆́кѡ ᲂу҆дивѝ млⷭ҇ть свою̀ во гра́дѣ ѡ҆гражде́нїѧ. А҆́зъ же рѣ́хъ во и҆зстꙋпле́нїи мое́мъ: ѿве́рженъ є҆́смь ѿ лица̀ ѻ҆́чїю твоє́ю: сегѡ̀ ра́ди ᲂу҆слы́шалъ є҆сѝ гла́съ моли́твы моеѧ̀, внегда̀ воззва́хъ къ тебѣ̀. Возлюби́те гдⷭ҇а, всѝ прпⷣбнїи є҆гѡ̀: ꙗ҆́кѡ и҆́стины взыска́етъ гдⷭ҇ь и҆ воздае́тъ и҆зли́ше творѧ́щымъ горды́ню. Мꙋжа́йтесѧ, и҆ да крѣпи́тсѧ се́рдце ва́ше, всѝ ᲂу҆пова́ющїи на гдⷭ҇а.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду, изступле́ния.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ, и҆зстꙋпле́нїѧ."
}

add_psalom {
  ["номер"] = 31,
  ["часть"] = 1,
  ["кафизма"] = 4,
  ["слава"] = 3,
  ["текст_ру"] = "Блаже́ни, и́хже оста́вишася беззако́ния и и́хже прикры́шася греси́. Блаже́н муж, eму́же не вмени́т Госпо́дь греха́, ниже́ есть во усте́х eго́ лесть. Я́ко умолча́х, обетша́ша ко́сти моя́, от е́же зва́ти ми весь день. Я́ко день и нощь отяготе́ на мне рука́ Твоя́, возврати́хся на страсть, егда́ унзе́ ми терн. Беззако́ние мое́ позна́х и греха́ моего́ не покры́х, рех: испове́м на мя беззако́ние мое́ Го́сподеви, и Ты оста́вил еси́ нече́стие се́рдца моего́. За то помо́лится к Тебе́ всяк преподо́бный во вре́мя благопотре́бно: оба́че в пото́пе вод мно́гих к нему́ не прибли́жатся. Ты еси́ прибе́жище мое́ от ско́рби обдержа́щия мя: ра́досте моя́, изба́ви мя от обыше́дших мя. Вразумлю́ тя и наста́влю тя на путь сей, во́ньже по́йдеши, утвержу́ на тя о́чи Мои́. Не бу́дите я́ко конь и меск, и́мже несть ра́зума: брозда́ми и уздо́ю че́люсти их востя́гнеши, не приближа́ющихся к тебе́. Мно́ги ра́ны гре́шному, упова́ющаго же на Го́спода ми́лость обы́дет. Весели́теся о Го́споде, и ра́дуйтеся, пра́веднии, и хвали́теся, вси пра́вии се́рдцем.",
  ["текст_цс"] = "Бл҃же́ни, и҆́хже ѡ҆ста́вишасѧ беззакѡ́нїѧ, и҆ и҆́хже прикры́шасѧ грѣсѝ. Бл҃же́нъ мꙋ́жъ, є҆мꙋ́же не вмѣни́тъ гдⷭ҇ь грѣха̀, нижѐ є҆́сть во ᲂу҆стѣ́хъ є҆гѡ̀ ле́сть. Ꙗ҆́кѡ ᲂу҆молча́хъ, ѡ҆бетша́ша кѡ́сти моѧ̑, ѿ є҆́же зва́ти мѝ ве́сь де́нь, Ꙗ҆́кѡ де́нь и҆ но́щь ѡ҆тѧготѣ̀ на мнѣ̀ рꙋка̀ твоѧ̀: возврати́хсѧ на стра́сть, є҆гда̀ ᲂу҆нзе́ ми те́рнъ. Беззако́нїе моѐ позна́хъ и҆ грѣха̀ моегѡ̀ не покры́хъ, рѣ́хъ: и҆сповѣ́мъ на мѧ̀ беззако́нїе моѐ гдⷭ҇еви: и҆ ты̀ ѡ҆ста́вилъ є҆сѝ нече́стїе се́рдца моегѡ̀. За то̀ помо́литсѧ къ тебѣ̀ всѧ́къ прпⷣбный во вре́мѧ бл҃гопотре́бно: ѻ҆ба́че въ пото́пѣ во́дъ мно́гихъ къ немꙋ̀ не прибли́жатсѧ. Ты̀ є҆сѝ прибѣ́жище моѐ ѿ ско́рби ѡ҆бдержа́щїѧ мѧ̀: ра́досте моѧ̀, и҆зба́ви мѧ̀ ѿ ѡ҆быше́дшихъ мѧ̀. Вразꙋмлю́ тѧ, и҆ наста́влю тѧ̀ на пꙋ́ть се́й, во́ньже по́йдеши: ᲂу҆твержꙋ̀ на тѧ̀ ѻ҆́чи моѝ. Не бꙋ́дите ꙗ҆́кѡ ко́нь и҆ ме́скъ, и҆́мже нѣ́сть ра́зꙋма: брозда́ми и҆ ᲂу҆здо́ю чє́люсти и҆́хъ востѧ́гнеши, не приближа́ющихсѧ къ тебѣ̀. Мнѡ́ги ра̑ны грѣ́шномꙋ: ᲂу҆пова́ющаго же на гдⷭ҇а млⷭ҇ть ѡ҆бы́детъ. Весели́тесѧ ѡ҆ гдⷭ҇ѣ и҆ ра́дꙋйтесѧ првⷣнїи, и҆ хвали́тесѧ, всѝ пра́вїи срⷣцемъ.",
  ["заголовок_ру"] = "Псало́м Дави́ду, ра́зума.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, ра́зꙋма."
}

add_psalom {
  ["номер"] = 32,
  ["часть"] = 1,
  ["кафизма"] = 5,
  ["слава"] = 1,
  ["текст_ру"] = "Ра́дуйтеся, пра́веднии, о Го́споде, пра́вым подоба́ет похвала́. Испове́дайтеся Го́сподеви в гу́слех, во псалти́ри десятостру́ннем по́йте Ему́. Воспо́йте Ему́ песнь но́ву, до́бре по́йте Ему́ со восклица́нием: я́ко пра́во сло́во Госпо́дне, и вся дела́ Его́ в ве́ре. Лю́бит ми́лостыню и суд Госпо́дь, ми́лости Госпо́дни испо́лнь земля́. Сло́вом Госпо́дним небеса́ утверди́шася, и ду́хом уст Его́ вся си́ла их. Собира́яй я́ко мех во́ды морски́я, полага́яй в сокро́вищах бе́здны. Да убои́тся Го́спода вся земля́, от Него́же да подви́жутся вси живу́щии по вселе́нней. Я́ко Той рече́, и бы́ша, Той повеле́, и созда́шася. Госпо́дь разоря́ет сове́ты язы́ков, отмета́ет же мы́сли люде́й, и отмета́ет сове́ты князе́й. Сове́т же Госпо́день во век пребыва́ет, помышле́ния се́рдца Его́ в род и род. Блаже́н язы́к, eму́же есть Госпо́дь Бог eго́, лю́ди, я́же избра́ в насле́дие Себе́. С небесе́ призре́ Госпо́дь, ви́де вся сы́ны челове́ческия. От гото́ваго жили́ща Своего́ призре́ на вся живу́щыя на земли́. Созда́вый на еди́не сердца́ их, разумева́яй на вся дела́ их. Не спаса́ется царь мно́гою си́лою, и исполи́н не спасе́тся мно́жеством кре́пости своея́. Лож конь во спасе́ние, во мно́жестве же си́лы своея́ не спасе́тся. Се о́чи Госпо́дни на боя́щыяся Его́, упова́ющыя на ми́лость Его́. Изба́вити от сме́рти ду́шы их, и препита́ти я́ в глад. Душа́ же на́ша ча́ет Го́спода, я́ко помо́щник и защи́титель наш есть. Я́ко о Нем возвесели́тся се́рдце на́ше, и во и́мя свято́е Его́ упова́хом. Бу́ди, Го́споди, ми́лость Твоя́ на нас, я́коже упова́хом на Тя.",
  ["текст_цс"] = "Ра́дꙋйтесѧ, првⷣнїи, ѡ҆ гдⷭ҇ѣ: пра̑вымъ подоба́етъ похвала̀. И҆сповѣ́дайтесѧ гдⷭ҇еви въ гꙋ́слехъ, во ѱалти́ри десѧтострꙋ́ннѣмъ по́йте є҆мꙋ̀: Воспо́йте є҆мꙋ̀ пѣ́снь но́вꙋ, до́брѣ по́йте є҆мꙋ̀ со восклица́нїемъ: Ꙗ҆́кѡ пра́во сло́во гдⷭ҇не, и҆ всѧ̑ дѣла̀ є҆гѡ̀ въ вѣ́рѣ. Лю́битъ млⷭ҇тыню и҆ сꙋ́дъ гдⷭ҇ь, млⷭ҇ти гдⷭ҇ни и҆спо́лнь землѧ̀. Сло́вомъ гдⷭ҇нимъ небеса̀ ᲂу҆тверди́шасѧ, и҆ дх҃омъ ᲂу҆́стъ є҆гѡ̀ всѧ̀ си́ла и҆́хъ: Собира́ѧй ꙗ҆́кѡ мѣ́хъ во́ды морскі̑ѧ, полага́ѧй въ сокро́вищихъ бе́здны. Да ᲂу҆бои́тсѧ гдⷭ҇а всѧ̀ землѧ̀, ѿ негѡ́же да подви́жꙋтсѧ всѝ живꙋ́щїи по вселе́ннѣй: Ꙗ҆́кѡ то́й речѐ, и҆ бы́ша: то́й повелѣ̀, и҆ созда́шасѧ. Гдⷭ҇ь разорѧ́етъ совѣ́ты ꙗ҆зы́кѡвъ, ѿмета́етъ же мы̑сли люде́й и҆ ѿмета́етъ совѣ́ты кнѧзе́й. Совѣ́тъ же гдⷭ҇ень во вѣ́къ пребыва́етъ, помышлє́нїѧ срⷣца є҆гѡ̀ въ ро́дъ и҆ ро́дъ. Бл҃же́нъ ꙗ҆зы́къ, є҆мꙋ́же є҆́сть гдⷭ҇ь бг҃ъ є҆гѡ̀, лю́дїе, ꙗ҆̀же и҆збра̀ въ наслѣ́дїе себѣ̀. Съ нб҃сѐ призрѣ̀ гдⷭ҇ь, ви́дѣ всѧ̑ сы́ны человѣ́чєскїѧ: Ѿ гото́вагѡ жили́ща своегѡ̀ призрѣ̀ на всѧ̑ живꙋ́щыѧ на землѝ: Созда́вый на є҆ди́нѣ сердца̀ и҆́хъ, разꙋмѣва́ѧй на всѧ̑ дѣла̀ и҆́хъ. Не спаса́етсѧ ца́рь мно́гою си́лою, и҆ и҆споли́нъ не спасе́тсѧ мно́жествомъ крѣ́пости своеѧ̀. Ло́жь ко́нь во спасе́нїе, во мно́жествѣ же си́лы своеѧ̀ не спасе́тсѧ. Сѐ, ѻ҆́чи гдⷭ҇ни на боѧ́щыѧсѧ є҆гѡ̀, ᲂу҆пова́ющыѧ на млⷭ҇ть є҆гѡ̀: И҆зба́вити ѿ сме́рти дꙋ́шы и҆́хъ, и҆ препита́ти ѧ҆̀ въ гла́дъ. Дꙋша́ же на́ша ча́етъ гдⷭ҇а, ꙗ҆́кѡ помо́щникъ и҆ защи́титель на́шъ є҆́сть: Ꙗ҆́кѡ ѡ҆ не́мъ возвесели́тсѧ се́рдце на́ше, и҆ во и҆́мѧ ст҃о́е є҆гѡ̀ ᲂу҆пова́хомъ. Бꙋ́ди, гдⷭ҇и, млⷭ҇ть твоѧ̀ на на́съ, ꙗ҆́коже ᲂу҆пова́хомъ на тѧ̀.",
  ["заголовок_ру"] = "Псало́м Дави́ду, не надпи́сан у евре́й.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, не надпи́санъ ᲂу҆ є҆врє́й."
}

add_psalom {
  ["номер"] = 33,
  ["часть"] = 1,
  ["кафизма"] = 5,
  ["слава"] = 1,
  ["текст_ру"] = "Благословлю́ Го́спода на вся́кое вре́мя, вы́ну хвала́ Его́ во усте́х мои́х. О Го́споде похва́лится душа́ моя́, да услы́шат кро́тцыи и возвеселя́тся. Возвели́чите Го́спода со мно́ю и вознесе́м и́мя Его́ вку́пе. Взыска́х Го́спода и услы́ша мя, и от всех скорбе́й мои́х изба́ви мя. Приступи́те к Нему́ и просвети́теся, и ли́ца ва́ша не постыдя́тся. Сей ни́щий воззва́, и Госпо́дь услы́ша и́, и от всех скорбе́й eго́ спасе́ и́. Ополчи́тся А́нгел Госпо́день о́крест боя́щихся Его́, и изба́вит их. Вкуси́те и ви́дите, я́ко благ Госпо́дь; блаже́н муж, и́же упова́ет Нань. Бо́йтеся Го́спода, вси святи́и Его́, я́ко несть лише́ния боя́щымся Его́. Бога́тии обнища́ша и взалка́ша, взыска́ющии же Го́спода не лиша́тся вся́каго бла́га. Прииди́те, ча́да, послу́шайте мене́, стра́ху Госпо́дню научу́ вас. Кто́ есть челове́к хотя́й живо́т, любя́й дни ви́дети бла́ги? Удержи́ язы́к твой от зла, и устне́ твои́, е́же не глаго́лати льсти. Уклони́ся от зла и сотвори́ бла́го. Взыщи́ ми́ра, и пожени́ и́. О́чи Госпо́дни на пра́ведныя, и у́ши Его́ в моли́тву их. Лице́ же Госпо́дне на творя́щыя зла́я, е́же потреби́ти от земли́ па́мять их. Воззва́ша пра́веднии, и Госпо́дь услы́ша их, и от всех скорбе́й их изба́ви их. Близ Госпо́дь сокруше́нных се́рдцем, и смире́нныя ду́хом спасе́т. Мно́ги ско́рби пра́ведным, и от всех их изба́вит я́ Госпо́дь. Храни́т Госпо́дь вся ко́сти их, ни еди́на от них сокруши́тся. Смерть гре́шников люта́, и ненави́дящии пра́веднаго прегре́шат. Изба́вит Госпо́дь ду́шы раб Свои́х, и не прегреша́т вси, упова́ющии на Него́.",
  ["текст_цс"] = "Бл҃гословлю̀ гдⷭ҇а на всѧ́кое вре́мѧ, вы́нꙋ хвала̀ є҆гѡ̀ во ᲂу҆стѣ́хъ мои́хъ. Ѡ҆ гдⷭ҇ѣ похва́литсѧ дꙋша̀ моѧ̀: да ᲂу҆слы́шатъ кро́тцыи и҆ возвеселѧ́тсѧ. Возвели́чите гдⷭ҇а со мно́ю, и҆ вознесе́мъ и҆́мѧ є҆гѡ̀ вкꙋ́пѣ. Взыска́хъ гдⷭ҇а, и҆ ᲂу҆слы́ша мѧ̀ и҆ ѿ всѣ́хъ скорбе́й мои́хъ и҆зба́ви мѧ̀. Пристꙋпи́те къ немꙋ̀ и҆ просвѣти́тесѧ, и҆ ли́ца ва̑ша не постыдѧ́тсѧ. Се́й ни́щїй воззва̀, и҆ гдⷭ҇ь ᲂу҆слы́ша и҆̀, и҆ ѿ всѣ́хъ скорбе́й є҆гѡ̀ сп҃сѐ и҆̀. Ѡ҆полчи́тсѧ а҆́гг҃лъ гдⷭ҇ень ѡ҆́крестъ боѧ́щихсѧ є҆гѡ̀ и҆ и҆зба́витъ и҆̀хъ. Вкꙋси́те и҆ ви́дите, ꙗ҆́кѡ бл҃гъ гдⷭ҇ь: бл҃же́нъ мꙋ́жъ, и҆́же ᲂу҆пова́етъ на́нь. Бо́йтесѧ гдⷭ҇а, всѝ ст҃і́и є҆гѡ̀, ꙗ҆́кѡ нѣ́сть лише́нїѧ боѧ́щымсѧ є҆гѡ̀. Бога́тїи ѡ҆бнища́ша и҆ взалка́ша: взыска́ющїи же гдⷭ҇а не лиша́тсѧ всѧ́кагѡ бла́га. Прїиди́те, ча̑да, послꙋ́шайте менѐ, стра́хꙋ гдⷭ҇ню наꙋчꙋ̀ ва́съ. Кто́ є҆сть человѣ́къ хотѧ́й живо́тъ, любѧ́й дни̑ ви́дѣти бла́ги; Оу҆держѝ ѧ҆зы́къ тво́й ѿ ѕла̀ и҆ ᲂу҆стнѣ̀ твоѝ, є҆́же не глаго́лати льстѝ. Оу҆клони́сѧ ѿ ѕла̀ и҆ сотворѝ бла́го: взыщѝ ми́ра и҆ поженѝ и҆̀. Ѻ҆́чи гдⷭ҇ни на првⷣныѧ, и҆ ᲂу҆́ши є҆гѡ̀ въ моли́твꙋ и҆́хъ. Лице́ же гдⷭ҇не на творѧ́щыѧ ѕла̑ѧ, є҆́же потреби́ти ѿ землѝ па́мѧть и҆́хъ. Воззва́ша првⷣнїи, и҆ гдⷭ҇ь ᲂу҆слы́ша и҆̀хъ и҆ ѿ всѣ́хъ скорбе́й и҆́хъ и҆зба́ви и҆̀хъ. Бли́з̾ гдⷭ҇ь сокрꙋше́нныхъ се́рдцемъ, и҆ смирє́нныѧ дꙋ́хомъ сп҃се́тъ. Мнѡ́ги скѡ́рби првⷣнымъ, и҆ ѿ всѣ́хъ и҆́хъ и҆зба́витъ ѧ҆̀ гдⷭ҇ь. Храни́тъ гдⷭ҇ь всѧ̑ кѡ́сти и҆́хъ, ни є҆ди́на ѿ ни́хъ сокрꙋши́тсѧ. Сме́рть грѣ́шникѡвъ люта̀, и҆ ненави́дѧщїи првⷣнаго прегрѣша́тъ. И҆зба́витъ гдⷭ҇ь дꙋ́шы ра̑бъ свои́хъ, и҆ не прегрѣша́тъ всѝ ᲂу҆пова́ющїи на него̀.",
  ["заголовок_ру"] = "Псало́м Дави́ду, внегда́ измени́ лице́ свое́ пред Авимеле́хом, и отпусти́ его́, и отъи́де.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, внегда̀ и҆змѣнѝ лицѐ своѐ пред̾ а҆вїмеле́хомъ: и҆ ѿпꙋстѝ є҆го̀, и҆ ѿи́де."
}

add_psalom {
  ["номер"] = 34,
  ["часть"] = 1,
  ["кафизма"] = 5,
  ["слава"] = 2,
  ["текст_ру"] = "Суди́, Го́споди, оби́дящыя мя, побори́ борю́щыя мя. Приими́ ору́жие и щит, и воста́ни в по́мощь мою́. Изсу́ни мечь, и заключи́ сопроти́в гоня́щих мя. Рцы души́ мое́й: спасе́ние твое́ есмь Аз. Да постыдя́тся и посра́мятся и́щущии ду́шу мою́, да возвратя́тся вспять и постыдя́тся мы́слящии ми зла́я. Да бу́дут я́ко прах пред лице́м ве́тра, и А́нгел Госпо́день оскорбля́я их. Да бу́дет путь их тма и по́лзок, и А́нгел Госпо́день погоня́яй их: я́ко ту́не скры́ша ми па́губу се́ти своея́, всу́е поноси́ша души́ мое́й. Да прии́дет eму́ сеть, ю́же не весть, и лови́тва, ю́же скры, да объи́мет и́, и в сеть да впаде́т в ню. Душа́ же моя́ возра́дуется о Го́споде, возвесели́тся о спасе́нии Его́. Вся ко́сти моя́ реку́т: Го́споди, Го́споди, кто́ подо́бен Тебе́? Избавля́яй ни́ща из руки́ кре́пльших eго́, и ни́ща, и убо́га от расхища́ющих eго́. Воста́вше на мя свиде́теле непра́веднии, я́же не ве́дях, вопроша́ху мя. Возда́ша ми лука́вая воз блага́я, и безча́дие души́ мое́й. Аз же, внегда́ они́ стужа́ху ми, облача́хся во вре́тище, и смиря́х посто́м ду́шу мою́, и моли́тва моя́ в не́дро мое́ возврати́тся. Я́ко бли́жнему, я́ко бра́ту на́шему, та́ко угожда́х, я́ко пла́ча и се́туя, та́ко смиря́хся. И на мя возвесели́шася и собра́шася: собра́шася на мя ра́ны, и не позна́х, раздели́шася, и не умили́шася. Искуси́ша мя, подражни́ша мя подражне́нием, поскрежета́ша на мя зубы́ свои́ми. Го́споди, когда́ у́зриши? Устро́й ду́шу мою́ от злоде́йства их, от лев единоро́дную мою́. Испове́мся Тебе́ в це́ркви мно́зе, в лю́дех тя́жцех восхвалю́ Тя. Да не возра́дуются о мне вражду́ющии ми непра́ведно, ненави́дящии мя ту́не и помиза́ющии очи́ма. Я́ко мне у́бо ми́рная глаго́лаху и на гнев ле́сти помышля́ху. Разшири́ша на мя уста́ своя́, ре́ша: бла́гоже, бла́гоже, ви́деша о́чи на́ши. Ви́дел еси́, Го́споди, да не премолчи́ши. Го́споди, не отступи́ от мене́. Воста́ни, Го́споди, и вонми́ суду́ моему́, Бо́же мой и Го́споди мой, на прю мою́. суди́ ми, Го́споди, по пра́вде Твое́й, Го́споди Бо́же мой, и да не возра́дуются о мне. Да не реку́т в сердца́х своих: бла́гоже, бла́гоже души́ на́шей, ниже́ да реку́т: пожро́хом eго́. Да постыдя́тся и посра́мятся вку́пе ра́дующиися злом мои́м, да облеку́тся в студ и срам велере́чующии на мя. Да возра́дуются и возвеселя́тся хотя́щии пра́вды моея́, и да реку́т вы́ну: да возвели́чится Госпо́дь, хотя́щии ми́ра рабу́ Его́. И язы́к мой поучи́тся пра́вде Твое́й, весь день хвале́ Твое́й.",
  ["текст_цс"] = "Сꙋдѝ, гдⷭ҇и, ѡ҆би́дѧщыѧ мѧ̀, поборѝ борю́щыѧ мѧ̀. Прїимѝ ѻ҆рꙋ́жїе и҆ щи́тъ и҆ воста́ни въ по́мощь мою̀: И҆зсꙋ́ни ме́чь и҆ заключѝ сопроти́въ гонѧ́щихъ мѧ̀: рцы̀ дꙋшѝ мое́й: сп҃се́нїе твоѐ є҆́смь а҆́зъ. Да постыдѧ́тсѧ и҆ посра́мѧтсѧ и҆́щꙋщїи дꙋ́шꙋ мою̀, да возвратѧ́тсѧ вспѧ́ть и҆ постыдѧ́тсѧ мы́слѧщїи мѝ ѕла̑ѧ. Да бꙋ́дꙋтъ ꙗ҆́кѡ пра́хъ пред̾ лице́мъ вѣ́тра, и҆ а҆́гг҃лъ гдⷭ҇ень ѡ҆скорблѧ́ѧ и҆̀хъ: Да бꙋ́детъ пꙋ́ть и҆́хъ тма̀ и҆ по́лзокъ, и҆ а҆́гг҃лъ гдⷭ҇ень погонѧ́ѧй и҆̀хъ: Ꙗ҆́кѡ тꙋ́не скры́ша мѝ па́гꙋбꙋ сѣ́ти своеѧ̀, всꙋ́е поноси́ша дꙋшѝ мое́й. Да прїи́детъ є҆мꙋ̀ сѣ́ть, ю҆́же не вѣ́сть, и҆ лови́тва, ю҆́же скры̀, да ѡ҆б̾и́метъ и҆̀, и҆ въ сѣ́ть да впаде́тъ въ ню̀. Дꙋша́ же моѧ̀ возра́дꙋетсѧ ѡ҆ гдⷭ҇ѣ, возвесели́тсѧ ѡ҆ сп҃се́нїи є҆гѡ̀. Всѧ̑ кѡ́сти моѧ̑ рекꙋ́тъ: гдⷭ҇и, гдⷭ҇и, кто̀ подо́бенъ тебѣ̀; и҆збавлѧ́ѧй ни́ща и҆з̾ рꙋкѝ крѣ́пльшихъ є҆гѡ̀, и҆ ни́ща, и҆ ᲂу҆бо́га ѿ расхища́ющихъ є҆го̀. Воста́вше на мѧ̀ свидѣ́телє непра́веднїи, ꙗ҆̀же не вѣ́дѧхъ, вопроша́хꙋ мѧ̀. Возда́ша мѝ лꙋка̑ваѧ воз̾ бл҃га̑ѧ, и҆ безча́дїе дꙋшѝ мое́й. А҆́зъ же, внегда̀ ѻ҆нѝ стꙋжа́хꙋ мѝ, ѡ҆блача́хсѧ во вре́тище и҆ смирѧ́хъ посто́мъ дꙋ́шꙋ мою̀, и҆ моли́тва моѧ̀ въ нѣ́дро моѐ возврати́тсѧ. Ꙗ҆́кѡ бли́жнемꙋ, ꙗ҆́кѡ бра́тꙋ на́шемꙋ, та́кѡ ᲂу҆гожда́хъ: ꙗ҆́кѡ пла́чѧ и҆ сѣ́тꙋѧ, та́кѡ смирѧ́хсѧ. И҆ на мѧ̀ возвесели́шасѧ и҆ собра́шасѧ: собра́шасѧ на мѧ̀ ра̑ны, и҆ не позна́хъ: раздѣли́шасѧ, и҆ не ᲂу҆мили́шасѧ. И҆скꙋси́ша мѧ̀, подражни́ша мѧ̀ подражне́нїемъ, поскрежета́ша на мѧ̀ зꙋбы̀ свои́ми. Гдⷭ҇и, когда̀ ᲂу҆́зриши; ᲂу҆стро́й дꙋ́шꙋ мою̀ ѿ ѕлодѣ́йства и҆́хъ, ѿ лє́въ є҆диноро́днꙋю мою̀. И҆сповѣ́мсѧ тебѣ̀ въ цр҃кви мно́зѣ, въ лю́дехъ тѧ́жцѣхъ восхвалю́ тѧ. Да не возра́дꙋютсѧ ѡ҆ мнѣ̀ враждꙋ́ющїи мѝ непра́веднѡ, ненави́дѧщїи мѧ̀ тꙋ́не и҆ помиза́ющїи ѻ҆чи́ма: Ꙗ҆́кѡ мнѣ̀ ᲂу҆́бѡ ми̑рнаѧ глаго́лахꙋ, и҆ на гнѣ́въ лє́сти помышлѧ́хꙋ. Разшири́ша на мѧ̀ ᲂу҆ста̀ своѧ̑, рѣ́ша: бла́гоже, бла́гоже, ви́дѣша ѻ҆́чи на́ши. Ви́дѣлъ є҆сѝ, гдⷭ҇и, да не премолчи́ши: гдⷭ҇и, не ѿстꙋпѝ ѿ менѐ. Воста́ни, гдⷭ҇и, и҆ вонмѝ сꙋдꙋ̀ моемꙋ̀, бж҃е мо́й и҆ гдⷭ҇и мо́й, на прю̀ мою̀. Сꙋди́ ми, гдⷭ҇и, по пра́вдѣ твое́й, гдⷭ҇и бж҃е мо́й, и҆ да не возра́дꙋютсѧ ѡ҆ мнѣ̀. Да не рекꙋ́тъ въ сердца́хъ свои́хъ: бла́гоже, бла́гоже дꙋшѝ на́шей: нижѐ да рекꙋ́тъ: пожро́хомъ є҆го̀. Да постыдѧ́тсѧ и҆ посра́мѧтсѧ вкꙋ́пѣ ра́дꙋющїисѧ ѕлѡ́мъ мои̑мъ: да ѡ҆блекꙋ́тсѧ въ стꙋ́дъ и҆ сра́мъ велерѣ́чꙋющїи на мѧ̀. Да возра́дꙋютсѧ и҆ возвеселѧ́тсѧ хотѧ́щїи пра́вды моеѧ̀: и҆ да рекꙋ́тъ вы́нꙋ, да возвели́читсѧ гдⷭ҇ь, хотѧ́щїи ми́ра рабꙋ̀ є҆гѡ̀. И҆ ѧ҆зы́къ мо́й поꙋчи́тсѧ пра́вдѣ твое́й, ве́сь де́нь хвалѣ̀ твое́й.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 35,
  ["часть"] = 1,
  ["кафизма"] = 5,
  ["слава"] = 2,
  ["текст_ру"] = "Глаго́лет пребеззако́нный согреша́ти в себе́: несть стра́ха Бо́жия пред очи́ма eго́. Я́ко ульсти́ пред ним обрести́ беззако́ние свое́ и возненави́дети. Глаго́лы уст eго́ беззако́ние и лесть, не восхоте́ разуме́ти е́же ублажи́ти. Беззако́ние помы́сли на ло́жи свое́м: предста́ вся́кому пути́ небла́гу, о зло́бе же не негодова́. Го́споди, на небеси́ ми́лость Твоя́ и и́стина Твоя́ до о́блак. Пра́вда Твоя́, я́ко го́ры Бо́жия, судьбы́ Твоя́ бе́здна мно́га. Челове́ки и скоты́ спасе́ши, Го́споди. Я́ко умно́жил еси́ ми́лость Твою́, Бо́же, сы́нове же челове́честии в кро́ве крилу́ Твое́ю наде́ятися и́мут. Упию́тся от ту́ка до́му Твоего́, и пото́ком сла́дости Твоея́ напои́ши я́. Я́ко у Тебе́ исто́чник живота́, во све́те Твое́м у́зрим свет. Проба́ви ми́лость Твою́ ве́дущим Тя и пра́вду Твою́ пра́вым се́рдцем. Да не прии́дет мне нога́ горды́ни, и рука́ гре́шнича да не подви́жит мене́. Та́мо падо́ша вси де́лающии беззако́ние: изринове́ни бы́ша, и не возмо́гут ста́ти.",
  ["текст_цс"] = "Глаго́летъ пребеззако́нный согрѣша́ти въ себѣ̀: нѣ́сть стра́ха бж҃їѧ пред̾ ѻ҆чи́ма є҆гѡ̀: Ꙗ҆́кѡ ᲂу҆льстѝ пред̾ ни́мъ ѡ҆брѣстѝ беззако́нїе своѐ, и҆ возненави́дѣти. Глаго́лы ᲂу҆́стъ є҆гѡ̀ беззако́нїе и҆ ле́сть: не восхотѣ̀ разꙋмѣ́ти є҆́же ᲂу҆блажи́ти. Беззако́нїе помы́сли на ло́жи свое́мъ: предста̀ всѧ́комꙋ пꙋтѝ небла́гꙋ, ѡ҆ ѕло́бѣ же не негодова̀. Гдⷭ҇и, на нб҃сѝ млⷭ҇ть твоѧ̀, и҆ и҆́стина твоѧ̀ до ѻ҆́блакъ: Пра́вда твоѧ̀ ꙗ҆́кѡ го́ры бж҃їѧ, сꙋдьбы̑ твоѧ̑ бе́здна мно́га: человѣ́ки и҆ скоты̀ сп҃се́ши, гдⷭ҇и. Ꙗ҆́кѡ ᲂу҆мно́жилъ є҆сѝ млⷭ҇ть твою̀, бж҃е: сы́нове же человѣ́честїи въ кро́вѣ крилꙋ̑ твоє́ю надѣ́ѧтисѧ и҆́мꙋтъ. Оу҆пїю́тсѧ ѿ тꙋ́ка до́мꙋ твоегѡ̀, и҆ пото́комъ сла́дости твоеѧ̀ напои́ши ѧ҆̀. Ꙗ҆́кѡ ᲂу҆ тебє̀ и҆сто́чникъ живота̀, во свѣ́тѣ твое́мъ ᲂу҆́зримъ свѣ́тъ. Проба́ви млⷭ҇ть твою̀ вѣ́дꙋщымъ тѧ̀ и҆ пра́вдꙋ твою̀ пра̑вымъ се́рдцемъ. Да не прїи́детъ мнѣ̀ нога̀ горды́ни, и҆ рꙋка̀ грѣ́шнича да не подви́житъ менѐ. Та́мѡ падо́ша всѝ дѣ́лающїи беззако́нїе: и҆зринове́ни бы́ша, и҆ не возмо́гꙋтъ ста́ти.",
  ["заголовок_ру"] = "В коне́ц, о́троку Госпо́дню Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѻ҆́трокꙋ гдⷭ҇ню дв҃дꙋ."
}

add_psalom {
  ["номер"] = 36,
  ["часть"] = 1,
  ["кафизма"] = 5,
  ["слава"] = 3,
  ["текст_ру"] = "Не ревну́й лука́внующым, ниже́ зави́ди творя́щим беззако́ние. Зане́ я́ко трава́ ско́ро и́зсшут, и я́ко зе́лие зла́ка ско́ро отпаду́т. Упова́й на Го́спода и твори́ благосты́ню, и насели́ зе́млю, и упасе́шися в бога́тстве ея́. Наслади́ся Го́сподеви, и даст ти проше́ния се́рдца Твоего́. Откры́й ко Го́споду путь твой и упова́й на Него́, и Той сотвори́т: и изведе́т, я́ко свет, пра́вду твою́ и судьбу́ твою́, я́ко полу́дне. Повини́ся Го́сподеви и умоли́ Его́. Не ревну́й спе́ющему в пути́ свое́м, челове́ку, творя́щему законопреступле́ние. Преста́ни от гне́ва и оста́ви я́рость, не ревну́й е́же лука́вновати. Зане́ лука́внующии потребя́тся, терпя́щии же Го́спода, ти́и насле́дят зе́млю. И еще́ ма́ло, и не бу́дет гре́шника, и взы́щеши ме́сто eго́, и не обря́щеши. Кро́тцыи же насле́дят зе́млю и насладя́тся о мно́жестве ми́ра. Назира́ет гре́шный пра́веднаго и поскреже́щет нань зубы́ свои́ми. Госпо́дь же посмее́тся eму́, зане́ прозира́ет, я́ко прии́дет день eго́. Мечь извлеко́ша гре́шницы, напряго́ша лук свой, низложи́ти убо́га и ни́ща, закла́ти пра́выя се́рдцем. Мечь их да вни́дет в сердца́ их, и лу́цы их да сокруша́тся. Лу́чше ма́лое пра́веднику, па́че бога́тства гре́шных мно́га. Зане́ мы́шцы гре́шных сокруша́тся, утвержда́ет же пра́ведныя Госпо́дь. Весть Госпо́дь пути́ непоро́чных, и достоя́ние их в век бу́дет. Не постыдя́тся во вре́мя лю́тое, и во днех гла́да насы́тятся, я́ко гре́шницы поги́бнут. Врази́ же Госпо́дни, ку́пно просла́витися им и вознести́ся, исчеза́юще я́ко дым исчезо́ша. Зае́млет гре́шный и не возврати́т, пра́ведный же ще́дрит и дае́т. Я́ко благословя́щии Его́ насле́дят зе́млю, клену́щии же Его́ потребя́тся. От Го́спода стопы́ челове́ку исправля́ются, и пути́ eго́ восхо́щет зело́. Егда́ паде́т, не разбие́тся, я́ко Госпо́дь подкрепля́ет ру́ку eго́. Юне́йший бых, и́бо состаре́хся, и не ви́дех пра́ведника оста́влена, ниже́ се́мени eго́ прося́ща хле́бы. Весь день ми́лует и взаи́м дае́т пра́ведный, и се́мя eго́ во благослове́ние бу́дет. Уклони́ся от зла и сотвори́ бла́го, и всели́ся в век ве́ка. Я́ко Госпо́дь лю́бит суд и не оста́вит преподо́бных Свои́х, во век сохраня́тся. Беззако́нницы же изжену́тся, и се́мя нечести́вых потреби́тся. Пра́ведницы же насле́дят зе́млю и вселя́тся в век ве́ка на ней. Уста́ пра́веднаго поуча́тся прему́дрости, и язы́к eго́ возглаго́лет суд. Зако́н Бо́га eго́ в се́рдце eго́, и не за́пнутся стопы́ eго́. Сматря́ет гре́шный пра́веднаго и и́щет е́же умертви́ти eго́. Госпо́дь же не оста́вит eго́ в руку́ eго́, ниже́ осу́дит eго́, егда́ су́дит eму́. Потерпи́ Го́спода и сохрани́ путь Его́, и вознесе́т тя, е́же насле́дити зе́млю, внегда́ потребля́тися гре́шником у́зриши. Ви́дех нечести́ваго превознося́щася и вы́сящася, я́ко ке́дры лива́нския. И ми́мо идо́х, и се не бе́, и взыска́х eго́, и не обре́теся ме́сто eго́. Храни́ незло́бие и виждь правоту́, я́ко есть оста́нок челове́ку ми́рну. Беззако́нницы же потребя́тся вку́пе: оста́нцы же нечести́вых потребя́тся. Спасе́ние же пра́ведных от Го́спода, и Защи́титель их есть во вре́мя ско́рби. И помо́жет им Госпо́дь, и изба́вит их, и изме́т их от гре́шник, и спасе́т их, я́ко упова́ша на Него́.",
  ["текст_цс"] = "Не ревнꙋ́й лꙋка́внꙋющымъ, нижѐ зави́ди творѧ́щымъ беззако́нїе. Занѐ ꙗ҆́кѡ трава̀ ско́рѡ и҆́зсшꙋтъ, и҆ ꙗ҆́кѡ ѕе́лїе ѕла́ка ско́рѡ ѿпадꙋ́тъ. Оу҆пова́й на гдⷭ҇а и҆ творѝ бл҃госты́ню: и҆ населѝ зе́млю, и҆ ᲂу҆пасе́шисѧ въ бога́тствѣ є҆ѧ̀. Наслади́сѧ гдⷭ҇еви, и҆ да́стъ тѝ прошє́нїѧ се́рдца твоегѡ̀. Ѿкры́й ко гдⷭ҇ꙋ пꙋ́ть тво́й и҆ ᲂу҆пова́й на него̀, и҆ то́й сотвори́тъ. И҆ и҆зведе́тъ ꙗ҆́кѡ свѣ́тъ пра́вдꙋ твою̀ и҆ сꙋдьбꙋ̀ твою̀ ꙗ҆́кѡ полꙋ́дне. Повини́сѧ гдⷭ҇еви и҆ ᲂу҆молѝ є҆го̀. Не ревнꙋ́й спѣ́ющемꙋ въ пꙋтѝ свое́мъ, человѣ́кꙋ творѧ́щемꙋ законопрестꙋпле́нїе. Преста́ни ѿ гнѣ́ва и҆ ѡ҆ста́ви ꙗ҆́рость: не ревнꙋ́й, є҆́же лꙋка́вновати, Занѐ лꙋка́внꙋющїи потребѧ́тсѧ, терпѧ́щїи же гдⷭ҇а, ті́и наслѣ́дѧтъ зе́млю. И҆ є҆щѐ ма́лѡ, и҆ не бꙋ́детъ грѣ́шника: и҆ взы́щеши мѣ́сто є҆гѡ̀ и҆ не ѡ҆брѧ́щеши. Кро́тцыи же наслѣ́дѧтъ зе́млю и҆ насладѧ́тсѧ ѡ҆ мно́жествѣ ми́ра. Назира́етъ грѣ́шный првⷣнаго и҆ поскреже́щетъ на́нь зꙋбы̀ свои́ми: Гдⷭ҇ь же посмѣе́тсѧ є҆мꙋ̀, занѐ прозира́етъ, ꙗ҆́кѡ прїи́детъ де́нь є҆гѡ̀. Ме́чь и҆звлеко́ша грѣ̑шницы, напрѧго́ша лꙋ́къ сво́й, низложи́ти ᲂу҆бо́га и҆ ни́ща, закла́ти пра̑выѧ се́рдцемъ. Ме́чь и҆́хъ да вни́детъ въ сердца̀ и҆́хъ, и҆ лꙋ́цы и҆́хъ да сокрꙋша́тсѧ. Лꙋ́чше ма́лое првⷣникꙋ, па́че бога́тства грѣ́шныхъ мно́га. Занѐ мы̑шцы грѣ́шныхъ сокрꙋша́тсѧ, ᲂу҆твержда́етъ же првⷣныѧ гдⷭ҇ь. Вѣ́сть гдⷭ҇ь пꙋти̑ непоро́чныхъ, и҆ достоѧ́нїе и҆́хъ въ вѣ́къ бꙋ́детъ. Не постыдѧ́тсѧ во вре́мѧ лю́тое и҆ во дне́хъ гла́да насы́тѧтсѧ, ꙗ҆́кѡ грѣ̑шницы поги́бнꙋтъ. Врази́ же гдⷭ҇ни, кꙋ́пнѡ просла́витисѧ и҆̀мъ и҆ вознести́сѧ, и҆счеза́юще ꙗ҆́кѡ ды́мъ и҆счезо́ша. Зае́млетъ грѣ́шный и҆ не возврати́тъ: првⷣный же ще́дритъ и҆ дае́тъ. Ꙗ҆́кѡ бл҃гословѧ́щїи є҆го̀ наслѣ́дѧтъ зе́млю, кленꙋ́щїи же є҆го̀ потребѧ́тсѧ. Ѿ гдⷭ҇а стѡпы̀ человѣ́кꙋ и҆справлѧ́ютсѧ, и҆ пꙋтѝ є҆гѡ̀ восхо́щетъ ѕѣлѡ̀. Є҆гда̀ паде́тъ, не разбїе́тсѧ, ꙗ҆́кѡ гдⷭ҇ь подкрѣплѧ́етъ рꙋ́кꙋ є҆гѡ̀. Ю҆нѣ́йшїй бы́хъ, и҆́бо состарѣ́хсѧ, и҆ не ви́дѣхъ првⷣника ѡ҆ста́влена, нижѐ сѣ́мене є҆гѡ̀ просѧ́ща хлѣ́бы. Ве́сь де́нь ми́лꙋетъ и҆ взаи́мъ дае́тъ првⷣный, и҆ сѣ́мѧ є҆гѡ̀ во бл҃гослове́нїе бꙋ́детъ. Оу҆клони́сѧ ѿ ѕла̀ и҆ сотворѝ бл҃го, и҆ всели́сѧ въ вѣ́къ вѣ́ка. Ꙗ҆́кѡ гдⷭ҇ь лю́битъ сꙋ́дъ и҆ не ѡ҆ста́витъ прпⷣбныхъ свои́хъ: во вѣ́къ сохранѧ́тсѧ: беззакѡ́нницы же и҆зженꙋ́тсѧ, и҆ сѣ́мѧ нечести́выхъ потреби́тсѧ. Првⷣницы же наслѣ́дѧтъ зе́млю и҆ вселѧ́тсѧ въ вѣ́къ вѣ́ка на не́й. Оу҆ста̀ првⷣнагѡ поꙋча́тсѧ премⷣрости, и҆ ѧ҆зы́къ є҆гѡ̀ возглаго́летъ сꙋ́дъ. Зако́нъ бг҃а є҆гѡ̀ се́рдцы є҆гѡ̀, и҆ не за́пнꙋтсѧ стѡпы̀ є҆гѡ̀. Сматрѧ́етъ грѣ́шный првⷣнаго и҆ и҆́щетъ є҆́же ᲂу҆мертви́ти є҆го̀: Гдⷭ҇ь же не ѡ҆ста́витъ є҆гѡ̀ въ рꙋкꙋ̀ є҆гѡ̀, нижѐ ѡ҆сꙋ́дитъ є҆го̀, є҆гда̀ сꙋ́дитъ є҆мꙋ̀. Потерпѝ гдⷭ҇а и҆ сохранѝ пꙋ́ть є҆гѡ̀, и҆ вознесе́тъ тѧ̀ є҆́же наслѣ́дити зе́млю: внегда̀ потреблѧ́тисѧ грѣ́шникѡмъ, ᲂу҆́зриши. Ви́дѣхъ нечести́ваго превозносѧ́щасѧ и҆ вы́сѧщасѧ ꙗ҆́кѡ ке́дры лїва̑нскїѧ: И҆ ми́мѡ и҆до́хъ, и҆ сѐ, не бѣ̀, и҆ взыска́хъ є҆го̀, и҆ не ѡ҆брѣ́тесѧ мѣ́сто є҆гѡ̀. Хранѝ неѕло́бїе и҆ ви́ждь правотꙋ̀, ꙗ҆́кѡ є҆́сть ѡ҆ста́нокъ человѣ́кꙋ ми́рнꙋ. Беззакѡ́нницы же потребѧ́тсѧ вкꙋ́пѣ: ѡ҆ста́нцы же нечести́выхъ потребѧ́тсѧ. Сп҃се́нїе же првⷣныхъ ѿ гдⷭ҇а, и҆ защи́титель и҆́хъ є҆́сть во вре́мѧ ско́рби: И҆ помо́жетъ и҆̀мъ гдⷭ҇ь и҆ и҆зба́витъ и҆̀хъ, и҆ и҆́зметъ и҆̀хъ ѿ грѣ̑шникъ и҆ сп҃се́тъ и҆̀хъ, ꙗ҆́кѡ ᲂу҆пова́ша на него̀.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 37,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 1,
  ["текст_ру"] = "Го́споди, да не я́ростию Твое́ю обличи́ши мене́, ниже́ гне́вом Твои́м нака́жеши мене́. Я́ко стре́лы Твоя́ унзо́ша во мне, и утверди́л еси́ на мне ру́ку Твою́. Несть исцеле́ния в пло́ти мое́й от лица́ гне́ва Твоего́, несть ми́ра в косте́х мои́х от лица́ грех мои́х. Я́ко беззако́ния моя́ превзыдо́ша главу́ мою́, я́ко бре́мя тя́жкое отяготе́ша на мне. Возсмерде́ша и согни́ша ра́ны моя́ от лица́ безу́мия моего́. Пострада́х и сляко́хся до конца́, весь день се́туя хожда́х. Я́ко ля́двия моя́ напо́лнишася поруга́ний, и несть исцеле́ния в пло́ти мое́й. Озло́блен бых и смири́хся до зела́, рыка́х от воздыха́ния се́рдца моего́. Го́споди, пред Тобо́ю все жела́ние мое́ и воздыха́ние мое́ от Тебе́ не утаи́ся. Се́рдце мое́ смяте́ся, оста́ви мя си́ла моя́, и свет о́чию мое́ю, и той несть со мно́ю. Дру́зи мои́ и и́скреннии мои́ пря́мо мне прибли́жишася и ста́ша, и бли́жнии мои́ отдале́че мене́ ста́ша и нужда́хуся и́щущии ду́шу мою́, и и́щущии зла́я мне глаго́лаху су́етная и льсти́вным весь день поуча́хуся. Аз же я́ко глух не слы́шах и я́ко нем не отверза́яй уст свои́х. И бых я́ко челове́к не слы́шай и не имы́й во усте́х свои́х обличе́ния. Я́ко на Тя, Го́споди, упова́х, Ты услы́шиши, Го́споди Бо́же мой. Я́ко рех: да не когда́ пора́дуют ми ся врази́ мои́: и внегда́ подвижа́тися нога́м мои́м, на мя велере́чеваша. Я́ко аз на ра́ны гото́в, и боле́знь моя́ предо мно́ю есть вы́ну. Я́ко беззако́ние мое́ аз возвещу́ и попеку́ся о гресе́ мое́м. Врази́ же мои́ живу́т и укрепи́шася па́че мене́, и умно́жишася ненави́дящии мя без пра́вды. Воздаю́щии ми зла́я возблага́я оболга́ху мя, зане́ гоня́х благосты́ню. Не оста́ви мене́, Го́споди Бо́же мой, не отступи́ от мене́. Вонми́ в по́мощь мою́, Го́споди спасе́ния моего́.",
  ["текст_цс"] = "Гдⷭ҇и, да не ꙗ҆́ростїю твое́ю ѡ҆бличи́ши менѐ, нижѐ гнѣ́вомъ твои́мъ нака́жеши менѐ: Ꙗ҆́кѡ стрѣ́лы твоѧ̑ ᲂу҆нзо́ша во мнѣ̀, и҆ ᲂу҆тверди́лъ є҆сѝ на мнѣ̀ рꙋ́кꙋ твою̀. Нѣ́сть и҆сцѣле́нїѧ въ пло́ти мое́й ѿ лица̀ гнѣ́ва твоегѡ̀, нѣ́сть ми́ра въ косте́хъ мои́хъ ѿ лица̀ грѣ̑хъ мои́хъ. Ꙗ҆́кѡ беззакѡ́нїѧ моѧ̑ превзыдо́ша главꙋ̀ мою̀, ꙗ҆́кѡ бре́мѧ тѧ́жкое ѡ҆тѧготѣ́ша на мнѣ̀. Возсмердѣ́ша и҆ согни́ша ра̑ны моѧ̑, ѿ лица̀ безꙋ́мїѧ моегѡ̀. Пострада́хъ и҆ слѧко́хсѧ до конца̀, ве́сь де́нь сѣ́тꙋѧ хожда́хъ: Ꙗ҆́кѡ лѧ̑двїѧ моѧ̑ напо́лнишасѧ порꙋга́нїй, и҆ нѣ́сть и҆сцѣле́нїѧ въ пло́ти мое́й. Ѡ҆ѕло́бленъ бы́хъ и҆ смири́хсѧ до ѕѣла̀, рыка́хъ ѿ воздыха́нїѧ се́рдца моегѡ̀. Гдⷭ҇и, пред̾ тобо́ю всѐ жела́нїе моѐ, и҆ воздыха́нїе моѐ ѿ тебє̀ не ᲂу҆таи́сѧ. Се́рдце моѐ смѧте́сѧ, ѡ҆ста́ви мѧ̀ си́ла моѧ̀, и҆ свѣ́тъ ѻ҆́чїю моє́ю, и҆ то́й нѣ́сть со мно́ю. Дрꙋ́зи моѝ и҆ и҆́скреннїи моѝ прѧ́мѡ мнѣ̀ прибли́жишасѧ и҆ ста́ша. И҆ бли́жнїи моѝ ѿдале́че менѐ ста́ша, и҆ нꙋжда́хꙋсѧ и҆́щꙋщїи дꙋ́шꙋ мою̀: и҆ и҆́щꙋщїи ѕла̑ѧ мнѣ̀ глаго́лахꙋ сꙋ́єтнаѧ, и҆ льсти̑внымъ ве́сь де́нь поꙋча́хꙋсѧ. А҆́зъ же ꙗ҆́кѡ глꙋ́хъ не слы́шахъ, и҆ ꙗ҆́кѡ нѣ́мъ не ѿверза́ѧй ᲂу҆́стъ свои́хъ: И҆ бы́хъ ꙗ҆́кѡ человѣ́къ не слы́шай и҆ не и҆мы́й во ᲂу҆стѣ́хъ свои́хъ ѡ҆бличе́нїѧ. Ꙗ҆́кѡ на тѧ̀, гдⷭ҇и, ᲂу҆пова́хъ, ты̀ ᲂу҆слы́шиши, гдⷭ҇и бж҃е мо́й. Ꙗ҆́кѡ рѣ́хъ: да не когда̀ пора́дꙋютъ ми сѧ вразѝ моѝ: и҆ внегда̀ подвижа́тисѧ нога́мъ мои̑мъ, на мѧ̀ велерѣ́чеваша. Ꙗ҆́кѡ а҆́зъ на ра̑ны гото́въ, и҆ болѣ́знь моѧ̀ предо мно́ю є҆́сть вы́нꙋ. Ꙗ҆́кѡ беззако́нїе моѐ а҆́зъ возвѣщꙋ̀ и҆ попекꙋ́сѧ ѡ҆ грѣсѣ̀ мое́мъ. Врази́ же моѝ живꙋ́тъ и҆ ᲂу҆крѣпи́шасѧ па́че менѐ, и҆ ᲂу҆мно́жишасѧ ненави́дѧщїи мѧ̀ без̾ пра́вды: Воздаю́щїи мѝ ѕла̑ѧ воз̾ блага̑ѧ ѡ҆болга́хꙋ мѧ̀, занѐ гонѧ́хъ бл҃госты́ню. Не ѡ҆ста́ви менѐ, гдⷭ҇и бж҃е мо́й, не ѿстꙋпѝ ѿ менѐ: Вонмѝ въ по́мощь мою̀, гдⷭ҇и сп҃се́нїѧ моегѡ̀.",
  ["заголовок_ру"] = "Псало́м Дави́ду, в воспомина́ние о суббо́те.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, въ воспомина́нїе ѡ҆ сꙋббѡ́тѣ."
}

add_psalom {
  ["номер"] = 38,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 1,
  ["текст_ру"] = "Рех: сохраню́ пути́ моя́, е́же не согреша́ти ми язы́ком мои́м: положи́х усто́м мои́м храни́ло, внегда́ воста́ти гре́шному предо мно́ю. Онеме́х и смири́хся, и умолча́х от благ, и боле́знь моя́ обнови́ся. Согре́яся се́рдце мое́ во мне, и в поуче́нии мое́м разгори́тся огнь. Глаго́лах язы́ком мои́м: скажи́ ми, Го́споди, кончи́ну мою́ и число́ дней мои́х, ко́е есть? Да разуме́ю, что лиша́юся аз? Се пя́ди положи́л еси́ дни моя́, и соста́в мой я́ко ничто́же пред Тобо́ю, оба́че вся́ческая суета́ всяк челове́к живы́й. У́бо о́бразом хо́дит челове́к, оба́че всу́е мяте́тся: сокро́вищствует, и не весть, кому́ собере́т я́. И ны́не кто терпе́ние мое́, не Госпо́дь ли? И соста́в мой от Тебе́ есть. От всех беззако́ний мои́х изба́ви мя, поноше́ние безу́мному дал мя еси́. Онеме́х и не отверзо́х уст мои́х, я́ко Ты сотвори́л еси́. Отста́ви от мене́ ра́ны Твоя́: от кре́пости бо руки́ Твоея́ аз исчезо́х. Во обличе́ниих о беззако́нии наказа́л еси́ челове́ка и иста́ял еси́, я́ко паучи́ну, ду́шу eго́: оба́че всу́е всяк челове́к. Услы́ши моли́тву мою́, Го́споди, и моле́ние мое́ внуши́, слез мои́х не премолчи́: я́ко пресе́льник аз есмь у Тебе́ и пришле́ц, я́коже вси отцы́ мои́. Осла́би ми, да почи́ю, пре́жде да́же не отъиду́, и ктому́ не бу́ду.",
  ["текст_цс"] = "Рѣ́хъ: сохраню̀ пꙋти̑ моѧ̑, є҆́же не согрѣша́ти мѝ ѧ҆зы́комъ мои́мъ: положи́хъ ᲂу҆стѡ́мъ мои̑мъ храни́ло, внегда̀ воста́ти грѣ́шномꙋ предо мно́ю. Ѡ҆нѣмѣ́хъ и҆ смири́хсѧ, и҆ ᲂу҆молча́хъ ѿ бла̑гъ, и҆ болѣ́знь моѧ̀ ѡ҆бнови́сѧ. Согрѣ́ѧсѧ се́рдце моѐ во мнѣ̀, и҆ въ поꙋче́нїи мое́мъ разгори́тсѧ ѻ҆́гнь: глаго́лахъ ѧ҆зы́комъ мои́мъ: Скажи́ ми, гдⷭ҇и, кончи́нꙋ мою̀ и҆ число̀ дні́й мои́хъ, ко́е є҆́сть, да разꙋмѣ́ю, что̀ лиша́юсѧ а҆́зъ. Сѐ, пѧ̑ди положи́лъ є҆сѝ дни̑ моѧ̑, и҆ соста́въ мо́й ꙗ҆́кѡ ничто́же пред̾ тобо́ю: ѻ҆ба́че всѧ́чєскаѧ сꙋета̀ всѧ́къ человѣ́къ живы́й. Оу҆̀бо ѡ҆́бразомъ хо́дитъ человѣ́къ, ѻ҆ба́че всꙋ́е мѧте́тсѧ: сокро́вищствꙋетъ, и҆ не вѣ́сть, комꙋ̀ собере́тъ ѧ҆̀. И҆ ны́нѣ кто̀ терпѣ́нїе моѐ; не гдⷭ҇ь ли; и҆ соста́въ мо́й ѿ тебє̀ є҆́сть. Ѿ всѣ́хъ беззако́нїй мои́хъ и҆зба́ви мѧ̀: поноше́нїе безꙋ́мномꙋ да́лъ мѧ̀ є҆сѝ. Ѡ҆нѣмѣ́хъ и҆ не ѿверзо́хъ ᲂу҆́стъ мои́хъ, ꙗ҆́кѡ ты̀ сотвори́лъ є҆сѝ. Ѿста́ви ѿ менѐ ра̑ны твоѧ̑: ѿ крѣ́пости бо рꙋкѝ твоеѧ̀ а҆́зъ и҆счезо́хъ. Во ѡ҆бличе́нїихъ ѡ҆ беззако́нїи наказа́лъ є҆сѝ человѣ́ка, и҆ и҆ста́ѧлъ є҆сѝ ꙗ҆́кѡ паꙋчи́нꙋ дꙋ́шꙋ є҆гѡ̀: ѻ҆ба́че всꙋ́е всѧ́къ человѣ́къ. Оу҆слы́ши моли́твꙋ мою̀, гдⷭ҇и, и҆ моле́нїе моѐ внꙋшѝ, сле́зъ мои́хъ не премолчѝ: ꙗ҆́кѡ пресе́льникъ а҆́зъ є҆́смь ᲂу҆ тебє̀ и҆ пришле́цъ, ꙗ҆́коже всѝ ѻ҆тцы̀ моѝ. Ѡ҆сла́би мѝ, да почі́ю, пре́жде да́же не ѿидꙋ̀, и҆ ктомꙋ̀ не бꙋ́дꙋ.",
  ["заголовок_ру"] = "В коне́ц, Идифу́му, песнь Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, і҆дїѳꙋ́мꙋ, пѣ́снь дв҃дꙋ."
}

add_psalom {
  ["номер"] = 39,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 1,
  ["текст_ру"] = "Терпя́, потерпе́х Го́спода, и внят ми, и услы́ша моли́тву мою́. И возведе́ мя от ро́ва страсте́й, и от бре́ния ти́ны, и поста́ви на ка́мени но́зе мои́, и испра́ви стопы́ моя́, и вложи́ во уста́ моя́ песнь но́ву, пе́ние Бо́гу на́шему. У́зрят мно́зи и убоя́тся, и упова́ют на Го́спода. Блаже́н муж, eму́же есть и́мя Госпо́дне упова́ние eго́, и не призре́ в суеты́ и неистовле́ния ло́жная. Мно́га сотвори́л еси́ Ты, Го́споди, Бо́же мой, чудеса́ Твоя́ и помышле́нием Твои́м несть кто уподо́бится Тебе́: возвести́х и глаго́лах, умно́жишася па́че числа́. Же́ртвы и приноше́ния не восхоте́л еси́, те́ло же сверши́л ми еси́, всесожже́ний и о гресе́ не взыска́л еси́. Тогда́ рех: се прииду́, в глави́зне кни́жне пи́сано есть о мне: е́же сотвори́ти во́лю Твою́, Бо́же мой, восхоте́х, и зако́н Твой посреде́ чре́ва моего́. Благовести́х пра́вду в це́ркви вели́цей, се устна́м мои́м не возбраню́: Го́споди, Ты разуме́л еси́. Пра́вду Твою́ не скрых в се́рдце мое́м, и́стину Твою́ и спасе́ние Твое́ рех, не скрых ми́лость Твою́ и и́стину Твою́ от со́нма мно́га. Ты же, Го́споди, не удали́ щедро́т Твои́х от мене́: ми́лость Твоя́ и и́стина Твоя́ вы́ну да засту́пите мя. Я́ко одержа́ша мя зла́я, и́мже несть числа, постиго́ша мя беззако́ния моя́, и не возмого́х зре́ти, умно́жишася па́че влас главы́ моея́, и се́рдце мое́ оста́ви мя. Благоволи́, Го́споди, изба́вити мя: Го́споди, во е́же помощи́ ми вонми́. Да постыдя́тся и посра́мятся вку́пе и́щущии ду́шу мою́ изъя́ти ю́, да возвратя́тся вспять и постыдя́тся хотя́щии ми зла́я. Да прии́мут а́бие студ свой глаго́лющии ми: бла́гоже, бла́гоже. Да возра́дуются и возвеселя́тся о Тебе́ вси и́щущии Тебе́, Го́споди, и да реку́т вы́ну: да возвели́чится Госпо́дь, лю́бящии спасе́ние Твое́. Аз же нищ есмь и убо́г, Госпо́дь попече́тся о мне. Помо́щник мой и Защи́титель мой еси́ Ты, Бо́же мой, не закосни́.",
  ["текст_цс"] = "Терпѧ̀ потерпѣ́хъ гдⷭ҇а, и҆ внѧ́тъ мѝ и҆ ᲂу҆слы́ша моли́твꙋ мою̀: И҆ возведе́ мѧ ѿ ро́ва страсте́й и҆ ѿ бре́нїѧ ти́ны, и҆ поста́ви на ка́мени но́зѣ моѝ и҆ и҆спра́ви стѡпы̀ моѧ̑: И҆ вложѝ во ᲂу҆ста̀ моѧ̑ пѣ́снь но́вꙋ, пѣ́нїе бг҃ꙋ на́шемꙋ. Оу҆́зрѧтъ мно́зи и҆ ᲂу҆боѧ́тсѧ, и҆ ᲂу҆пова́ютъ на гдⷭ҇а. Бл҃же́нъ мꙋ́жъ, є҆мꙋ́же є҆́сть и҆́мѧ гдⷭ҇не ᲂу҆пова́нїе є҆гѡ̀, и҆ не призрѣ̀ въ сꙋєты̀ и҆ неистовлє́нїѧ лѡ́жнаѧ. Мнѡ́га сотвори́лъ є҆сѝ ты̀, гдⷭ҇и бж҃е мо́й, чꙋдеса̀ твоѧ̑, и҆ помышле́нїємъ твои̑мъ нѣ́сть кто̀ ᲂу҆подо́битсѧ тебѣ̀: возвѣсти́хъ и҆ глаго́лахъ: ᲂу҆мно́жишасѧ па́че числа̀. Же́ртвы и҆ приноше́нїѧ не восхотѣ́лъ є҆сѝ, тѣ́ло же сверши́лъ мѝ є҆сѝ: всесожже́нїй и҆ ѡ҆ грѣсѣ̀ не взыска́лъ є҆сѝ. Тогда̀ рѣ́хъ: сѐ, прїидꙋ̀: въ глави́знѣ кни́жнѣ пи́сано є҆́сть ѡ҆ мнѣ̀: Є҆́же сотвори́ти во́лю твою̀, бж҃е мо́й, восхотѣ́хъ, и҆ зако́нъ тво́й посредѣ̀ чре́ва моегѡ̀. Бл҃говѣсти́хъ пра́вдꙋ въ цр҃кви вели́цѣй, сѐ, ᲂу҆стна́мъ мои̑мъ не возбраню̀: гдⷭ҇и, ты̀ разꙋмѣ́лъ є҆сѝ. Пра́вдꙋ твою̀ не скры́хъ въ се́рдцы мое́мъ, и҆́стинꙋ твою̀ и҆ сп҃се́нїе твоѐ рѣ́хъ, не скры́хъ млⷭ҇ть твою̀ и҆ и҆́стинꙋ твою̀ ѿ со́нма мно́га. Ты́ же, гдⷭ҇и, не ᲂу҆далѝ щедро́тъ твои́хъ ѿ менѐ: млⷭ҇ть твоѧ̀ и҆ и҆́стина твоѧ̀ вы́нꙋ да застꙋ́питѣ мѧ̀. Ꙗ҆́кѡ ѡ҆держа́ша мѧ̀ ѕла̑ѧ, и҆̀мже нѣ́сть числа̀: постиго́ша мѧ̀ беззакѡ́нїѧ моѧ̑, и҆ не возмого́хъ зрѣ́ти: ᲂу҆мно́жишасѧ па́че вла̑съ главы̀ моеѧ̀, и҆ се́рдце моѐ ѡ҆ста́ви мѧ̀. Бл҃говолѝ, гдⷭ҇и, и҆зба́вити мѧ̀: гдⷭ҇и, во є҆́же помощи́ ми, вонмѝ. Да постыдѧ́тсѧ и҆ посра́мѧтсѧ вкꙋ́пѣ и҆́щꙋщїи дꙋ́шꙋ мою̀, и҆з̾ѧ́ти ю҆̀: да возвратѧ́тсѧ вспѧ́ть и҆ постыдѧ́тсѧ хотѧ́щїи мѝ ѕла̑ѧ. Да прїи́мꙋтъ а҆́бїе стꙋ́дъ сво́й глаго́лющїи мѝ: бла́гоже, бла́гоже. Да возра́дꙋютсѧ и҆ возвеселѧ́тсѧ ѡ҆ тебѣ̀ всѝ и҆́щꙋщїи тебѐ, гдⷭ҇и, и҆ да рекꙋ́тъ вы́нꙋ, да возвели́читсѧ гдⷭ҇ь, лю́бѧщїи сп҃се́нїе твоѐ. А҆́зъ же ни́щъ є҆́смь и҆ ᲂу҆бо́гъ, гдⷭ҇ь попече́тсѧ ѡ҆ мнѣ̀: помо́щникъ мо́й и҆ защи́титель мо́й є҆сѝ ты̀, бж҃е мо́й, не закоснѝ.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 40,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 2,
  ["текст_ру"] = "Блаже́н разумева́яй на ни́ща и убо́га, в день лют изба́вит eго́ Госпо́дь. Госпо́дь да сохрани́т eго́ и живи́т eго́, и да ублажи́т eго́ на земли́, и да не преда́ст eго́ в ру́ки враго́в eго́. Госпо́дь да помо́жет eму́ на одре́ боле́зни eго́: все ло́же eго́ обрати́л еси́ в боле́зни eго́. Аз рех: Го́споди, поми́луй мя, исцели́ ду́шу мою́, я́ко согреши́х Ти. Врази́ мои́ ре́ша мне зла́я: когда́ у́мрет и поги́бнет и́мя eго́? И вхожда́ше ви́дети, всу́е глаго́лаше се́рдце eго́, собра́ беззако́ние себе́, исхожда́ше вон и глаго́лаше вку́пе. На мя шепта́ху вси врази́ мои́, на мя помышля́ху зла́я мне. Сло́во законопресту́пное возложи́ша на мя: еда́ спяй не приложи́т воскресну́ти? И́бо челове́к ми́ра моего́, на него́же упова́х, яды́й хле́бы моя́, возвели́чи на мя запина́ние. Ты же, Го́споди, поми́луй мя и возста́ви мя и возда́м им. В сем позна́х, я́ко восхоте́л мя еси́, я́ко не возра́дуется враг мой о мне. Мене́ же за незло́бие прия́л и утверди́л мя еси́ пред Тобою́ в век. Благослове́н Госпо́дь Бог Изра́илев от ве́ка и до ве́ка: бу́ди, бу́ди.",
  ["текст_цс"] = "Бл҃же́нъ разꙋмѣва́ѧй на ни́ща и҆ ᲂу҆бо́га, въ де́нь лю́тъ и҆зба́витъ є҆го̀ гдⷭ҇ь. Гдⷭ҇ь да сохрани́тъ є҆го̀ и҆ живи́тъ є҆го̀, и҆ да ᲂу҆бл҃жи́тъ є҆го̀ на землѝ и҆ да не преда́стъ є҆гѡ̀ въ рꙋ́ки врагѡ́въ є҆гѡ̀. Гдⷭ҇ь да помо́жетъ є҆мꙋ̀ на ѻ҆дрѣ̀ болѣ́зни є҆гѡ̀: всѐ ло́же є҆гѡ̀ ѡ҆брати́лъ є҆сѝ въ болѣ̑зни є҆гѡ̀. А҆́зъ рѣ́хъ: гдⷭ҇и, поми́лꙋй мѧ̀, и҆сцѣлѝ дꙋ́шꙋ мою̀, ꙗ҆́кѡ согрѣши́хъ тѝ. Вразѝ моѝ рѣ́ша мнѣ̀ ѕла̑ѧ: когда̀ ᲂу҆́мретъ, и҆ поги́бнетъ и҆́мѧ є҆гѡ̀; И҆ вхожда́ше ви́дѣти, всꙋ́е глаго́лаше се́рдце є҆гѡ̀: собра̀ беззако́нїе себѣ̀, и҆схожда́ше во́нъ и҆ глаго́лаше вкꙋ́пѣ. На мѧ̀ шепта́хꙋ всѝ вразѝ моѝ, на мѧ̀ помышлѧ́хꙋ ѕла̑ѧ мнѣ̀. Сло́во законопрестꙋ́пное возложи́ша на мѧ̀: є҆да̀ спѧ́й не приложи́тъ воскреснꙋ́ти; И҆́бо человѣ́къ ми́ра моегѡ̀, на него́же ᲂу҆пова́хъ, ꙗ҆ды́й хлѣ́бы моѧ̑, возвели́чи на мѧ̀ запина́нїе. Ты́ же, гдⷭ҇и, поми́лꙋй мѧ̀ и҆ возста́ви мѧ̀, и҆ возда́мъ и҆̀мъ. Въ се́мъ позна́хъ, ꙗ҆́кѡ восхотѣ́лъ мѧ̀ є҆сѝ, ꙗ҆́кѡ не возра́дꙋетсѧ вра́гъ мо́й ѡ҆ мнѣ̀. Мене́ же за неѕло́бїе прїѧ́лъ, и҆ ᲂу҆тверди́лъ мѧ̀ є҆сѝ пред̾ тобо́ю въ вѣ́къ. Бл҃гослове́нъ гдⷭ҇ь бг҃ъ і҆и҃левъ ѿ вѣ́ка и҆ до вѣ́ка: бꙋ́ди, бꙋ́ди.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 41,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 2,
  ["текст_ру"] = "И́мже о́бразом жела́ет еле́нь на исто́чники водны́я, си́це жела́ет душа́ моя́ к Тебе́, Бо́же. Возжада́ душа́ моя́ к Бо́гу кре́пкому, живо́му: когда́ прииду́ и явлю́ся лицу́ Бо́жию? Бы́ша сле́зы моя́ мне хлеб день и нощь, внегда́ глаго́латися мне на всяк день: где есть Бог твой? Сия́ помяну́х и излия́х на мя ду́шу мою́, я́ко пройду́ в ме́сто селе́ния ди́вна, да́же до до́му Бо́жия, во гла́се ра́дования и испове́дания шу́ма пра́зднующаго. Вску́ю приско́рбна еси́, душе́ моя́? И вску́ю смуща́еши мя? Упова́й на Бо́га, я́ко испове́мся Ему́, спасе́ние лица́ моего́, и Бог мой. Ко мне самому́ душа́ моя́ смяте́ся: сего́ ра́ди помяну́х Тя от земли́ Иорда́нски и Ермонии́мски, от горы́ ма́лыя. Бе́здна бе́здну призыва́ет во гла́се хля́бий Твои́х, вся высоты́ Твоя́ и во́лны Твоя́ на мне преидо́ша. В день запове́сть Госпо́дь ми́лость Свою́, и но́щию песнь Его́ от мене́, моли́тва Бо́гу живота́ моего́. Реку́ Бо́гу: Засту́пник мой еси́, почто́ мя забы́л еси́? И вску́ю се́туя хожду́, внегда́ оскорбля́ет враг? Внегда́ сокруша́тися косте́м мои́м, поноша́ху ми врази́ мои́, внегда́ глаго́лати им мне на всяк день: где есть Бог твой? Вску́ю приско́рбна еси́, душе́ моя́? И вску́ю смуща́еши мя? Упова́й на Бо́га, я́ко испове́мся Ему́, спасе́ние лица́ моего́, и Бог мой.",
  ["текст_цс"] = "И҆́мже ѡ҆́бразомъ жела́етъ є҆ле́нь на и҆сто́чники водны̑ѧ, си́це жела́етъ дꙋша̀ моѧ̀ къ тебѣ̀, бж҃е. Возжада̀ дꙋша̀ моѧ̀ къ бг҃ꙋ крѣ́пкомꙋ, живо́мꙋ: когда̀ прїидꙋ̀ и҆ ꙗ҆влю́сѧ лицꙋ̀ бж҃їю; Бы́ша сле́зы моѧ̑ мнѣ̀ хлѣ́бъ де́нь и҆ но́щь, внегда̀ глаго́латисѧ мнѣ̀ на всѧ́къ де́нь: гдѣ̀ є҆́сть бг҃ъ тво́й; Сїѧ̑ помѧнꙋ́хъ, и҆ и҆злїѧ́хъ на мѧ̀ дꙋ́шꙋ мою̀: ꙗ҆́кѡ пройдꙋ̀ въ мѣ́сто селе́нїѧ ди́вна, да́же до до́мꙋ бж҃їѧ, во гла́сѣ ра́дованїѧ и҆ и҆сповѣ́данїѧ, шꙋ́ма пра́зднꙋющагѡ. Вскꙋ́ю приско́рбна є҆сѝ, дꙋшѐ моѧ̀; и҆ вскꙋ́ю смꙋща́еши мѧ̀; ᲂу҆пова́й на бг҃а, ꙗ҆́кѡ и҆сповѣ́мсѧ є҆мꙋ̀, сп҃се́нїе лица̀ моегѡ̀ и҆ бг҃ъ мо́й. Ко мнѣ̀ самомꙋ̀ дꙋша̀ моѧ̀ смѧте́сѧ: сегѡ̀ ра́ди помѧнꙋ́хъ тѧ̀ ѿ землѝ і҆ѻрда́нски и҆ є҆рмѡнїи́мски, ѿ горы̀ ма́лыѧ. Бе́здна бе́зднꙋ призыва́етъ во гла́сѣ хлѧ́бїй твои́хъ: всѧ̑ высоты̑ твоѧ̑ и҆ вѡ́лны твоѧ̑ на мнѣ̀ преидо́ша. Въ де́нь заповѣ́сть гдⷭ҇ь млⷭ҇ть свою̀, и҆ но́щїю пѣ́снь є҆гѡ̀ ѿ менѐ, моли́тва бг҃ꙋ живота̀ моегѡ̀. Рекꙋ̀ бг҃ꙋ: застꙋ́пникъ мо́й є҆сѝ, почто̀ мѧ̀ забы́лъ є҆сѝ; и҆ вскꙋ́ю сѣ́тꙋѧ хождꙋ̀, внегда̀ ѡ҆скорблѧ́етъ вра́гъ; Внегда̀ сокрꙋша́тисѧ косте́мъ мои̑мъ, поноша́хꙋ мѝ вразѝ моѝ, внегда̀ глаго́лати и҆̀мъ мнѣ̀ на всѧ́къ де́нь: гдѣ̀ є҆́сть бг҃ъ тво́й; Вскꙋ́ю приско́рбна є҆сѝ, дꙋшѐ моѧ̀; и҆ вскꙋ́ю смꙋща́еши мѧ̀; ᲂу҆пова́й на бг҃а, ꙗ҆́кѡ и҆сповѣ́мсѧ є҆мꙋ̀, сп҃се́нїе лица̀ моегѡ̀ и҆ бг҃ъ мо́й.",
  ["заголовок_ру"] = "В коне́ц, в ра́зум сыно́в Коре́овых, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, въ ра́зꙋмъ сынѡ́въ коре́овыхъ, ѱало́мъ дв҃дꙋ."
}

