  ["кафизма"] = 6,
  ["слава"] = 2,
  ["текст_ру"] = "Суди́ ми, Бо́же, и разсуди́ прю мою́, от язы́ка непреподо́бна, от челове́ка непра́ведна и льсти́ва изба́ви мя. Зане́ Ты еси́, Бо́же, Кре́пость моя́, вску́ю отри́нул мя еси́? И вску́ю се́туя хожду́, внегда́ оскорбля́ет враг? Посли́ свет Твой и и́стину Твою́, та мя наста́виста и введо́ста мя в го́ру святу́ю Твою́ и в селе́ния Твоя́. И вни́ду к же́ртвеннику Бо́жию, к Бо́гу веселя́щему ю́ность мою́, испове́мся Тебе́ в гу́слех, Бо́же, Бо́же мой. Вску́ю приско́рбна еси́, душе́ моя́? И вску́ю смуща́еши мя? Упова́й на Бо́га, я́ко испове́мся Ему́, спасе́ние лица́ моего́, и Бог мой.",
  ["текст_цс"] = "Сꙋди́ ми, бж҃е, и҆ разсꙋдѝ прю̀ мою̀: ѿ ꙗ҆зы́ка непреподо́бна, ѿ человѣ́ка непра́ведна и҆ льсти́ва и҆зба́ви мѧ̀. Занѐ ты̀ є҆сѝ, бж҃е, крѣ́пость моѧ̀, вскꙋ́ю ѿри́нꙋлъ мѧ̀ є҆сѝ; и҆ вскꙋ́ю сѣ́тꙋѧ хождꙋ̀, внегда̀ ѡ҆скорблѧ́етъ вра́гъ; Послѝ свѣ́тъ тво́й и҆ и҆́стинꙋ твою̀: та̑ мѧ̀ наста́виста, и҆ введо́ста мѧ̀ въ го́рꙋ ст҃ꙋ́ю твою̀ и҆ въ селє́нїѧ твоѧ̑. И҆ вни́дꙋ къ же́ртвенникꙋ бж҃їю, къ бг҃ꙋ веселѧ́щемꙋ ю҆́ность мою̀: и҆сповѣ́мсѧ тебѣ̀ въ гꙋ́слехъ, бж҃е, бж҃е мо́й. Вскꙋ́ю приско́рбна є҆сѝ, дꙋшѐ моѧ̀; и҆ вскꙋ́ю смꙋща́еши мѧ̀; ᲂу҆пова́й на бг҃а, ꙗ҆́кѡ и҆сповѣ́мсѧ є҆мꙋ̀, сп҃се́нїе лица̀ моегѡ̀ и҆ бг҃ъ мо́й.",
  ["заголовок_ру"] = "Псало́м Дави́ду, не надпи́сан у евре́й.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, не надпи́санъ ᲂу҆ є҆врє́й."
}

add_psalom {
  ["номер"] = 43,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 3,
  ["текст_ру"] = "Бо́же, уши́ма на́шима услы́шахом, и отцы́ на́ши возвести́ша нам де́ло, е́же соде́лал еси́ во днех их, во днех дре́вних. Рука́ Твоя́ язы́ки потреби́, и насади́л я́ еси́, озло́бил еси́ лю́ди и изгна́л еси́ я́. Не бо мече́м свои́м насле́диша зе́млю, и мы́шца их не спа́се их, но десни́ца Твоя́, и мы́шца Твоя́, и просвеще́ние лица́ Твоего́, я́ко благоволи́л еси́ в них. Ты еси́ Сам Царь мой и Бог мой, запове́даяй спасе́ния Иа́ковля. О Тебе́ враги́ на́ша избоде́м ро́ги, и о и́мени Твое́м уничижи́м востаю́щыя на ны. Не на лук бо мой упова́ю, и мечь мой не спасе́т мене́. Спасл бо еси́ нас от стужа́ющих нам, и ненави́дящих нас посрами́л еси́. О Бо́зе похва́лимся весь день и о и́мени Твое́м испове́мыся во век. Ны́не же отри́нул еси́ и посрами́л еси́ нас, и не изы́деши, Бо́же, в си́лах на́ших. Возврати́л еси́ нас вспять при вразе́х на́ших, и ненави́дящии нас расхища́ху себе́. Дал еси́ нас я́ко о́вцы сне́ди, и во язы́цех разсе́ял ны еси́. Отда́л еси́ лю́ди Твоя́ без цены́, и не бе мно́жество в восклица́ниих на́ших. Положи́л еси́ нас поноше́ние сосе́дом на́шим, подражне́ние и поруга́ние су́щым о́крест нас. Положи́л еси́ нас в при́тчу во язы́цех, покива́нию главы́ в лю́дех. Весь день срам мой предо мно́ю есть, и студ лица́ моего́ покры́ мя от гла́са поноша́ющаго и оклевета́ющаго, от лица́ вра́жия и изгоня́щаго. Сия́ вся приидо́ша на ны, и не забы́хом Тебе́, и не непра́вдовахом в заве́те Твое́м. И не отступи́ вспять се́рдце на́ше, и уклони́л еси́ стези́ на́ша от пути́ Твоего́. Я́ко смири́л еси́ нас на ме́сте озлобле́ния, и прикры́ ны сень сме́ртная. А́ще забы́хом и́мя Бо́га на́шего и а́ще возде́хом ру́ки на́ша к бо́гу чужде́му. Не Бог ли взы́щет сих? Той бо весть та́йная се́рдца. Зане́ Тебе́ ра́ди умерщвля́емся весь день, вмени́хомся я́ко о́вцы заколе́ния. Воста́ни, вску́ю спи́ши, Го́споди? Воскресни́ и не отри́ни до конца́. Вску́ю лице́ Твое́ отвраща́еши? Забыва́еши нищету́ на́шу и скорбь на́шу? Я́ко смири́ся в персть душа́ на́ша, прильпе́ земли́ утро́ба на́ша. Воскресни́, Го́споди, помози́ нам и изба́ви нас и́мене ра́ди Твоего́.",
  ["текст_цс"] = "Бж҃е, ᲂу҆ши́ма на́шима ᲂу҆слы́шахомъ, и҆ ѻ҆тцы̀ на́ши возвѣсти́ша на́мъ дѣ́ло, є҆́же содѣ́лалъ є҆сѝ во дне́хъ и҆́хъ, во дне́хъ дре́внихъ. Рꙋка̀ твоѧ̀ ꙗ҆зы́ки потребѝ, и҆ насади́лъ ѧ҆̀ є҆сѝ: ѡ҆ѕло́билъ є҆сѝ лю́ди и҆ и҆згна́лъ є҆сѝ ѧ҆̀. Не бо мече́мъ свои́мъ наслѣ́диша зе́млю, и҆ мы́шца и҆́хъ не спасѐ и҆́хъ, но десни́ца твоѧ̀ и҆ мы́шца твоѧ̀ и҆ просвѣще́нїе лица̀ твоегѡ̀, ꙗ҆́кѡ бл҃говоли́лъ є҆сѝ въ ни́хъ. Ты̀ є҆сѝ са́мъ цр҃ь мо́й и҆ бг҃ъ мо́й, заповѣ́даѧй спасє́нїѧ і҆а̑кѡвлѧ. Ѡ҆ тебѣ̀ врагѝ на́шѧ и҆збоде́мъ ро́ги, и҆ ѡ҆ и҆́мени твое́мъ ᲂу҆ничижи́мъ востаю́щыѧ на ны̀. Не на лꙋ́къ бо мо́й ᲂу҆пова́ю, и҆ ме́чь мо́й не спасе́тъ менѐ: Сп҃слъ бо є҆сѝ на́съ ѿ стꙋжа́ющихъ на́мъ, и҆ ненави́дѧщихъ на́съ посрами́лъ є҆сѝ. Ѡ҆ бз҃ѣ похва́лимсѧ ве́сь де́нь, и҆ ѡ҆ и҆́мени твое́мъ и҆сповѣ́мысѧ во вѣ́къ. Ны́нѣ же ѿри́нꙋлъ є҆сѝ и҆ посрами́лъ є҆сѝ на́съ, и҆ не и҆зы́деши, бж҃е, въ си́лахъ на́шихъ. Возврати́лъ є҆сѝ на́съ вспѧ́ть при вразѣ́хъ на́шихъ, и҆ ненави́дѧщїи на́съ расхища́хꙋ себѣ̀. Да́лъ є҆сѝ на́съ ꙗ҆́кѡ ѻ҆́вцы снѣ́ди, и҆ во ꙗ҆зы́цѣхъ разсѣ́ѧлъ ны̀ є҆сѝ. Ѿда́лъ є҆сѝ лю́ди твоѧ̑ без̾ цѣны̀, и҆ не бѣ̀ мно́жество въ восклица́нїихъ на́шихъ. Положи́лъ є҆сѝ на́съ поноше́нїе сосѣ́дѡмъ на́шымъ, подражне́нїе и҆ порꙋга́нїе сꙋ́щымъ ѡ҆́крестъ на́съ. Положи́лъ є҆сѝ на́съ въ при́тчꙋ во ꙗ҆зы́цѣхъ, покива́нїю главы̀ въ лю́дехъ. Ве́сь де́нь сра́мъ мо́й предо мно́ю є҆́сть, и҆ стꙋ́дъ лица̀ моегѡ̀ покры́ мѧ, Ѿ гла́са поноша́ющагѡ и҆ ѡ҆клевета́ющагѡ, ѿ лица̀ вра́жїѧ и҆ и҆згонѧ́щагѡ. Сїѧ̑ всѧ̑ прїидо́ша на ны̀, и҆ не забы́хомъ тебє̀, и҆ не непра́вдовахомъ въ завѣ́тѣ твое́мъ, И҆ не ѿстꙋпѝ вспѧ́ть се́рдце на́ше: и҆ ᲂу҆клони́лъ є҆сѝ стезѝ на́шѧ ѿ пꙋтѝ твоегѡ̀, Ꙗ҆́кѡ смири́лъ є҆сѝ на́съ на мѣ́стѣ ѡ҆ѕлобле́нїѧ, и҆ прикры́ ны сѣ́нь сме́ртнаѧ. А҆́ще забы́хомъ и҆́мѧ бг҃а на́шегѡ, и҆ а҆́ще воздѣ́хомъ рꙋ́ки на́шѧ къ бо́гꙋ чꙋжде́мꙋ, Не бг҃ъ ли взы́щетъ си́хъ; то́й бо вѣ́сть та̑йнаѧ се́рдца. Занѐ тебє̀ ра́ди ᲂу҆мерщвлѧ́емсѧ ве́сь де́нь, вмѣни́хомсѧ ꙗ҆́кѡ ѻ҆́вцы заколе́нїѧ. Воста́ни, вскꙋ́ю спи́ши, гдⷭ҇и; воскрⷭ҇нѝ, и҆ не ѿри́ни до конца̀. Вскꙋ́ю лицѐ твоѐ ѿвраща́еши; забыва́еши нищетꙋ̀ на́шꙋ и҆ ско́рбь на́шꙋ; Ꙗ҆́кѡ смири́сѧ въ пе́рсть дꙋша̀ на́ша, прильпѐ землѝ ᲂу҆тро́ба на́ша. Воскрⷭ҇нѝ, гдⷭ҇и, помозѝ на́мъ, и҆ и҆зба́ви на́съ и҆́мене ра́ди твоегѡ̀.",
  ["заголовок_ру"] = "В коне́ц, сыно́в Коре́овых, в ра́зум.",
  ["заголовок_цс"] = "Въ коне́цъ, сынѡ́въ коре́овыхъ, въ ра́зꙋмъ."
}

add_psalom {
  ["номер"] = 44,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 3,
  ["текст_ру"] = "Отры́гну се́рдце мое́ сло́во бла́го, глаго́лю аз дела́ моя́ Царе́ви: язы́к мой трость кни́жника скоропи́сца. Красе́н добро́тою па́че сыно́в челове́ческих, излия́ся благода́ть во устна́х Твои́х, сего́ ра́ди благослови́ Тя Бог во век. Препоя́ши мечь Твой по бедре́ Твое́й, Си́льне. Красото́ю Твое́ю и добро́тою Твое́ю, и наляцы́, и успева́й, и ца́рствуй и́стины ра́ди и кро́тости, и пра́вды, и наста́вит Тя ди́вно десни́ца Твоя́. Стре́лы Твоя́ изощре́ны, Си́льне, лю́дие под Тобо́ю паду́т в се́рдцы враг царе́вых. Престо́л Твой, Бо́же, в век ве́ка: жезл пра́вости, жезл Ца́рствия Твоего́. Возлюби́л еси́ пра́вду и возненави́дел еси́ беззако́ние, сего́ ра́ди пома́за Тя, Бо́же, Бог Твой еле́ем ра́дости, па́че прича́стник Твои́х. Сми́рна и ста́кти и касси́а от риз Твои́х, от тя́жестей слоно́вых, из ни́хже возвесели́ша Тя. Дще́ри царе́й в че́сти Твое́й, предста́ Цари́ца одесну́ю Тебе́, в ри́зах позлаще́нных оде́яна преиспещре́на. Слы́ши, Дщи, и виждь, и приклони́ у́хо Твое́, и забу́ди лю́ди Твоя́, и дом отца́ Твоего́. И возжела́ет Царь добро́ты Твоея́: зане́ Той есть Госпо́дь Твой и поклони́шися Ему́. И дщи Ти́рова с да́ры, лицу́ Твоему́ помо́лятся бога́тии лю́дстии. Вся сла́ва Дще́ре Царе́вы внутрь, ря́сны златы́ми оде́яна и преиспещре́на. Приведу́тся Царю́ де́вы в след ея́, и́скренния ея́ приведу́тся Тебе́. Приведу́тся в весе́лии и ра́довании, введу́тся в храм Царе́в. Вме́сто оте́ц Твои́х бы́ша сы́нове Твои́: поста́виши я́ кня́зи по всей земли́. Помяну́ и́мя Твое́ во вся́ком ро́де и ро́де. Сего́ ра́ди лю́дие испове́дятся Тебе́ в век и во век ве́ка.",
  ["текст_цс"] = "Ѿры́гнꙋ се́рдце моѐ сло́во бла́го, глаго́лю а҆́зъ дѣла̀ моѧ̑ цр҃е́ви: ѧ҆зы́къ мо́й тро́сть кни́жника скоропи́сца. Красе́нъ добро́тою па́че сынѡ́въ человѣ́ческихъ, и҆злїѧ́сѧ бл҃года́ть во ᲂу҆стна́хъ твои́хъ: сегѡ̀ ра́ди бл҃гослови́ тѧ бг҃ъ во вѣ́къ. Препоѧ́ши ме́чь тво́й по бедрѣ̀ твое́й, си́льне, Красото́ю твое́ю и҆ добро́тою твое́ю: и҆ налѧцы̀, и҆ ᲂу҆спѣва́й, и҆ црⷭ҇твꙋй и҆́стины ра́ди и҆ кро́тости и҆ пра́вды: и҆ наста́витъ тѧ̀ ди́внѡ десни́ца твоѧ̀. Стрѣ́лы твоѧ̑ и҆з̾ѡщрє́ны, си́льне: лю́дїе под̾ тобо́ю падꙋ́тъ въ се́рдцы вра̑гъ цр҃е́выхъ. Прⷭ҇то́лъ тво́й, бж҃е, въ вѣ́къ вѣ́ка: же́злъ пра́вости же́злъ црⷭ҇твїѧ твоегѡ̀. Возлюби́лъ є҆сѝ пра́вдꙋ и҆ возненави́дѣлъ є҆сѝ беззако́нїе: сегѡ̀ ра́ди пома́за тѧ̀, бж҃е, бг҃ъ тво́й є҆ле́емъ ра́дости па́че прича̑стникъ твои́хъ. Смѵ́рна и҆ ста́кти и҆ касі́а ѿ ри́зъ твои́хъ, ѿ тѧ́жестей слоно́выхъ, и҆з̾ ни́хже возвесели́ша тѧ̀. Дщє́ри царе́й въ че́сти твое́й: предста̀ цари́ца ѡ҆деснꙋ́ю тебє̀, въ ри́захъ позлаще́нныхъ ѡ҆дѣ́ѧна преиспещре́на. Слы́ши, дщѝ, и҆ ви́ждь, и҆ приклонѝ ᲂу҆́хо твоѐ, и҆ забꙋ́ди лю́ди твоѧ̑ и҆ до́мъ ѻ҆тца̀ твоегѡ̀: И҆ возжела́етъ цр҃ь добро́ты твоеѧ̀, занѐ то́й є҆́сть гдⷭ҇ь тво́й, и҆ поклони́шисѧ є҆мꙋ̀, И҆ дщѝ тѵ́рова съ да́ры: лицꙋ̀ твоемꙋ̀ помо́лѧтсѧ бога́тїи лю́дстїи. Всѧ̀ сла́ва дще́ре цр҃е́вы внꙋ́трь: рѧ̑сны златы́ми ѡ҆дѣ́ѧна и҆ преиспещре́на. Приведꙋ́тсѧ цр҃ю̀ дѣ̑вы в̾слѣ́дъ є҆ѧ̀, и҆́скрєннїѧ є҆ѧ̀ приведꙋ́тсѧ тебѣ̀: Приведꙋ́тсѧ въ весе́лїи и҆ ра́дованїи, введꙋ́тсѧ въ хра́мъ цр҃е́въ. Вмѣ́стѡ ѻ҆тє́цъ твои́хъ бы́ша сы́нове твоѝ: поста́виши ѧ҆̀ кнѧ̑зи по все́й землѝ. Помѧнꙋ̀ и҆́мѧ твоѐ во всѧ́комъ ро́дѣ и҆ ро́дѣ: сегѡ̀ ра́ди лю́дїе и҆сповѣ́дѧтсѧ тебѣ̀ въ вѣ́къ и҆ во вѣ́къ вѣ́ка.",
  ["заголовок_ру"] = "В коне́ц, о изменя́емых сыно́м Коре́овым, в ра́зум, песнь о возлю́бленнем.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ и҆змѣнѧ́емыхъ сынѡ́мъ коре́ѡвымъ въ ра́зꙋмъ, пѣ́снь ѡ҆ возлю́бленнѣмъ."
}

add_psalom {
  ["номер"] = 45,
  ["часть"] = 1,
  ["кафизма"] = 6,
  ["слава"] = 3,
  ["текст_ру"] = "Бог нам прибе́жище и си́ла, помо́щник в ско́рбех, обре́тших ны зело́. Сего́ ра́ди не убои́мся, внегда́ смуща́ется земля́ и прелага́ются го́ры в сердца́ морска́я. Возшуме́ша и смято́шася во́ды их, смято́шася го́ры кре́постию Его́. Ре́чная устремле́ния веселя́т град Бо́жий: освяти́л есть селе́ние Свое́ Вы́шний. Бог посреде́ eго́, и не подви́жится: помо́жет eму́ Бог у́тро зау́тра. Смято́шася язы́цы, уклони́шася ца́рствия: даде́ глас Свой Вы́шний, подви́жеся земля́. Госпо́дь Сил с на́ми, засту́пник наш Бог Иа́ковль. Прииди́те и ви́дите дела́ Бо́жия, я́же положи́ чудеса́ на земли́: отъе́мля бра́ни до коне́ц земли́, лук сокруши́т и сло́мит ору́жие, и щиты́ сожже́т огне́м. Упраздни́теся и разуме́йте, я́ко Аз есмь Бог: вознесу́ся во язы́цех, вознесу́ся на земли́. Госпо́дь Сил с на́ми, Засту́пник наш Бог Иа́ковль.",
  ["текст_цс"] = "Бг҃ъ на́мъ прибѣ́жище и҆ си́ла, помо́щникъ въ ско́рбехъ ѡ҆брѣ́тшихъ ны̀ ѕѣлѡ̀. Сегѡ̀ ра́ди не ᲂу҆бои́мсѧ, внегда̀ смꙋща́етсѧ землѧ̀, и҆ прелага́ютсѧ го́ры въ сердца̀ морска̑ѧ. Возшꙋмѣ́ша и҆ смѧто́шасѧ во́ды и҆́хъ, смѧто́шасѧ го́ры крѣ́постїю є҆гѡ̀. Рѣ̑чнаѧ ᲂу҆стремлє́нїѧ веселѧ́тъ гра́дъ бж҃їй: ѡ҆ст҃и́лъ є҆́сть селе́нїе своѐ вы́шнїй. Бг҃ъ посредѣ̀ є҆гѡ̀, и҆ не подви́житсѧ: помо́жетъ є҆мꙋ̀ бг҃ъ ᲂу҆́трѡ заꙋ́тра. Смѧто́шасѧ ꙗ҆зы́цы, ᲂу҆клони́шасѧ ца̑рствїѧ: дадѐ гла́съ сво́й вы́шнїй, подви́жесѧ землѧ̀. Гдⷭ҇ь си́лъ съ на́ми, застꙋ́пникъ на́шъ бг҃ъ і҆а́кѡвль. Прїиди́те и҆ ви́дите дѣла̀ бж҃їѧ, ꙗ҆̀же положѝ чꙋдеса̀ на землѝ: Ѿе́млѧ бра̑ни до конє́цъ землѝ, лꙋ́къ сокрꙋши́тъ и҆ сло́митъ ѻ҆рꙋ́жїе, и҆ щиты̀ сожже́тъ ѻ҆гне́мъ. Оу҆праздни́тесѧ и҆ разꙋмѣ́йте, ꙗ҆́кѡ а҆́зъ є҆́смь бг҃ъ: вознесꙋ́сѧ во ꙗ҆зы́цѣхъ, вознесꙋ́сѧ на землѝ. Гдⷭ҇ь си́лъ съ на́ми, застꙋ́пникъ на́шъ бг҃ъ і҆а́кѡвль.",
  ["заголовок_ру"] = "В коне́ц, о сыне́х Коре́овых, о та́йных, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ сынѣ́хъ коре́овыхъ, ѡ҆ та́йныхъ, ѱало́мъ."
}

add_psalom {
  ["номер"] = 46,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 1,
  ["текст_ру"] = "В коне́ц, о сыне́х Коре́овых, псало́м. Вси язы́цы восплещи́те рука́ми, воскли́кните Бо́гу гла́сом ра́дования. Я́ко Госпо́дь Вы́шний стра́шен, Царь ве́лий по всей земли́. Покори́ лю́ди нам и язы́ки под но́ги на́ша: избра́ нам достоя́ние Свое́, добро́ту Иа́ковлю, ю́же возлюби́. Взы́де Бог в воскликнове́нии, Госпо́дь во гла́се тру́бне. По́йте Бо́гу на́шему, по́йте, по́йте Царе́ви на́шему, по́йте. Я́ко Царь всея́ земли́ Бог, по́йте разу́мно. Воцари́ся Бог над язы́ки, Бог седи́т на престо́ле святе́м Свое́м. Кня́зи лю́дстии собра́шася с Бо́гом Авраа́млим. Я́ко Бо́жии держа́внии земли́ зело́ вознесо́шася.",
  ["текст_цс"] = "Всѝ ꙗ҆зы́цы, восплещи́те рꙋка́ми, воскли́кните бг҃ꙋ гла́сомъ ра́дованїѧ: Ꙗ҆́кѡ гдⷭ҇ь вы́шнїй стра́шенъ, цр҃ь ве́лїй по все́й землѝ: Покорѝ лю́ди на́мъ и҆ ꙗ҆зы́ки под̾ но́ги на́ша: И҆збра̀ на́мъ достоѧ́нїѧ своѐ, добро́тꙋ і҆а́кѡвлю, ю҆́же возлюбѝ. Взы́де бг҃ъ въ воскликнове́нїи, гдⷭ҇ь во гла́сѣ трꙋ́бнѣ. По́йте бг҃ꙋ на́шемꙋ, по́йте: по́йте цр҃е́ви на́шемꙋ, по́йте: Ꙗ҆́кѡ цр҃ь всеѧ̀ землѝ бг҃ъ, по́йте разꙋ́мнѡ. Воцр҃и́сѧ бг҃ъ над̾ ꙗ҆зы́ки: бг҃ъ сѣди́тъ на прⷭ҇то́лѣ ст҃ѣ́мъ свое́мъ. Кнѧ̑зи лю́дстїи собра́шасѧ съ бг҃омъ а҆враа́млимъ: ꙗ҆́кѡ бж҃їи держа́внїи землѝ ѕѣлѡ̀ вознесо́шасѧ.",
  ["заголовок_ру"] = "В коне́ц, о сыне́х Коре́овых, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ сынѣ́хъ коре́овыхъ, ѱало́мъ."
}

add_psalom {
  ["номер"] = 47,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 1,
  ["текст_ру"] = "Ве́лий Госпо́дь и хва́лен зело́ во гра́де Бо́га на́шего, в горе́ святе́й Его́. Благокоре́нным ра́дованием всея́ земли́: го́ры Сио́нския, ре́бра се́верова, град Царя́ вели́каго. Бог в тя́жестех eго́ зна́емь есть, егда́ заступа́ет и́. Я́ко се ца́рие зе́мстии собра́шася, снидо́шася вку́пе. Ти́и ви́девше та́ко, удиви́шася, смято́шася, подвиго́шася. Тре́пет прия́т я́: та́мо боле́зни я́ко ражда́ющия. Ду́хом бу́рным сокруши́ши корабли́ Фарси́йския. Я́коже слы́шахом, та́ко и ви́дехом во гра́де Го́спода Сил, во гра́де Бо́га на́шего, Бог основа́ и́ в век. Прия́хом, Бо́же, ми́лость Твою́ посреде́ люде́й Твои́х. По и́мени Твоему́, Бо́же, та́ко и хвала́ Твоя́ на конца́х земли́, пра́вды испо́лнь десни́ца Твоя́. Да возвесели́тся гора́ Сио́нская и да возра́дуются дще́ри Иуде́йския суде́б ра́ди Твои́х, Го́споди. Обыди́те Сио́н и обыми́те eго́, пове́дите в столпе́х eго́. Положи́те сердца́ ва́ша в си́лу Его́ и раздели́те до́мы Его́, я́ко да пове́сте в ро́де ино́м. Я́ко Той есть Бог наш во век и в век ве́ка, Той упасе́т нас во ве́ки.",
  ["текст_цс"] = "Ве́лїй гдⷭ҇ь и҆ хва́ленъ ѕѣлѡ̀ во гра́дѣ бг҃а на́шегѡ, въ горѣ̀ ст҃ѣ́й є҆гѡ̀, Бл҃гокоре́ннымъ ра́дованїемъ всеѧ̀ землѝ: го́ры сїѡ́нскїѧ, ре́бра сѣ́верѡва, гра́дъ цр҃ѧ̀ вели́кагѡ. Бг҃ъ въ тѧ́жестѣхъ є҆гѡ̀ зна́емь є҆́сть, є҆гда̀ застꙋпа́етъ и҆̀. Ꙗ҆́кѡ сѐ, ца́рїе зе́мстїи собра́шасѧ, снидо́шасѧ вкꙋ́пѣ: Ті́и ви́дѣвше та́кѡ, ᲂу҆диви́шасѧ, смѧто́шасѧ, подвиго́шасѧ: Тре́петъ прїѧ́тъ ѧ҆̀ та́мѡ, бѡлѣ́зни ꙗ҆́кѡ ражда́ющїѧ. Дꙋ́хомъ бꙋ́рнымъ сокрꙋши́ши кораблѝ ѳарсі̑йскїѧ. Ꙗ҆́коже слы́шахомъ, та́кѡ и҆ ви́дѣхомъ во гра́дѣ гдⷭ҇а си́лъ, во гра́дѣ бг҃а на́шегѡ: бг҃ъ ѡ҆снова̀ и҆ въ вѣ́къ. Прїѧ́хомъ, бж҃е, млⷭ҇ть твою̀ посредѣ̀ люде́й твои́хъ. По и҆́мени твоемꙋ̀, бж҃е, та́кѡ и҆ хвала̀ твоѧ̀ на конца́хъ землѝ: пра́вды и҆спо́лнь десни́ца твоѧ̀. Да возвесели́тсѧ гора̀ сїѡ́нскаѧ, и҆ да возра́дꙋютсѧ дщє́ри і҆ꙋдє́йскїѧ, сꙋде́бъ ра́ди твои́хъ, гдⷭ҇и. Ѡ҆быди́те сїѡ́нъ и҆ ѡ҆быми́те є҆го̀, повѣ́дите въ столпѣ́хъ є҆гѡ̀: Положи́те сердца̀ ва̑ша въ си́лꙋ є҆гѡ̀, и҆ раздѣли́те до́мы є҆гѡ̀, ꙗ҆́кѡ да повѣ́сте въ ро́дѣ и҆нѣ́мъ. Ꙗ҆́кѡ то́й є҆́сть бг҃ъ на́шъ во вѣ́къ и҆ въ вѣ́къ вѣ́ка: то́й ᲂу҆пасе́тъ на́съ во вѣ́ки.",
  ["заголовок_ру"] = "Псало́м, пе́сни сыно́в Коре́овых, вторы́я суббо́ты.",
  ["заголовок_цс"] = "Ѱало́мъ пѣ́сни сынѡ́въ коре́овыхъ, вторы́ѧ сꙋббѡ́ты."
}

add_psalom {
  ["номер"] = 48,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 1,
  ["текст_ру"] = "Услы́шите сия́ вси язы́цы, внуши́те вси живу́щии по вселе́нней: земноро́днии же и сы́нове челове́честии, вку́пе бога́т и убо́г. Уста́ моя́ возглаго́лют прему́дрость, и поуче́ние се́рдца моего́ ра́зум. Приклоню́ в при́тчу у́хо мое́, отве́рзу во псалти́ри гана́ние мое́. Вску́ю бою́ся, в день лют? Беззако́ние пяты́ моея́ обы́дет мя. Наде́ющиися на си́лу свою́ и о мно́жестве бога́тства своего́ хва́лящиися, брат не изба́вит, изба́вит ли челове́к? Не даст Бо́гу изме́ны за ся, и це́ну избавле́ния души́ своея́, и утруди́ся в век. И жив бу́дет до конца́, не у́зрит па́губы. Егда́ уви́дит прему́дрыя умира́ющыя, вку́пе безу́мен и несмы́слен поги́бнут и оста́вят чужди́м бога́тство свое́. И гро́би их жили́ща их во век, селе́ния их в род и род, нареко́ша имена́ своя́ на земля́х. И челове́к в че́сти сый не разуме́, приложи́ся ското́м несмы́сленным и уподо́бися им. Сей путь их собла́зн им, и по сих во усте́х своих благоволя́т. Я́ко о́вцы во а́де положе́ни суть, смерть упасе́т я́, и облада́ют и́ми пра́вии зау́тра, и по́мощь их обетша́ет во а́де, от сла́вы своея́ изринове́ни бы́ша. Оба́че Бог изба́вит ду́шу мою́ из руки́ а́довы, егда́ прие́млет мя. Не убо́йся, егда́ разбогате́ет челове́к или́ егда́ умно́жится сла́ва до́му eго́: я́ко внегда́ умре́ти eму́, не во́змет вся, ниже́ сни́дет с ним сла́ва eго́. Я́ко душа́ eго́ в животе́ eго́ благослови́тся: испове́стся Тебе́, егда́ благосотвори́ши eму́. Вни́дет да́же до ро́да оте́ц свои́х, да́же до ве́ка не у́зрит све́та. И челове́к в че́сти сый не разуме́, приложи́ся ското́м несмы́сленным и уподо́бися им.",
  ["текст_цс"] = "Оу҆слы́шите сїѧ̑, всѝ ꙗ҆зы́цы, внꙋши́те, всѝ живꙋ́щїи по вселе́ннѣй, Земноро́днїи же и҆ сы́нове человѣ́честїи, вкꙋ́пѣ бога́тъ и҆ ᲂу҆бо́гъ. Оу҆ста̀ моѧ̑ возглаго́лютъ премꙋ́дрость, и҆ поꙋче́нїе се́рдца моегѡ̀ ра́зꙋмъ. Приклоню̀ въ при́тчꙋ ᲂу҆́хо моѐ, ѿве́рзꙋ во ѱалти́ри гана́нїе моѐ. Вскꙋ́ю бою́сѧ въ де́нь лю́тъ; беззако́нїе пѧты̀ моеѧ̀ ѡ҆бы́детъ мѧ̀. Надѣ́ющїисѧ на си́лꙋ свою̀ и҆ ѡ҆ мно́жествѣ бога́тства своегѡ̀ хва́лѧщїисѧ: Бра́тъ не и҆зба́витъ, и҆зба́витъ ли человѣ́къ; не да́стъ бг҃ꙋ и҆змѣ́ны за сѧ̀, И҆ цѣ́нꙋ и҆збавле́нїѧ дꙋшѝ своеѧ̀: и҆ ᲂу҆трꙋди́сѧ въ вѣ́къ, И҆ жи́въ бꙋ́детъ до конца̀, не ᲂу҆́зритъ па́гꙋбы. Є҆гда̀ ᲂу҆ви́дитъ премꙋ̑дрыѧ ᲂу҆мира́ющыѧ, вкꙋ́пѣ безꙋ́менъ и҆ несмы́сленъ поги́бнꙋтъ, и҆ ѡ҆ста́вѧтъ чꙋжди̑мъ бога́тство своѐ. И҆ гро́би и҆́хъ жили̑ща и҆́хъ во вѣ́къ, селє́нїѧ и҆́хъ въ ро́дъ и҆ ро́дъ, нареко́ша и҆мена̀ своѧ̑ на землѧ́хъ. И҆ человѣ́къ въ че́сти сы́й не разꙋмѣ̀, приложи́сѧ скотѡ́мъ несмы́слєннымъ и҆ ᲂу҆подо́бисѧ и҆̀мъ. Се́й пꙋ́ть и҆́хъ собла́знъ и҆̀мъ, и҆ по си́хъ во ᲂу҆стѣ́хъ свои́хъ бл҃говолѧ́тъ. Ꙗ҆́кѡ ѻ҆́вцы во а҆́дѣ положе́ни сꙋ́ть, сме́рть ᲂу҆пасе́тъ ѧ҆̀: и҆ ѡ҆блада́ютъ и҆́ми пра́вїи заꙋ́тра, и҆ по́мощь и҆́хъ ѡ҆бетша́етъ во а҆́дѣ: ѿ сла́вы своеѧ̀ и҆зринове́ни бы́ша. Ѻ҆ба́че бг҃ъ и҆зба́витъ дꙋ́шꙋ мою̀ и҆з̾ рꙋкѝ а҆́довы, є҆гда̀ прїе́млетъ мѧ̀. Не ᲂу҆бо́йсѧ, є҆гда̀ разбогатѣ́етъ человѣ́къ, и҆лѝ є҆гда̀ ᲂу҆мно́житсѧ сла́ва до́мꙋ є҆гѡ̀: Ꙗ҆́кѡ внегда̀ ᲂу҆мре́ти є҆мꙋ̀, не во́зметъ всѧ̑, нижѐ сни́детъ съ ни́мъ сла́ва є҆гѡ̀. Ꙗ҆́кѡ дꙋша̀ є҆гѡ̀ въ животѣ̀ є҆гѡ̀ бл҃гослови́тсѧ, и҆сповѣ́стсѧ тебѣ̀, є҆гда̀ бл҃госотвори́ши є҆мꙋ̀. Вни́детъ да́же до ро́да ѻ҆тє́цъ свои́хъ, да́же до вѣ́ка не ᲂу҆́зритъ свѣ́та. И҆ человѣ́къ въ че́сти сы́й не разꙋмѣ̀, приложи́сѧ скотѡ́мъ несмы́слєннымъ и҆ ᲂу҆подо́бисѧ и҆̀мъ.",
  ["заголовок_ру"] = "В коне́ц, сыно́м Коре́овым, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, сынѡ́мъ коре́ѡвымъ, ѱало́мъ."
}

add_psalom {
