  ["кафизма"] = 7,
  ["слава"] = 2,
  ["текст_ру"] = "Бог бого́в Госпо́дь глаго́ла и призва́ зе́млю от восто́к со́лнца до за́пад. От Сио́на благоле́пие красоты́ Его́. Бог я́ве прии́дет, Бог наш, и не премолчи́т: огнь пред Ним возгори́тся, и о́крест Его́ бу́ря зе́льна. Призове́т Не́бо свы́ше и зе́млю разсуди́ти лю́ди Своя́. Собери́те Ему́ преподо́бныя Его́, завеща́ющыя заве́т Его́ о же́ртвах. И возвестя́т небеса́ пра́вду Его́, я́ко Бог судия́ есть. Услы́шите, лю́дие мои́, и возглаго́лю вам, Изра́илю, и засвиде́тельствую тебе́: Бог, Бог твой есмь Аз. Не о же́ртвах твои́х обличу́ тя, всесожже́ния же твоя́ предо Мно́ю суть вы́ну. Не прииму́ от до́му Твоего́ тельцо́в, ниже́ от стад твои́х козло́в. Я́ко мои́ суть вси зве́рие дубра́внии, ско́ти в гора́х и воло́ве. Позна́х вся пти́цы небе́сныя, и красота́ се́льная со Мно́ю есть. А́ще вза́лчу, не реку́ тебе́: Моя́ бо есть вселе́нная и исполне́ние ея́. Еда́ ям мяса́ ю́нча или́ кровь козло́в пию́? Пожри́ Бо́гови же́ртву хвалы́ и возда́ждь Вы́шнему моли́твы Твоя́. И призови́ Мя в день ско́рби твоея́, и изму́ тя, и просла́виши Мя. Гре́шнику же рече́ Бог: вску́ю ты пове́даеши оправда́ния Моя́ и восприе́млеши заве́т Мой усты́ твои́ми? Ты же возненави́дел еси́ наказа́ние и отве́ргл еси́ словеса́ Моя́ вспять. А́ще ви́дел еси́ та́тя, текл еси́ с ним, и с прелюбоде́ем уча́стие твое́ полага́л еси́. Уста́ Твоя́ умно́жиша зло́бу, и язы́к твой сплета́ше льще́ния. Седя́, на бра́та твоего́ клевета́л еси́ и на сы́на ма́тере твоея́ полага́л еси́ собла́зн. Сия́ сотвори́л еси́ и умолча́х, вознепщева́л еси́ беззако́ние, я́ко бу́ду тебе́ подо́бен. Обличу́ тя и предста́влю пред лице́м твои́м грехи́ Твоя́. Разуме́йте у́бо сия́, забыва́ющии Бо́га, да не когда́ похи́тит, и не бу́дет избавля́яй. Же́ртва хвалы́ просла́вит Мя, и та́мо путь, и́мже явлю́ eму́ спасе́ние Мое́.",
  ["текст_цс"] = "Бг҃ъ богѡ́въ гдⷭ҇ь глаго́ла, и҆ призва̀ зе́млю ѿ востѡ́къ со́лнца до за̑падъ. Ѿ сїѡ́на бл҃голѣ́пїе красоты̀ є҆гѡ̀: Бг҃ъ ꙗ҆́вѣ прїи́детъ, бг҃ъ на́шъ, и҆ не премолчи́тъ: ѻ҆́гнь пред̾ ни́мъ возгори́тсѧ, и҆ ѡ҆́крестъ є҆гѡ̀ бꙋ́рѧ ѕѣ́лна. Призове́тъ не́бо свы́ше, и҆ зе́млю, разсꙋди́ти лю́ди своѧ̑. Собери́те є҆мꙋ̀ прпⷣбныѧ є҆гѡ̀, завѣща́ющыѧ завѣ́тъ є҆гѡ̀ ѡ҆ же́ртвахъ. И҆ возвѣстѧ́тъ нб҃са̀ пра́вдꙋ є҆гѡ̀: ꙗ҆́кѡ бг҃ъ сꙋдїѧ̀ є҆́сть. Оу҆слы́шите, лю́дїе моѝ, и҆ возглаго́лю ва́мъ, і҆и҃лю, и҆ засвидѣ́тельствꙋю тебѣ̀: бг҃ъ, бг҃ъ тво́й є҆́смь а҆́зъ. Не ѡ҆ же́ртвахъ твои́хъ ѡ҆бличꙋ̀ тѧ̀, всесожжє́нїѧ же твоѧ̑ предо мно́ю сꙋ́ть вы́нꙋ: Не прїимꙋ̀ ѿ до́мꙋ твоегѡ̀ тельцѡ́въ, нижѐ ѿ ста́дъ твои́хъ козлѡ́въ. Ꙗ҆́кѡ моѝ сꙋ́ть всѝ ѕвѣ́рїе дꙋбра́внїи, ско́ти въ гора́хъ и҆ воло́ве: Позна́хъ всѧ̑ пти̑цы небє́сныѧ, и҆ красота̀ се́льнаѧ со мно́ю є҆́сть. А҆́ще вза́лчꙋ, не рекꙋ̀ тебѣ̀: моѧ́ бо є҆́сть вселе́ннаѧ и҆ и҆сполне́нїе є҆ѧ̀. Є҆да̀ ꙗ҆́мъ мѧса̀ ю҆́нча; и҆лѝ кро́вь козлѡ́въ пїю̀; Пожрѝ бг҃ови же́ртвꙋ хвалы̀ и҆ возда́ждь вы́шнемꙋ моли̑твы твоѧ̑: И҆ призови́ мѧ въ де́нь ско́рби твоеѧ̀, и҆ и҆змꙋ́ тѧ, и҆ просла́виши мѧ̀. Грѣ́шникꙋ же речѐ бг҃ъ: вскꙋ́ю ты̀ повѣ́даеши ѡ҆правда̑нїѧ моѧ̑ и҆ воспрїе́млеши завѣ́тъ мо́й ᲂу҆сты̀ твои́ми; Ты́ же возненави́дѣлъ є҆сѝ наказа́нїе и҆ ѿве́рглъ є҆сѝ словеса̀ моѧ̑ вспѧ́ть. А҆́ще ви́дѣлъ є҆сѝ та́тѧ, те́клъ є҆сѝ съ ни́мъ, и҆ съ прелюбодѣ́емъ ᲂу҆ча́стїе твоѐ полага́лъ є҆сѝ: Оу҆ста̀ твоѧ̑ ᲂу҆мно́жиша ѕло́бꙋ, и҆ ѧ҆зы́къ тво́й сплета́ше льщє́нїѧ: Сѣдѧ̀ на бра́та твоего̀ клевета́лъ є҆сѝ и҆ на сы́на ма́тере твоеѧ̀ полага́лъ є҆сѝ собла́знъ. Сїѧ̑ сотвори́лъ є҆сѝ, и҆ ᲂу҆молча́хъ, вознепщева́лъ є҆сѝ беззако́нїе, ꙗ҆́кѡ бꙋ́дꙋ тебѣ̀ подо́бенъ: ѡ҆бличꙋ́ тѧ и҆ предста́влю пред̾ лице́мъ твои́мъ грѣхѝ твоѧ̑. Разꙋмѣ́йте ᲂу҆́бѡ сїѧ̑, забыва́ющїи бг҃а, да не когда̀ похи́титъ, и҆ не бꙋ́детъ и҆збавлѧ́ѧй. Же́ртва хвалы̀ просла́витъ мѧ̀, и҆ та́мѡ пꙋ́ть, и҆́мже ꙗ҆влю̀ є҆мꙋ̀ сп҃се́нїе моѐ.",
  ["заголовок_ру"] = "Псало́м Аса́фу.",
  ["заголовок_цс"] = "Ѱало́мъ а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 50,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 2,
  ["текст_ру"] = "Поми́луй мя, Бо́же, по вели́цей ми́лости Твое́й, и по мно́жеству щедро́т Твои́х очи́сти беззако́ние мое́. Наипа́че омы́й мя от беззако́ния моего́, и от греха́ моего́ очи́сти мя. Я́ко беззако́ние мое́ аз зна́ю и грех мой предо мно́ю есть вы́ну. Тебе́ Еди́ному согреши́х, и лука́вое пред Тобо́ю сотвори́х, я́ко да оправди́шися во словесе́х Твои́х и победи́ши, внегда́ суди́ти Ти. Се бо в беззако́ниих зача́т есмь, и во гресе́х роди́ мя ма́ти моя́. Се бо и́стину возлюби́л еси́, безве́стная и та́йная прему́дрости Твоея́ яви́л ми еси́. Окропи́ши мя иссо́пом, и очи́щуся, омы́еши мя, и па́че сне́га убелю́ся. Слу́ху моему́ да́си ра́дость и весе́лие, возра́дуются ко́сти смире́нныя. Отврати́ лице́ Твое́ от грех мои́х, и вся беззако́ния моя́ очи́сти. Се́рдце чи́сто сози́жди во мне, Бо́же, и дух прав обнови́ во утро́бе мое́й. Не отве́ржи мене́ от лица́ Твоего́, и Ду́ха Твоего́ Свята́го не отыми́ от мене́. Возда́ждь ми ра́дость спасе́ния Твоего́, и Ду́хом Влады́чним утверди́ мя. Научу́ беззако́нныя путе́м Твои́м, и нечести́вии к Тебе́ обратя́тся. Изба́ви мя от крове́й, Бо́же, Бо́же спасе́ния моего́, возра́дуется язы́к мой пра́вде Твое́й. Го́споди, устне́ мои́ отве́рзеши, и уста́ моя́ возвестя́т хвалу́ Твою́. Я́ко а́ще бы восхоте́л еси́ же́ртвы, дал бых у́бо, всесожже́ния не благоволи́ши. Же́ртва Бо́гу дух сокруше́н, се́рдце сокруше́нно и смире́нно Бог не уничижи́т. Ублажи́, Го́споди, благоволе́нием Твои́м Сио́на, и да сози́ждутся сте́ны Иерусали́мския. тогда́ благоволи́ши же́ртву пра́вды, возноше́ние и всесожега́емая: тогда́ возложа́т на олта́рь Твой тельцы́.",
  ["текст_цс"] = "Поми́лꙋй мѧ̀, бж҃е, по вели́цѣй млⷭ҇ти твое́й, и҆ по мно́жествꙋ щедро́тъ твои́хъ ѡ҆чи́сти беззако́нїе моѐ. Наипа́че ѡ҆мы́й мѧ̀ ѿ беззако́нїѧ моегѡ̀ и҆ ѿ грѣха̀ моегѡ̀ ѡ҆чи́сти мѧ̀: Ꙗ҆́кѡ беззако́нїе моѐ а҆́зъ зна́ю, и҆ грѣ́хъ мо́й предо мно́ю є҆́сть вы́нꙋ. Тебѣ̀ є҆ди́номꙋ согрѣши́хъ и҆ лꙋка́вое пред̾ тобо́ю сотвори́хъ: ꙗ҆́кѡ да ѡ҆правди́шисѧ во словесѣ́хъ твои́хъ и҆ побѣди́ши, внегда̀ сꙋди́ти тѝ. Се́ бо, въ беззако́нїихъ зача́тъ є҆́смь, и҆ во грѣсѣ́хъ роди́ мѧ ма́ти моѧ̀. Се́ бо, и҆́стинꙋ возлюби́лъ є҆сѝ, безвѣ̑стнаѧ и҆ та̑йнаѧ премⷣрости твоеѧ̀ ꙗ҆ви́лъ мѝ є҆сѝ. Ѡ҆кропи́ши мѧ̀ ѵ҆ссѡ́помъ, и҆ ѡ҆чи́щꙋсѧ: ѡ҆мы́еши мѧ̀, и҆ па́че снѣ́га ᲂу҆бѣлю́сѧ. Слꙋ́хꙋ моемꙋ̀ да́си ра́дость и҆ весе́лїе: возра́дꙋютсѧ кѡ́сти смирє́нныѧ. Ѿвратѝ лицѐ твоѐ ѿ грѣ̑хъ мои́хъ и҆ всѧ̑ беззакѡ́нїѧ моѧ̑ ѡ҆чи́сти. Се́рдце чи́сто сози́жди во мнѣ̀, бж҃е, и҆ дꙋ́хъ пра́въ ѡ҆бновѝ во ᲂу҆тро́бѣ мое́й. Не ѿве́ржи менѐ ѿ лица̀ твоегѡ̀ и҆ дх҃а твоегѡ̀ ст҃а́гѡ не ѿимѝ ѿ менѐ. Возда́ждь мѝ ра́дость сп҃се́нїѧ твоегѡ̀ и҆ дх҃омъ влⷣчнимъ ᲂу҆тверди́ мѧ. Наꙋчꙋ̀ беззакѡ́нныѧ пꙋтє́мъ твои̑мъ, и҆ нечести́вїи къ тебѣ̀ ѡ҆братѧ́тсѧ. И҆зба́ви мѧ̀ ѿ крове́й, бж҃е, бж҃е сп҃се́нїѧ моегѡ̀: возра́дꙋетсѧ ѧ҆зы́къ мо́й пра́вдѣ твое́й. Гдⷭ҇и, ᲂу҆стнѣ̀ моѝ ѿве́рзеши, и҆ ᲂу҆ста̀ моѧ̑ возвѣстѧ́тъ хвалꙋ̀ твою̀. Ꙗ҆́кѡ а҆́ще бы восхотѣ́лъ є҆сѝ же́ртвы, да́лъ бы́хъ ᲂу҆́бѡ: всесожжє́нїѧ не бл҃говоли́ши. Же́ртва бг҃ꙋ дꙋ́хъ сокрꙋше́нъ: се́рдце сокрꙋше́нно и҆ смире́нно бг҃ъ не ᲂу҆ничижи́тъ. Оу҆бл҃жѝ, гдⷭ҇и, бл҃говоле́нїемъ твои́мъ сїѡ́на, и҆ да сози́ждꙋтсѧ стѣ́ны і҆ерⷭ҇ли̑мскїѧ: Тогда̀ бл҃говоли́ши же́ртвꙋ пра́вды, возноше́нїе и҆ всесожега́ємаѧ: тогда̀ возложа́тъ на ѻ҆лта́рь тво́й тельцы̀.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду, внегда́ вни́ти к нему́ Нафа́ну проро́ку, егда́ вни́де к Вирсави́и, жене́ Ури́еве.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ, внегда̀ вни́ти къ немꙋ̀ наѳа́нꙋ прⷪ҇ро́кꙋ, Є҆гда̀ вни́де къ вирсаві́и женѣ̀ ᲂу҆рі́евѣ."
}

add_psalom {
  ["номер"] = 51,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 3,
  ["текст_ру"] = "Что хва́лишися во зло́бе, си́льне? Беззако́ние весь день. Непра́вду умы́сли язы́к твой, я́ко бри́тву изощре́ну сотвори́л еси́ лесть. Возлюби́л еси́ зло́бу па́че благосты́ни, непра́вду не́же глаго́лати пра́вду. Возлюби́л еси́ вся глаго́лы пото́пныя, язы́к льстив. Сего́ ра́ди Бог разруши́т тя до конца́, восто́ргнет тя, и пресели́т тя от селе́ния твоего́ и ко́рень твой от земли́ живы́х. У́зрят пра́веднии и убоя́тся, и о нем возсмею́тся и реку́т: се челове́к, и́же не положи́ Бо́га помо́щника себе́, но упова́ на мно́жество бога́тства своего́, и возмо́же суе́тою свое́ю. Аз же я́ко ма́слина плодови́та в дому́ Бо́жии, упова́х на ми́лость Бо́жию во век и в век ве́ка. Испове́мся Тебе́ во век, я́ко сотвори́л еси́, и терплю́ и́мя Твое́, я́ко бла́го пред преподо́бными Твои́ми.",
  ["текст_цс"] = "Что̀ хва́лишисѧ во ѕло́бѣ, си́льне; беззако́нїе ве́сь де́нь, Непра́вдꙋ ᲂу҆мы́сли ѧ҆зы́къ тво́й: ꙗ҆́кѡ бри́твꙋ и҆з̾ѡщре́нꙋ сотвори́лъ є҆сѝ ле́сть. Возлюби́лъ є҆сѝ ѕло́бꙋ па́че бл҃госты́ни, непра́вдꙋ не́же глаго́лати пра́вдꙋ: Возлюби́лъ є҆сѝ всѧ̑ глаго́лы потѡ́пныѧ, ѧ҆зы́къ льсти́въ. Сегѡ̀ ра́ди бг҃ъ разрꙋши́тъ тѧ̀ до конца̀: восто́ргнетъ тѧ̀, и҆ пресели́тъ тѧ̀ ѿ селе́нїѧ твоегѡ̀ и҆ ко́рень тво́й ѿ землѝ живы́хъ. Оу҆́зрѧтъ првⷣнїи и҆ ᲂу҆боѧ́тсѧ, и҆ ѡ҆ не́мъ возсмѣю́тсѧ и҆ рекꙋ́тъ: Сѐ, человѣ́къ, и҆́же не положѝ бг҃а помо́щника себѣ̀, но ᲂу҆пова̀ на мно́жество бога́тства своегѡ̀, и҆ возмо́же сꙋето́ю свое́ю. А҆́зъ же ꙗ҆́кѡ ма́слина плодови́та въ домꙋ̀ бж҃їи: ᲂу҆пова́хъ на млⷭ҇ть бж҃їю во вѣ́къ и҆ въ вѣ́къ вѣ́ка. И҆сповѣ́мсѧ тебѣ̀ въ вѣ́къ, ꙗ҆́кѡ сотвори́лъ є҆сѝ: и҆ терплю̀ и҆́мѧ твоѐ, ꙗ҆́кѡ бл҃го пред̾ прпⷣбными твои́ми.",
  ["заголовок_ру"] = "В коне́ц, ра́зума Дави́ду, внегда́ приити́ Дои́ку Идуме́йску, и возвести́ти Сау́лу, и рещи́ ему́: прии́де Дави́д в дом Авимеле́хов.",
  ["заголовок_цс"] = "Въ коне́цъ, ра́зꙋма дв҃дꙋ, Внегда̀ прїитѝ дѡи́кꙋ і҆дꙋме́йскꙋ, и҆ возвѣсти́ти саꙋ́лꙋ, и҆ рещѝ є҆мꙋ̀: прїи́де дв҃дъ въ до́мъ а҆вїмеле́ховъ."
}

add_psalom {
  ["номер"] = 52,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 3,
  ["текст_ру"] = "Рече́ безу́мен в се́рдце свое́м: несть Бог, растле́ша и омерзи́шася в беззако́ниих, несть творя́й благо́е. Бог с небесе́ прини́че на сы́ны челове́ческия, ви́дети, а́ще есть разумева́яй или́ взыска́яй Бо́га? Вси уклони́шася, вку́пе непотре́бни бы́ша, несть творя́й благо́е, несть до еди́наго. Ни ли уразуме́ют вси де́лающии беззако́ние, снеда́ющии лю́ди моя́ в снедь хле́ба, Го́спода не призва́ша. Та́мо устраши́шася стра́ха, иде́же не бе страх, я́ко Бог разсы́па ко́сти человекоуго́дников: постыде́шася, я́ко Бог уничижи́ их. Кто даст от Сио́на спасе́ние Изра́илево? Внегда́ возврати́т Бог плене́ние люде́й Свои́х, возра́дуется Иа́ков и возвесели́тся Изра́иль.",
  ["текст_цс"] = "Речѐ безꙋ́менъ въ се́рдцы свое́мъ: нѣ́сть бг҃ъ. Растлѣ́ша и҆ ѡ҆мерзи́шасѧ въ беззако́нїихъ, нѣ́сть творѧ́й бл҃го́е. Бг҃ъ съ нб҃сѐ прини́че на сы́ны человѣ́чєскїѧ, ви́дѣти, а҆́ще є҆́сть разꙋмѣва́ѧй и҆лѝ взыска́ѧй бг҃а. Всѝ ᲂу҆клони́шасѧ, вкꙋ́пѣ непотре́бни бы́ша: нѣ́сть творѧ́й бл҃го́е, нѣ́сть до є҆ди́нагѡ. Ни лѝ ᲂу҆разꙋмѣ́ютъ всѝ дѣ́лающїи беззако́нїе, снѣда́ющїи лю́ди моѧ̑ въ снѣ́дь хлѣ́ба; гдⷭ҇а не призва́ша. Та́мѡ ᲂу҆страши́шасѧ стра́ха, и҆дѣ́же не бѣ̀ стра́хъ: ꙗ҆́кѡ бг҃ъ разсы́па кѡ́сти человѣкоꙋго́дникѡвъ: постыдѣ́шасѧ, ꙗ҆́кѡ бг҃ъ ᲂу҆ничижѝ и҆̀хъ. Кто̀ да́стъ ѿ сїѡ́на сп҃се́нїе і҆и҃лево; внегда̀ возврати́тъ бг҃ъ плѣне́нїе люде́й свои́хъ, возра́дꙋетсѧ і҆а́кѡвъ и҆ возвесели́тсѧ і҆и҃ль.",
  ["заголовок_ру"] = "В коне́ц, о маеле́фе, ра́зума Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ маеле́ѳѣ, ра́зꙋма дв҃дꙋ."
}

add_psalom {
  ["номер"] = 53,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 3,
  ["текст_ру"] = "Бо́же, во и́мя Твое́ спаси́ мя, и в си́ле Твое́й суди́ ми. Бо́же, услы́ши моли́тву мою́, внуши́ глаго́лы уст мои́х. Я́ко чу́ждии воста́ша на мя и кре́пцыи взыска́ша ду́шу мою́, и не предложи́ша Бо́га пред собо́ю. Се бо Бог помога́ет ми, и Госпо́дь засту́пник души́ мое́й. Отврати́т зла́я враго́м мои́м, и́стиною Твое́ю потреби́ их. Во́лею пожру́ Тебе́, испове́мся и́мени Твоему́, Го́споди, я́ко бла́го, я́ко от вся́кия печа́ли изба́вил мя еси́, и на враги́ моя́ воззре́ о́ко мое́.",
  ["текст_цс"] = "Бж҃е, во и҆́мѧ твоѐ сп҃си́ мѧ и҆ въ си́лѣ твое́й сꙋди́ ми. Бж҃е, ᲂу҆слы́ши моли́твꙋ мою̀, внꙋшѝ глаго́лы ᲂу҆́стъ мои́хъ: Ꙗ҆́кѡ чꙋ́ждїи воста́ша на мѧ̀, и҆ крѣ́пцыи взыска́ша дꙋ́шꙋ мою̀, и҆ не предложи́ша бг҃а пред̾ собо́ю. Се́ бо, бг҃ъ помога́етъ мѝ, и҆ гдⷭ҇ь застꙋ́пникъ дꙋшѝ мое́й: Ѿврати́тъ ѕла̑ѧ врагѡ́мъ мои̑мъ: и҆́стиною твое́ю потребѝ и҆̀хъ. Во́лею пожрꙋ̀ тебѣ̀, и҆сповѣ́мсѧ и҆́мени твоемꙋ̀, гдⷭ҇и, ꙗ҆́кѡ бл҃го: Ꙗ҆́кѡ ѿ всѧ́кїѧ печа́ли и҆зба́вилъ мѧ̀ є҆сѝ, и҆ на врагѝ моѧ̑ воззрѣ̀ ѻ҆́ко моѐ.",
  ["заголовок_ру"] = "В коне́ц, в пе́снех ра́зума Дави́ду, внегда́ приити́ Зифе́ем, и рещи́ Сау́лови: не се́ ли Дави́д скры́ся в нас.",
  ["заголовок_цс"] = "Въ коне́цъ, въ пѣ́снехъ ра́зꙋма дв҃дꙋ, Внегда̀ прїитѝ зїфе́ємъ и҆ рещѝ саꙋ́лови: не се́ ли, дв҃дъ скры́сѧ въ на́съ."
}

add_psalom {
  ["номер"] = 54,
  ["часть"] = 1,
  ["кафизма"] = 7,
  ["слава"] = 3,
  ["текст_ру"] = "Внуши́, Бо́же, моли́тву мою́ и не пре́зри моле́ния моего́. Вонми́ ми и услы́ши мя: возскорбе́х печа́лию мое́ю и смято́хся. От гла́са вра́жия и от стуже́ния гре́шнича, я́ко уклони́ша на мя беззако́ние и во гне́ве враждова́ху ми. Се́рдце мое́ смяте́ся во мне и боя́знь сме́рти нападе́ на мя. Страх и тре́пет прии́де на мя и покры́ мя тьма. И рех: кто даст ми криле́, я́ко голуби́не? И полещу́, и почи́ю? Се удали́хся бе́гая и водвори́хся в пусты́ни. Ча́ях Бо́га, спаса́ющаго мя от малоду́шия и от бу́ри. Потопи́, Го́споди, и раздели́ язы́ки их: я́ко ви́дех беззако́ние и пререка́ние во гра́де. Днем и но́щию обы́дет и́ по стена́м eго́. Беззако́ние и труд посреде́ eго́ и непра́вда. И не оскуде́ от стогн eго́ ли́хва и лесть. Я́ко а́ще бы враг поноси́л ми, претерпе́л бых у́бо, и а́ще бы ненави́дяй мя на мя́ велере́чевал, укры́л бых ся от него́. Ты же, челове́че равноду́шне, влады́ко мой и зна́емый мой, и́же ку́пно наслажда́лся еси́ со мно́ю бра́шен, в дому́ Бо́жии ходи́хом единомышле́нием. Да прии́дет же смерть на ня, и да сни́дут во ад жи́ви, я́ко лука́вство в жили́щах их, посреде́ их. Аз к Бо́гу воззва́х, и Госпо́дь услы́ша мя. Ве́чер и зау́тра, и полу́дне пове́м, и возвещу́, и услы́шит глас мой. Изба́вит ми́ром ду́шу мою́ от приближа́ющихся мне, я́ко во мно́зе бя́ху со мно́ю. Услы́шит Бог и смири́т я́, Сый пре́жде век. Несть бо им измене́ния, я́ко не убоя́шася Бо́га. Простре́ ру́ку свою́ на воздая́ние, оскверни́ша заве́т Его́. Раздели́шася от гне́ва лица́ Его́, и прибли́жишася сердца́ их, умя́кнуша словеса́ их па́че еле́а, и та суть стре́лы. Возве́рзи на Го́спода печа́ль твою́, и Той тя препита́ет, не даст в век молвы́ пра́веднику. Ты же, Бо́же, низведе́ши их во студене́ц истле́ния, му́жие крове́й и льсти не преполовя́т дней свои́х. Аз же, Го́споди, упова́ю на Тя.",
  ["текст_цс"] = "Внꙋшѝ, бж҃е, моли́твꙋ мою̀ и҆ не пре́зри моле́нїѧ моегѡ̀: Вонми́ ми и҆ ᲂу҆слы́ши мѧ̀: возскорбѣ́хъ печа́лїю мое́ю, и҆ смѧто́хсѧ Ѿ гла́са вра́жїѧ и҆ ѿ стꙋже́нїѧ грѣ́шнича: ꙗ҆́кѡ ᲂу҆клони́ша на мѧ̀ беззако́нїе и҆ во гнѣ́вѣ враждова́хꙋ мѝ. Се́рдце моѐ смѧте́сѧ во мнѣ̀, и҆ боѧ́знь сме́рти нападѐ на мѧ̀: Стра́хъ и҆ тре́петъ прїи́де на мѧ̀, и҆ покры́ мѧ тма̀. И҆ рѣ́хъ: кто̀ да́стъ мѝ крилѣ̑ ꙗ҆́кѡ голꙋби̑нѣ; и҆ полещꙋ̀, и҆ почі́ю. Сѐ, ᲂу҆дали́хсѧ бѣ́гаѧ и҆ водвори́хсѧ въ пꙋсты́ни. Ча́ѧхъ бг҃а сп҃са́ющагѡ мѧ̀ ѿ малодꙋ́шїѧ и҆ ѿ бꙋ́ри. Потопѝ, гдⷭ҇и, и҆ раздѣлѝ ѧ҆зы́ки и҆́хъ: ꙗ҆́кѡ ви́дѣхъ беззако́нїе и҆ прерѣка́нїе во гра́дѣ. Дне́мъ и҆ но́щїю ѡ҆бы́детъ и҆̀ по стѣна́мъ є҆гѡ̀: беззако́нїе и҆ трꙋ́дъ посредѣ̀ є҆гѡ̀, и҆ непра́вда: И҆ не ѡ҆скꙋдѣ̀ ѿ сто́гнъ є҆гѡ̀ ли́хва и҆ ле́сть. Ꙗ҆́кѡ а҆́ще бы вра́гъ поноси́лъ мѝ, претерпѣ́лъ бы́хъ ᲂу҆́бѡ: и҆ а҆́ще бы ненави́дѧй мѧ̀ на мѧ̀ велерѣ́чевалъ, ᲂу҆кры́лъ бы́хъ сѧ ѿ негѡ̀. Ты́ же, человѣ́че равнодꙋ́шне, влады́ко мо́й и҆ зна́емый мо́й, И҆́же кꙋ́пнѡ наслажда́лсѧ є҆сѝ со мно́ю бра́шенъ: въ домꙋ̀ бж҃їи ходи́хомъ є҆диномышле́нїемъ. Да прїи́детъ же сме́рть на нѧ̀, и҆ да сни́дꙋтъ во а҆́дъ жи́ви: ꙗ҆́кѡ лꙋка́вство въ жили́щахъ и҆́хъ, посредѣ̀ и҆́хъ. А҆́зъ къ бг҃ꙋ воззва́хъ, и҆ гдⷭ҇ь ᲂу҆слы́ша мѧ̀. Ве́черъ и҆ заꙋ́тра и҆ полꙋ́дне повѣ́мъ и҆ возвѣщꙋ̀, и҆ ᲂу҆слы́шитъ гла́съ мо́й. И҆зба́витъ ми́ромъ дꙋ́шꙋ мою̀ ѿ приближа́ющихсѧ мнѣ̀: ꙗ҆́кѡ во мно́зѣ бѧ́хꙋ со мно́ю. Оу҆слы́шитъ бг҃ъ, и҆ смири́тъ ѧ҆̀ сы́й пре́жде вѣ̑къ: нѣ́сть бо и҆̀мъ и҆змѣне́нїѧ, ꙗ҆́кѡ не ᲂу҆боѧ́шасѧ бг҃а. Прострѐ рꙋ́кꙋ свою̀ на воздаѧ́нїе: ѡ҆скверни́ша завѣ́тъ є҆гѡ̀. Раздѣли́шасѧ ѿ гнѣ́ва лица̀ є҆гѡ̀, и҆ прибли́жишасѧ сердца̀ и҆́хъ: ᲂу҆мѧ́кнꙋша словеса̀ и҆́хъ па́че є҆ле́а, и҆ та̑ сꙋ́ть стрѣ́лы. Возве́рзи на гдⷭ҇а печа́ль твою̀, и҆ то́й тѧ̀ препита́етъ: не да́стъ въ вѣ́къ молвы̀ првⷣникꙋ. Ты́ же, бж҃е, низведе́ши и҆̀хъ въ стꙋдене́цъ и҆стлѣ́нїѧ: мꙋ́жїе крове́й и҆ льстѝ не преполовѧ́тъ дні́й свои́хъ. А҆́зъ же, гдⷭ҇и, ᲂу҆пова́ю на тѧ̀.",
  ["заголовок_ру"] = "В коне́ц, в пе́снех ра́зума Аса́фу, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, въ пѣ́снехъ ра́зꙋма, а҆са́фꙋ, ѱало́мъ."
}

add_psalom {
  ["номер"] = 55,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 1,
  ["текст_ру"] = "Поми́луй мя, Бо́же, я́ко попра́ мя челове́к, весь день боря́ стужи́ ми. Попра́ша мя врази́ мои́ весь день, я́ко мно́зи борю́щии мя с высоты́. В день не убою́ся, аз же упова́ю на Тя. О Бо́зе похвалю́ словеса́ моя́, на Бо́га упова́х, не убою́ся, что сотвори́т мне плоть? Весь день слове́с мои́х гнуша́хуся, на мя вся помышле́ния их на зло. Вселя́тся и скры́ют, ти́и пя́ту мою́ сохраня́т, я́коже потерпе́ша ду́шу мою́. Ни о чесо́мже отри́неши я́, гне́вом лю́ди низведе́ши. Бо́же, живо́т мой возвести́х Тебе́, положи́л еси́ сле́зы моя́ пред Тобо́ю, я́ко и во обетова́нии Твое́м. Да возвратя́тся врази́ мои́ вспять, во́ньже а́ще день призову́ Тя, се позна́х, я́ко Бог мой еси́ Ты. О Бо́зе похвалю́ глаго́л, о Го́споде похвалю́ сло́во. На Бо́га упова́х, не убою́ся, что сотвори́т мне челове́к? Во мне, Бо́же, моли́твы, я́же возда́м хвалы́ Твоея́, я́ко изба́вил еси́ ду́шу мою́ от сме́рти, о́чи мои́ от слез, и но́зе мои́ от поползнове́ния, благоугожду́ пред Го́сподем во све́те живы́х.",
  ["текст_цс"] = "Поми́лꙋй мѧ̀, бж҃е, ꙗ҆́кѡ попра́ мѧ человѣ́къ: ве́сь де́нь борѧ̀ стꙋжи́ ми. Попра́ша мѧ̀ вразѝ моѝ ве́сь де́нь: ꙗ҆́кѡ мно́зи борю́щїи мѧ̀ съ высоты̀. Въ де́нь не ᲂу҆бою́сѧ, а҆́зъ же ᲂу҆пова́ю на тѧ̀. Ѡ҆ бз҃ѣ похвалю̀ словеса̀ моѧ̑: на бг҃а ᲂу҆пова́хъ, не ᲂу҆бою́сѧ: что̀ сотвори́тъ мнѣ̀ пло́ть; Ве́сь де́нь слове́съ мои́хъ гнꙋша́хꙋсѧ: на мѧ̀ всѧ̑ помышлє́нїѧ и҆́хъ на ѕло̀. Вселѧ́тсѧ и҆ скры́ютъ, ті́и пѧ́тꙋ мою̀ сохранѧ́тъ, ꙗ҆́коже потерпѣ́ша дꙋ́шꙋ мою̀. Ни ѡ҆ чесо́мъ же ѿри́неши ѧ҆̀, гнѣ́вомъ лю́ди низведе́ши. Бж҃е, живо́тъ мо́й возвѣсти́хъ тебѣ̀: положи́лъ є҆сѝ сле́зы моѧ̑ пред̾ тобо́ю, ꙗ҆́кѡ и҆ во ѡ҆бѣтова́нїи твое́мъ. Да возвратѧ́тсѧ вразѝ моѝ вспѧ́ть, во́ньже а҆́ще де́нь призовꙋ́ тѧ: сѐ, позна́хъ, ꙗ҆́кѡ бг҃ъ мо́й є҆сѝ ты̀. Ѡ҆ бз҃ѣ похвалю̀ глаго́лъ, ѡ҆ гдⷭ҇ѣ похвалю̀ сло́во. На бг҃а ᲂу҆пова́хъ, не ᲂу҆бою́сѧ: что̀ сотвори́тъ мнѣ̀ человѣ́къ; Во мнѣ̀, бж҃е, моли́твы, ꙗ҆̀же возда́мъ хвалы̀ твоеѧ̀: Ꙗ҆́кѡ и҆зба́вилъ є҆сѝ дꙋ́шꙋ мою̀ ѿ сме́рти, ѻ҆́чи моѝ ѿ сле́зъ и҆ но́зѣ моѝ ѿ поползнове́нїѧ: бл҃гоꙋгождꙋ̀ пред̾ гдⷭ҇емъ во свѣ́тѣ живы́хъ.",
  ["заголовок_ру"] = "В коне́ц, о лю́дех, от святы́х удале́нных, Дави́ду в столпописа́ние, внегда́ удержа́ша и́ иноплеме́нницы в Ге́фе, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ лю́дехъ ѿ ст҃ы́хъ ᲂу҆дале́нныхъ, дв҃дꙋ въ столпописа́нїе, внегда̀ ᲂу҆держа́ша и҆̀ и҆ноплемє́нницы въ ге́ѳѣ, ѱало́мъ."
}

add_psalom {
  ["номер"] = 56,
