  ["слава"] = 1,
  ["текст_ру"] = "Поми́луй мя, Бо́же, поми́луй мя, я́ко на Тя упова́ душа́ моя́, и на сень крилу́ Твое́ю наде́юся, до́ндеже пре́йдет беззако́ние. Воззову́ к Бо́гу Вы́шнему, Бо́гу, благоде́явшему мне. Посла́ с небесе́ и спасе́ мя, даде́ в поноше́ние попира́ющыя мя, посла́ Бог ми́лость Свою́ и и́стину Свою́, и изба́ви ду́шу мою́ от среды́ ски́мнов. Поспа́х смуще́н, сы́нове челове́честии, зу́бы их ору́жия и стре́лы, и язы́к их меч остр. Вознеси́ся на небеса́, Бо́же, и по всей земли́ сла́ва Твоя́. Сеть угото́ваша нога́м мои́м и сляко́ша ду́шу мою́, ископа́ша пред лице́м мои́м я́му и впадо́ша в ню. Гото́во се́рдце мое́, Бо́же, гото́во се́рдце мое́, воспою́ и пою́ во сла́ве мое́й. Воста́ни сла́ва моя́, воста́ни псалти́рю и гу́сли, воста́ну ра́но. Испове́мся Тебе́ в лю́дех, Го́споди, воспою́ Тебе́ во язы́цех, я́ко возвели́чися до небе́с ми́лость Твоя́, и да́же до о́блак и́стина Твоя́. Вознеси́ся на небеса́, Бо́же, и по всей земли́ сла́ва Твоя́.",
  ["текст_цс"] = "Поми́лꙋй мѧ̀, бж҃е, поми́лꙋй мѧ̀: ꙗ҆́кѡ на тѧ̀ ᲂу҆пова̀ дꙋша̀ моѧ̀, и҆ на сѣ́нь крилꙋ̑ твоє́ю надѣ́юсѧ, до́ндеже пре́йдетъ беззако́нїе. Воззовꙋ̀ къ бг҃ꙋ вы́шнемꙋ, бг҃ꙋ бл҃годѣ́ѧвшемꙋ мнѣ̀. Посла̀ съ нб҃сѐ и҆ сп҃се́ мѧ, дадѐ въ поноше́нїе попира́ющыѧ мѧ̀: посла̀ бг҃ъ млⷭ҇ть свою̀ и҆ и҆́стинꙋ свою̀, И҆ и҆зба́ви дꙋ́шꙋ мою̀ ѿ среды̀ скѵ́мнѡвъ. Поспа́хъ смꙋще́нъ: сы́нове человѣ́честїи, зꙋ́бы и҆́хъ ѻ҆рꙋ̑жїѧ и҆ стрѣ́лы, и҆ ѧ҆зы́къ и҆́хъ ме́чь ѻ҆́стръ. Вознеси́сѧ на нб҃са̀, бж҃е, и҆ по все́й землѝ сла́ва твоѧ̀. Сѣ́ть ᲂу҆гото́ваша нога́мъ мои̑мъ, и҆ слѧко́ша дꙋ́шꙋ мою̀: и҆скопа́ша пред̾ лице́мъ мои́мъ ꙗ҆́мꙋ, и҆ впадо́ша въ ню̀. Гото́во се́рдце моѐ, бж҃е, гото́во се́рдце моѐ: воспою̀ и҆ пою̀ во сла́вѣ мое́й. Воста́ни, сла́ва моѧ̀, воста́ни, ѱалти́рю и҆ гꙋ́сли: воста́нꙋ ра́нѡ. И҆сповѣ́мсѧ тебѣ̀ въ лю́дехъ, гдⷭ҇и, воспою̀ тебѣ̀ во ꙗ҆зы́цѣхъ: Ꙗ҆́кѡ возвели́чисѧ до нб҃съ млⷭ҇ть твоѧ̀ и҆ да́же до ѻ҆́блакъ и҆́стина твоѧ̀. Вознеси́сѧ на нб҃са̀, бж҃е, и҆ по все́й землѝ сла́ва твоѧ̀.",
  ["заголовок_ру"] = "В коне́ц, да не растли́ши, Дави́ду в столпописа́ние, внегда́ ему́ отбега́ти от лица́ Сау́лова в пеще́ру.",
  ["заголовок_цс"] = "Въ коне́цъ, да не растли́ши, дв҃дꙋ въ столпописа́нїе, внегда̀ є҆мꙋ̀ ѿбѣга́ти ѿ лица̀ саꙋ́лова въ пеще́рꙋ."
}

add_psalom {
  ["номер"] = 57,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 1,
  ["текст_ру"] = "А́ще вои́стинну у́бо пра́вду глаго́лете, пра́вая суди́те, сы́нове челове́честии. И́бо в се́рдце беззако́ние де́лаете, на земли́ непра́вду ру́ки ва́ша сплета́ют. Очужди́шася гре́шницы от ложе́сн, заблуди́ша от чре́ва, глаго́лаша лжу. Я́рость их по подо́бию змиину́, я́ко а́спида глу́ха и затыка́ющаго у́ши свои́, и́же не услы́шит гла́са обава́ющих, обава́емь обава́ется от прему́дра. Бог сокруши́т зу́бы их во усте́х их, члено́вныя львов сокруши́л есть Госпо́дь. Уничижа́тся я́ко вода́ мимотеку́щая, напряже́т лук свой, до́ндеже изнемо́гут. Я́ко воск раста́яв отъи́мутся, паде́ огнь на них и не ви́деша со́лнца. Пре́жде е́же разуме́ти те́рния ва́шего ра́мна, я́ко жи́вы, я́ко во гне́ве пожре́т я́. Возвесели́тся пра́ведник, егда́ уви́дит отмще́ние, ру́це свои́ умы́ет в кро́ви гре́шника. И рече́т челове́к: а́ще у́бо есть плод пра́веднику, у́бо есть Бог судя́ им на земли́.",
  ["текст_цс"] = "А҆́ще вои́стиннꙋ ᲂу҆́бѡ пра́вдꙋ глаго́лете, пра̑ваѧ сꙋди́те, сы́нове человѣ́честїи. И҆́бо въ се́рдцы беззако́нїе дѣ́лаете на землѝ, непра́вдꙋ рꙋ́ки ва́шѧ сплета́ютъ. Ѡ҆чꙋжди́шасѧ грѣ̑шницы ѿ ложе́снъ, заблꙋди́ша ѿ чре́ва, глаго́лаша лжꙋ̀. Ꙗ҆́рость и҆́хъ по подо́бїю ѕмїинꙋ̀, ꙗ҆́кѡ а҆́спїда глꙋ́ха и҆ затыка́ющагѡ ᲂу҆́ши своѝ, И҆́же не ᲂу҆слы́шитъ гла́са ѡ҆бава́ющихъ, ѡ҆бава́емь ѡ҆бава́етсѧ ѿ премꙋ́дра. Бг҃ъ сокрꙋши́тъ зꙋ́бы и҆́хъ во ᲂу҆стѣ́хъ и҆́хъ: членѡ́вныѧ львѡ́въ сокрꙋши́лъ є҆́сть гдⷭ҇ь. Оу҆ничижа́тсѧ ꙗ҆́кѡ вода̀ мимотекꙋ́щаѧ: напрѧже́тъ лꙋ́къ сво́й, до́ндеже и҆знемо́гꙋтъ. Ꙗ҆́кѡ во́скъ раста́ѧвъ ѿи́мꙋтсѧ: падѐ ѻ҆́гнь на ни́хъ, и҆ не ви́дѣша со́лнца. Пре́жде є҆́же разꙋмѣ́ти тє́рнїѧ ва́шегѡ ра́мна, ꙗ҆́кѡ жи̑вы, ꙗ҆́кѡ во гнѣ́вѣ пожре́тъ ѧ҆̀. Возвесели́тсѧ првⷣникъ, є҆гда̀ ᲂу҆ви́дитъ ѿмще́нїе: рꙋ́цѣ своѝ ᲂу҆мы́етъ въ кро́ви грѣ́шника. И҆ рече́тъ человѣ́къ: а҆́ще ᲂу҆́бѡ є҆́сть пло́дъ првⷣникꙋ, ᲂу҆̀бо є҆́сть бг҃ъ сꙋдѧ̀ и҆̀мъ на землѝ.",
  ["заголовок_ру"] = "В коне́ц, да не растли́ши, Дави́ду в столпописа́ние.",
  ["заголовок_цс"] = "Въ коне́цъ, да не растли́ши, дв҃дꙋ въ столпописа́нїе."
}

add_psalom {
  ["номер"] = 58,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 2,
  ["текст_ру"] = "Изми́ мя от враг мои́х, Бо́же, и от востаю́щих на мя изба́ви мя. Изба́ви мя от де́лающих беззако́ние и от муж крове́й спаси́ мя. Я́ко се улови́ша ду́шу мою́, нападо́ша на мя кре́пцыи, ниже́ беззако́ние мое́, ниже́ грех мой, Го́споди. Без беззако́ния теко́х и испра́вих, воста́ни в сре́тение мое́ и виждь. И ты, Го́споди Бо́же Сил, Бо́же Изра́илев, вонми́ посети́ти вся язы́ки, да не уще́дриши вся де́лающыя беззако́ние. Возвратя́тся на ве́чер и вза́лчут, я́ко пес, и обы́дут град. Се ти́и отвеща́ют усты́ свои́ми, и меч во устна́х их, я́ко кто слы́ша? И Ты, Го́споди, посмее́шися им, уничижи́ши вся язы́ки. Держа́ву мою́ к Тебе́ сохраню́, я́ко Ты, Бо́же, Засту́пник мой еси́. Бог мой, ми́лость Его́ предвари́т мя, Бог мой, яви́т мне на вразе́х мои́х. Не уби́й их, да не когда́ забу́дут зако́н Твой, расточи́ я́ си́лою Твое́ю и низведи́ я́, защи́тниче мой, Го́споди. Грех уст их, сло́во усте́н их, и я́ти да бу́дут в горды́ни свое́й, и от кля́твы и лжи возвестя́тся в кончи́не. Во гне́ве кончи́ны, и не бу́дут, и уве́дят, я́ко Бог влады́чествует Иа́ковом и концы́ земли́. Возвратя́тся на ве́чер, и вза́лчут, я́ко пес, и обы́дут град. Ти́и разы́дутся я́сти. А́ще ли же не насы́тятся, и поро́пщут. Аз же воспою́ си́лу Твою́ и возра́дуюся зау́тра о ми́лости Твое́й, я́ко был еси́ засту́пник мой и прибе́жище мое́ в день ско́рби моея́. Помо́щник мой еси́, Тебе́ пою́: я́ко Бог Засту́пник мой еси́, Бо́же мой, ми́лость моя́.",
  ["текст_цс"] = "И҆зми́ мѧ ѿ вра̑гъ мои́хъ, бж҃е, и҆ ѿ востаю́щихъ на мѧ̀ и҆зба́ви мѧ̀: И҆зба́ви мѧ̀ ѿ дѣ́лающихъ беззако́нїе, и҆ ѿ мꙋ̑жъ крове́й сп҃си́ мѧ. Ꙗ҆́кѡ сѐ, ᲂу҆лови́ша дꙋ́шꙋ мою̀, нападо́ша на мѧ̀ крѣ́пцыи: нижѐ беззако́нїе моѐ, нижѐ грѣ́хъ мо́й, гдⷭ҇и: Без̾ беззако́нїѧ теко́хъ и҆ и҆спра́вихъ: воста́ни въ срѣ́тенїе моѐ и҆ ви́ждь. И҆ ты̀, гдⷭ҇и бж҃е си́лъ, бж҃е і҆и҃левъ, вонмѝ посѣти́ти всѧ̑ ꙗ҆зы́ки: да не ᲂу҆ще́дриши всѧ̑ дѣ́лающыѧ беззако́нїе. Возвратѧ́тсѧ на ве́черъ, и҆ вза́лчꙋтъ ꙗ҆́кѡ пе́съ, и҆ ѡ҆бы́дꙋтъ гра́дъ. Сѐ, ті́и ѿвѣща́ютъ ᲂу҆сты̑ свои́ми, и҆ ме́чь во ᲂу҆стна́хъ и҆́хъ: ꙗ҆́кѡ кто̀ слы́ша; И҆ ты̀, гдⷭ҇и, посмѣе́шисѧ и҆̀мъ, ᲂу҆ничижи́ши всѧ̑ ꙗ҆зы́ки. Держа́вꙋ мою̀ къ тебѣ̀ сохраню̀: ꙗ҆́кѡ ты̀, бж҃е, застꙋ́пникъ мо́й є҆сѝ. Бг҃ъ мо́й, млⷭ҇ть є҆гѡ̀ предвари́тъ мѧ̀: бг҃ъ мо́й, ꙗ҆ви́тъ мнѣ̀ на вразѣ́хъ мои́хъ. Не ᲂу҆бі́й и҆̀хъ, да не когда̀ забꙋ́дꙋтъ зако́нъ тво́й: расточѝ ѧ҆̀ си́лою твое́ю и҆ низведѝ ѧ҆̀, защи́тниче мо́й, гдⷭ҇и, Грѣ́хъ ᲂу҆́стъ и҆́хъ, сло́во ᲂу҆сте́нъ и҆́хъ: и҆ ꙗ҆́ти да бꙋ́дꙋтъ въ горды́ни свое́й, и҆ ѿ клѧ́твы и҆ лжѝ возвѣстѧ́тсѧ въ кончи́нѣ, Во гнѣ́вѣ кончи́ны, и҆ не бꙋ́дꙋтъ: и҆ ᲂу҆вѣ́дѧтъ, ꙗ҆́кѡ бг҃ъ влⷣчествꙋетъ і҆а́кѡвомъ и҆ концы̀ землѝ. Возвратѧ́тсѧ на ве́черъ, и҆ вза́лчꙋтъ ꙗ҆́кѡ пе́съ, и҆ ѡ҆бы́дꙋтъ гра́дъ: Ті́и разы́дꙋтсѧ ꙗ҆́сти: а҆́ще ли же не насы́тѧтсѧ, и҆ поро́пщꙋтъ. А҆́зъ же воспою̀ си́лꙋ твою̀ и҆ возра́дꙋюсѧ заꙋ́тра ѡ҆ млⷭ҇ти твое́й: ꙗ҆́кѡ бы́лъ є҆сѝ застꙋ́пникъ мо́й и҆ прибѣ́жище моѐ въ де́нь ско́рби моеѧ̀. Помо́щникъ мо́й є҆сѝ, тебѣ̀ пою̀: ꙗ҆́кѡ бг҃ъ застꙋ́пникъ мо́й є҆сѝ, бж҃е мо́й, млⷭ҇ть моѧ̀.",
  ["заголовок_ру"] = "В коне́ц, да не растли́ши, Дави́ду в столпописа́ние, внегда́ посла́ Сау́л, и стреже́ дом его́, е́же умертви́ти его́.",
  ["заголовок_цс"] = "Въ коне́цъ, да не растли́ши, дв҃дꙋ въ столпописа́нїе, внегда̀ посла̀ саꙋ́лъ и҆ стрежѐ до́мъ є҆гѡ̀, є҆́же ᲂу҆мертви́ти є҆го̀."
}

add_psalom {
  ["номер"] = 59,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 2,
  ["текст_ру"] = "Бо́же, отри́нул ны еси́ и низложи́л еси́ нас, разгне́вался еси́, и уще́дрил еси́ нас. Стрясл еси́ зе́млю и смути́л еси́ ю́, исцели́ сокруше́ние ея́, я́ко подви́жеся. Показа́л еси́ лю́дем Твои́м жесто́кая, напои́л еси́ нас вино́м умиле́ния. Дал еси́ боя́щымся Тебе́ зна́мение, е́же убежа́ти от лица́ лу́ка. Я́ко да изба́вятся возлю́бленнии Твои́, спаси́ десни́цею Твое́ю и услы́ши мя. Бог возглаго́ла во святе́м Свое́м: возра́дуюся и разделю́ Сики́му, и юдо́ль жили́щ разме́рю. Мой есть Галаа́д, и Мой есть Манасси́й, и Ефре́м – кре́пость главы́ Моея́, Иу́да – царь Мой. Моа́в – коно́б упова́ния Моего́, на Идуме́ю простру́ сапо́г Мой, Мне иноплеме́нницы покори́шася. Кто введе́т мя во град огражде́ния? или́ кто наста́вит мя до Идуме́и? Не Ты ли, Бо́же, отри́нувый нас? И не изы́деши, Бо́же, в си́лах на́ших? Даждь нам по́мощь от ско́рби, и су́етно спасе́ние челове́ческо. О Бо́зе сотвори́м си́лу, и Той уничижи́т стужа́ющыя нам.",
  ["текст_цс"] = "Бж҃е, ѿри́нꙋлъ ны̀ є҆сѝ и҆ низложи́лъ є҆сѝ на́съ, разгнѣ́валсѧ є҆сѝ и҆ ᲂу҆ще́дрилъ є҆сѝ на́съ. Стрѧ́слъ є҆сѝ зе́млю и҆ смꙋти́лъ є҆сѝ ю҆̀: и҆сцѣлѝ сокрꙋше́нїе є҆ѧ̀, ꙗ҆́кѡ подви́жесѧ. Показа́лъ є҆сѝ лю́демъ твои̑мъ жестѡ́каѧ: напои́лъ є҆сѝ на́съ вїно́мъ ᲂу҆миле́нїѧ. Да́лъ є҆сѝ боѧ́щымсѧ тебє̀ зна́менїе, є҆́же ᲂу҆бѣжа́ти ѿ лица̀ лꙋ́ка. Ꙗ҆́кѡ да и҆зба́вѧтсѧ возлю́бленнїи твоѝ, сп҃сѝ десни́цею твое́ю и҆ ᲂу҆слы́ши мѧ̀. Бг҃ъ возглаго́ла во ст҃ѣ́мъ свое́мъ: возра́дꙋюсѧ, и҆ раздѣлю̀ сїки́мꙋ, и҆ ю҆до́ль жили́щъ размѣ́рю. Мо́й є҆́сть галаа́дъ, и҆ мо́й є҆́сть манассі́й, є҆фре́мъ крѣ́пость главы̀ моеѧ̀, і҆ꙋ́да ца́рь мо́й. Мѡа́въ коно́бъ ᲂу҆пова́нїѧ моегѡ̀: на і҆дꙋме́ю прострꙋ̀ сапо́гъ мо́й: мнѣ̀ и҆ноплемє́нницы покори́шасѧ. Кто̀ введе́тъ мѧ̀ во гра́дъ ѡ҆гражде́нїѧ; и҆лѝ кто̀ наста́витъ мѧ̀ до і҆дꙋме́и; Не ты́ ли, бж҃е, ѿри́нꙋвый на́съ; и҆ не и҆зы́деши, бж҃е, въ си́лахъ на́шихъ; Да́ждь на́мъ по́мощь ѿ ско́рби: и҆ сꙋ́етно спасе́нїе человѣ́ческо. Ѡ҆ бз҃ѣ сотвори́мъ си́лꙋ: и҆ то́й ᲂу҆ничижи́тъ стꙋжа́ющыѧ на́мъ.",
  ["заголовок_ру"] = "В коне́ц, о измени́тися хотя́щих, в столпописа́ние Дави́ду, в науче́ние: внегда́ сожже́ Средоре́чие Сири́йское, и Си́рию Сова́льскую, и возврати́ся Иоа́в, и порази́ Едо́ма в де́бри Соле́й двана́десять ты́сящ.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ и҆змѣни́тисѧ хотѧ́щихъ, въ столпописа́нїе дв҃дꙋ, въ наꙋче́нїе: Внегда̀ сожжѐ средорѣ́чїе сѷрі́йское и҆ сѷрі́ю сова́лскꙋю, и҆ возврати́сѧ і҆ѡа́въ и҆ поразѝ є҆дѡ́ма въ де́бри соле́й двана́десѧть ты́сѧщъ."
}

add_psalom {
  ["номер"] = 60,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 2,
  ["текст_ру"] = "Услы́ши, Бо́же, моле́ние мое́, вонми́ моли́тве мое́й. От коне́ц земли́ к Тебе́ воззва́х, внегда́ уны́ се́рдце мое́, на ка́мень возне́сл мя еси́, наста́вил мя еси́. Я́ко был еси́ упова́ние мое́, столп кре́пости от лица́ вра́жия. Вселю́ся в селе́нии Твое́м во ве́ки, покры́юся в кро́ве крил Твои́х. Я́ко Ты, Бо́же, услы́шал еси́ моли́твы моя́, дал еси́ достоя́ние боя́щымся и́мене Твоего́. Дни на дни царе́вы приложи́ши, ле́та eго́ до дне ро́да и ро́да. Пребу́дет в век пред Бо́гом, ми́лость и и́стину Его́ кто взы́щет? Та́ко воспою́ и́мени Твоему́ во ве́ки, возда́ти ми моли́твы моя́ день от дне.",
  ["текст_цс"] = "Оу҆слы́ши, бж҃е, моле́нїе моѐ, вонмѝ моли́твѣ мое́й: Ѿ конє́цъ землѝ къ тебѣ̀ воззва́хъ, внегда̀ ᲂу҆ны̀ се́рдце моѐ: на ка́мень возне́слъ мѧ̀ є҆сѝ, наста́вилъ мѧ̀ є҆сѝ, Ꙗ҆́кѡ бы́лъ є҆сѝ ᲂу҆пова́нїе моѐ, сто́лпъ крѣ́пости ѿ лица̀ вра́жїѧ. Вселю́сѧ въ селе́нїи твое́мъ во вѣ́ки, покры́юсѧ въ кро́вѣ кри́лъ твои́хъ. Ꙗ҆́кѡ ты̀, бж҃е, ᲂу҆слы́шалъ є҆сѝ моли̑твы моѧ̑, да́лъ є҆сѝ достоѧ́нїе боѧ́щымсѧ и҆́мене твоегѡ̀. Дни̑ на дни̑ царє́вы приложи́ши, лѣ̑та є҆гѡ̀ до днѐ ро́да и҆ ро́да. Пребꙋ́детъ въ вѣ́къ пред̾ бг҃омъ: млⷭ҇ть и҆ и҆́стинꙋ є҆гѡ̀ кто̀ взы́щетъ; Та́кѡ воспою̀ и҆́мени твоемꙋ̀ во вѣ́ки, возда́ти мѝ моли̑твы моѧ̑ де́нь ѿ днѐ.",
  ["заголовок_ру"] = "В коне́ц, в пе́снех, Дави́ду, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, въ пѣ́снехъ, дв҃дꙋ ѱало́мъ."
}

add_psalom {
  ["номер"] = 61,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 3,
  ["текст_ру"] = "Не Бо́гу ли повине́тся душа́ моя́? От Того́ бо спасе́ние мое́. И́бо Той Бог мой и Спас мой, Засту́пник мой, не подви́жуся наипа́че. Доко́ле належите́ на челове́ка? Убива́ете вси вы, я́ко стене́ преклоне́не, и опло́ту возринове́ну. Оба́че це́ну мою́ совеща́ша отри́нути, теко́ша в жа́жди, усты́ свои́ми благословля́ху и се́рдцем свои́м кленя́ху. Оба́че Бо́гови повини́ся, душе́ моя́, я́ко от Того́ терпе́ние мое́. И́бо Той Бог мой и Спас мой, Засту́пник мой, не преселю́ся. О Бо́зе спасе́ние мое́ и сла́ва моя́, Бог по́мощи моея́, и упова́ние мое́ на Бо́га. Упова́йте на Него́ весь сонм люде́й, излия́йте пред Ним сердца́ ва́ша, я́ко Бог помо́щник наш. Оба́че су́етни сы́нове челове́честии, лжи́ви сы́нове челове́честии в ме́рилех е́же непра́вдовати, ти́и от суеты́ вку́пе. Не упова́йте на непра́вду и на восхище́ние не жела́йте. Бога́тство а́ще тече́т, не прилага́йте се́рдца. Еди́ною глаго́ла Бог, дво́я сия́ слы́шах, зане́ держа́ва Бо́жия, и Твоя́, Го́споди, ми́лость, я́ко Ты возда́си кому́ждо по дело́м eго́.",
  ["текст_цс"] = "Не бг҃ꙋ ли повине́тсѧ дꙋша̀ моѧ̀; ѿ тогѡ́ бо сп҃се́нїе моѐ. И҆́бо то́й бг҃ъ мо́й и҆ сп҃съ мо́й, застꙋ́пникъ мо́й: не подви́жꙋсѧ наипа́че. Доко́лѣ належитѐ на человѣ́ка; ᲂу҆бива́ете всѝ вы̀, ꙗ҆́кѡ стѣнѣ̀ преклоне́нѣ и҆ ѡ҆пло́тꙋ возринове́нꙋ. Ѻ҆ба́че цѣ́нꙋ мою̀ совѣща́ша ѿри́нꙋти, теко́ша въ жа́жди: ᲂу҆сты̑ свои́ми бл҃гословлѧ́хꙋ, и҆ се́рдцемъ свои́мъ кленѧ́хꙋ. Ѻ҆ба́че бг҃ови повини́сѧ, дꙋшѐ моѧ̀: ꙗ҆́кѡ ѿ тогѡ̀ терпѣ́нїе моѐ. И҆́бо то́й бг҃ъ мо́й и҆ сп҃съ мо́й, застꙋ́пникъ мо́й: не преселю́сѧ. Ѡ҆ бз҃ѣ сп҃се́нїе моѐ и҆ сла́ва моѧ̀: бг҃ъ по́мощи моеѧ̀, и҆ ᲂу҆пова́нїе моѐ на бг҃а. Оу҆пова́йте на него̀, ве́сь со́нмъ люде́й: и҆злїѧ́йте пред̾ ни́мъ сердца̀ ва̑ша, ꙗ҆́кѡ бг҃ъ помо́щникъ на́шъ. Ѻ҆ба́че сꙋ́етни сы́нове человѣ́честїи, лжи́ви сы́нове человѣ́честїи въ мѣ́рилѣхъ є҆́же непра́вдовати: ті́и ѿ сꙋеты̀ вкꙋ́пѣ. Не ᲂу҆пова́йте на непра́вдꙋ, и҆ на восхище́нїе не жела́йте: бога́тство а҆́ще тече́тъ, не прилага́йте се́рдца. Є҆ди́ною глаго́ла бг҃ъ, дво́ѧ сїѧ̑ слы́шахъ, занѐ держа́ва бж҃їѧ, И҆ твоѧ̀, гдⷭ҇и, млⷭ҇ть: ꙗ҆́кѡ ты̀ возда́си комꙋ́ждо по дѣлѡ́мъ є҆гѡ̀.",
  ["заголовок_ру"] = "В коне́ц, о Идифу́ме, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ і҆дїѳꙋ́мѣ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 62,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 3,
  ["текст_ру"] = "Бо́же, Бо́же мой, к Тебе́ у́тренюю, возжада́ Тебе́ душа́ моя́, коль мно́жицею Тебе́ плоть моя́, в земли́ пу́сте и непрохо́дне, и безво́дне. Та́ко во святе́м яви́хся Тебе́, ви́дети си́лу Твою́ и сла́ву Твою́. Я́ко лу́чши ми́лость Твоя́ па́че живо́т, устне́ мои́ похвали́те Тя. Та́ко благословлю́ Тя в животе́ мое́м, о и́мени Твое́м воздежу́ ру́це мои́. Я́ко от ту́ка и ма́сти да испо́лнится душа́ моя́, и устна́ма ра́дости восхва́лят Тя уста́ моя́. А́ще помина́х Тя на посте́ли мое́й, на у́тренних поуча́хся в Тя. Я́ко был еси́ помо́щник мой, и в кро́ве крилу́ Твое́ю возра́дуюся. Прильпе́ душа́ моя́ по Тебе́, мене́ же прия́т десни́ца Твоя́. Ти́и же всу́е иска́ша ду́шу мою́, вни́дут в преиспо́дняя земли́, предадя́тся в ру́ки ору́жия, ча́сти ли́совом бу́дут. Царь же возвесели́тся о Бо́зе, похва́лится всяк клены́йся Им, я́ко загради́шася уста́ глаго́лющих непра́ведная.",
  ["текст_цс"] = "Бж҃е, бж҃е мо́й, къ тебѣ̀ ᲂу҆́тренюю: возжада̀ тебѐ дꙋша̀ моѧ̀, ко́ль мно́жицею тебѣ̀ пло́ть моѧ̀, въ землѝ пꙋ́стѣ и҆ непрохо́днѣ и҆ безво́днѣ. Та́кѡ во ст҃ѣ́мъ ꙗ҆ви́хсѧ тебѣ̀, ви́дѣти си́лꙋ твою̀ и҆ сла́вꙋ твою̀. Ꙗ҆́кѡ лꙋ́чши млⷭ҇ть твоѧ̀ па́че живѡ́тъ: ᲂу҆стнѣ̀ моѝ похвали́тѣ тѧ̀. Та́кѡ бл҃гословлю́ тѧ въ животѣ̀ мое́мъ и҆ ѡ҆ и҆́мени твое́мъ воздѣжꙋ̀ рꙋ́цѣ моѝ. Ꙗ҆́кѡ ѿ тꙋ́ка и҆ ма́сти да и҆спо́лнитсѧ дꙋша̀ моѧ̀, и҆ ᲂу҆стна́ма ра́дости восхва́лѧтъ тѧ̀ ᲂу҆ста̀ моѧ̑. А҆́ще помина́хъ тѧ̀ на посте́ли мое́й, на ᲂу҆́треннихъ поꙋча́хсѧ въ тѧ̀: Ꙗ҆́кѡ бы́лъ є҆сѝ помо́щникъ мо́й, и҆ въ кро́вѣ крилꙋ̑ твоє́ю возра́дꙋюсѧ. Прильпѐ дꙋша̀ моѧ̀ по тебѣ̀: мене́ же прїѧ́тъ десни́ца твоѧ̀. Ті́и же всꙋ́е и҆ска́ша дꙋ́шꙋ мою̀: вни́дꙋтъ въ преиспѡ́днѧѧ землѝ: Предадѧ́тсѧ въ рꙋ́ки ѻ҆рꙋ́жїѧ, ча̑сти ли́совѡмъ бꙋ́дꙋтъ. Ца́рь же возвесели́тсѧ ѡ҆ бз҃ѣ: похва́литсѧ всѧ́къ клены́йсѧ и҆́мъ, ꙗ҆́кѡ загради́шасѧ ᲂу҆ста̀ глаго́лющихъ непра́вєднаѧ.",
  ["заголовок_ру"] = "Псало́м Дави́ду, внегда́ бы́ти ему́ в пусты́ни Иуде́йстей.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, внегда̀ бы́ти є҆мꙋ̀ въ пꙋсты́ни і҆ꙋде́йстѣй."
}

add_psalom {
  ["номер"] = 63,
  ["часть"] = 1,
  ["кафизма"] = 8,
  ["слава"] = 3,
  ["текст_ру"] = "Услы́ши, Бо́же, глас мой, внегда́ моли́ти ми ся к Тебе́, от стра́ха вра́жия изми́ ду́шу мою́. Покры́й мя от со́нма лука́внующих, от мно́жества де́лающих непра́вду. И́же изостри́ша, я́ко мечь, язы́ки своя́, напряго́ша лук свой, вещь го́рьку, состреля́ти в та́йных непоро́чна, внеза́пу состреля́ют eго́ и не убоя́тся. Утверди́ша себе́ сло́во лука́вое, пове́даша скры́ти сеть, ре́ша: кто у́зрит их? Испыта́ша беззако́ние, исчезо́ша испыта́ющии испыта́ния, присту́пит челове́к, и се́рдце глубоко́, и вознесе́тся Бог. Стре́лы младе́нец бы́ша я́звы их, и изнемого́ша на ня язы́цы их. Смути́шася вси ви́дящии их, и убоя́ся всяк челове́к, и возвести́ша дела́ Бо́жия, и творе́ния Его́ разуме́ша. Возвесели́тся пра́ведник о Го́споде и упова́ет на Него́, и похва́лятся вси пра́вии се́рдцем.",
  ["текст_цс"] = "Оу҆слы́ши, бж҃е, гла́съ мо́й, внегда̀ моли́ти ми сѧ къ тебѣ̀: ѿ стра́ха вра́жїѧ и҆змѝ дꙋ́шꙋ мою̀. Покры́й мѧ̀ ѿ со́нма лꙋка́внꙋющихъ, ѿ мно́жества дѣ́лающихъ непра́вдꙋ: И҆̀же и҆з̾ѡстри́ша ꙗ҆́кѡ ме́чь ѧ҆зы́ки своѧ̑, напрѧго́ша лꙋ́къ сво́й, ве́щь го́рькꙋ, Сострѣлѧ́ти въ та́йныхъ непоро́чна: внеза́пꙋ сострѣлѧ́ютъ є҆го̀, и҆ не ᲂу҆боѧ́тсѧ. Оу҆тверди́ша себѣ̀ сло́во лꙋка́вое: повѣ́даша скры́ти сѣ́ть, рѣ́ша: кто̀ ᲂу҆́зритъ и҆̀хъ; И҆спыта́ша беззако́нїе: и҆счезо́ша и҆спыта́ющїи и҆спыта̑нїѧ: пристꙋ́питъ человѣ́къ, и҆ се́рдце глꙋбоко̀. И҆ вознесе́тсѧ бг҃ъ: стрѣ́лы младе́нєцъ бы́ша ꙗ҆́звы и҆́хъ, И҆ и҆знемого́ша на нѧ̀ ꙗ҆зы́цы и҆́хъ: смꙋти́шасѧ всѝ ви́дѧщїи и҆̀хъ. И҆ ᲂу҆боѧ́сѧ всѧ́къ человѣ́къ: и҆ возвѣсти́ша дѣла̀ бж҃їѧ, и҆ творє́нїѧ є҆гѡ̀ разꙋмѣ́ша. Возвесели́тсѧ првⷣникъ ѡ҆ гдⷭ҇ѣ и҆ ᲂу҆пова́етъ на него̀: и҆ похва́лѧтсѧ всѝ пра́вїи срⷣцемъ.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 64,
