  ["текст_ру"] = "Коль благ Бог Изра́илев, пра́вым се́рдцем. Мои́ же вма́ле не подвижа́стеся но́зе: вма́ле не пролия́шася стопы́ моя́. Я́ко возревнова́х на беззако́нныя, мир гре́шников зря. Я́ко несть восклоне́ния в сме́рти их, и утверже́ния в ра́не их, в труде́х челове́ческих не суть, и с челове́ки не прии́мут ран. Сего́ ра́ди удержа́ я́ горды́ня их до конца́: оде́яшася непра́вдою и нече́стием свои́м. Изы́дет я́ко из ту́ка непра́вда их, преидо́ша в любо́вь се́рдца. Помы́слиша и глаго́лаша в лука́встве, непра́вду в высоту́ глаго́лаша. Положи́ша на небеси́ уста́ своя́, и язы́к их пре́йде по земли́. Сего́ ра́ди обратя́тся лю́дие мои́ се́мо, и дни́е испо́лнени обря́щутся в них. И ре́ша: ка́ко уве́де Бог? И а́ше есть ра́зум в Вы́шнем? Се си́и гре́шницы и гобзу́ющии в век, удержа́ша бога́тство. И рех: еда́ всу́е оправди́х се́рдце мое́ и умы́х в непови́нных ру́це мои́, и бых я́звен весь день, и обличе́ние мое́ на у́тренних. А́ще глаго́лах, пове́м та́ко: се ро́ду сыно́в Твои́х, eму́же обеща́хся, и непщева́х разуме́ти: сие́ труд есть предо мно́ю, до́ндеже вни́ду во святи́ло Бо́жие и разуме́ю в после́дняя их. Оба́че за льще́ния их положи́л еси́ им зла́я, низложи́л еси́ я́, внегда́ разгорде́шася. Ка́ко бы́ша в запусте́ние? Внеза́пу исчезо́ша, погибо́ша за беззако́ние свое́. Я́ко со́ние востаю́щаго, Го́споди, во гра́де Твое́м о́браз их уничижи́ши. Я́ко разжже́ся се́рдце мое́, и утро́бы моя́ измени́шася. И аз уничиже́н и не разуме́х, ско́тен бых у Тебе́. И аз вы́ну с Тобо́ю, удержа́л еси́ ру́ку десну́ю мою́, и сове́том Твои́м наста́вил мя еси́, и со сла́вою прия́л мя еси́. Что бо ми есть на небеси́? И от Тебе́ что восхоте́х на земли́? Исчезе́ се́рдце мое́ и плоть моя́, Бо́же се́рдца моего́, и часть моя́, Бо́же, во век. Я́ко се удаля́ющии себе́ от Тебе́ поги́бнут; потреби́л еси́ вся́каго любоде́ющаго от Тебе́. Мне же прилепля́тися Бо́гови бла́го есть, полага́ти на Го́спода упова́ние мое́, возвести́ти ми вся хвалы́ Твоя́ во врате́х дще́ре Сио́ни.",
  ["текст_цс"] = "Ко́ль бл҃гъ бг҃ъ і҆и҃левъ пра̑вымъ се́рдцемъ. Мои́ же вма́лѣ не подвижа́стѣсѧ но́зѣ: вма́лѣ не пролїѧ́шасѧ стопы̑ моѧ̑: Ꙗ҆́кѡ возревнова́хъ на беззакѡ́нныѧ, ми́ръ грѣ́шникѡвъ зрѧ̀: Ꙗ҆́кѡ нѣ́сть восклоне́нїѧ въ сме́рти и҆́хъ и҆ ᲂу҆твержде́нїѧ въ ра́нѣ и҆́хъ: Въ трꙋдѣ́хъ человѣ́ческихъ не сꙋ́ть, и҆ съ человѣ́ки не прїи́мꙋтъ ра́нъ. Сегѡ̀ ра́ди ᲂу҆держа̀ ѧ҆̀ горды́нѧ и҆́хъ до конца̀: ѡ҆дѣ́ѧшасѧ непра́вдою и҆ нече́стїемъ свои́мъ. И҆зы́детъ ꙗ҆́кѡ и҆з̾ тꙋ́ка непра́вда и҆́хъ: преидо́ша въ любо́вь се́рдца. Помы́слиша и҆ глаго́лаша въ лꙋка́вствѣ, непра́вдꙋ въ высотꙋ̀ глаго́лаша: Положи́ша на небесѝ ᲂу҆ста̀ своѧ̑, и҆ ѧ҆зы́къ и҆́хъ пре́йде по землѝ. Сегѡ̀ ра́ди ѡ҆братѧ́тсѧ лю́дїе моѝ сѣ́мѡ, и҆ дні́е и҆спо́лнени ѡ҆брѧ́щꙋтсѧ въ ни́хъ. И҆ рѣ́ша: ка́кѡ ᲂу҆вѣ́дѣ бг҃ъ; и҆ а҆́ще є҆́сть ра́зꙋмъ въ вы́шнѣмъ; Сѐ, сі́и грѣ̑шницы и҆ гобзꙋ́ющїи въ вѣ́къ ᲂу҆держа́ша бога́тство. И҆ рѣ́хъ: є҆да̀ всꙋ́е ѡ҆правди́хъ се́рдце моѐ и҆ ᲂу҆мы́хъ въ непови́нныхъ рꙋ́цѣ моѝ, И҆ бы́хъ ꙗ҆́звенъ ве́сь де́нь, и҆ ѡ҆бличе́нїе моѐ на ᲂу҆́треннихъ; А҆́ще глаго́лахъ, повѣ́мъ та́кѡ: сѐ, ро́дꙋ сынѡ́въ твои́хъ, є҆мꙋ́же ѡ҆бѣща́хсѧ: И҆ непщева́хъ разꙋмѣ́ти: сїѐ трꙋ́дъ є҆́сть предо мно́ю, До́ндеже вни́дꙋ во ст҃и́ло бж҃їе и҆ разꙋмѣ́ю въ послѣ̑днѧѧ и҆́хъ. Ѻ҆ба́че за льщє́нїѧ и҆́хъ положи́лъ є҆сѝ и҆̀мъ ѕла̑ѧ, низложи́лъ є҆сѝ ѧ҆̀, внегда̀ разгордѣ́шасѧ. Ка́кѡ бы́ша въ запꙋстѣ́нїе; внеза́пꙋ и҆счезо́ша, погибо́ша за беззако́нїе своѐ. Ꙗ҆́кѡ со́нїе востаю́щагѡ, гдⷭ҇и, во гра́дѣ твое́мъ ѡ҆́бразъ и҆́хъ ᲂу҆ничижи́ши. Ꙗ҆́кѡ разжже́сѧ се́рдце моѐ, и҆ ᲂу҆трѡ́бы моѧ̑ и҆змѣни́шасѧ: И҆ а҆́зъ ᲂу҆ничиже́нъ, и҆ не разꙋмѣ́хъ, ско́тенъ бы́хъ ᲂу҆ тебє̀. И҆ а҆́зъ вы́нꙋ съ тобо́ю: ᲂу҆держа́лъ є҆сѝ рꙋ́кꙋ деснꙋ́ю мою̀, И҆ совѣ́томъ твои́мъ наста́вилъ мѧ̀ є҆сѝ, и҆ со сла́вою прїѧ́лъ мѧ̀ є҆сѝ. Что́ бо мѝ є҆́сть на нб҃сѝ; и҆ ѿ тебє̀ что̀ восхотѣ́хъ на землѝ; И҆счезѐ се́рдце моѐ и҆ пло́ть моѧ̀, бж҃е се́рдца моегѡ̀, и҆ ча́сть моѧ̀, бж҃е, во вѣ́къ. Ꙗ҆́кѡ сѐ, ᲂу҆далѧ́ющїи себѐ ѿ тебє̀ поги́бнꙋтъ: потреби́лъ є҆сѝ всѧ́каго любодѣ́ющаго ѿ тебє̀. Мнѣ́ же прилѣплѧ́тисѧ бг҃ови бла́го є҆́сть, полага́ти на гдⷭ҇а ᲂу҆пова́нїе моѐ, возвѣсти́ти мѝ всѧ̑ хвалы̑ твоѧ̑, во вратѣ́хъ дще́ре сїѡ́ни.",
  ["заголовок_ру"] = "Оскуде́ша пе́сни Дави́да, сы́на Иессе́ова. Псало́м Аса́фу.",
  ["заголовок_цс"] = "Ѡ҆скꙋдѣ́ша пѣ̑сни дв҃да, сы́на і҆ессе́ова. Ѱало́мъ а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 73,
  ["часть"] = 1,
  ["кафизма"] = 10,
  ["слава"] = 2,
  ["текст_ру"] = "Вску́ю, Бо́же, отри́нул еси́ до конца́? Разгне́вася я́рость Твоя́ на о́вцы па́жити Твоея́? Помяни́ сонм Твой, eго́же стяжа́л еси́ испе́рва, изба́вил еси́ жезло́м достоя́ния Твоего́, гора́ Сио́н сия́, в не́йже всели́лся еси́. Воздви́гни ру́це Твои́ на горды́ни их в коне́ц, ели́ка лука́внова враг во святе́м Твое́м. И восхвали́шася ненави́дящии Тя посреде́ пра́здника Твоего́, положи́ша зна́мения своя́, зна́мения, и не позна́ша, я́ко во исхо́де превы́ше, я́ко в дубра́ве дре́вяне секи́рами разсеко́ша. Две́ри eго́ вку́пе: се́чивом и оско́рдом разруши́ша и́. Возжго́ша огне́м святи́ло Твое́, на земли́ оскверни́ша жили́ще и́мене Твоего́. Ре́ша в се́рдце свое́м ю́жики их вку́пе: прииди́те и отста́вим вся пра́здники Бо́жия от земли́. Зна́мения их не ви́дехом: несть ктому́ проро́ка, и нас не позна́ет ктому́. Доко́ле, Бо́же, поно́сит враг? Раздражи́т проти́вный и́мя Твое́ до конца́? Вску́ю отвраща́еши ру́ку Твою́ и десни́цу Твою́ от среды́ не́дра Твоего́ в коне́ц? Бог же Царь наш пре́жде ве́ка соде́ла спасе́ние посреде́ земли́. Ты утверди́л еси́ си́лою Твое́ю мо́ре, Ты сте́рл еси́ главы́ змие́в в воде́, Ты сокруши́л еси́ главу́ зми́еву, дал еси́ того́ бра́шно лю́дем Ефио́пским. Ты расто́ргл еси́ исто́чники и пото́ки, Ты изсуши́л еси́ ре́ки Ифа́мския. Твой есть день, и Твоя́ есть нощь: Ты соверши́л еси́ зарю́ и со́лнце. Ты сотвори́л еси́ вся преде́лы земли́, жа́тву и ве́сну Ты созда́л еси́ я́. Помяни́ сия́, враг поноси́ Го́сподеви, и лю́дие безу́мнии раздражи́ша и́мя Твое́. Не преда́ждь звере́м ду́шу, испове́дающуся Тебе́, душ убо́гих Твои́х не забу́ди до конца́. При́зри на заве́т Твой, я́ко испо́лнишася помраче́ннии земли́ домо́в беззако́ний. Да не возврати́тся смире́нный посра́млен, нищ и убо́г восхвали́та и́мя Твое́. Воста́ни, Бо́же, суди́ прю Твою́, помяни́ поноше́ние Твое́, е́же от безу́мнаго весь день. Не забу́ди гла́са моли́твенник Твои́х, горды́ня ненави́дящих Тя взы́де вы́ну.",
  ["текст_цс"] = "Вскꙋ́ю, бж҃е, ѿри́нꙋлъ є҆сѝ до конца̀; разгнѣ́васѧ ꙗ҆́рость твоѧ̀ на ѻ҆́вцы па́жити твоеѧ̀; Помѧнѝ со́нмъ тво́й, є҆го́же стѧжа́лъ є҆сѝ и҆спе́рва, и҆зба́вилъ є҆сѝ жезло́мъ достоѧ́нїѧ твоегѡ̀, гора̀ сїѡ́нъ сїѧ̀, въ не́йже всели́лсѧ є҆сѝ. Воздви́гни рꙋ́цѣ твоѝ на горды̑ни и҆́хъ въ коне́цъ, є҆ли̑ка лꙋка́внова вра́гъ во ст҃ѣ́мъ твое́мъ. И҆ восхвали́шасѧ ненави́дѧщїи тѧ̀ посредѣ̀ пра́здника твоегѡ̀: положи́ша зна́мєнїѧ своѧ̑ зна́мєнїѧ, и҆ не позна́ша, Ꙗ҆́кѡ во и҆схо́дѣ превы́ше: ꙗ҆́кѡ въ дꙋбра́вѣ дре́вѧнѣ сѣки́рами разсѣко́ша Двє́ри є҆гѡ̀ вкꙋ́пѣ, сѣ́чивомъ и҆ ѻ҆ско́рдомъ разрꙋши́ша и҆̀. Возжго́ша ѻ҆гне́мъ ст҃и́ло твоѐ: на землѝ ѡ҆скверни́ша жили́ще и҆́мене твоегѡ̀. Рѣ́ша въ се́рдцы свое́мъ ю҆́жики и҆́хъ вкꙋ́пѣ: прїиди́те, и҆ ѿста́вимъ всѧ̑ пра́здники бж҃їѧ ѿ землѝ. Зна́мєнїѧ и҆́хъ не ви́дѣхомъ: нѣ́сть ктомꙋ̀ прⷪ҇ро́ка, и҆ на́съ не позна́етъ ктомꙋ̀. Доко́лѣ, бж҃е, поно́ситъ вра́гъ; раздражи́тъ проти́вный и҆́мѧ твоѐ до конца̀; Вскꙋ́ю ѿвраща́еши рꙋ́кꙋ твою̀ и҆ десни́цꙋ твою̀ ѿ среды̀ нѣ́дра твоегѡ̀ въ коне́цъ; Бг҃ъ же, цр҃ь на́шъ, пре́жде вѣ́ка содѣ́ла сп҃се́нїе посредѣ̀ землѝ. Ты̀ ᲂу҆тверди́лъ є҆сѝ си́лою твое́ю мо́ре: ты̀ сте́рлъ є҆сѝ главы̑ ѕмїє́въ въ водѣ̀: Ты̀ сокрꙋши́лъ є҆сѝ главꙋ̀ ѕмі́евꙋ, да́лъ є҆сѝ того̀ бра́шно лю́демъ є҆ѳїѡ́пскимъ. Ты̀ расто́рглъ є҆сѝ и҆сто́чники и҆ пото́ки: ты̀ и҆зсꙋши́лъ є҆сѝ рѣ́ки и҆ѳа̑мскїѧ. Тво́й є҆́сть де́нь, и҆ твоѧ̀ є҆́сть но́щь: ты̀ соверши́лъ є҆сѝ зарю̀ и҆ со́лнце. Ты̀ сотвори́лъ є҆сѝ всѧ̑ предѣ́лы землѝ: жа́твꙋ и҆ ве́снꙋ ты̀ созда́лъ є҆сѝ ѧ҆̀. Помѧнѝ сїѧ̑: вра́гъ поносѝ гдⷭ҇еви, и҆ лю́дїе безꙋ́мнїи раздражи́ша и҆́мѧ твоѐ. Не преда́ждь ѕвѣрє́мъ дꙋ́шꙋ и҆сповѣ́дающꙋюсѧ тебѣ̀: дꙋ́шъ ᲂу҆бо́гихъ твои́хъ не забꙋ́ди до конца̀. При́зри на завѣ́тъ тво́й: ꙗ҆́кѡ и҆спо́лнишасѧ помраче́ннїи землѝ домѡ́въ беззако́нїй. Да не возврати́тсѧ смире́нный посра́мленъ: ни́щъ и҆ ᲂу҆бо́гъ восхвали́та и҆́мѧ твоѐ. Воста́ни, бж҃е, сꙋдѝ прю̀ твою̀: помѧнѝ поноше́нїе твоѐ, є҆́же ѿ безꙋ́мнагѡ ве́сь де́нь. Не забꙋ́ди гла́са моли́твєнникъ твои́хъ: горды́нѧ ненави́дѧщихъ тѧ̀ взы́де вы́нꙋ.",
  ["заголовок_ру"] = "Ра́зума Аса́фу.",
  ["заголовок_цс"] = "Ра́зꙋма а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 74,
  ["часть"] = 1,
  ["кафизма"] = 10,
  ["слава"] = 3,
  ["текст_ру"] = "Испове́мыся Тебе́, Бо́же, испове́мыся Тебе́, и призове́м и́мя Твое́; пове́м вся чудеса́ Твоя́. Егда́ прииму́ вре́мя, Аз правоты́ возсужду́. Раста́яся земля́ и вси живу́щии на ней, Аз утверди́х столпы́ ея́. Рех беззако́ннующым, не беззако́ннуйте: и согреша́ющым, не возноси́те ро́га, не воздвиза́йте на высоту́ ро́га ва́шего, и не глаго́лите на Бо́га непра́вду: я́ко ниже́ от исхо́д, ниже́ от за́пад, ниже́ от пусты́х гор. Я́ко Бог судия́ есть: сего́ смиря́ет, и сего́ возно́сит. Я́ко ча́ша в руце́ Госпо́дни, вина́ нерастворе́на, испо́лнь растворе́ния, и уклони́ от сея́ в сию́: оба́че дро́ждие Его́ не истощи́ся, испию́т вси гре́шнии земли́. Аз же возра́дуюся в век, воспою́ Бо́гу Иа́ковлю: и вся ро́ги гре́шных сломлю́, и вознесе́тся рог пра́веднаго.",
  ["текст_цс"] = "И҆сповѣ́мысѧ тебѣ̀, бж҃е, и҆сповѣ́мысѧ тебѣ̀ и҆ призове́мъ и҆́мѧ твоѐ: повѣ́мъ всѧ̑ чꙋдеса̀ твоѧ̑. Є҆гда̀ прїимꙋ̀ вре́мѧ, а҆́зъ правѡты̀ возсꙋждꙋ̀. Раста́ѧсѧ землѧ̀ и҆ всѝ живꙋ́щїи на не́й, а҆́зъ ᲂу҆тверди́хъ столпы̀ є҆ѧ̀. Рѣ́хъ беззако́ннꙋющымъ, не беззако́ннꙋйте: и҆ согрѣша́ющымъ, не возноси́те ро́га. Не воздвиза́йте на высотꙋ̀ ро́га ва́шегѡ и҆ не глаго́лите на бг҃а непра́вдꙋ: Ꙗ҆́кѡ нижѐ ѿ и҆схѡ́дъ, нижѐ и҆ за̑падъ, нижѐ ѿ пꙋсты́хъ го́ръ. Ꙗ҆́кѡ бг҃ъ сꙋдїѧ̀ є҆́сть: сего̀ смирѧ́етъ, и҆ сего̀ возно́ситъ. Ꙗ҆́кѡ ча́ша въ рꙋцѣ̀ гдⷭ҇ни, вїна̀ нерастворе́на и҆спо́лнь растворе́нїѧ, и҆ ᲂу҆клонѝ ѿ сеѧ̀ въ сїю̀: ѻ҆ба́че дро́ждїе є҆гѡ̀ не и҆стощи́сѧ, и҆спїю́тъ всѝ грѣ́шнїи землѝ. А҆́зъ же возра́дꙋюсѧ въ вѣ́къ, воспою̀ бг҃ꙋ і҆а́кѡвлю: И҆ всѧ̑ ро́ги грѣ́шныхъ сломлю̀, и҆ вознесе́тсѧ ро́гъ првⷣнагѡ.",
  ["заголовок_ру"] = "В коне́ц, да не растли́ши, псало́м пе́сни Аса́фу.",
  ["заголовок_цс"] = "Въ коне́цъ, да не растли́ши, ѱало́мъ пѣ́сни а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 75,
  ["часть"] = 1,
  ["кафизма"] = 10,
  ["слава"] = 3,
  ["текст_ру"] = "Ве́дом во Иуде́и Бог: во Изра́или ве́лие и́мя Его́. И бысть в ми́ре ме́сто Его́ и жили́ще Его́ в Сио́не. Та́мо сокруши́ кре́пости луко́в, ору́жие и мечь и брань. Просвеща́еши Ты ди́вно от гор ве́чных. Смято́шася вси неразу́мнии се́рдцем: усну́ша сном свои́м, и ничто́же обрето́ша вси му́жие бога́тства в рука́х свои́х. От запреще́ния Твоего́, Бо́же Иа́ковль, воздрема́ша все́дшии на ко́ни. Ты стра́шен еси́, и кто противоста́нет Тебе́? Отто́ле гнев Твой. С небесе́ слы́шан сотвори́л еси́ суд: земля́ убоя́ся, и умолча́, внегда́ воста́ти на суд Бо́гу, спасти́ вся кро́ткия земли́. Я́ко помышле́ние челове́ческое испове́стся Тебе́: и оста́нок помышле́ния пра́зднует Ти. Помоли́теся и воздади́те Го́сподеви Бо́гу на́шему. Вси и́же о́крест Его́ принесу́т да́ры, стра́шному и отъе́млющему ду́хи князе́й, стра́шному па́че царе́й земны́х.",
  ["текст_цс"] = "Вѣ́домъ во і҆ꙋде́и бг҃ъ: во і҆и҃ли ве́лїе и҆́мѧ є҆гѡ̀. И҆ бы́сть въ ми́рѣ мѣ́сто є҆гѡ̀, и҆ жили́ще є҆гѡ̀ въ сїѡ́нѣ. Та́мѡ сокрꙋшѝ крѣ́пѡсти лꙋкѡ́въ, ѻ҆рꙋ́жїе и҆ ме́чь и҆ бра́нь. Просвѣща́еши ты̀ ди́внѡ ѿ го́ръ вѣ́чныхъ. Смѧто́шасѧ всѝ неразꙋ́мнїи се́рдцемъ: ᲂу҆снꙋ́ша сно́мъ свои́мъ, и҆ ничто́же ѡ҆брѣто́ша всѝ мꙋ́жїе бога́тства въ рꙋка́хъ свои́хъ. Ѿ запреще́нїѧ твоегѡ̀, бж҃е і҆а́кѡвль, воздрема́ша всѣ́дшїи на ко́ни. Ты̀ стра́шенъ є҆сѝ, и҆ кто̀ противоста́нетъ тебѣ̀; ѿто́лѣ гнѣ́въ тво́й. Съ нб҃сѐ слы́шанъ сотвори́лъ є҆сѝ сꙋ́дъ: землѧ̀ ᲂу҆боѧ́сѧ и҆ ᲂу҆молча̀, Внегда̀ воста́ти на сꙋ́дъ бг҃ꙋ, сп҃стѝ всѧ̑ крѡ́ткїѧ землѝ. Ꙗ҆́кѡ помышле́нїе человѣ́ческое и҆сповѣ́стсѧ тебѣ̀, и҆ ѡ҆ста́нокъ помышле́нїѧ пра́зднꙋетъ тѝ. Помоли́тесѧ и҆ воздади́те гдⷭ҇еви бг҃ꙋ на́шемꙋ: всѝ, и҆̀же ѡ҆́крестъ є҆гѡ̀, принесꙋ́тъ да́ры Стра́шномꙋ и҆ ѿе́млющемꙋ дꙋ́хи кнѧзе́й, стра́шномꙋ па́че царе́й земны́хъ.",
  ["заголовок_ру"] = "В коне́ц, в пе́снех, псало́м Аса́фу, песнь ко ассири́анину.",
  ["заголовок_цс"] = "Въ коне́цъ, въ пѣ́снехъ, ѱало́мъ а҆са́фꙋ, пѣ́снь ко а҆ссѷрі́анинꙋ."
}

add_psalom {
  ["номер"] = 76,
  ["часть"] = 1,
  ["кафизма"] = 10,
  ["слава"] = 3,
  ["текст_ру"] = "Гла́сом мои́м ко Го́споду воззва́х, гла́сом мои́м к Бо́гу, и внят ми. В день ско́рби моея́ Бо́га взыска́х рука́ма мои́ма, но́щию пред Ним, и не прельще́н бых. Отве́ржеся уте́шитися душа́ моя́. Помяну́х Бо́га и возвесели́хся, поглумля́хся и малоду́шествоваше дух мой. Предвари́сте стражбы́ о́чи мои́: смято́хся и не глаго́лах. Помы́слих дни пе́рвыя, и ле́та ве́чная помяну́х, и поуча́хся: но́щию се́рдцем мои́м глумля́хся, и тужа́ше дух мой: еда́ во ве́ки отри́нет Госпо́дь, и не приложи́т благоволи́ти па́ки? Или́ до конца́ ми́лость Свою́ отсече́т, сконча́ глаго́л от ро́да в род? Еда́ забу́дет уще́дрити Бог? Или́ удержи́т во гне́ве Свое́м щедро́ты Своя́? И рех: ны́не нача́х, сия́ изме́на десни́цы Вы́шняго. Помяну́х дела́ Госпо́дня, я́ко помяну́ от нача́ла чудеса́ Твоя́, и поучу́ся во всех де́лех Твои́х, и в начина́ниих Твои́х поглумлю́ся. Бо́же, во святе́м путь Твой: кто Бог ве́лий я́ко Бог наш? Ты еси́ Бог творя́й чудеса́: сказа́л еси́ в лю́дех си́лу Твою́, изба́вил еси́ мы́шцею Твое́ю лю́ди Твоя́, сы́ны Иа́ковли и Ио́сифовы. Ви́деша Тя во́ды, Бо́же, ви́деша Тя во́ды, и убоя́шася: смято́шася бе́здны, мно́жество шу́ма вод, глас да́ша о́блацы, и́бо стре́лы Твоя́ прехо́дят. Глас гро́ма Твоего́ в колеси́, освети́ша мо́лния Твоя́ вселе́нную: подви́жеся и тре́петна бысть земля́. В мо́ри путие́ Твои́, и стези́ Твои́ в вода́х мно́гих, и следы́ Твоя́ не позна́ются. Наста́вил еси́ я́ко о́вцы лю́ди Твоя́ руко́ю Моисе́овою и Ааро́нею.",
  ["текст_цс"] = "Гла́сомъ мои́мъ ко гдⷭ҇ꙋ воззва́хъ, гла́сомъ мои́мъ къ бг҃ꙋ, и҆ внѧ́тъ мѝ. Въ де́нь ско́рби моеѧ̀ бг҃а взыска́хъ рꙋка́ма мои́ма, но́щїю пред̾ ни́мъ, и҆ не прельще́нъ бы́хъ: ѿве́ржесѧ ᲂу҆тѣ́шитисѧ дꙋша̀ моѧ̀. Помѧнꙋ́хъ бг҃а и҆ возвесели́хсѧ, поглꙋмлѧ́хсѧ, и҆ малодꙋ́шствоваше дꙋ́хъ мо́й. Предвари́стѣ стражбы̑ ѻ҆́чи моѝ: смѧто́хсѧ и҆ не глаго́лахъ. Помы́слихъ дни̑ пє́рвыѧ, и҆ лѣ̑та вѣ̑чнаѧ помѧнꙋ́хъ, и҆ поꙋча́хсѧ: Но́щїю се́рдцемъ мои́мъ глꙋмлѧ́хсѧ, и҆ тꙋжа́ше дꙋ́хъ мо́й: Є҆да̀ во вѣ́ки ѿри́нетъ гдⷭ҇ь и҆ не приложи́тъ бл҃говоли́ти па́ки; И҆лѝ до конца̀ млⷭ҇ть свою̀ ѿсѣче́тъ, сконча̀ глаго́лъ ѿ ро́да въ ро́дъ; Є҆да̀ забꙋ́детъ ᲂу҆ще́дрити бг҃ъ; и҆лѝ ᲂу҆держи́тъ во гнѣ́вѣ свое́мъ щедрѡ́ты своѧ̑; И҆ рѣ́хъ: ны́нѣ нача́хъ, сїѧ̀ и҆змѣ́на десни́цы вы́шнѧгѡ. Помѧнꙋ́хъ дѣла̀ гдⷭ҇нѧ: ꙗ҆́кѡ помѧнꙋ̀ ѿ нача́ла чꙋдеса̀ твоѧ̑, И҆ поꙋчꙋ́сѧ во всѣ́хъ дѣ́лѣхъ твои́хъ, и҆ въ начина́нїихъ твои́хъ поглꙋмлю́сѧ. Бж҃е, во ст҃ѣ́мъ пꙋ́ть тво́й: кто̀ бг҃ъ ве́лїй, ꙗ҆́кѡ бг҃ъ на́шъ; Ты̀ є҆сѝ бг҃ъ творѧ́й чꙋдеса̀: сказа́лъ є҆сѝ въ лю́дехъ си́лꙋ твою̀, И҆зба́вилъ є҆сѝ мы́шцею твое́ю лю́ди твоѧ̑, сы́ны і҆а̑кѡвли и҆ і҆ѡ́сифѡвы. Ви́дѣша тѧ̀ во́ды, бж҃е, ви́дѣша тѧ̀ во́ды и҆ ᲂу҆боѧ́шасѧ: смѧто́шасѧ бє́здны. Мно́жество шꙋ́ма во́дъ: гла́съ да́ша ѻ҆́блацы, и҆́бо стрѣ́лы твоѧ̑ прехо́дѧтъ. Гла́съ гро́ма твоегѡ̀ въ колесѝ, ѡ҆свѣти́ша мѡ́лнїѧ твоѧ̑ вселе́ннꙋю: подви́жесѧ и҆ тре́петна бы́сть землѧ̀. Въ мо́ри пꙋтїѐ твоѝ, и҆ стєзѝ твоѧ̑ въ вода́хъ мно́гихъ, и҆ слѣды̀ твоѝ не позна́ютсѧ. Наста́вилъ є҆сѝ ꙗ҆́кѡ ѻ҆́вцы лю́ди твоѧ̑ рꙋко́ю мѡѷсе́овою и҆ а҆арѡ́нею.",
  ["заголовок_ру"] = "В коне́ц, о Идифу́ме, псало́м Аса́фу.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ і҆дїѳꙋ́мѣ, ѱало́мъ а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 77,
  ["часть"] = 1,
  ["кафизма"] = 11,
  ["слава"] = 1,
  ["текст_ру"] = "Внемли́те, лю́дие мои́, зако́ну моему́, приклони́те у́хо ва́ше во глаго́лы уст мои́х. Отве́рзу в при́тчах уста́ моя́, провеща́ю гана́ния испе́рва. Ели́ка слы́шахом и позна́хом я́, и отцы́ на́ши пове́даша нам: не утаи́шася от чад их в род ин, возвеша́юще хвалы́ Госпо́дни и си́лы Его́, и чудеса́ Его́, я́же сотвори́. И воздви́же свиде́ние во Иа́кове, и зако́н положи́ во Изра́или: ели́ка запове́да отце́м на́шим, сказа́ти я́ сыново́м свои́м, я́ко да позна́ет род ин, сы́нове родя́щиися, и воста́нут и пове́дят я́ сыново́м свои́м: да положа́т на Бо́га упова́ние свое́, и не забу́дут дел Бо́жиих, и за́поведи Его́ взы́щут. Да не бу́дут я́коже отцы́ их, род стропти́в и преогорчева́яй, род и́же не испра́ви се́рдца своего́, и не уве́ри с Бо́гом ду́ха своего́. Сы́нове Ефре́мли наляца́юще и стреля́юще лу́ки, возврати́шася в день бра́ни: не сохрани́ша заве́та Бо́жия, и в зако́не Его́ не восхоте́ша ходи́ти. И забы́ша благодея́ния Его́, и чудеса́ Его́, я́же показа́ им пред отцы́ их, я́же сотвори́ чудеса́ в земли́ Еги́петстей, на по́ли Танео́се. Разве́рзе мо́ре, и проведе́ их, предста́ви во́ды я́ко мех. И наста́ви я́ о́блаком во дни, и всю нощь просвеще́нием огня́. Разве́рзе ка́мень в пусты́ни, и напои́ я́ я́ко в бе́здне мно́зе, и изведе́ во́ду из ка́мене, и низведе́ я́ко ре́ки во́ды. И приложи́ша еще́ согреша́ти Ему́, преогорчи́ша Вы́шняго в безво́дней; и искуси́ша Бо́га в сердца́х свои́х, вопроси́ти бра́шна душа́м свои́м. И клевета́ша на Бо́га, и ре́ша: еда́ возмо́жет Бог угото́вати трапе́зу в пусты́ни? Поне́же порази́ ка́мень, и потеко́ша во́ды, и пото́цы наводни́шася: еда́ и хлеб мо́жет да́ти, или́ угото́вати трапе́зу лю́дем Свои́м? Сего́ ра́ди слы́ша Госпо́дь и презре́: и огнь возгоре́ся во Иа́кове, и гнев взы́де на Изра́иля, я́ко не ве́роваша Бо́гови, ниже́ упова́ша на спасе́ние Его́. И запове́да облако́м свы́ше, и две́ри небесе́ отве́рзе, и одожди́ им ма́нну я́сти, и хлеб небе́сный даде́ им. Хлеб а́нгельский яде́ челове́к, бра́шно посла́ им до сы́тости. Воздви́же юг с небесе́, и наведе́ си́лою Свое́ю ли́ва, и одожди́ на ня я́ко прах пло́ти, и я́ко песо́к морски́й пти́цы перна́ты. И нападо́ша посреде́ ста́на их, о́крест жили́щ их. И ядо́ша и насы́тишася зело́, и жела́ние их принесе́ им. Не лиши́шася от жела́ния своего́: еще́ бра́шну су́щу во усте́х их: и гнев Бо́жий взы́де на ня, и уби́ мно́жайшая их, и избра́нным Изра́илевым запя́т. Во всех сих согреши́ша еще́, и не ве́роваша чудесе́м Его́. И исчезо́ша в суете́ дни́е их, и ле́та их со тща́нием. Егда́ убива́ше я́, тогда́ взыска́ху Его́, и обраща́хуся, и у́треневаху к Бо́гу: и помяну́ша, я́ко Бог Помо́щник им есть, и Бог Вы́шний Изба́витель им есть. И возлюби́ша Его́ усты́ свои́ми, и язы́ком свои́м солга́ша Ему́: се́рдце же их не бе пра́во с Ним, ниже́ уве́ришася в заве́те Его́. То́йже есть щедр, и очи́стит грехи́ их, и не растли́т, и умно́жит отврати́ти я́рость Свою́, и не разжже́т всего́ гне́ва Своего́. И помяну́, я́ко плоть суть, дух ходя́й и не обраща́яйся. Колькра́ты преогорчи́ша Его́ в пусты́ни, прогне́ваша Его́ в земли́ безво́дней? И обрати́шася, и искуси́ша Бо́га, и Свята́го Изра́илева раздражи́ша, и не помяну́ша руки́ Его́ в день, во́ньже изба́ви я́ из руки́ оскорбля́юшаго, я́коже положи́ во Еги́пте зна́мения Своя́, и чудеса́ Своя́ на по́ли Танео́се, и преложи́ в кровь ре́ки их, и исто́чники их, я́ко да не пию́т. Посла́ на ня пе́сия му́хи и поядо́ша я́: и жа́бы, и растли́ я́. И даде́ рже плоды́ их, и труды́ их пруго́м. Уби́ гра́дом виногра́ды их, и черни́чие их сла́ною, и предаде́ гра́ду скоты́ их, и име́ние их огню́. Посла́ на ня гнев я́рости Своея́, я́рость и гнев и скорбь, посла́ние А́нгелы лю́тыми. Путесотвори́ стезю́ гне́ву Своему́, и не пощаде́ от сме́рти душ их: и скоты́ их в сме́рти заключи́, и порази́ вся́кое перворо́дное в земли́ Еги́петстей, нача́ток вся́каго труда́ их в селе́ниих Ха́мовых. И воздви́же я́ко о́вцы лю́ди Своя́, и возведе́ я́ я́ко ста́до в пусты́ни, и наста́ви я́ на упова́ние, и не убоя́шася, и враги́ их покры́ мо́ре. И введе́ я́ в го́ру святы́ни Своея́, го́ру сию́, ю́же стяжа́ десни́ца Его́. И изгна́ от лица́ их язы́ки, и по жре́бию даде́ им зе́млю у́жем жребодая́ния, и всели́ в селе́ниих их коле́на Изра́илева. И искуси́ша и преогорчи́ша Бо́га Вы́шняго, и свиде́ний Его́ не сохрани́ша, и отврати́шася, и отверго́шася, я́коже и отцы́ их, преврати́шася в лук развраще́н, и прогне́ваша Его́ в хо́лмех свои́х и во истука́нных свои́х раздражи́ша Его́. Слы́ша Бог и презре́, и уничижи́ зело́ Изра́иля, и отри́ну ски́нию Сило́мскую, селе́ние, е́же всели́ся в челове́цех. И предаде́ в плен кре́пость их, и добро́ту их в ру́ки враго́в, и затвори́ во ору́жии лю́ди Своя́, и достоя́ние Свое́ презре́. Ю́ношы их пояде́ огнь, и де́вы их не осе́тованы бы́ша; свяще́нницы их мече́м падо́ша, и вдови́цы их не опла́каны бу́дут. И воста́ я́ко спя́ Госпо́дь, я́ко си́лен и шу́мен от вина́, и порази́ враги́ Своя́ вспять, поноше́ние ве́чное даде́ им. И отри́ну селе́ние Ио́сифово, и коле́но Ефре́мово не избра́, и избра́ коле́но Иу́дово, го́ру Сио́ню, ю́же возлюби́, и созда́ я́ко единоро́га святи́лище Свое́, на земли́ основа́ и́ в век. И избра́ Дави́да раба́ Своего́, и восприя́т eго́ от стад о́вчих. От дои́лиц поя́т eго́ пасти́ Иа́кова раба́ Своего́ и Изра́иля достоя́ние Свое́. И упасе́ я́ в незло́бии се́рдца своего́, и в ра́зумех руку́ свое́ю наста́вил я́ есть.",
  ["текст_цс"] = "Внемли́те, лю́дїе моѝ, зако́нꙋ моемꙋ̀, приклони́те ᲂу҆́хо ва́ше во глаго́лы ᲂу҆́стъ мои́хъ. Ѿве́рзꙋ въ при́тчахъ ᲂу҆ста̀ моѧ̑, провѣща́ю гана̑нїѧ и҆спе́рва. Є҆ли̑ка слы́шахомъ и҆ позна́хомъ ѧ҆̀, и҆ ѻ҆тцы̀ на́ши повѣ́даша на́мъ: Не ᲂу҆таи́шасѧ ѿ ча̑дъ и҆́хъ въ ро́дъ и҆́нъ, возвѣща́юще хвалы̑ гдⷭ҇ни, и҆ си̑лы є҆гѡ̀ и҆ чꙋдеса̀ є҆гѡ̀, ꙗ҆̀же сотворѝ. И҆ воздви́же свидѣ́нїе во і҆а́кѡвѣ, и҆ зако́нъ положѝ во і҆и҃ли, є҆ли̑ка заповѣ́да ѻ҆тцє́мъ на́шымъ сказа́ти ѧ҆̀ сыновѡ́мъ свои̑мъ, Ꙗ҆́кѡ да позна́етъ ро́дъ и҆́нъ, сы́нове родѧ́щїисѧ, и҆ воста́нꙋтъ и҆ повѣ́дѧтъ ѧ҆̀ сыновѡ́мъ свои̑мъ: Да положа́тъ на бг҃а ᲂу҆пова́нїе своѐ, и҆ не забꙋ́дꙋтъ дѣ́лъ бж҃їихъ, и҆ за́пѡвѣди є҆гѡ̀ взы́щꙋтъ: Да не бꙋ́дꙋтъ ꙗ҆́коже ѻ҆тцы̀ и҆́хъ, ро́дъ стропти́въ и҆ преѡгорчева́ѧй, ро́дъ и҆́же не и҆спра́ви се́рдца своегѡ̀ и҆ не ᲂу҆вѣ́ри съ бг҃омъ дꙋ́ха своегѡ̀. Сы́нове є҆фрє́мли налѧца́юще и҆ стрѣлѧ́юще лꙋ́ки возврати́шасѧ въ де́нь бра́ни: Не сохрани́ша завѣ́та бж҃їѧ, и҆ въ зако́нѣ є҆гѡ̀ не восхотѣ́ша ходи́ти. И҆ забы́ша бл҃годѣѧ̑нїѧ є҆гѡ̀ и҆ чꙋдеса̀ є҆гѡ̀, ꙗ҆̀же показа̀ и҆̀мъ Пред̾ ѻ҆тцы̀ и҆́хъ, ꙗ҆̀же сотворѝ чꙋдеса̀ въ землѝ є҆гѵ́петстѣй, на по́ли танеѡ́сѣ: Разве́рзе мо́ре и҆ проведѐ и҆̀хъ: предста́ви во́ды ꙗ҆́кѡ мѣ́хъ, И҆ наста́ви ѧ҆̀ ѻ҆́блакомъ во днѝ и҆ всю̀ но́щь просвѣще́нїемъ ѻ҆гнѧ̀. Разве́рзе ка́мень въ пꙋсты́ни и҆ напоѝ ѧ҆̀ ꙗ҆́кѡ въ бе́зднѣ мно́зѣ: И҆ и҆зведѐ во́дꙋ и҆з̾ ка́мене и҆ низведѐ ꙗ҆́кѡ рѣ́ки во́ды. И҆ приложи́ша є҆щѐ согрѣша́ти є҆мꙋ̀, преѡгорчи́ша вы́шнѧго въ безво́днѣй: И҆ и҆скꙋси́ша бг҃а въ сердца́хъ свои́хъ, воспроси́ти бра̑шна дꙋша́мъ свои̑мъ. И҆ клевета́ша на бг҃а и҆ рѣ́ша: є҆да̀ возмо́жетъ бг҃ъ ᲂу҆гото́вати трапе́зꙋ въ пꙋсты́ни; Поне́же поразѝ ка́мень, и҆ потеко́ша во́ды, и҆ пото́цы наводни́шасѧ: є҆да̀ и҆ хлѣ́бъ мо́жетъ да́ти; и҆лѝ ᲂу҆гото́вати трапе́зꙋ лю́демъ свои̑мъ; Сегѡ̀ ра́ди слы́ша гдⷭ҇ь и҆ презрѣ̀, и҆ ѻ҆́гнь возгорѣ́сѧ во і҆а́кѡвѣ, и҆ гнѣ́въ взы́де на і҆и҃лѧ: Ꙗ҆́кѡ не вѣ́роваша бг҃ови, нижѐ ᲂу҆пова́ша на сп҃се́нїе є҆гѡ̀. И҆ заповѣ́да ѻ҆блакѡ́мъ свы́ше, и҆ двє́ри небесѐ ѿве́рзе: И҆ ѡ҆дождѝ и҆̀мъ ма́ннꙋ ꙗ҆́сти, и҆ хлѣ́бъ небе́сный дадѐ и҆̀мъ. Хлѣ́бъ а҆́гг҃льскїй ꙗ҆дѐ человѣ́къ: бра́шно посла̀ и҆̀мъ до сы́тости. Воздви́же ю҆́гъ съ небесѐ, и҆ наведѐ си́лою свое́ю лі́ва: И҆ ѡ҆дождѝ на нѧ̀ ꙗ҆́кѡ пра́хъ плѡ́ти, и҆ ꙗ҆́кѡ песо́къ морскі́й пти̑цы перна̑ты. И҆ нападо́ша посредѣ̀ ста́на и҆́хъ, ѡ҆́крестъ жили́щъ и҆́хъ. И҆ ꙗ҆до́ша и҆ насы́тишасѧ ѕѣлѡ̀, и҆ жела́нїе и҆́хъ пренесѐ и҆̀мъ. Не лиши́шасѧ ѿ жела́нїѧ своегѡ̀: є҆щѐ бра́шнꙋ сꙋ́щꙋ во ᲂу҆стѣ́хъ и҆́хъ, И҆ гнѣ́въ бж҃їй взы́де на нѧ̀, и҆ ᲂу҆бѝ мнѡ́жайшаѧ и҆́хъ, и҆ и҆збра̑ннымъ і҆и҃лєвымъ запѧ́тъ. Во всѣ́хъ си́хъ согрѣши́ша є҆щѐ и҆ не вѣ́роваша чꙋдесє́мъ є҆гѡ̀: И҆ и҆счезо́ша въ сꙋетѣ̀ дні́е и҆́хъ, и҆ лѣ̑та и҆́хъ со тща́нїемъ. Є҆гда̀ ᲂу҆бива́ше ѧ҆̀, тогда̀ взыска́хꙋ є҆го̀ и҆ ѡ҆браща́хꙋсѧ и҆ ᲂу҆́треневахꙋ къ бг҃ꙋ: И҆ помѧнꙋ́ша, ꙗ҆́кѡ бг҃ъ помо́щникъ и҆̀мъ є҆́сть, и҆ бг҃ъ вы́шнїй и҆зба́витель и҆̀мъ є҆́сть: И҆ возлюби́ша є҆го̀ ᲂу҆сты̑ свои́ми, и҆ ѧ҆зы́комъ свои́мъ солга́ша є҆мꙋ̀: Се́рдце же и҆́хъ не бѣ̀ пра́во съ ни́мъ, нижѐ ᲂу҆вѣ́ришасѧ въ завѣ́тѣ є҆гѡ̀. То́й же є҆́сть ще́дръ, и҆ ѡ҆чи́ститъ грѣхѝ и҆́хъ, и҆ не растли́тъ: и҆ ᲂу҆мно́житъ ѿврати́ти ꙗ҆́рость свою̀, и҆ не разжже́тъ всегѡ̀ гнѣ́ва своегѡ̀. И҆ помѧнꙋ̀, ꙗ҆́кѡ пло́ть сꙋ́ть, дꙋ́хъ ходѧ́й и҆ не ѡ҆браща́ѧйсѧ: Колькра́ты преѡгорчи́ша є҆го̀ въ пꙋсты́ни, прогнѣ́ваша є҆го̀ въ землѝ безво́днѣй; И҆ ѡ҆брати́шасѧ, и҆ и҆скꙋси́ша бг҃а, и҆ ст҃а́го і҆и҃лева раздражи́ша: И҆ не помѧнꙋ́ша рꙋкѝ є҆гѡ̀ въ де́нь, во́ньже и҆зба́ви ѧ҆̀ и҆з̾ рꙋкѝ ѡ҆скорблѧ́ющагѡ: Ꙗ҆́коже положѝ во є҆гѵ́птѣ зна́мєнїѧ своѧ̑, и҆ чꙋдеса̀ своѧ̑ на по́ли танеѡ́сѣ: И҆ преложѝ въ кро́вь рѣ́ки и҆́хъ и҆ и҆сто́чники и҆́хъ, ꙗ҆́кѡ да не пїю́тъ. Посла̀ на нѧ̀ пє́сїѧ мꙋ̑хи, и҆ поѧдо́ша ѧ҆̀, и҆ жа̑бы, и҆ растлѝ ѧ҆̀: И҆ дадѐ ржѣ̀ плоды̀ и҆́хъ, и҆ трꙋды̀ и҆́хъ прꙋгѡ́мъ. Оу҆бѝ гра́домъ вїногра́ды и҆́хъ и҆ черни́чїе и҆́хъ сла́ною: И҆ предадѐ гра́дꙋ скоты̀ и҆́хъ, и҆ и҆мѣ́нїе и҆́хъ ѻ҆гню̀. Посла̀ на нѧ̀ гнѣ́въ ꙗ҆́рости своеѧ̀, ꙗ҆́рость и҆ гнѣ́въ и҆ ско́рбь, посла́нїе а҆́ггєлы лю́тыми. Пꙋтесотворѝ стезю̀ гнѣ́вꙋ своемꙋ̀, и҆ не пощадѣ̀ ѿ сме́рти дꙋ́шъ и҆́хъ, и҆ скоты̀ и҆́хъ въ сме́рти заключѝ: И҆ поразѝ всѧ́кое перворо́дное въ землѝ є҆гѵ́петстѣй, нача́токъ всѧ́кагѡ трꙋда̀ и҆́хъ въ селе́нїихъ ха́мовыхъ. И҆ воздви́же ꙗ҆́кѡ ѻ҆́вцы лю́ди своѧ̑, и҆ возведѐ ѧ҆̀ ꙗ҆́кѡ ста́до въ пꙋсты́ни: И҆ наста́ви ѧ҆̀ на ᲂу҆пова́нїе, и҆ не ᲂу҆боѧ́шасѧ: и҆ врагѝ и҆́хъ покры̀ мо́ре. И҆ введѐ ѧ҆̀ въ го́рꙋ ст҃ы́ни своеѧ̀, го́рꙋ сїю̀, ю҆́же стѧжа̀ десни́ца є҆гѡ̀. И҆ и҆згна̀ ѿ лица̀ и҆́хъ ꙗ҆зы́ки, и҆ по жре́бїю дадѐ и҆̀мъ зе́млю ᲂу҆́жемъ жребодаѧ́нїѧ, и҆ вселѝ въ селе́нїихъ и҆́хъ кѡлѣ́на і҆и҃лєва. И҆ и҆скꙋси́ша и҆ преѡгорчи́ша бг҃а вы́шнѧго, и҆ свидѣ́нїй є҆гѡ̀ не сохрани́ша: И҆ ѿврати́шасѧ и҆ ѿверго́шасѧ, ꙗ҆́коже и҆ ѻ҆тцы̀ и҆́хъ: преврати́шасѧ въ лꙋ́къ развраще́нъ: И҆ прогнѣ́ваша є҆го̀ въ хо́лмѣхъ свои́хъ, и҆ во и҆стꙋка́нныхъ свои́хъ раздражи́ша є҆го̀. Слы́ша бг҃ъ и҆ презрѣ̀, и҆ ᲂу҆ничижѝ ѕѣлѡ̀ і҆и҃лѧ: И҆ ѿри́нꙋ ски́нїю силѡ́мскꙋю, селе́нїе є҆́же всели́сѧ въ человѣ́цѣхъ: И҆ предадѐ въ плѣ́нъ крѣ́пость и҆́хъ, и҆ добро́тꙋ и҆́хъ въ рꙋ́ки врагѡ́въ: И҆ затворѝ во ѻ҆рꙋ́жїи лю́ди своѧ̑ и҆ достоѧ́нїе своѐ презрѣ̀. Ю҆́ношы и҆́хъ поѧдѐ ѻ҆́гнь, и҆ дѣ̑вы и҆́хъ не ѡ҆сѣ́тѡваны бы́ша: Свѧще́нницы и҆́хъ мече́мъ падо́ша, и҆ вдови̑цы и҆́хъ не ѡ҆пла̑каны бꙋ́дꙋтъ. И҆ воста̀ ꙗ҆́кѡ спѧ̀ гдⷭ҇ь, ꙗ҆́кѡ си́ленъ и҆ шꙋ́менъ ѿ вїна̀: И҆ поразѝ врагѝ своѧ̑ вспѧ́ть, поноше́нїе вѣ́чное дадѐ и҆̀мъ: И҆ ѿри́нꙋ селе́нїе і҆ѡ́сифово, и҆ колѣ́но є҆фре́мово не и҆збра̀: И҆ и҆збра̀ колѣ́но і҆ꙋ́дово, го́рꙋ сїѡ́ню, ю҆́же возлюбѝ: И҆ созда̀ ꙗ҆́кѡ є҆диноро́га ст҃и́лище своѐ: на землѝ ѡ҆снова̀ и҆̀ въ вѣ́къ. И҆ и҆збра̀ дв҃да раба̀ своего̀, и҆ воспрїѧ́тъ є҆го̀ ѿ ста́дъ ѻ҆́вчихъ: Ѿ дои́лицъ поѧ́тъ є҆го̀, пастѝ і҆а́кѡва раба̀ своего̀, и҆ і҆и҃лѧ достоѧ́нїе своѐ. И҆ ᲂу҆пасѐ ѧ҆̀ въ неѕло́бїи се́рдца своегѡ̀, и҆ въ ра́зꙋмѣхъ рꙋкꙋ̀ своє́ю наста́вилъ ѧ҆̀ є҆́сть.",
  ["заголовок_ру"] = "Ра́зума Аса́фу.",
  ["заголовок_цс"] = "Ра́зꙋма а҆са́фꙋ."
}

