  ["слава"] = 2,
  ["текст_ру"] = "Бо́же, приидо́ша язы́цы в достоя́ние Твое́, оскверни́ша храм святы́й Твой, положи́ша Иерусали́м я́ко ово́щное храни́лище, положи́ша тру́пия раб Твои́х бра́шно пти́цам небе́сным, пло́ти преподо́бных Твои́х звере́м земны́м. Пролия́ша кровь их я́ко во́ду о́крест Иерусали́ма, и не бе погреба́яй. Бы́хом поноше́ние сосе́дом на́шым, подражне́ние и поруга́ние су́щым о́крест нас. Доко́ле, Го́споди, прогне́ваешися до конца́? Разжже́тся я́ко огнь рве́ние Твое́? Проле́й гнев Твой на язы́ки не зна́ющыя Тебе́, и на ца́рствия, я́же и́мене Твоего́ не призва́ша, я́ко поядо́ша Иа́кова, и ме́сто eго́ опустоши́ша. Не помяни́ на́ших беззако́ний пе́рвых: ско́ро да предваря́т ны щедро́ты Твоя́, Го́споди, я́ко обнища́хом зело́. Помози́ нам, Бо́же, Спаси́телю наш, сла́вы ра́ди и́мене Твоего́, Го́споди, изба́ви ны, и очи́сти грехи́ на́ша и́мене ра́ди Твоего́. Да не когда́ реку́т язы́цы, где есть Бог их? И да уве́стся во язы́цех пред очи́ма на́шима отмще́ние кро́ве раб Твои́х пролиты́я. Да вни́дет пред Тя воздыха́ние окова́нных, по вели́чию мы́шцы Твоея́ снабди́ сы́ны умерщвле́нных. Возда́ждь сосе́дом на́шым седмери́цею в не́дро их поноше́ние их, и́мже поноси́ша Тя, Го́споди. Мы же, лю́дие Твои́ и о́вцы па́жити Твоея́, испове́мыся Тебе́, Бо́же, во век, в род и род возвести́м хвалу́ Твою́.",
  ["текст_цс"] = "Бж҃е, прїидо́ша ꙗ҆зы́цы въ достоѧ́нїе твоѐ, ѡ҆скверни́ша хра́мъ ст҃ы́й тво́й, Положи́ша і҆ерⷭ҇ли́мъ ꙗ҆́кѡ ѻ҆во́щное храни́лище: положи́ша трꙋ̑пїѧ ра̑бъ твои́хъ бра́шно пти́цамъ небє́снымъ, плѡ́ти прпⷣбныхъ твои́хъ ѕвѣрє́мъ земны́мъ: Пролїѧ́ша кро́вь и҆́хъ ꙗ҆́кѡ во́дꙋ ѡ҆́крестъ і҆ерⷭ҇ли́ма, и҆ не бѣ̀ погреба́ѧй. Бы́хомъ поноше́нїе сосѣ́дѡмъ на́шымъ, подражне́нїе и҆ порꙋга́нїе сꙋ́щымъ ѡ҆́крестъ на́съ. Доко́лѣ, гдⷭ҇и, прогнѣ́ваешисѧ до конца̀; разжже́тсѧ ꙗ҆́кѡ ѻ҆́гнь рве́нїе твоѐ; Проле́й гнѣ́въ тво́й на ꙗ҆зы́ки незна́ющыѧ тебє̀, и҆ на ца̑рствїѧ, ꙗ҆̀же и҆́мене твоегѡ̀ не призва́ша: Ꙗ҆́кѡ поѧдо́ша і҆а́кѡва, и҆ мѣ́сто є҆гѡ̀ ѡ҆пꙋстоши́ша. Не помѧнѝ на́шихъ беззако́нїй пе́рвыхъ: ско́рѡ да предварѧ́тъ ны̀ щедрѡ́ты твоѧ̑, гдⷭ҇и, ꙗ҆́кѡ ѡ҆бнища́хомъ ѕѣлѡ̀. Помозѝ на́мъ, бж҃е, сп҃си́телю на́шъ, сла́вы ра́ди и҆́мене твоегѡ̀: гдⷭ҇и, и҆зба́ви ны̀ и҆ ѡ҆чи́сти грѣхѝ на́шѧ и҆́мене ра́ди твоегѡ̀. Да не когда̀ рекꙋ́тъ ꙗ҆зы́цы: гдѣ̀ є҆́сть бг҃ъ и҆́хъ; и҆ да ᲂу҆вѣ́стсѧ во ꙗ҆зы́цѣхъ пред̾ ѻ҆чи́ма на́шима ѿмще́нїе кро́ве ра̑бъ твои́хъ пролиты́ѧ. Да вни́детъ пред̾ тѧ̀ воздыха́нїе ѡ҆кова́нныхъ: по вели́чїю мы́шцы твоеѧ̀ снабдѝ сы́ны ᲂу҆мерщвле́нныхъ. Возда́ждь сосѣ́дѡмъ на́шымъ седмери́цею въ нѣ́дро и҆́хъ поноше́нїе и҆́хъ, и҆́мже поноси́ша тѧ̀, гдⷭ҇и. Мы́ же лю́дїе твоѝ и҆ ѻ҆́вцы па́жити твоеѧ̀ и҆сповѣ́мысѧ тебѣ̀, бж҃е, во вѣ́къ, въ ро́дъ и҆ ро́дъ возвѣсти́мъ хвалꙋ̀ твою̀.",
  ["заголовок_ру"] = "Псало́м Аса́фу.",
  ["заголовок_цс"] = "Ѱало́мъ а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 79,
  ["часть"] = 1,
  ["кафизма"] = 11,
  ["слава"] = 2,
  ["текст_ру"] = "Пасы́й Изра́иля вонми́: наставля́яй я́ко овча́ Ио́сифа, седя́й на Херуви́мех, яви́ся, пред Ефре́мом и Beниами́ном и Манасси́ем, воздви́гни си́лу Твою́, и прииди́ во е́же спасти́ нас. Бо́же, обрати́ ны, и просвети́ лице́ Твое́, и спасе́мся. Го́споди Бо́же Сил, доко́ле гне́ваешися на моли́тву раб Твои́х? Напита́еши нас хле́бом сле́зным, и напои́ши нас слеза́ми в ме́ру. Положи́л еси́ нас в пререка́ние сосе́дом на́шым, и врази́ на́ши подражни́ша ны. Го́споди Бо́же Сил, обрати́ ны, и просвети́ лице́ Твое́, и спасе́мся. Виногра́д из Еги́пта прене́сл еси́, изгна́л еси́ язы́ки, и насади́л еси́ и́. Путесотвори́л еси́ пред ним, и насади́л еси́ коре́ния eго́, и испо́лни зе́млю. Покры́ го́ры сень eго́, и ве́твия eго́ ке́дры Бо́жия; простре́ ро́зги eго́ до мо́ря, и да́же до рек о́трасли eго́. Вску́ю низложи́л еси́ опло́т eго́, и объима́ют и́ вси мимоходя́щии путе́м? Озоба́ и́ вепрь от дубра́вы, и уедине́нный ди́вий пояде́ и́. Бо́же Сил, обрати́ся у́бо, и при́зри с небесе́ и виждь, и посети́ виногра́д сей, и соверши́ и́, eго́же насади́ десни́ца Твоя́, и на сы́на челове́ческаго, eго́же укрепи́л еси́ Себе́. Пожже́н огне́м и раско́пан, от запреще́ния лица́ Твоего́ поги́бнут. Да бу́дет рука́ Твоя́ на му́жа десни́цы Твоея́, и на сы́на челове́ческаго, eго́же укрепи́л еси́ Себе́, и не отсту́пим от Тебе́; оживи́ши ны, и и́мя Твое́ призове́м. Го́споди Бо́же Сил, обрати́ ны, и просвети́ лице́ Твое́, и спасе́мся.",
  ["текст_цс"] = "Пасы́й і҆и҃лѧ вонмѝ: наставлѧ́ѧй ꙗ҆́кѡ ѻ҆вча̀ і҆ѡ́сифа, сѣдѧ́й на херꙋві́мѣхъ, ꙗ҆ви́сѧ: Пред̾ є҆фре́момъ и҆ венїамі́номъ и҆ манассі́емъ воздви́гни си́лꙋ твою̀, и҆ прїидѝ во є҆́же сп҃стѝ на́съ. Бж҃е, ѡ҆брати́ ны, и҆ просвѣтѝ лицѐ твоѐ, и҆ спасе́мсѧ. Гдⷭ҇и бж҃е си́лъ, доко́лѣ гнѣ́ваешисѧ на моли́твꙋ ра̑бъ твои́хъ; Напита́еши на́съ хлѣ́бомъ сле́знымъ, и҆ напои́ши на́съ слеза́ми въ мѣ́рꙋ. Положи́лъ є҆сѝ на́съ въ прерѣка́нїе сосѣ́дѡмъ на́шымъ, и҆ вразѝ на́ши подражни́ша ны̀. Гдⷭ҇и бж҃е си́лъ, ѡ҆брати́ ны, и҆ просвѣтѝ лицѐ твоѐ, и҆ спасе́мсѧ. Вїногра́дъ и҆з̾ є҆гѵ́пта прене́слъ є҆сѝ: и҆згна́лъ є҆сѝ ꙗ҆зы́ки, и҆ насади́лъ є҆сѝ и҆̀: Пꙋтесотвори́лъ є҆сѝ пред̾ ни́мъ, и҆ насади́лъ є҆сѝ корє́нїѧ є҆гѡ̀, и҆ и҆спо́лни зе́млю. Покры̀ го́ры сѣ́нь є҆гѡ̀, и҆ вѣ̑твїѧ є҆гѡ̀ ке́дры бж҃їѧ: Прострѐ ро́зги є҆гѡ̀ до мо́рѧ, и҆ да́же до рѣ́къ ѻ҆́трасли є҆гѡ̀. Вскꙋ́ю низложи́лъ є҆сѝ ѡ҆пло́тъ є҆гѡ̀, и҆ ѡ҆б̾има́ютъ и҆̀ всѝ мимоходѧ́щїи пꙋте́мъ; Ѡ҆зоба̀ и҆̀ ве́прь ѿ дꙋбра́вы, и҆ ᲂу҆едине́нный ди́вїй поѧдѐ и҆̀. Бж҃е си́лъ, ѡ҆брати́сѧ ᲂу҆̀бо, и҆ при́зри съ нб҃сѐ и҆ ви́ждь, и҆ посѣтѝ вїногра́дъ се́й: И҆ совершѝ и҆̀, є҆го́же насадѝ десни́ца твоѧ̀, и҆ на сы́на человѣ́ческаго, є҆го́же ᲂу҆крѣпи́лъ є҆сѝ себѣ̀. Пожже́нъ ѻ҆гне́мъ и҆ раско́панъ: ѿ запреще́нїѧ лица̀ твоегѡ̀ поги́бнꙋтъ. Да бꙋ́детъ рꙋка̀ твоѧ̀ на мꙋ́жа десни́цы твоеѧ̀ и҆ на сы́на человѣ́ческаго, є҆го́же ᲂу҆крѣпи́лъ є҆сѝ себѣ̀, И҆ не ѿстꙋ́пимъ ѿ тебє̀: ѡ҆живи́ши ны̀, и҆ и҆́мѧ твоѐ призове́мъ. Гдⷭ҇и бж҃е си́лъ, ѡ҆брати́ ны, и҆ просвѣтѝ лицѐ твоѐ, и҆ спасе́мсѧ.",
  ["заголовок_ру"] = "В коне́ц, о изме́ншихся, свиде́ние Аса́фу, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ и҆змѣ́ншихсѧ, свидѣ́нїе а҆са́фꙋ, ѱало́мъ."
}

add_psalom {
  ["номер"] = 80,
  ["часть"] = 1,
  ["кафизма"] = 11,
  ["слава"] = 2,
  ["текст_ру"] = "Ра́дуйтеся Бо́гу, Помо́щнику на́шему, воскли́кните Бо́гу Иа́ковлю, приими́те псало́м и дади́те тимпа́н, псалти́рь красе́н с гу́сльми, воструби́те в новоме́сячии трубо́ю, во благознамени́тый день пра́здника ва́шего, я́ко повеле́ние Изра́илеви есть, и судьба́ Бо́гу Иа́ковлю. Свиде́ние во Ио́сифе положи́ е́, внегда́ изы́ти eму́ от земли́ Еги́петския, язы́ка eго́же не ве́дяше услы́ша. Отъя́т от бре́мене хребе́т eго́, ру́це eго́ в коши́ порабо́тасте. В ско́рби призва́л Мя еси́, и изба́вих тя, услы́шах тя в та́йне бу́рне, искуси́х тя на воде́ пререка́ния. Слы́шите, лю́дие мои́, и засвиде́тельствую вам, Изра́илю, а́ще послу́шаеши Мене́. Не бу́дет Тебе́ бог нов, ниже́ поклони́шися бо́гу чужде́му. Аз бо есмь Госпо́дь Бог твой, изведы́й тя от земли́ Еги́петския, разшири́ уста́ Твоя́, и испо́лню я́. И не послу́шаша лю́дие мои́ гла́са Моего́, и Изра́иль не внят Ми: и отпусти́х я́ по начина́нием серде́ц их, по́йдут в начина́ниих свои́х. А́ще бы́ша лю́дие Мои́ послу́шали Мене́, Изра́иль а́ще бы в пути́ Моя́ ходи́л, ни о чесо́м же у́бо враги́ eго́ смири́л бых, и на оскорбля́юшыя их возложи́л бых ру́ку Мою́. Врази́ Госпо́дни солга́ша Eму́, и бу́дет вре́мя их в век. И напита́ их от ту́ка пшени́чна, и от ка́мене ме́да насы́ти их.",
  ["текст_цс"] = "Ра́дꙋйтесѧ бг҃ꙋ помо́щникꙋ на́шемꙋ, воскли́кните бг҃ꙋ і҆а́кѡвлю: Прїими́те ѱало́мъ и҆ дади́те тѷмпа́нъ, ѱалти́рь красе́нъ съ гꙋ́сльми: Вострꙋби́те въ новомѣ́сѧчїи трꙋбо́ю, во бл҃гознамени́тый де́нь пра́здника ва́шегѡ: Ꙗ҆́кѡ повелѣ́нїе і҆и҃леви є҆́сть, и҆ сꙋдьба̀ бг҃ꙋ і҆а́кѡвлю. Свидѣ́нїе во і҆ѡ́сифѣ положѝ є҆̀, внегда̀ и҆зы́ти є҆мꙋ̀ ѿ землѝ є҆гѵ́петскїѧ: ѧ҆зы́ка, є҆гѡ́же не вѣ́дѧше, ᲂу҆слы́ша. Ѿѧ́тъ ѿ бре́мене хребе́тъ є҆гѡ̀: рꙋ́цѣ є҆гѡ̀ въ кошѝ порабо́тастѣ. Въ ско́рби призва́лъ мѧ̀ є҆сѝ, и҆ и҆зба́вихъ тѧ̀: ᲂу҆слы́шахъ тѧ̀ въ та́йнѣ бꙋ́рнѣ: и҆скꙋси́хъ тѧ̀ на водѣ̀ прерѣка́нїѧ. Слы́шите, лю́дїе моѝ, и҆ засвидѣ́тельствꙋю ва́мъ, і҆и҃лю, а҆́ще послꙋ́шаеши менѐ: Не бꙋ́детъ тебѣ̀ бо́гъ но́въ, нижѐ поклони́шисѧ бо́гꙋ чꙋжде́мꙋ. А҆́зъ бо є҆́смь гдⷭ҇ь бг҃ъ тво́й, и҆зведы́й тѧ̀ ѿ землѝ є҆гѵ́петскїѧ: разширѝ ᲂу҆ста̀ твоѧ̀, и҆ и҆спо́лню ѧ҆̀. И҆ не послꙋ́шаша лю́дїе моѝ гла́са моегѡ̀, и҆ і҆и҃ль не внѧ́тъ мѝ: И҆ ѿпꙋсти́хъ ѧ҆̀ по начина́нїємъ серде́цъ и҆́хъ, по́йдꙋтъ въ начина́нїихъ свои́хъ. А҆́ще бы́ша лю́дїе моѝ послꙋ́шали менѐ, і҆и҃ль а҆́ще бы въ пꙋти̑ моѧ̑ ходи́лъ: Ни ѡ҆ чесо́мъ же ᲂу҆́бѡ врагѝ є҆гѡ̀ смири́лъ бы́хъ, и҆ на ѡ҆скорблѧ́ющыѧ и҆̀хъ возложи́лъ бы́хъ рꙋ́кꙋ мою̀. Вразѝ гдⷭ҇ни солга́ша є҆мꙋ̀, и҆ бꙋ́детъ вре́мѧ и҆́хъ въ вѣ́къ: И҆ напита̀ и҆̀хъ ѿ тꙋ́ка пшени́чна, и҆ ѿ ка́мене ме́да насы́ти и҆̀хъ.",
  ["заголовок_ру"] = "В коне́ц, о точи́лех, псало́м Аса́фу.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ точи́лѣхъ, ѱало́мъ а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 81,
  ["часть"] = 1,
  ["кафизма"] = 11,
  ["слава"] = 3,
  ["текст_ру"] = "Бог ста в со́нме бого́в, посреде́ же бо́ги разсу́дит. Доко́ле су́дите непра́вду, и ли́ца гре́шников прие́млете? Суди́те си́ру и убо́гу, смире́на и ни́ща оправда́йте. Изми́те ни́ща и убо́га, из руки́ гре́шничи изба́вите eго́. Не позна́ша, ниже́ уразуме́ша, во тьме хо́дят: да подви́жатся вся основа́ния земли́. Аз рех: бо́зи есте́, и сы́нове Вы́шняго вси. Вы же я́ко челове́цы умира́ете, и я́ко еди́н от князе́й па́даете. Воскресни́, Бо́же, суди́ земли́: я́ко Ты насле́диши во всех язы́цех.",
  ["текст_цс"] = "Бг҃ъ ста̀ въ со́нмѣ богѡ́въ, посредѣ́ же бо́ги разсꙋ́дитъ. Доко́лѣ сꙋ́дите непра́вдꙋ, и҆ ли́ца грѣ́шникѡвъ прїе́млете; Сꙋди́те си́рꙋ и҆ ᲂу҆бо́гꙋ, смире́на и҆ ни́ща ѡ҆правда́йте: И҆зми́те ни́ща и҆ ᲂу҆бо́га, и҆з̾ рꙋкѝ грѣ́шничи и҆зба́вите є҆го̀. Не позна́ша, нижѐ ᲂу҆разꙋмѣ́ша, во тмѣ̀ хо́дѧтъ: да подви́жатсѧ всѧ̑ ѡ҆снова̑нїѧ землѝ. А҆́зъ рѣ́хъ: бо́зи є҆стѐ, и҆ сы́нове вы́шнѧгѡ всѝ: Вы́ же ꙗ҆́кѡ человѣ́цы ᲂу҆мира́ете, и҆ ꙗ҆́кѡ є҆ди́нъ ѿ кнѧзе́й па́даете. Воскрⷭ҇нѝ, бж҃е, сꙋдѝ землѝ: ꙗ҆́кѡ ты̀ наслѣ́диши во всѣ́хъ ꙗ҆зы́цѣхъ.",
  ["заголовок_ру"] = "Псало́м Аса́фу.",
  ["заголовок_цс"] = "Ѱало́мъ а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 82,
  ["часть"] = 1,
  ["кафизма"] = 11,
  ["слава"] = 3,
  ["текст_ру"] = "Бо́же, кто уподо́бится Тебе́? Не премолчи́ ниже́ укроти́, Бо́же. Я́ко се врази́ Твои́ возшуме́ша, и ненави́дящии Тя воздвиго́ша главу́. На лю́ди Твоя́ лука́вноваша во́лею, и совеща́ша на святы́я Твоя́. Ре́ша: прииди́те и потреби́м я́ от язы́к, и не помяне́тся и́мя Изра́илево ктому́. Я́ко совеща́ша единомышле́нием вку́пе, на Тя заве́т завеща́ша: селе́ния Идуме́йска, и Исма́илите, Моа́в и Ага́ряне: Гева́л и Аммо́н и Амали́к, иноплеме́нницы с живу́щими в Ти́ре, и́бо и Ассу́р прии́де с ни́ми, бы́ша в заступле́ние сыново́м Ло́товым. Сотвори́ им я́ко Мадиа́му и Сиса́ре, я́ко Иави́му в пото́це Ки́ссове. Потреби́шася во Аендо́ре, бы́ша я́ко гной земны́й. Положи́ кня́зи их, я́ко Ори́ва и Зи́ва, и Зеве́а и Салма́на, вся кня́зи их, и́же ре́ша: да насле́дим себе́ святи́лише Бо́жие. Бо́же мой, положи́ я́ я́ко ко́ло, я́ко трость пред лице́м ве́тра. Я́ко огнь попаля́яй дубра́вы, я́ко пла́мень пожига́яй го́ры, та́ко пожене́ши я́ бу́рею Твое́ю, и гне́вом Твои́м смяте́ши я́. Испо́лни ли́ца их безче́стия, и взы́щут и́мене Твоего́, Го́споди. Да постыдя́тся и смяту́тся в век ве́ка, и посра́мятся и поги́бнут. И да позна́ют, я́ко и́мя Тебе́ Госпо́дь, Ты еди́н Вы́шний по всей земли́.",
  ["текст_цс"] = "Бж҃е, кто̀ ᲂу҆подо́битсѧ тебѣ̀; не премолчѝ, нижѐ ᲂу҆кротѝ, бж҃е: Ꙗ҆́кѡ сѐ, вразѝ твоѝ возшꙋмѣ́ша, и҆ ненави́дѧщїи тѧ̀ воздвиго́ша главꙋ̀. На лю́ди твоѧ̑ лꙋка́вноваша во́лею, и҆ совѣща́ша на ст҃ы̑ѧ твоѧ̑. Рѣ́ша: прїиди́те и҆ потреби́мъ ѧ҆̀ ѿ ꙗ҆зы̑къ, и҆ не помѧне́тсѧ и҆́мѧ і҆и҃лево ктомꙋ̀. Ꙗ҆́кѡ совѣща́ша є҆диномышле́нїемъ вкꙋ́пѣ, на тѧ̀ завѣ́тъ завѣща́ша: Селє́нїѧ і҆дꙋмє́йска и҆ і҆сма́илїте, мѡа́въ и҆ а҆га́рѧне, Гева́лъ и҆ а҆ммѡ́нъ и҆ а҆мали́къ, и҆ноплемє́нницы съ живꙋ́щими въ тѵ́рѣ: И҆́бо и҆ а҆ссꙋ́ръ прїи́де съ ни́ми, бы́ша въ застꙋпле́нїе сыновѡ́мъ лѡ́тѡвымъ: Сотворѝ и҆̀мъ ꙗ҆́кѡ мадїа́мꙋ и҆ сїса́рѣ, ꙗ҆́кѡ і҆аві́мꙋ въ пото́цѣ кі́ссовѣ: Потреби́шасѧ во а҆ендѡ́рѣ, бы́ша ꙗ҆́кѡ гно́й земны́й. Положѝ кнѧ̑зи и҆́хъ ꙗ҆́кѡ ѻ҆ри́ва и҆ зи́ва, и҆ зеве́а и҆ салма́на, всѧ̑ кнѧ̑зи и҆́хъ, И҆́же рѣ́ша: да наслѣ́димъ себѣ̀ ст҃и́лище бж҃їе. Бж҃е мо́й, положѝ ѧ҆̀ ꙗ҆́кѡ ко́ло, ꙗ҆́кѡ тро́сть пред̾ лице́мъ вѣ́тра. Ꙗ҆́кѡ ѻ҆́гнь попалѧ́ѧй дꙋбра̑вы, ꙗ҆́кѡ пла́мень пожига́ѧй го́ры: Та́кѡ пожене́ши ѧ҆̀ бꙋ́рею твое́ю, и҆ гнѣ́вомъ твои́мъ смѧте́ши ѧ҆̀. И҆спо́лни ли́ца и҆́хъ безче́стїѧ, и҆ взы́щꙋтъ и҆́мене твоегѡ̀, гдⷭ҇и. Да постыдѧ́тсѧ и҆ смѧтꙋ́тсѧ въ вѣ́къ вѣ́ка, и҆ посра́мѧтсѧ и҆ поги́бнꙋтъ. И҆ да позна́ютъ, ꙗ҆́кѡ и҆́мѧ тебѣ̀ гдⷭ҇ь, ты̀ є҆ди́нъ вы́шнїй по все́й землѝ.",
  ["заголовок_ру"] = "Песнь псалма́ Аса́фу.",
  ["заголовок_цс"] = "Пѣ́снь ѱалма̀ а҆са́фꙋ."
}

add_psalom {
  ["номер"] = 83,
  ["часть"] = 1,
  ["кафизма"] = 11,
  ["слава"] = 3,
  ["текст_ру"] = "Коль возлю́бленна селе́ния Твоя́, Го́споди Сил! Жела́ет и скончава́ется душа́ моя́ во дворы́ Госпо́дни, се́рдце мое́ и плоть моя́ возра́довастася о Бо́зе жи́ве. И́бо пти́ца обре́те себе́ хра́мину, и го́рлица гнездо́ себе́, иде́же положи́т птенцы́ своя́, олтари́ Твоя́, Го́споди Сил, Царю́ мой и Бо́же мой. Блаже́ни живу́щии в дому́ Твое́м, в ве́ки веко́в восхва́лят Тя. Блаже́н муж, eму́же есть заступле́ние eго́ у Тебе́; восхожде́ния в се́рдце свое́м положи́, во юдо́ль плаче́вную, в ме́сто е́же положи́, и́бо благослове́ние даст законополага́яй. По́йдут от си́лы в си́лу: яви́тся Бог бого́в в Сио́не. Го́споди Бо́же Сил, услы́ши моли́тву мою́, внуши́, Бо́же Иа́ковль. Защи́тниче наш, виждь, Бо́же, и при́зри на лице́ христа́ Твоего́. Я́ко лу́чше день еди́н во дво́рех Твои́х па́че ты́сящ: изво́лих примета́тися в дому́ Бо́га моего́ па́че, не́же жи́ти ми в селе́ниих гре́шничих. Я́ко ми́лость и и́стину лю́бит Госпо́дь, Бог благода́ть и сла́ву даст, Госпо́дь не лиши́т благи́х ходя́щих незло́бием. Го́споди Бо́же Сил, Блаже́н челове́к упова́яй на Тя.",
  ["текст_цс"] = "Ко́ль возлю́блєнна селє́нїѧ твоѧ̑, гдⷭ҇и си́лъ. Жела́етъ и҆ скончава́етсѧ дꙋша̀ моѧ̀ во дворы̀ гдⷭ҇ни: се́рдце моѐ и҆ пло́ть моѧ̀ возра́довастасѧ ѡ҆ бз҃ѣ жи́вѣ. И҆́бо пти́ца ѡ҆брѣ́те себѣ̀ хра́минꙋ, и҆ го́рлица гнѣздо̀ себѣ̀, и҆дѣ́же положи́тъ птенцы̀ своѧ̑, ѻ҆лтарѝ твоѧ̑, гдⷭ҇и си́лъ, цр҃ю̀ мо́й и҆ бж҃е мо́й. Бл҃же́ни живꙋ́щїи въ домꙋ̀ твое́мъ: въ вѣ́ки вѣкѡ́въ восхва́лѧтъ тѧ̀. Бл҃же́нъ мꙋ́жъ, є҆мꙋ́же є҆́сть застꙋпле́нїе є҆гѡ̀ ᲂу҆ тебє̀: восхождє́нїѧ въ се́рдцы свое́мъ положѝ, Во ю҆до́ль плаче́внꙋю, въ мѣ́сто є҆́же положѝ и҆́бо бл҃гослове́нїе да́стъ законополага́ѧй. По́йдꙋтъ ѿ си́лы въ си́лꙋ: ꙗ҆ви́тсѧ бг҃ъ богѡ́въ въ сїѡ́нѣ. Гдⷭ҇и бж҃е си́лъ, ᲂу҆слы́ши моли́твꙋ мою̀, внꙋшѝ, бж҃е і҆а́кѡвль. Защи́тниче на́шъ, ви́ждь, бж҃е, и҆ при́зри на лицѐ хрїста̀ твоегѡ̀. Ꙗ҆́кѡ лꙋ́чше де́нь є҆ди́нъ во дво́рѣхъ твои́хъ па́че ты́сѧщъ: и҆зво́лихъ примета́тисѧ въ домꙋ̀ бг҃а моегѡ̀ па́че, не́же жи́ти мѝ въ селе́нїихъ грѣ́шничихъ. Ꙗ҆́кѡ млⷭ҇ть и҆ и҆́стинꙋ лю́битъ гдⷭ҇ь, бг҃ъ блгⷣть и҆ сла́вꙋ да́стъ: гдⷭ҇ь не лиши́тъ бл҃ги́хъ ходѧ́щихъ неѕло́бїемъ. Гдⷭ҇и бж҃е си́лъ, бл҃же́нъ человѣ́къ ᲂу҆пова́ѧй на тѧ̀.",
  ["заголовок_ру"] = "В коне́ц, о точи́лех, сыно́м Коре́овым, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, ѡ҆ точи́лѣхъ, сынѡ́мъ коре́ѡвымъ, ѱало́мъ."
}

add_psalom {
  ["номер"] = 84,
  ["часть"] = 1,
  ["кафизма"] = 11,
  ["слава"] = 3,
  ["текст_ру"] = "Благоволи́л еси́, Го́споди, зе́млю Твою́, возврати́л еси́ плен Иа́ковль: оста́вил еси́ беззако́ния люде́й Твои́х, покры́л еси́ вся грехи́ их. Укроти́л еси́ весь гнев Твой, возврати́лся еси́ от гне́ва я́рости Твоея́. Возврати́ нас, Бо́же спасе́ний на́ших, и отврати́ я́рость Твою́ от нас. Еда́ во ве́ки прогне́ваешися на ны? Или́ простре́ши гнев Твой от ро́да в род? Бо́же, Ты обра́щься оживи́ши ны, и лю́дие Твои́ возвеселя́тся о Тебе́. Яви́ нам, Го́споди, ми́лость Твою́, и спасе́ние Твое́ даждь нам. Услы́шу, что рече́т о мне Госпо́дь Бог: я́ко рече́т мир на лю́ди Своя́, и на преподо́бныя Своя́, и на обраща́ющыя сердца́ к Нему́. Оба́че близ боя́щихся Его́ спасе́ние Его́, всели́ти сла́ву в зе́млю на́шу. Ми́лость и и́стина срето́стеся, пра́вда и мир облобыза́стася. И́стина от земли́ возсия́, и пра́вда с небесе́ прини́че, и́бо Госпо́дь даст бла́гость, и земля́ на́ша даст плод свой. Пра́вда пред Ним предъи́дет, и положи́т в путь стопы́ своя́.",
  ["текст_цс"] = "Бл҃говоли́лъ є҆сѝ, гдⷭ҇и, зе́млю твою̀, возврати́лъ є҆сѝ плѣ́нъ і҆а́кѡвль. Ѡ҆ста́вилъ є҆сѝ беззакѡ́нїѧ люде́й твои́хъ, покры́лъ є҆сѝ всѧ̑ грѣхѝ и҆́хъ. Оу҆кроти́лъ є҆сѝ ве́сь гнѣ́въ тво́й, возврати́лсѧ є҆сѝ ѿ гнѣ́ва ꙗ҆́рости твоеѧ̀. Возвратѝ на́съ, бж҃е сп҃се́нїй на́шихъ, и҆ ѿвратѝ ꙗ҆́рость твою̀ ѿ на́съ. Є҆да̀ во вѣ́ки прогнѣ́ваешисѧ на ны̀; и҆лѝ простре́ши гнѣ́въ тво́й ѿ ро́да въ ро́дъ; Бж҃е, ты̀ ѡ҆бра́щьсѧ ѡ҆живи́ши ны̀, и҆ лю́дїе твоѝ возвеселѧ́тсѧ ѡ҆ тебѣ̀. Ꙗ҆вѝ на́мъ, гдⷭ҇и, млⷭ҇ть твою̀, и҆ сп҃се́нїе твоѐ да́ждь на́мъ. Оу҆слы́шꙋ, что̀ рече́тъ ѡ҆ мнѣ̀ гдⷭ҇ь бг҃ъ: ꙗ҆́кѡ рече́тъ ми́ръ на лю́ди своѧ̑, и҆ на прпⷣбныѧ своѧ̑, и҆ на ѡ҆браща́ющыѧ сердца̀ къ немꙋ̀. Ѻ҆ба́че бли́з̾ боѧ́щихсѧ є҆гѡ̀ сп҃се́нїе є҆гѡ̀, всели́ти сла́вꙋ въ зе́млю на́шꙋ. Млⷭ҇ть и҆ и҆́стина срѣто́стѣсѧ, пра́вда и҆ ми́ръ ѡ҆блобыза́стасѧ: И҆́стина ѿ землѝ возсїѧ̀, и҆ пра́вда съ нб҃сѐ прини́че: И҆́бо гдⷭ҇ь да́стъ бл҃гость, и҆ землѧ̀ на́ша да́стъ пло́дъ сво́й. Пра́вда пред̾ ни́мъ пред̾и́детъ, и҆ положи́тъ въ пꙋ́ть стѡпы̀ своѧ̑.",
  ["заголовок_ру"] = "В коне́ц, сыно́м Коре́овым, псало́м.",
  ["заголовок_цс"] = "Въ коне́цъ, сынѡ́мъ коре́ѡвымъ, ѱало́мъ."
}

