  ["кафизма"] = 12,
  ["слава"] = 1,
  ["текст_ру"] = "Приклони́, Го́споди, у́хо Твое́, и услы́ши мя, я́ко нищ и убо́г есмь аз. Сохрани́ ду́шу мою́, я́ко преподо́бен есмь: спаси́ раба́ Твоего́, Бо́же мой, упова́ющаго на Тя. Поми́луй мя, Го́споди, я́ко к Тебе́ воззову́ весь день. Возвесели́ ду́шу раба́ Твоего́, я́ко к Тебе́ взях ду́шу мою́. Я́ко Ты, Го́споди, благ и кро́ток, и многоми́лостив всем призыва́ющым Тя. Внуши́, Го́споди, моли́тву мою́, и вонми́ гла́су моле́ния моего́. В день ско́рби моея́ воззва́х к Тебе́, я́ко услы́шал мя еси́. Несть подо́бен Тебе́ в бозе́х, Го́споди, и несть по дело́м Твои́м. Вси язы́цы, ели́ки сотвори́л еси́, прии́дут и покло́нятся пред Тобо́ю, Го́споди, и просла́вят и́мя Твое́, я́ко ве́лий еси́ Ты, и творя́й чудеса́, Ты еси́ Бог еди́н. Наста́ви мя, Го́споди, на путь Твой, и пойду́ во и́стине Твое́й; да возвесели́тся се́рдце мое́ боя́тися и́мене Твоего́. Испове́мся Тебе́, Го́споди Бо́же мой, всем се́рдцем мои́м, и просла́влю и́мя Твое́ в век: я́ко ми́лость Твоя́ ве́лия на мне, и изба́вил еси́ ду́шу мою́ от а́да преиспо́днейшаго. Бо́же, законопресту́пницы воста́ша на мя, и сонм держа́вных взыска́ша ду́шу мою́, и не предложи́ша Тебе́ пред собо́ю. И Ты, Го́споди Бо́же мой, ще́дрый и ми́лостивый, долготерпели́вый, и многоми́лостивый и и́стинный, при́зри на мя и поми́луй мя, даждь держа́ву Твою́ о́троку Твоему́, и спаси́ сы́на рабы́ Твоея́. Сотвори́ со мно́ю зна́мение во бла́го, и да ви́дят ненави́дящии мя, и постыдя́тся, я́ко Ты, Го́споди, помо́гл ми и уте́шил мя еси́.",
  ["текст_цс"] = "Приклонѝ, гдⷭ҇и, ᲂу҆́хо твоѐ, и҆ ᲂу҆слы́ши мѧ̀: ꙗ҆́кѡ ни́щъ и҆ ᲂу҆бо́гъ є҆́смь а҆́зъ. Сохранѝ дꙋ́шꙋ мою̀, ꙗ҆́кѡ прпⷣбенъ є҆́смь: сп҃сѝ раба̀ твоего̀, бж҃е мо́й, ᲂу҆пова́ющаго на тѧ̀. Поми́лꙋй мѧ̀, гдⷭ҇и, ꙗ҆́кѡ къ тебѣ̀ воззовꙋ̀ ве́сь де́нь. Возвеселѝ дꙋ́шꙋ раба̀ твоегѡ̀: ꙗ҆́кѡ къ тебѣ̀ взѧ́хъ дꙋ́шꙋ мою̀. Ꙗ҆́кѡ ты̀, гдⷭ҇и, бл҃гъ и҆ кро́токъ и҆ многомлⷭ҇тивъ всѣ̑мъ призыва́ющымъ тѧ̀. Внꙋшѝ, гдⷭ҇и, моли́твꙋ мою̀ и҆ вонмѝ гла́сꙋ моле́нїѧ моегѡ̀. Въ де́нь ско́рби моеѧ̀ воззва́хъ къ тебѣ̀, ꙗ҆́кѡ ᲂу҆слы́шалъ мѧ̀ є҆сѝ. Нѣ́сть подо́бенъ тебѣ̀ въ бозѣ́хъ, гдⷭ҇и, и҆ нѣ́сть по дѣлѡ́мъ твои̑мъ. Всѝ ꙗ҆зы́цы, є҆ли́ки сотвори́лъ є҆сѝ, прїи́дꙋтъ и҆ покло́нѧтсѧ пред̾ тобо́ю, гдⷭ҇и, и҆ просла́вѧтъ и҆́мѧ твоѐ: Ꙗ҆́кѡ ве́лїй є҆сѝ ты̀ и҆ творѧ́й чꙋдеса̀, ты̀ є҆сѝ бг҃ъ є҆ди́нъ. Наста́ви мѧ̀, гдⷭ҇и, на пꙋ́ть тво́й, и҆ пойдꙋ̀ во и҆́стинѣ твое́й: да возвесели́тсѧ се́рдце моѐ боѧ́тисѧ и҆́мене твоегѡ̀. И҆сповѣ́мсѧ тебѣ̀, гдⷭ҇и бж҃е мо́й, всѣ́мъ се́рдцемъ мои́мъ и҆ просла́влю и҆́мѧ твоѐ въ вѣ́къ: Ꙗ҆́кѡ млⷭ҇ть твоѧ̀ ве́лїѧ на мнѣ̀, и҆ и҆зба́вилъ є҆сѝ дꙋ́шꙋ мою̀ ѿ а҆́да преиспо́днѣйшагѡ. Бж҃е, законопрестꙋ̑пницы воста́ша на мѧ̀, и҆ со́нмъ держа́вныхъ взыска́ша дꙋ́шꙋ мою̀, и҆ не предложи́ша тебѐ пред̾ собо́ю. И҆ ты̀, гдⷭ҇и бж҃е мо́й, ще́дрый и҆ млⷭ҇тивый, долготерпѣли́вый и҆ многомлⷭ҇тивый и҆ и҆́стинный, При́зри на мѧ̀ и҆ поми́лꙋй мѧ̀: да́ждь держа́вꙋ твою̀ ѻ҆́трокꙋ твоемꙋ̀ и҆ сп҃сѝ сы́на рабы̀ твоеѧ̀. Сотворѝ со мно́ю зна́менїе во бл҃го: и҆ да ви́дѧтъ ненави́дѧщїи мѧ̀, и҆ постыдѧ́тсѧ, ꙗ҆́кѡ ты̀, гдⷭ҇и, помо́глъ мѝ и҆ ᲂу҆тѣ́шилъ мѧ̀ є҆сѝ.",
  ["заголовок_ру"] = "Моли́тва Дави́ду.",
  ["заголовок_цс"] = "Мл҃тва дв҃дꙋ."
}

add_psalom {
  ["номер"] = 86,
  ["часть"] = 1,
  ["кафизма"] = 12,
  ["слава"] = 1,
  ["текст_ру"] = "Основа́ния eго́ на гора́х святы́х; лю́бит Госпо́дь врата́ Сио́ня па́че всех селе́ний Иа́ковлих. Пресла́вная глаго́лашася о тебе́, гра́де Бо́жий. Помяну́ Раа́в и Вавило́на ве́дущым мя, и се иноплеме́нницы, и Тир, и лю́дие Ефио́пстии, си́и бы́ша та́мо. Ма́ти Сио́н рече́т: челове́к, и челове́к роди́ся в нем, и Той основа́ и́ Вы́шний. Госпо́дь пове́сть в писа́нии люде́й, и князе́й сих бы́вших в нем. Я́ко веселя́щихся всех жили́ще в тебе́.",
  ["текст_цс"] = "Ѡ҆снова̑нїѧ є҆гѡ̀ на гора́хъ ст҃ы́хъ: лю́битъ гдⷭ҇ь врата̀ сїѡ̑нѧ па́че всѣ́хъ селе́нїй і҆а́кѡвлихъ. Пресла̑внаѧ глаго́лашасѧ ѡ҆ тебѣ̀, гра́де бж҃їй. Помѧнꙋ̀ раа́въ и҆ вавѷлѡ́на вѣ́дꙋщымъ мѧ̀: и҆ сѐ, и҆ноплемє́нницы и҆ тѵ́ръ и҆ лю́дїе є҆ѳїо́пстїи, сі́и бы́ша та́мѡ. Ма́ти сїѡ́нъ рече́тъ: человѣ́къ и҆ человѣ́къ роди́сѧ въ не́мъ, и҆ то́й ѡ҆снова̀ и҆̀ вы́шнїй. Гдⷭ҇ь повѣ́сть въ писа́нїи люде́й и҆ кнѧзе́й, си́хъ бы́вшихъ въ не́мъ. Ꙗ҆́кѡ веселѧ́щихсѧ всѣ́хъ жили́ще въ тебѣ̀.",
  ["заголовок_ру"] = "Сыно́м Коре́овым, псало́м пе́сни.",
  ["заголовок_цс"] = "Сынѡ́мъ коре́ѡвымъ, ѱало́мъ пѣ́сни."
}

add_psalom {
  ["номер"] = 87,
  ["часть"] = 1,
  ["кафизма"] = 12,
  ["слава"] = 1,
  ["текст_ру"] = "Го́споди Бо́же спасе́ния моего́, во дни воззва́х, и в нощи́ пред Тобо́ю. Да вни́дет пред Тя моли́тва моя́: приклони́ у́хо Твое́ к моле́нию моему́, я́ко испо́лнися зол душа́ моя́, и живо́т мой аду прибли́жися. Привмене́н бых с низходя́щими в ров, бых я́ко челове́к без по́мощи, в ме́ртвых свобо́дь, я́ко я́звеннии спя́щии во гро́бе, и́хже не помяну́л еси́ ктому́, и ти́и от руки́ Твоея́ отринове́ни бы́ша. Положи́ша мя в ро́ве преиспо́днем, в те́мных и се́ни сме́ртней. На мне утверди́ся я́рость Твоя́, и вся во́лны Твоя́ наве́л еси́ на мя. Уда́лил еси́ зна́емых мои́х от мене́, положи́ша мя ме́рзость себе́: пре́дан бых и не исхожда́х. О́чи мои́ изнемого́сте от нищеты́, воззва́х к Тебе́, Го́споди, весь день, возде́х к Тебе́ ру́це мои́. Еда́ ме́ртвыми твори́ши чудеса́? Или́ вра́чеве воскреся́т, и испове́дятся Тебе́? Еда́ пове́сть кто во гро́бе ми́лость Твою́, и и́стину Твою́ в поги́бели? Еда́ позна́на бу́дут во тьме чудеса́ Твоя́, и пра́вда Твоя́ в земли́ забве́нней? И аз к Тебе́, Го́споди, воззва́х и у́тро моли́тва моя́ предвари́т Тя. Вску́ю, Го́споди, отре́еши ду́шу мою́, отвраща́еши лице́ Твое́ от мене́? Нищ есмь аз, и в труде́х от ю́ности моея́; возне́с же ся, смири́хся, и изнемого́х. На мне преидо́ша гне́ви Твои́, устраше́ния Твоя́ возмути́ша мя, обыдо́ша мя я́ко вода́, весь день одержа́ша мя вку́пе. Уда́лил еси́ от мене́ дру́га и и́скренняго, и зна́емых мои́х от страсте́й.",
  ["текст_цс"] = "Гдⷭ҇и бж҃е сп҃се́нїѧ моегѡ̀, во днѝ воззва́хъ и҆ въ нощѝ пред̾ тобо́ю: Да вни́детъ пред̾ тѧ̀ моли́тва моѧ̀, приклонѝ ᲂу҆́хо твоѐ къ моле́нїю моемꙋ̀. Ꙗ҆́кѡ и҆спо́лнисѧ ѕѡ́лъ дꙋша̀ моѧ̀, и҆ живо́тъ мо́й а҆́дꙋ прибли́жисѧ. Привмѣне́нъ бы́хъ съ низходѧ́щими въ ро́въ: бы́хъ ꙗ҆́кѡ человѣ́къ без̾ по́мощи, Въ ме́ртвыхъ свобо́дь: ꙗ҆́кѡ ꙗ҆́звеннїи спѧ́щїи во гро́бѣ, и҆́хже не помѧнꙋ́лъ є҆сѝ ктомꙋ̀, и҆ ті́и ѿ рꙋкѝ твоеѧ̀ ѿринове́ни бы́ша. Положи́ша мѧ̀ въ ро́вѣ преиспо́днѣмъ, въ те́мныхъ и҆ сѣ́ни сме́ртнѣй. На мнѣ̀ ᲂу҆тверди́сѧ ꙗ҆́рость твоѧ̀, и҆ всѧ̑ вѡ́лны твоѧ̑ наве́лъ є҆сѝ на мѧ̀. Оу҆да́лилъ є҆сѝ зна́емыхъ мои́хъ ѿ менѐ: положи́ша мѧ̀ ме́рзость себѣ̀: пре́данъ бы́хъ и҆ не и҆схожда́хъ. Ѻ҆́чи моѝ и҆знемого́стѣ ѿ нищеты̀: воззва́хъ къ тебѣ̀, гдⷭ҇и, ве́сь де́нь, воздѣ́хъ къ тебѣ̀ рꙋ́цѣ моѝ. Є҆да̀ ме́ртвыми твори́ши чꙋдеса̀; и҆лѝ вра́чеве воскресѧ́тъ, и҆ и҆сповѣ́дѧтсѧ тебѣ̀; Є҆да̀ повѣ́сть кто̀ во гро́бѣ млⷭ҇ть твою̀, и҆ и҆́стинꙋ твою̀ въ поги́бели; Є҆да̀ позна̑на бꙋ́дꙋтъ во тмѣ̀ чꙋдеса̀ твоѧ̑, и҆ пра́вда твоѧ̀ въ землѝ забве́ннѣй; И҆ а҆́зъ къ тебѣ̀, гдⷭ҇и, воззва́хъ, и҆ ᲂу҆́трѡ моли́тва моѧ̀ предвари́тъ тѧ̀. Вскꙋ́ю, гдⷭ҇и, ѿрѣ́еши дꙋ́шꙋ мою̀; ѿвраща́еши лицѐ твоѐ ѿ менѐ; Ни́щъ є҆́смь а҆́зъ, и҆ въ трꙋдѣ́хъ ѿ ю҆́ности моеѧ̀: возне́съ же сѧ смири́хсѧ и҆ и҆знемого́хъ. На мнѣ̀ преидо́ша гнѣ́ви твоѝ, ᲂу҆страшє́нїѧ твоѧ̑ возмꙋти́ша мѧ̀: Ѡ҆быдо́ша мѧ̀ ꙗ҆́кѡ вода̀ ве́сь де́нь, ѡ҆держа́ша мѧ̀ вкꙋ́пѣ. Оу҆да́лилъ є҆сѝ ѿ менѐ дрꙋ́га и҆ и҆́скреннѧго, и҆ зна́емыхъ мои́хъ ѿ страсте́й.",
  ["заголовок_ру"] = "Песнь псалма́ сыно́м Коре́овым, в коне́ц, о маеле́фе е́же отвеща́ти, ра́зума Ема́ну Изра́ильтянину.",
  ["заголовок_цс"] = "Пѣ́снь ѱалма̀ сынѡ́мъ коре́ѡвымъ, въ коне́цъ, ѡ҆ маеле́ѳѣ є҆́же ѿвѣща́ти, ра́зꙋма є҆ма́нꙋ і҆и҃льтѧнинꙋ."
}

add_psalom {
  ["номер"] = 88,
  ["часть"] = 1,
  ["кафизма"] = 12,
  ["слава"] = 2,
  ["текст_ру"] = "Ми́лости Твоя́, Го́споди, во век воспою́, в род и род возвещу́ и́стину Твою́ усты́ мои́ми. Зане́ рекл еси́: в век ми́лость сози́ждется, на небесе́х угото́вится и́стина Твоя́. Завеща́х заве́т избра́нным мои́м, кля́хся Дави́ду рабу́ Моему́: до ве́ка угото́ваю се́мя твое́, и сози́жду в род и род престо́л твой. Испове́дят небеса́ чудеса́ Твоя́, Го́споди, и́бо и́стину Твою́ в це́ркви святы́х. Я́ко кто во о́блацех уравни́тся Го́сподеви? Уподо́бится Го́сподеви в сыне́х Бо́жиих? Бог прославля́емь в сове́те святы́х, ве́лий и стра́шен есть над все́ми окре́стными Его́. Го́споди Бо́же Сил, кто подо́бен Тебе́? Си́лен еси́, Го́споди, и и́стина Твоя́ о́крест Тебе́. Ты влады́чествуеши держа́вою морско́ю: возмуще́ние же волн eго́ Ты укроча́еши. Ты смири́л еси́ я́ко я́звена го́рдаго, мы́шцею си́лы Твоея́ расточи́л еси́ враги́ Твоя́. Твоя́ суть небеса́, и Твоя́ есть земля́, вселе́нную и исполне́ние ея́ Ты основа́л еси́. Се́вер и мо́ре Ты созда́л еси́, Фаво́р и Ермо́н о и́мени Твое́м возра́дуетася. Твоя́ мы́шца с си́лою: да укрепи́тся рука́ Твоя́, и вознесе́тся десни́ца Твоя́. Пра́вда и судьба́ угото́вание престо́ла Твоего́: ми́лость и и́стина предъи́дете пред лице́м Твои́м. Блаже́ни лю́дие ве́дущии воскликнове́ние: Го́споди, во све́те лица́ Твоего́ по́йдут, и о и́мени Твое́м возра́дуются весь день, и пра́вдою Твое́ю вознесу́тся. Я́ко похвала́ си́лы их Ты еси́, и во благоволе́нии Твое́м вознесе́тся рог наш. Я́ко Госпо́дне есть заступле́ние, и Свята́го Изра́илева Царя́ на́шего. Тогда́ глаго́лал еси́ в виде́нии сыново́м Твои́м, и рекл еси́: положи́х по́мошь на си́льнаго, вознесо́х избра́ннаго от люде́й Мои́х, обрето́х Дави́да раба́ Moeгo, еле́ем святы́м Мои́м пома́зах eго́. И́бо рука́ Моя́ засту́пит eго́, и мы́шца Моя́ укрепи́т eго́, ничто́же успе́ет враг на него́, и сын беззако́ния не приложи́т озло́бити eго́: и ссеку́ от лица́ eго́ враги́ eго́, и ненави́дящыя eго́ побежду́. И и́стина Моя́ и ми́лость Моя́ с ним, и о и́мени Мое́м вознесе́тся рог eго́, и положу́ на мо́ри ру́ку eго́, и на река́х десни́цу eго́. Той призове́т Мя: Оте́ц мой еси́ Ты, Бог мой и засту́пник спасе́ния моего́. И Аз пе́рвенца положу́ eго́, высока́ па́че царе́й земны́х: в век сохраню́ eму́ ми́лость Мою́, и заве́т Мой ве́рен eму́, и положу́ в век ве́ка се́мя eго́, и престо́л eго́ я́ко дни́е не́ба. А́ще оста́вят сы́нове eго́ зако́н Мой, и в судьба́х Мои́х не по́йдут, а́ще оправда́ния Моя́ оскверня́т, и заповедей Мои́х не сохраня́т, посещу́ жезло́м беззако́ния их, и ра́нами непра́вды их, ми́лость же Мою́ не разорю́ от них, ни преврежду́ во и́стине Мое́й, ниже́ оскверню́ заве́та Моего́, и исходя́щих от уст Мои́х не отве́ргуся. Еди́ною кля́хся о святе́м Мое́м, а́ще Дави́ду солжу́? Се́мя eго́ во век пребу́дет, и престо́л eго́, я́ко со́лнце предо́ Мно́ю, и я́ко луна́ соверше́на в век, и Свиде́тель на небеси́ ве́рен. Ты же отри́нул еси́ и уничижи́л, негодова́л еси́ пома́заннаго Твоего́, разори́л еси́ заве́т раба́ Твоего́, оскверни́л еси́ на земли́ святы́ню eго́: разори́л еси́ вся опло́ты eго́, положи́л еси́ тве́рдая eго́ страх. Расхища́ху eго́ вси мимоходя́щии путе́м, бысть поноше́ние сосе́дом свои́м. Возвы́сил еси́ десни́цу стужа́ющих eму́, возвесели́л еси́ вся враги́ eго́: отврати́л еси́ по́мощь меча́ eго́, и не заступи́л еси́ eго́ во бра́ни. Разори́л еси́ от очище́ния eго́, престо́л eго́ на зе́млю пове́ргл еси́, ума́лил еси́ дни вре́мене eго́, облия́л еси́ eго́ студо́м. Доко́ле, Го́споди, отвраща́ешися в коне́ц? Разжже́тся я́ко огнь гнев Твой? Помяни́, кий мой соста́в, еда́ бо всу́е созда́л еси́ вся сы́ны челове́ческия? Кто есть челове́к, и́же поживе́т и не у́зрит сме́рти, изба́вит ду́шу свою́ из руки́ а́довы? Где суть ми́лости Твоя́ дре́вния, Го́споди, и́миже кля́лся еси́ Давиду́ во и́стине Твое́й? Помяни́, Го́споди, поноше́ние раб Твои́х, е́же удержа́х в не́дре мое́м мно́гих язы́к, и́мже поноси́ша врази́ Твои, Го́споди, и́мже поноси́ша измене́нию христа́ Твоего́. Благослове́н Госпо́дь во век, бу́ди, бу́ди.",
  ["текст_цс"] = "Млⷭ҇ти твоѧ̑, гдⷭ҇и, во вѣ́къ воспою̀, въ ро́дъ и҆ ро́дъ возвѣщꙋ̀ и҆́стинꙋ твою̀ ᲂу҆сты̑ мои́ми. Занѐ ре́клъ є҆сѝ: въ вѣ́къ млⷭ҇ть сози́ждетсѧ: на нб҃сѣ́хъ ᲂу҆гото́витсѧ и҆́стина твоѧ̀. Завѣща́хъ завѣ́тъ и҆збра̑ннымъ мои̑мъ, клѧ́хсѧ дв҃дꙋ рабꙋ̀ моемꙋ̀: До вѣ́ка ᲂу҆гото́ваю сѣ́мѧ твоѐ, и҆ сози́ждꙋ въ ро́дъ и҆ ро́дъ прⷭ҇то́лъ тво́й. И҆сповѣ́дѧтъ нб҃са̀ чꙋдеса̀ твоѧ̑, гдⷭ҇и, и҆́бо и҆́стинꙋ твою̀ въ цр҃кви ст҃ы́хъ. Ꙗ҆́кѡ кто̀ во ѻ҆́блацѣхъ ᲂу҆равни́тсѧ гдⷭ҇еви; ᲂу҆подо́битсѧ гдⷭ҇еви въ сынѣ́хъ бж҃їихъ; Бг҃ъ прославлѧ́емь въ совѣ́тѣ ст҃ы́хъ, ве́лїй и҆ стра́шенъ є҆́сть над̾ всѣ́ми ѻ҆кре́стными є҆гѡ̀. Гдⷭ҇и бж҃е си́лъ, кто̀ подо́бенъ тебѣ̀; си́ленъ є҆сѝ, гдⷭ҇и, и҆ и҆́стина твоѧ̀ ѡ҆́крестъ тебє̀. Ты̀ влⷣчествꙋеши держа́вою морско́ю: возмꙋще́нїе же во́лнъ є҆гѡ̀ ты̀ ᲂу҆кроча́еши. Ты̀ смири́лъ, є҆сѝ, ꙗ҆́кѡ ꙗ҆́звена, го́рдаго: мы́шцею си́лы твоеѧ̀ расточи́лъ є҆сѝ врагѝ твоѧ̑. Твоѧ̑ сꙋ́ть небеса̀, и҆ твоѧ̀ є҆́сть землѧ̀: вселе́ннꙋю и҆ и҆сполне́нїе є҆ѧ̀ ты̀ ѡ҆снова́лъ є҆сѝ. Сѣ́веръ и҆ мо́ре ты̀ созда́лъ є҆сѝ: ѳавѡ́ръ и҆ є҆рмѡ́нъ ѡ҆ и҆́мени твое́мъ возра́дꙋетасѧ. Твоѧ̀ мы́шца съ си́лою: да ᲂу҆крѣпи́тсѧ рꙋка̀ твоѧ̀, и҆ вознесе́тсѧ десни́ца твоѧ̀. Пра́вда и҆ сꙋдьба̀ ᲂу҆гото́ванїе прⷭ҇то́ла твоегѡ̀: млⷭ҇ть и҆ и҆́стина пред̾и́детѣ пред̾ лице́мъ твои́мъ. Бл҃же́ни лю́дїе вѣ́дꙋщїи воскликнове́нїе: гдⷭ҇и, во свѣ́тѣ лица̀ твоегѡ̀ по́йдꙋтъ, И҆ ѡ҆ и҆́мени твое́мъ возра́дꙋютсѧ ве́сь де́нь, и҆ пра́вдою твое́ю вознесꙋ́тсѧ. Ꙗ҆́кѡ похвала̀ си́лы и҆́хъ ты̀ є҆сѝ, и҆ во бл҃говоле́нїи твое́мъ вознесе́тсѧ ро́гъ на́шъ: Ꙗ҆́кѡ гдⷭ҇не є҆́сть застꙋпле́нїе, и҆ ст҃а́гѡ і҆и҃лева цр҃ѧ̀ на́шегѡ. Тогда̀ глаго́лалъ є҆сѝ въ видѣ́нїи сыновѡ́мъ твои̑мъ, и҆ ре́клъ є҆сѝ: положи́хъ по́мощь на си́льнаго, вознесо́хъ и҆збра́ннаго ѿ люде́й мои́хъ: Ѡ҆брѣто́хъ дв҃да раба̀ моего̀, є҆ле́емъ ст҃ы́мъ мои́мъ пома́захъ є҆го̀. И҆́бо рꙋка̀ моѧ̀ застꙋ́питъ є҆го̀, и҆ мы́шца моѧ̀ ᲂу҆крѣпи́тъ є҆го̀: Ничто́же ᲂу҆спѣ́етъ вра́гъ на него̀, и҆ сы́нъ беззако́нїѧ не приложи́тъ ѡ҆ѕло́бити є҆го̀. И҆ ссѣкꙋ̀ ѿ лица̀ є҆гѡ̀ врагѝ є҆гѡ̀, и҆ ненави́дѧщыѧ є҆го̀ побѣждꙋ̀: И҆ и҆́стина моѧ̀ и҆ млⷭ҇ть моѧ̀ съ ни́мъ, и҆ ѡ҆ и҆́мени мое́мъ вознесе́тсѧ ро́гъ є҆гѡ̀: И҆ положꙋ̀ на мо́ри рꙋ́кꙋ є҆гѡ̀, и҆ на рѣка́хъ десни́цꙋ є҆гѡ̀. То́й призове́тъ мѧ̀: ѻ҆ц҃ъ мо́й є҆сѝ ты̀, бг҃ъ мо́й и҆ застꙋ́пникъ сп҃се́нїѧ моегѡ̀. И҆ а҆́зъ пе́рвенца положꙋ̀ є҆го̀, высока̀ па́че царе́й земны́хъ: Въ вѣ́къ сохраню̀ є҆мꙋ̀ млⷭ҇ть мою̀, и҆ завѣ́тъ мо́й вѣ́ренъ є҆мꙋ̀: И҆ положꙋ̀ въ вѣ́къ вѣ́ка сѣ́мѧ є҆гѡ̀, и҆ прⷭ҇то́лъ є҆гѡ̀ ꙗ҆́кѡ дні́е не́ба. А҆́ще ѡ҆ста́вѧтъ сы́нове є҆гѡ̀ зако́нъ мо́й, и҆ въ сꙋдьба́хъ мои́хъ не по́йдꙋтъ: А҆́ще ѡ҆правда̑нїѧ моѧ̑ ѡ҆сквернѧ́тъ, и҆ за́повѣдїй мои́хъ не сохранѧ́тъ: Посѣщꙋ̀ жезло́мъ беззакѡ́нїѧ и҆́хъ, и҆ ра́нами непра̑вды и҆́хъ, Млⷭ҇ть же мою̀ не разорю̀ ѿ ни́хъ, ни превреждꙋ̀ во и҆́стинѣ мое́й: Нижѐ ѡ҆скверню̀ завѣ́та моегѡ̀, и҆ и҆сходѧ́щихъ ѿ ᲂу҆́стъ мои́хъ не ѿве́ргꙋсѧ. Є҆ди́ною клѧ́хсѧ ѡ҆ ст҃ѣ́мъ мое́мъ: а҆́ще дв҃дꙋ солжꙋ̀; Сѣ́мѧ є҆гѡ̀ во вѣ́къ пребꙋ́детъ, и҆ престо́лъ є҆гѡ̀ ꙗ҆́кѡ со́лнце предо мно́ю, И҆ ꙗ҆́кѡ лꙋна̀ соверше́на въ вѣ́къ, и҆ свидѣ́тель на нб҃сѝ вѣ́ренъ. Ты́ же ѿри́нꙋлъ є҆сѝ и҆ ᲂу҆ничижи́лъ, негодова́лъ є҆сѝ пома́заннаго твоего̀: Разори́лъ є҆сѝ завѣ́тъ раба̀ твоегѡ̀, ѡ҆скверни́лъ є҆сѝ на землѝ ст҃ы́ню є҆гѡ̀: Разори́лъ є҆сѝ всѧ̑ ѡ҆пло́ты є҆гѡ̀, положи́лъ є҆сѝ твє́рдаѧ є҆гѡ̀ стра́хъ. Расхища́хꙋ є҆го̀ всѝ мимоходѧ́щїи пꙋте́мъ, бы́сть поноше́нїе сосѣ́дѡмъ свои̑мъ. Возвы́силъ є҆сѝ десни́цꙋ стꙋжа́ющихъ є҆мꙋ̀, возвесели́лъ є҆сѝ всѧ̑ врагѝ є҆гѡ̀: Ѿврати́лъ є҆сѝ по́мощь меча̀ є҆гѡ̀ и҆ не застꙋпи́лъ є҆сѝ є҆го̀ во бра́ни: Разори́лъ є҆сѝ ѿ ѡ҆чище́нїѧ є҆гѡ̀, престо́лъ є҆гѡ̀ на зе́млю пове́рглъ є҆сѝ: Оу҆ма́лилъ є҆сѝ дни̑ вре́мене є҆гѡ̀, ѡ҆блїѧ́лъ є҆сѝ є҆го̀ стꙋдо́мъ. Доко́лѣ, гдⷭ҇и, ѿвраща́ешисѧ въ коне́цъ, разжже́тсѧ ꙗ҆́кѡ ѻ҆́гнь гнѣ́въ тво́й; Помѧнѝ, кі́й мо́й соста́въ: є҆да́ бо всꙋ́е созда́лъ є҆сѝ всѧ̑ сы́ны человѣ́чєскїѧ; Кто̀ є҆́сть человѣ́къ, и҆́же поживе́тъ и҆ не ᲂу҆́зритъ сме́рти, и҆зба́витъ дꙋ́шꙋ свою̀ и҆з̾ рꙋкѝ а҆́довы; Гдѣ̀ сꙋ́ть млⷭ҇ти твоѧ̑ дрє́внїѧ, гдⷭ҇и, и҆́миже клѧ́лсѧ є҆сѝ дв҃дꙋ во и҆́стинѣ твое́й; Помѧнѝ, гдⷭ҇и, поноше́нїе ра̑бъ твои́хъ, є҆́же ᲂу҆держа́хъ въ нѣ́дрѣ мое́мъ мно́гихъ ꙗ҆зы̑къ: И҆́мже поноси́ша вразѝ твоѝ, гдⷭ҇и, и҆́мже поноси́ша и҆змѣне́нїю хрїста̀ твоегѡ̀. Бл҃гослове́нъ гдⷭ҇ь во вѣ́къ: бꙋ́ди, бꙋ́ди.",
  ["заголовок_ру"] = "Ра́зума Ефа́ма Изра́ильтянина.",
  ["заголовок_цс"] = "Ра́зꙋма є҆ѳа́ма і҆и҃льтѧнина."
}

