  ["кафизма"] = 12,
  ["слава"] = 3,
  ["текст_ру"] = "Го́споди, прибе́жище был еси́ нам в род и род. Пре́жде да́же гора́м не бы́ти и созда́тися земли́ и вселе́нней, и от ве́ка и до ве́ка Ты еси́. Не отврати́ челове́ка во смире́ние, и рекл еси́: обрати́теся, сы́нове челове́честии. Я́ко ты́сяща лет пред очи́ма Твои́ма, Го́споди, я́ко день вчера́шний, и́же мимои́де, и стра́жа нощна́я. Уничиже́ния их ле́та бу́дут. Утро я́ко трава́ мимои́дет, у́тро процвете́т и пре́йдет: на ве́чер отпаде́т ожесте́ет и и́зсхнет. Я́ко исче́зохом гне́вом Твои́м, и я́ростию Твое́ю смути́хомся. Положи́л еси́ беззако́ния на́ша пред Тобо́ю: век наш в просвеще́ние лица́ Твоего́. Я́ко вси дни́е на́ши оскуде́ша, и гне́вом Твои́м исчезо́хом, ле́та на́ша я́ко паучи́на поуча́хуся. Дни́е лет на́ших, в ни́хже се́дмьдесят лет, а́ще же в си́лах, о́смьдесят лет, и мно́жае их труд и боле́знь: я́ко прии́де кро́тость на ны, и нака́жемся. Кто весть держа́ву гне́ва Твоего́, и от стра́ха Твоего́, я́рость Твою́ исчести́? Десни́цу Твою́ та́ко скажи́ ми, и окова́нныя се́рдцем в му́дрости. Обрати́ся, Го́споди, доко́ле? И умоле́н бу́ди на рабы́ Твоя́. Испо́лнихомся зау́тра ми́лости Твоея́, Го́споди, и возра́довахомся, и возвесели́хомся, во вся дни на́ша возвесели́хомся, за дни в ня́же смири́л ны еси́, ле́та в ня́же ви́дехом зла́я. И при́зри на рабы́ Твоя́, и на дела́ Твоя́, и наста́ви сы́ны их. И бу́ди све́тлость Го́спода Бо́га на́шего на нас, и дела́ рук на́ших испра́ви на нас, и де́ло рук на́ших испра́ви.",
  ["текст_цс"] = "Гдⷭ҇и, прибѣ́жище бы́лъ є҆сѝ на́мъ въ ро́дъ и҆ ро́дъ. Пре́жде да́же гора́мъ не бы́ти и҆ созда́тисѧ землѝ и҆ вселе́ннѣй, и҆ ѿ вѣ́ка и҆ до вѣ́ка ты̀ є҆сѝ. Не ѿвратѝ человѣ́ка во смире́нїе, и҆ ре́клъ є҆сѝ: ѡ҆брати́тесѧ, сы́нове человѣ́честїи. Ꙗ҆́кѡ ты́сѧща лѣ́тъ пред̾ ѻ҆чи́ма твои́ма, гдⷭ҇и, ꙗ҆́кѡ де́нь вчера́шнїй, и҆́же ми́мѡ и҆́де, и҆ стра́жа нощна́ѧ. Оу҆ничижє́нїѧ и҆́хъ лѣ̑та бꙋ́дꙋтъ: ᲂу҆́трѡ ꙗ҆́кѡ трава̀ ми́мѡ и҆́детъ, ᲂу҆́трѡ процвѣте́тъ и҆ пре́йдетъ: на ве́черъ ѿпаде́тъ, ѡ҆жестѣ́етъ и҆ и҆́зсхнетъ: Ꙗ҆́кѡ и҆счезо́хомъ гнѣ́вомъ твои́мъ, и҆ ꙗ҆́ростїю твое́ю смꙋти́хомсѧ. Положи́лъ є҆сѝ беззакѡ́нїѧ на̑ша пред̾ тобо́ю, вѣ́къ на́шъ въ просвѣще́нїе лица̀ твоегѡ̀. Ꙗ҆́кѡ всѝ дні́е на́ши ѡ҆скꙋдѣ́ша, и҆ гнѣ́вомъ твои́мъ и҆счезо́хомъ: Лѣ̑та на̑ша ꙗ҆́кѡ паꙋчи́на поꙋча́хꙋсѧ: дні́е лѣ́тъ на́шихъ въ ни́хже се́дмьдесѧтъ лѣ́тъ, а҆́ще же въ си́лахъ, ѻ҆́смьдесѧтъ лѣ́тъ, и҆ мно́жае и҆́хъ трꙋ́дъ и҆ болѣ́знь: ꙗ҆́кѡ прїи́де кро́тость на ны̀, и҆ нака́жемсѧ. Кто̀ вѣ́сть держа́вꙋ гнѣ́ва твоегѡ̀, и҆ ѿ стра́ха твоегѡ̀ ꙗ҆́рость твою̀ и҆счестѝ; Десни́цꙋ твою̀ та́кѡ скажи́ ми, и҆ ѡ҆кова̑нныѧ се́рдцемъ въ мꙋ́дрости. Ѡ҆брати́сѧ, гдⷭ҇и, доко́лѣ; и҆ ᲂу҆моле́нъ бꙋ́ди на рабы̑ твоѧ̑. И҆спо́лнихомсѧ заꙋ́тра млⷭ҇ти твоеѧ̀, гдⷭ҇и, и҆ возра́довахомсѧ и҆ возвесели́хомсѧ: Во всѧ̑ дни̑ на́шѧ возвесели́хомсѧ, за дни̑, въ нѧ́же смири́лъ ны̀ є҆сѝ, лѣ̑та, въ нѧ́же ви́дѣхомъ ѕла̑ѧ. И҆ при́зри на рабы̑ твоѧ̑ и҆ на дѣла̀ твоѧ̑, и҆ наста́ви сы́ны и҆́хъ. И҆ бꙋ́ди свѣ́тлость гдⷭ҇а бг҃а на́шегѡ на на́съ, и҆ дѣла̀ рꙋ́къ на́шихъ и҆спра́ви на на́съ, и҆ дѣ́ло рꙋ́къ на́шихъ и҆спра́ви.",
  ["заголовок_ру"] = "Моли́тва Моисе́а челове́ка Бо́жия.",
  ["заголовок_цс"] = "Мл҃тва мѡѷсе́а человѣ́ка бж҃їѧ."
}

add_psalom {
  ["номер"] = 90,
  ["часть"] = 1,
  ["кафизма"] = 12,
  ["слава"] = 3,
  ["текст_ру"] = "Живы́й в по́мощи Вы́шняго, в кро́ве Бо́га небе́снаго водвори́тся. Рече́т Го́сподеви: Засту́пник мой еси́ и прибе́жище мое́, Бог мой, и упова́ю на Него́. Я́ко Той изба́вит тя от се́ти ло́вчи и от словесе́ мяте́жна, плещма́ Свои́ма осени́т тя, и под криле́ Его́ наде́ешися: ору́жием обы́дет тя и́стина Его́. Не убои́шися от стра́ха нощна́го, от стрелы́ летя́щия во дни, от ве́щи во тме преходя́щия, от сря́ща и бе́са полу́деннаго. Паде́т от страны́ твоея́ ты́сяща, и тма одесну́ю тебе́, к тебе́ же не прибли́жится, оба́че очи́ма твои́ма смо́триши и воздая́ние гре́шников у́зриши. Я́ко Ты, Го́споди, упова́ние мое́, Вы́шняго положи́л еси́ прибе́жище твое́. Не прии́дет к тебе́ зло, и ра́на не прибли́жится телеси́ твоему́, я́ко А́нгелом Свои́м запове́сть о тебе́, сохрани́ти тя во всех путе́х твои́х. На рука́х во́змут тя, да не когда́ преткне́ши о ка́мень но́гу твою́, на а́спида и васили́ска насту́пиши, и попере́ши льва и зми́я. Я́ко на Мя упова́, и изба́влю и́, покры́ю и́, я́ко позна́ и́мя Мое́. Воззове́т ко Мне, и услы́шу eго́, с ним есмь в ско́рби, изму́ eго́ и просла́влю eго́, долгото́ю дний испо́лню eго́ и явлю́ eму́ спасе́ние Мое́.",
  ["текст_цс"] = "Живы́й въ по́мощи вы́шнѧгѡ, въ кро́вѣ бг҃а нбⷭ҇нагѡ водвори́тсѧ, Рече́тъ гдⷭ҇еви: застꙋ́пникъ мо́й є҆сѝ и҆ прибѣ́жище моѐ, бг҃ъ мо́й, и҆ ᲂу҆пова́ю на него̀. Ꙗ҆́кѡ то́й и҆зба́витъ тѧ̀ ѿ сѣ́ти ло́вчи и҆ ѿ словесѐ мѧте́жна: Плещма̀ свои́ма ѡ҆сѣни́тъ тѧ̀, и҆ под̾ крилѣ̑ є҆гѡ̀ надѣ́ешисѧ: ѻ҆рꙋ́жїемъ ѡ҆бы́детъ тѧ̀ и҆́стина є҆гѡ̀. Не ᲂу҆бои́шисѧ ѿ стра́ха нощна́гѡ, ѿ стрѣлы̀ летѧ́щїѧ во днѝ, Ѿ ве́щи во тмѣ̀ преходѧ́щїѧ, ѿ срѧ́ща и҆ бѣ́са полꙋ́деннагѡ. Паде́тъ ѿ страны̀ твоеѧ̀ ты́сѧща, и҆ тма̀ ѡ҆деснꙋ́ю тебє̀, къ тебѣ́ же не прибли́житсѧ: Ѻ҆ба́че ѻ҆чи́ма твои́ма смо́триши и҆ воздаѧ́нїе грѣ́шникѡвъ ᲂу҆́зриши. Ꙗ҆́кѡ ты̀, гдⷭ҇и, ᲂу҆пова́нїе моѐ: вы́шнѧго положи́лъ є҆сѝ прибѣ́жище твоѐ. Не прїи́детъ къ тебѣ̀ ѕло̀, и҆ ра́на не прибли́житсѧ тѣлесѝ твоемꙋ̀: Ꙗ҆́кѡ а҆́гг҃лѡмъ свои̑мъ заповѣ́сть ѡ҆ тебѣ̀, сохрани́ти тѧ̀ во всѣ́хъ пꙋте́хъ твои́хъ. На рꙋка́хъ во́змꙋтъ тѧ̀, да не когда̀ преткне́ши ѡ҆ ка́мень но́гꙋ твою̀: На а҆́спїда и҆ васїлі́ска настꙋ́пиши, и҆ попере́ши льва̀ и҆ ѕмі́ѧ. Ꙗ҆́кѡ на мѧ̀ ᲂу҆пова̀, и҆ и҆зба́влю и҆̀: покры́ю и҆̀, ꙗ҆́кѡ позна̀ и҆́мѧ моѐ. Воззове́тъ ко мнѣ̀, и҆ ᲂу҆слы́шꙋ є҆го̀: съ ни́мъ є҆́смь въ ско́рби, и҆змꙋ̀ є҆го̀ и҆ просла́влю є҆го̀: Долгото́ю дні́й и҆спо́лню є҆го̀ и҆ ꙗ҆влю̀ є҆мꙋ̀ сп҃се́нїе моѐ.",
  ["заголовок_ру"] = "Хвала́ пе́сни Дави́довы, не надпи́сан у евре́й.",
  ["заголовок_цс"] = "Хвала̀ пѣ́сни дв҃довы, не надпи́санъ ᲂу҆ є҆врє́й."
}

add_psalom {
  ["номер"] = 91,
  ["часть"] = 1,
  ["кафизма"] = 13,
  ["слава"] = 1,
  ["текст_ру"] = "Бла́го есть испове́датися Го́сподеви, и пе́ти и́мени Твоему́, Вы́шний: возвеща́ти зау́тра ми́лость Твою́ и и́стину Твою́ на вся́ку нощь, в десятостру́ннем псалти́ри с пе́снию в гу́слех. Я́ко возвесели́л мя еси́, Го́споди, в творе́нии Твое́м, и в де́лех руку́ Твое́ю возра́дуюся. Я́ко возвели́чишася дела́ Твоя́, Го́споди, зело́ углуби́шася помышле́ния Твоя́. Муж безу́мен не позна́ет, и неразуми́в не разуме́ет сих. Внегда́ прозябо́ша гре́шницы я́ко трава́, и пронико́ша вси де́лающии беззако́ние: я́ко да потребя́тся в век ве́ка. Ты же Вы́шний во век, Го́споди. Я́ко се врази́ Твои́, Го́споди, я́ко се врази́ Твои́ поги́бнут, и разы́дутся вси де́лающии беззако́ние. И вознесе́тся я́ко единоро́га рог мой, и ста́рость моя́ в еле́и масти́те. И воззре́ о́ко мое́ на враги́ моя́, и востаю́щыя на мя лука́внующыя услы́шит у́хо мое́. Пра́ведник я́ко фи́никс процвете́т, я́ко кедр, и́же в Лива́не, умно́жится. Насажде́ни в дому́ Госпо́дни, во дво́рех Бо́га на́шего процвету́т, еще́ умно́жатся в ста́рости масти́те, и благоприе́млюще бу́дут. Да возвестя́т, я́ко прав Госпо́дь Бог наш, и несть непра́вды в Нем.",
  ["текст_цс"] = "Бл҃го є҆́сть и҆сповѣ́датисѧ гдⷭ҇еви и҆ пѣ́ти и҆́мени твоемꙋ̀, вы́шнїй: Возвѣща́ти заꙋ́тра млⷭ҇ть твою̀ и҆ и҆́стинꙋ твою̀ на всѧ́кꙋ но́щь, Въ десѧтострꙋ́ннѣмъ ѱалти́ри съ пѣ́снїю въ гꙋ́слехъ. Ꙗ҆́кѡ возвесели́лъ мѧ̀ є҆сѝ, гдⷭ҇и, въ творе́нїи твое́мъ, и҆ въ дѣ́лѣхъ рꙋкꙋ̀ твоє́ю возра́дꙋюсѧ. Ꙗ҆́кѡ возвели́чишасѧ дѣла̀ твоѧ̑, гдⷭ҇и: ѕѣлѡ̀ ᲂу҆глꙋби́шасѧ помышлє́нїѧ твоѧ̑. Мꙋ́жъ безꙋ́менъ не позна́етъ, и҆ неразꙋми́въ не разꙋмѣ́етъ си́хъ. Внегда̀ прозѧбо́ша грѣ̑шницы ꙗ҆́кѡ трава̀, и҆ пронико́ша всѝ дѣ́лающїи беззако́нїе, ꙗ҆́кѡ да потребѧ́тсѧ въ вѣ́къ вѣ́ка: Ты́ же вы́шнїй во вѣ́къ, гдⷭ҇и. Ꙗ҆́кѡ сѐ, вразѝ твоѝ, гдⷭ҇и, ꙗ҆́кѡ сѐ, вразѝ твоѝ поги́бнꙋтъ, и҆ разы́дꙋтсѧ всѝ дѣ́лающїи беззако́нїе. И҆ вознесе́тсѧ ꙗ҆́кѡ є҆диноро́га ро́гъ мо́й, и҆ ста́рость моѧ̀ въ є҆ле́и масти́тѣ: И҆ воззрѣ̀ ѻ҆́ко моѐ на врагѝ моѧ̑, и҆ востаю́щыѧ на мѧ̀ лꙋка́внꙋющыѧ ᲂу҆слы́шитъ ᲂу҆́хо моѐ. Првⷣникъ ꙗ҆́кѡ фі́нїѯъ процвѣте́тъ: ꙗ҆́кѡ ке́дръ, и҆́же въ лїва́нѣ, ᲂу҆мно́житсѧ. Насажде́ни въ домꙋ̀ гдⷭ҇ни во дво́рѣхъ бг҃а на́шегѡ процвѣтꙋ́тъ: Є҆щѐ ᲂу҆мно́жатсѧ въ ста́рости масти́тѣ, и҆ бл҃гопрїе́млюще бꙋ́дꙋтъ. Да возвѣстѧ́тъ, ꙗ҆́кѡ пра́въ гдⷭ҇ь бг҃ъ на́шъ, и҆ нѣ́сть непра́вды въ не́мъ.",
  ["заголовок_ру"] = "Псало́м пе́сни в день суббо́тный.",
  ["заголовок_цс"] = "Ѱало́мъ пѣ́сни, въ де́нь сꙋббѡ́тный."
}

add_psalom {
  ["номер"] = 92,
  ["часть"] = 1,
  ["кафизма"] = 13,
  ["слава"] = 1,
  ["текст_ру"] = "Госпо́дь воцари́ся, в ле́поту облече́ся: облече́ся Госпо́дь в си́лу и препоя́сася, и́бо утверди́ вселе́нную, я́же не подви́жится. Гото́в престо́л Твой отто́ле: от ве́ка Ты еси́. Воздвиго́ша ре́ки, Го́споди, воздвиго́ша ре́ки гла́сы своя́. Во́змут ре́ки сотре́ния своя́, от гласо́в вод мно́гих. Ди́вны высоты́ морски́я, ди́вен в высо́ких Госпо́дь. Свиде́ния Твоя́ уве́ришася зело́, до́му Твоему́ подоба́ет святы́ня, Го́споди, в долготу́ дний.",
  ["текст_цс"] = "Гдⷭ҇ь воцр҃и́сѧ, въ лѣ́потꙋ ѡ҆блече́сѧ: ѡ҆блече́сѧ гдⷭ҇ь въ си́лꙋ и҆ препоѧ́сасѧ: и҆́бо ᲂу҆твердѝ вселе́ннꙋю, ꙗ҆́же не подви́житсѧ. Гото́въ прⷭ҇то́лъ тво́й ѿто́лѣ: ѿ вѣ́ка ты̀ є҆сѝ. Воздвиго́ша рѣ́ки, гдⷭ҇и, воздвиго́ша рѣ́ки гла́сы своѧ̑: Во́змꙋтъ рѣ́ки сотрє́нїѧ своѧ̑, ѿ гласѡ́въ во́дъ мно́гихъ. Ди̑вны высѡты̀ мѡрскі́ѧ: ди́венъ въ высо́кихъ гдⷭ҇ь. Свидѣ̑нїѧ твоѧ̑ ᲂу҆вѣ́ришасѧ ѕѣлѡ̀. До́мꙋ твоемꙋ̀ подоба́етъ ст҃ы́нѧ, гдⷭ҇и, въ долготꙋ̀ дні́й.",
  ["заголовок_ру"] = "В день предсуббо́тный, внегда́ насели́ся земля́, хвала́ пе́сни Дави́ду.",
  ["заголовок_цс"] = "Въ де́нь предсꙋббѡ́тный, внегда̀ насели́сѧ землѧ̀, хвала̀ пѣ́сни дв҃дꙋ."
}

add_psalom {
  ["номер"] = 93,
  ["часть"] = 1,
  ["кафизма"] = 13,
  ["слава"] = 1,
  ["текст_ру"] = "Бог отмще́ний Госпо́дь, Бог отмще́ний не обину́лся есть. Вознеси́ся Судя́й земли́, возда́ждь воздая́ние го́рдым. Доко́ле гре́шницы, Го́споди, доко́ле гре́шницы восхва́лятся? Провеща́ют и возглаго́лют непра́вду, возглаго́лют вси де́лающии беззако́ние? Лю́ди Твоя́, Го́споди, смири́ша и достоя́ние Твое́ озло́биша. Вдови́цу и си́ра умори́ша и прише́льца уби́ша, и ре́ша: не у́зрит Госпо́дь, ниже́ уразуме́ет Бог Иа́ковль. Разуме́йте же безу́мнии в лю́дех и бу́ии не́когда умудри́теся. Насажде́й у́хо, не слы́шит ли? Или́ созда́вый о́ко, не сматря́ет ли? Наказу́яй язы́ки, не обличи́т ли, уча́й челове́ка ра́зуму? Госпо́дь весть помышле́ния челове́ческая, я́ко суть су́етна. Блаже́н челове́к, eго́же а́ще нака́жеши, Го́споди, и от зако́на Твоего́ научи́ши eго́, укроти́ти eго́ от дней лю́тых, до́ндеже изры́ется гре́шному я́ма. Я́ко не отри́нет Госпо́дь люде́й Свои́х, и достоя́ния Своего́ не оста́вит, до́ндеже пра́вда обрати́тся на суд, и держа́щиися ея́ вси пра́вии се́рдцем. Кто воста́нет ми на лука́внующыя? Или́ кто спредста́нет ми на де́лающыя беззако́ние? А́ще не Госпо́дь помо́гл бы ми, вма́ле всели́лася бы во ад душа́ моя́. А́ще глаго́лах, подви́жеся нога́ моя́, ми́лость Твоя́, Го́споди, помога́ше ми. По мно́жеству боле́зней мои́х в се́рдце мое́м, утеше́ния Твоя́ возвесели́ша ду́шу мою́. Да не прибу́дет Тебе́ престо́л беззако́ния, созида́яй труд на повеле́ние. Уловя́т на ду́шу пра́ведничу, и кровь непови́нную осу́дят. И бысть мне Госпо́дь в прибе́жище, и Бог мой в по́мошь упова́ния моего́. И возда́ст им Госпо́дь беззако́ние их и по лука́вствию их погуби́т я́ Госпо́дь Бог.",
  ["текст_цс"] = "Бг҃ъ ѿмще́нїй гдⷭ҇ь, бг҃ъ ѿмще́нїй не ѡ҆бинꙋ́лсѧ є҆́сть. Вознеси́сѧ, сꙋдѧ́й землѝ, возда́ждь воздаѧ́нїе гѡ́рдымъ. Доко́лѣ грѣ̑шницы, гдⷭ҇и, доко́лѣ грѣ̑шницы восхва́лѧтсѧ; Провѣща́ютъ и҆ возглаго́лютъ непра́вдꙋ, возглаго́лютъ всѝ дѣ́лающїи беззако́нїе; Лю́ди твоѧ̑, гдⷭ҇и, смири́ша, и҆ достоѧ́нїе твоѐ ѡ҆ѕло́биша: Вдови́цꙋ и҆ си́ра ᲂу҆мори́ша, и҆ прише́льца ᲂу҆би́ша, И҆ рѣ́ша: не ᲂу҆́зритъ гдⷭ҇ь, нижѐ ᲂу҆разꙋмѣ́етъ бг҃ъ і҆а́кѡвль. Разꙋмѣ́йте же, безꙋ́мнїи въ лю́дехъ, и҆ бꙋ́їи нѣ́когда, ᲂу҆мꙋдри́тесѧ: Насажде́й ᲂу҆́хо, не слы́шитъ ли; и҆лѝ созда́вый ѻ҆́ко, не сматрѧ́етъ ли; Наказꙋ́ѧй ꙗ҆зы́ки, не ѡ҆бличи́тъ ли, ᲂу҆ча́й человѣ́ка ра́зꙋмꙋ; Гдⷭ҇ь вѣ́сть помышлє́нїѧ человѣ́чєскаѧ, ꙗ҆́кѡ сꙋ́ть сꙋ́єтна. Бл҃же́нъ человѣ́къ, є҆го́же а҆́ще нака́жеши, гдⷭ҇и, и҆ ѿ зако́на твоегѡ̀ наꙋчи́ши є҆го̀: Оу҆кроти́ти є҆го̀ ѿ дні́й лю́тыхъ, до́ндеже и҆зры́етсѧ грѣ́шномꙋ ꙗ҆́ма. Ꙗ҆́кѡ не ѿри́нетъ гдⷭ҇ь люде́й свои́хъ, и҆ достоѧ́нїѧ своегѡ̀ не ѡ҆ста́витъ: До́ндеже пра́вда ѡ҆брати́тсѧ на сꙋ́дъ, и҆ держа́щїисѧ є҆ѧ̀ всѝ пра́вїи срⷣцемъ. Кто̀ воста́нетъ мѝ на лꙋка́внꙋющыѧ; и҆лѝ кто̀ спредста́нетъ мѝ на дѣ́лающыѧ беззако́нїе; А҆́ще не гдⷭ҇ь помо́глъ бы мѝ, вма́лѣ всели́ласѧ бы во а҆́дъ дꙋша̀ моѧ̀. А҆́ще глаго́лахъ: подви́жесѧ нога̀ моѧ̀, млⷭ҇ть твоѧ̀, гдⷭ҇и, помога́ше мѝ: По мно́жествꙋ болѣ́зней мои́хъ въ се́рдцы мое́мъ, ᲂу҆тѣшє́нїѧ твоѧ̑ возвесели́ша дꙋ́шꙋ мою̀. Да не пребꙋ́детъ тебѣ̀ престо́лъ беззако́нїѧ, созида́ѧй трꙋ́дъ на повелѣ́нїе. Оу҆ловѧ́тъ на дꙋ́шꙋ првⷣничꙋ, и҆ кро́вь непови́ннꙋю ѡ҆сꙋ́дѧтъ. И҆ бы́сть мнѣ̀ гдⷭ҇ь въ прибѣ́жище, и҆ бг҃ъ мо́й въ по́мощь ᲂу҆пова́нїѧ моегѡ̀: И҆ возда́стъ и҆̀мъ гдⷭ҇ь беззако́нїе и҆́хъ, и҆ по лꙋка́вствїю и҆́хъ погꙋби́тъ ѧ҆̀ гдⷭ҇ь бг҃ъ.",
  ["заголовок_ру"] = "Псало́м Дави́ду, в четве́ртый суббо́ты.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, въ четве́ртый сꙋббѡ́ты."
}

add_psalom {
