  ["часть"] = 1,
  ["кафизма"] = 13,
  ["слава"] = 2,
  ["текст_ру"] = "Прииди́те, возра́дуемся Го́сподеви, воскли́кнем Бо́гу Спаси́телю на́шему: предвари́м лице́ Его́ во испове́дании, и во псалме́х воскли́кнем Ему́. Я́ко Бог ве́лий Госпо́дь, и Царь ве́лий по всей земли́, я́ко в руце́ Его́ вси концы́ земли́, и высоты́ гор Того́ суть. Я́ко Того́ есть мо́ре, и Той сотвори́ е́, и су́шу ру́це Его́ созда́сте. Прииди́те, поклони́мся и припаде́м Ему́, и воспла́чемся пред Го́сподем сотво́ршим нас: я́ко Той есть Бог наш, и мы лю́дие па́жити Его́, и о́вцы руки́ Его́. Днесь а́ще глас Его́ услы́шите, не ожесточи́те серде́ц ва́ших, я́ко в прогне́вании, по дни искуше́ния в пусты́ни, во́ньже искуси́ша Мя отцы́ ва́ши, искуси́ша Мя, и ви́деша дела́ Моя́. Четы́редесять лет негодова́х ро́да того́, и рех, при́сно заблужда́ют се́рдцем, ти́и же не позна́ша путе́й Мои́х, я́ко кля́хся во гне́ве Мое́м, а́ще вни́дут в поко́й Мой.",
  ["текст_цс"] = "Прїиди́те, возра́дꙋемсѧ гдⷭ҇еви, воскли́кнемъ бг҃ꙋ сп҃си́телю на́шемꙋ: Предвари́мъ лицѐ є҆гѡ̀ во и҆сповѣ́данїи, и҆ во ѱалмѣ́хъ воскли́кнемъ є҆мꙋ̀: Ꙗ҆́кѡ бг҃ъ ве́лїй гдⷭ҇ь, и҆ цр҃ь ве́лїй по все́й землѝ: Ꙗ҆́кѡ въ рꙋцѣ̀ є҆гѡ̀ всѝ концы̀ землѝ, и҆ высѡты̀ го́ръ тогѡ̀ сꙋ́ть. Ꙗ҆́кѡ тогѡ̀ є҆́сть мо́ре, и҆ то́й сотворѝ є҆̀, и҆ сꙋ́шꙋ рꙋ́цѣ є҆гѡ̀ созда́стѣ. Прїиди́те, поклони́мсѧ и҆ припаде́мъ є҆мꙋ̀, и҆ воспла́чемсѧ пред̾ гдⷭ҇емъ сотво́ршимъ на́съ: Ꙗ҆́кѡ то́й є҆́сть бг҃ъ на́шъ, и҆ мы̀ лю́дїе па́жити є҆гѡ̀ и҆ ѻ҆́вцы рꙋкѝ є҆гѡ̀. Дне́сь а҆́ще гла́съ є҆гѡ̀ ᲂу҆слы́шите, Не ѡ҆жесточи́те серде́цъ ва́шихъ, ꙗ҆́кѡ въ прогнѣ́ванїи, по днѝ и҆скꙋше́нїѧ въ пꙋсты́ни: Во́ньже и҆скꙋси́ша мѧ̀ ѻ҆тцы̀ ва́ши, и҆скꙋси́ша мѧ̀, и҆ ви́дѣша дѣла̀ моѧ̑. Четы́редесѧть лѣ́тъ негодова́хъ ро́да тогѡ̀, и҆ рѣ́хъ: прⷭ҇нѡ заблꙋжда́ютъ се́рдцемъ, ті́и же не позна́ша пꙋте́й мои́хъ: Ꙗ҆́кѡ клѧ́хсѧ во гнѣ́вѣ мое́мъ, а҆́ще вни́дꙋтъ въ поко́й мо́й.",
  ["заголовок_ру"] = "Хвала́ пе́сни Дави́ду, не надпи́сан у евре́й.",
  ["заголовок_цс"] = "Хвала̀ пѣ́сни дв҃дꙋ, не надпи́санъ ᲂу҆ є҆врє́й."
}

add_psalom {
  ["номер"] = 95,
  ["часть"] = 1,
  ["кафизма"] = 13,
  ["слава"] = 2,
  ["текст_ру"] = "Воспо́йте Го́сподеви песнь но́ву, воспо́йте Го́сподеви вся земля́, воспо́йте Го́сподеви, благослови́те и́мя Его́, благовести́те день от дне спасе́ние Его́. Возвести́те во язы́цех сла́ву Его́, во всех лю́дех чудеса́ Его́. Я́ко Ве́лий Госпо́дь и хва́лен зело́, стра́шен есть над все́ми бо́ги. Я́ко вси бо́зи язы́к бе́сове: Госпо́дь же небеса́ сотвори́. Испове́дание и красота́ пред Ним, святы́ня и великоле́пие во святи́ле Его́. Принеси́те Го́сподеви оте́чествия язы́к, принеси́те Го́сподеви сла́ву и честь. Принеси́те Го́сподеви сла́ву и́мени Его́, возми́те же́ртвы, и входи́те во дворы́ Его́. Поклони́теся Го́сподеви во дворе́ святе́м Его́, да подви́жится от лица́ Его́ вся земля́. Рцы́те во язы́цех, я́ко Госпо́дь воцари́ся, и́бо испра́ви вселе́нную, я́же не подви́жится: су́дит лю́дем пра́востию. Да возвеселя́тся небеса́, и ра́дуется земля́, да подви́жится мо́ре и исполне́ние eго́. Возра́дуются поля́, и вся я́же на них: тогда́ возра́дуются вся древа́ дубра́вная от лица́ Госпо́дня, я́ко гряде́т, я́ко гряде́т суди́ти земли́, суди́ти вселе́нней в пра́вду, и лю́дем и́стиною Свое́ю.",
  ["текст_цс"] = "Воспо́йте гдⷭ҇еви пѣ́снь но́вꙋ, воспо́йте гдⷭ҇еви всѧ̀ землѧ̀: Воспо́йте гдⷭ҇еви, бл҃гослови́те и҆́мѧ є҆гѡ̀: бл҃говѣсти́те де́нь ѿ днѐ сп҃се́нїе є҆гѡ̀. Возвѣсти́те во ꙗ҆зы́цѣхъ сла́вꙋ є҆гѡ̀, во всѣ́хъ лю́дехъ чꙋдеса̀ є҆гѡ̀. Ꙗ҆́кѡ ве́лїй гдⷭ҇ь и҆ хва́ленъ ѕѣлѡ̀, стра́шенъ є҆́сть над̾ всѣ́ми бо́ги. Ꙗ҆́кѡ всѝ бо́зи ꙗ҆зы̑къ бѣ́сове: гдⷭ҇ь же небеса̀ сотворѝ. И҆сповѣ́данїе и҆ красота̀ пред̾ ни́мъ, ст҃ы́нѧ и҆ великолѣ́пїе во ст҃и́лѣ є҆гѡ̀. Принеси́те гдⷭ҇еви, ѻ҆те́чєствїѧ ꙗ҆зы̑къ, принеси́те гдⷭ҇еви сла́вꙋ и҆ че́сть. Принеси́те гдⷭ҇еви сла́вꙋ и҆́мени є҆гѡ̀: возми́те жє́ртвы и҆ входи́те во дворы̀ є҆гѡ̀. Поклони́тесѧ гдⷭ҇еви во дворѣ̀ ст҃ѣ́мъ є҆гѡ̀: да подви́житсѧ ѿ лица̀ є҆гѡ̀ всѧ̀ землѧ̀. Рцы́те во ꙗ҆зы́цѣхъ, ꙗ҆́кѡ гдⷭ҇ь воцр҃и́сѧ: и҆́бо и҆спра́ви вселе́ннꙋю, ꙗ҆́же не подви́житсѧ: сꙋ́дитъ лю́демъ пра́востїю. Да возвеселѧ́тсѧ нб҃са̀, и҆ ра́дꙋетсѧ землѧ̀: да подви́житсѧ мо́ре и҆ и҆сполне́нїе є҆гѡ̀: Возра́дꙋютсѧ полѧ̀, и҆ всѧ̑ ꙗ҆̀же на ни́хъ: тогда̀ возра́дꙋютсѧ всѧ̑ древа̀ дꙋбра̑внаѧ Ѿ лица̀ гдⷭ҇нѧ, ꙗ҆́кѡ грѧде́тъ, ꙗ҆́кѡ грѧде́тъ сꙋди́ти землѝ: сꙋди́ти вселе́ннѣй въ пра́вдꙋ, и҆ лю́демъ и҆́стиною свое́ю.",
  ["заголовок_ру"] = "Хвала́ пе́сни Дави́ду, внегда́ дом созида́шеся по плене́нии, не надпи́сан у евре́й.",
  ["заголовок_цс"] = "Хвала̀ пѣ́сни дв҃дꙋ, внегда̀ до́мъ созида́шесѧ по плѣне́нїи, не надпи́санъ ᲂу҆ є҆врє́й."
}

