add_psalom {
  ["номер"] = 100,
  ["часть"] = 1,
  ["кафизма"] = 13,
  ["слава"] = 3,
  ["текст_ру"] = "Ми́лость и суд воспою́ Тебе́, Го́споди. Пою́ и разуме́ю в пути́ непоро́чне, когда́ прии́деши ко мне? Прехожда́х в незло́бии се́рдца моего́ посреде́ до́му моего́. Не предлага́х пред очи́ма мои́ма вещь законопресту́пную: творя́щыя преступле́ние возненави́дех. Не прильпе́ мне се́рдце стропти́во, уклоня́ющагося от мене́ лука́ваго не позна́х. Оклевета́ющаго тай и́скренняго своего́, сего́ изгоня́х: го́рдым о́ком, и несы́тым се́рдцем, с сим не ядя́х. О́чи мои́ на ве́рныя земли́, посажда́ти я́ со мно́ю: ходя́й по пути́ непоро́чну, сей ми служа́ше. Не живя́ше посреде́ до́му моего́ творя́й горды́ню, глаго́ляй непра́ведная, не исправля́ше пред очи́ма мои́ма. Во у́трия избива́х вся гре́шныя земли́, е́же потреби́ти от гра́да Госпо́дня вся де́лающыя беззако́ние.",
  ["текст_цс"] = "Млⷭ҇ть и҆ сꙋ́дъ воспою̀ тебѣ̀, гдⷭ҇и: Пою̀ и҆ разꙋмѣ́ю въ пꙋтѝ непоро́чнѣ: когда̀ прїи́деши ко мнѣ̀; прехожда́хъ въ неѕло́бїи се́рдца моегѡ̀ посредѣ̀ до́мꙋ моегѡ̀. Не предлага́хъ пред̾ ѻ҆чи́ма мои́ма ве́щь законопрестꙋ́пнꙋю: творѧ́щыѧ престꙋпле́нїе возненави́дѣхъ: Не прильпѐ мнѣ̀ се́рдце стропти́во: ᲂу҆клонѧ́ющагосѧ ѿ менѐ лꙋка́ваго не позна́хъ. Ѡ҆клевета́ющаго та́й и҆́скреннѧго своего̀, сего̀ и҆згонѧ́хъ: го́рдымъ ѻ҆́комъ и҆ несы́тымъ се́рдцемъ, съ си́мъ не ꙗ҆дѧ́хъ. Ѻ҆́чи моѝ на вѣ̑рныѧ землѝ, посажда́ти ѧ҆̀ со мно́ю: ходѧ́й по пꙋтѝ непоро́чнꙋ, се́й мѝ слꙋжа́ше. Не живѧ́ше посредѣ̀ до́мꙋ моегѡ̀ творѧ́й горды́ню: глаго́лѧй непра́вєднаѧ не и҆справлѧ́ше пред̾ ѻ҆чи́ма мои́ма. Воꙋ́трїѧ и҆збива́хъ всѧ̑ грѣ̑шныѧ землѝ, є҆́же потреби́ти ѿ гра́да гдⷭ҇нѧ всѧ̑ дѣ́лающыѧ беззако́нїе.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
