  ["текст_ру"] = "Благослови́, душе́ моя́, Го́спода. Го́споди, Бо́же мой, возвели́чился еси́ зело́. Во испове́дание и в велеле́поту обле́клся еси́. Одея́йся све́том, я́ко ри́зою, простира́яй не́бо, я́ко ко́жу. Покрыва́яй вода́ми превы́спренняя Своя́, полага́яй о́блаки на восхожде́ние Свое́, ходя́й на крилу́ ве́треню. Творя́й А́нгелы Своя́ ду́хи и слуги́ Своя́ пла́мень о́гненный. Основа́яй зе́млю на тве́рди ея́, не преклони́тся в век ве́ка. Бе́здна, я́ко ри́за, одея́ние ея́, на гора́х ста́нут во́ды, от запреще́ния Твоего́ побе́гнут, от гла́са гро́ма Твоего́ убоя́тся. Восхо́дят го́ры и нисхо́дят поля́ в ме́сто, е́же основа́л еси́ им. Преде́л положи́л еси́, eго́же не пре́йдут, ниже́ обратя́тся покры́ти зе́млю. Посыла́яй исто́чники в де́брех, посреде́ гор про́йдут во́ды. Напая́ют вся зве́ри се́льныя, ждут она́гри в жа́жду свою́. На ты́х пти́цы небе́сныя привита́ют, от среды́ ка́мения дадя́т глас. Напая́яй го́ры от превы́спренних Свои́х, от плода́ дел Твои́х насы́тится земля́. Прозяба́яй траву́ ското́м, и злак на слу́жбу челове́ком, извести́ хлеб от земли́. И вино́ весели́т се́рдце челове́ка, ума́стити лице́ еле́ем, и хлеб се́рдце челове́ка укрепи́т. Насы́тятся древа́ польска́я, ке́дри Лива́нстии, и́хже еси́ насади́л. Та́мо пти́цы вогнездя́тся, ероди́ево жили́ще предводи́тельствует и́ми. Го́ры высо́кия еле́нем, ка́мень прибе́жище за́яцем. Сотвори́л есть луну́ во времена́, со́лнце позна́ за́пад свой. Положи́л еси́ тму, и бысть нощь, в не́йже про́йдут вси зве́рие дубра́внии. Ски́мни рыка́ющии, восхи́тити и взыска́ти от Бо́га пи́щу себе́. Возсия́ со́лнце и собра́шася и в ло́жах свои́х ля́гут. Изы́дет челове́к на де́ло свое́ и на де́лание свое́ до ве́чера. Я́ко возвели́чишася дела́ Твоя́, Го́споди, вся прему́дростию сотвори́л еси́, испо́лнися земля́ тва́ри Твоея́. Сие́ мо́ре вели́кое и простра́нное, та́мо га́ди, и́мже несть числа́, живо́тная ма́лая с вели́кими, та́мо корабли́ препла́вают, змий сей, eго́же созда́л еси руга́тися eму́. Вся к Тебе́ ча́ют, да́ти пи́щу им во бла́го вре́мя. Да́вшу Тебе́ им соберу́т, отве́рзшу Тебе́ ру́ку вся́ческая испо́лнятся бла́гости, отвра́щшу же Тебе́ лице́, возмяту́тся, отъи́меши дух их, и исче́знут, и в персть свою́ возвратя́тся. По́слеши Ду́ха Твоего́, и сози́ждутся, и обнови́ши лице́ земли́. Бу́ди сла́ва Госпо́дня во ве́ки, возвесели́тся Госпо́дь о де́лех Свои́х, призира́яй на зе́млю, и творя́й ю́ трясти́ся, прикаса́яйся гора́м, и дымя́тся. Воспою́ Го́сподеви в животе́ мое́м, пою́ Бо́гу моему́, до́ндеже есмь, да услади́тся Ему́ бесе́да моя́, аз же возвеселю́ся о Го́споде. Да исче́знут гре́шницы от земли́, и беззако́нницы, я́коже не бы́ти им. Благослови́, душе́ моя́, Го́спода.",
  ["текст_цс"] = "Бл҃гословѝ, дꙋшѐ моѧ̀, гдⷭ҇а. Гдⷭ҇и бж҃е мо́й, возвели́чилсѧ є҆сѝ ѕѣлѡ̀: во и҆сповѣ́данїе и҆ въ велелѣ́потꙋ ѡ҆бле́клсѧ є҆сѝ: Ѡ҆дѣѧ́йсѧ свѣ́томъ ꙗ҆́кѡ ри́зою, простира́ѧй не́бо ꙗ҆́кѡ ко́жꙋ: Покрыва́ѧй вода́ми превы́спрєннѧѧ своѧ̑, полага́ѧй ѻ҆́блаки на восхожде́нїе своѐ, ходѧ́й на крилꙋ̑ вѣ́трєню: Творѧ́й а҆́гг҃лы своѧ̑ дꙋ́хи, и҆ слꙋги̑ своѧ̑ пла́мень ѻ҆́гненный: Ѡ҆снова́ѧй зе́млю на тве́рди є҆ѧ̀: не преклони́тсѧ въ вѣ́къ вѣ́ка. Бе́здна ꙗ҆́кѡ ри́за ѡ҆дѣѧ́нїе є҆ѧ̀, на гора́хъ ста́нꙋтъ во́ды: Ѿ запреще́нїѧ твоегѡ̀ побѣ́гнꙋтъ, ѿ гла́са гро́ма твоегѡ̀ ᲂу҆боѧ́тсѧ. Восхо́дѧтъ го́ры, и҆ низхо́дѧтъ полѧ̀, въ мѣ́сто є҆́же ѡ҆снова́лъ є҆сѝ и҆̀мъ. Предѣ́лъ положи́лъ є҆сѝ, є҆гѡ́же не пре́йдꙋтъ, нижѐ ѡ҆братѧ́тсѧ покры́ти зе́млю. Посыла́ѧй и҆сто́чники въ де́брехъ, посредѣ̀ го́ръ про́йдꙋтъ во́ды. Напаѧ́ютъ всѧ̑ ѕвѣ́ри сє́льныѧ, ждꙋ́тъ ѻ҆на́гри въ жа́ждꙋ свою̀. На ты́хъ пти̑цы небє́сныѧ привита́ютъ: ѿ среды̀ ка́менїѧ дадѧ́тъ гла́съ. Напаѧ́ѧй го́ры ѿ превы́спреннихъ свои́хъ: ѿ плода̀ дѣ́лъ твои́хъ насы́титсѧ землѧ̀. Прозѧба́ѧй травꙋ̀ скотѡ́мъ, и҆ ѕла́къ на слꙋ́жбꙋ человѣ́кѡмъ, и҆звестѝ хлѣ́бъ ѿ землѝ: И҆ вїно̀ весели́тъ се́рдце человѣ́ка, ᲂу҆ма́стити лицѐ є҆ле́емъ: и҆ хлѣ́бъ се́рдце человѣ́ка ᲂу҆крѣпи́тъ. Насы́тѧтсѧ древа̀ пѡльска́ѧ, ке́дри лїва́нстїи, и҆̀хже є҆сѝ насади́лъ: Та́мѡ пти̑цы вогнѣздѧ́тсѧ, є҆рѡді́ево жили́ще предводи́тельствꙋетъ и҆́ми. Го́ры высѡ́кїѧ є҆ле́нємъ, ка́мень прибѣ́жище за́ѧцємъ. Сотвори́лъ є҆́сть лꙋнꙋ̀ во времена̀: со́лнце позна̀ за́падъ сво́й. Положи́лъ є҆сѝ тмꙋ̀, и҆ бы́сть но́щь, въ не́йже про́йдꙋтъ всѝ ѕвѣ́рїе дꙋбра́внїи, Скѵ́мни рыка́ющїи восхи́тити и҆ взыска́ти ѿ бг҃а пи́щꙋ себѣ̀. Возсїѧ̀ со́лнце, и҆ собра́шасѧ, и҆ въ ло́жахъ свои́хъ лѧ́гꙋтъ. И҆зы́детъ человѣ́къ на дѣ́ло своѐ и҆ на дѣ́ланїе своѐ до ве́чера. Ꙗ҆́кѡ возвели́чишасѧ дѣла̀ твоѧ̑, гдⷭ҇и: всѧ̑ премⷣростїю сотвори́лъ є҆сѝ: и҆спо́лнисѧ землѧ̀ тва́ри твоеѧ̀. Сїѐ мо́ре вели́кое и҆ простра́нное: та́мѡ га́ди, и҆́хже нѣ́сть числа̀, живѡ́тнаѧ ма̑лаѧ съ вели́кими: Та́мѡ кораблѝ препла́ваютъ, ѕмі́й се́й, є҆го́же созда́лъ є҆сѝ рꙋга́тисѧ є҆мꙋ̀. Всѧ̑ къ тебѣ̀ ча́ютъ, да́ти пи́щꙋ и҆̀мъ во бла́го вре́мѧ. Да́вшꙋ тебѣ̀ и҆̀мъ, соберꙋ́тъ: ѿве́рзшꙋ тебѣ̀ рꙋ́кꙋ, всѧ́чєскаѧ и҆спо́лнѧтсѧ бла́гости: Ѿвра́щшꙋ же тебѣ̀ лицѐ, возмѧтꙋ́тсѧ: ѿи́меши дꙋ́хъ и҆́хъ, и҆ и҆сче́знꙋтъ и҆ въ пе́рсть свою̀ возвратѧ́тсѧ: По́слеши дх҃а твоего̀, и҆ сози́ждꙋтсѧ, и҆ ѡ҆бнови́ши лицѐ землѝ. Бꙋ́ди сла́ва гдⷭ҇нѧ во вѣ́ки: возвесели́тсѧ гдⷭ҇ь ѡ҆ дѣ́лѣхъ свои́хъ: Призира́ѧй на зе́млю и҆ творѧ́й ю҆̀ трѧсти́сѧ: прикаса́ѧйсѧ гора́мъ, и҆ дымѧ́тсѧ. Воспою̀ гдⷭ҇еви въ животѣ̀ мое́мъ, пою̀ бг҃ꙋ моемꙋ̀, до́ндеже є҆́смь: Да ᲂу҆слади́тсѧ є҆мꙋ̀ бесѣ́да моѧ̀, а҆́зъ же возвеселю́сѧ ѡ҆ гдⷭ҇ѣ. Да и҆сче́знꙋтъ грѣ̑шницы ѿ землѝ, и҆ беззакѡ́нницы, ꙗ҆́коже не бы́ти и҆̀мъ. Бл҃гословѝ, дꙋшѐ моѧ̀, гдⷭ҇а.",
  ["заголовок_ру"] = "Псало́м Дави́ду, о мирсте́м бытии́.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, ѡ҆ мїрстѣ́мъ бытїѝ."
}

add_psalom {
  ["номер"] = 104,
  ["часть"] = 1,
  ["кафизма"] = 14,
  ["слава"] = 3,
  ["текст_ру"] = "Испове́дайтеся Го́сподеви, и призыва́йте и́мя Его́, возвести́те во язы́цех дела́ Его́. Воспо́йте Ему́ и по́йте Ему́, пове́дите вся чудеса́ Его́. Хвали́теся о и́мени святе́м Его́, да возвесели́тся се́рдце и́щущих Го́спода. Взыщи́те Го́спода, и утверди́теся, взыщи́те лица́ Его́ вы́ну. Помяни́те чудеса́ Его́, я́же сотвори́, чудеса́ Его́, и судьбы́ уст Его́. Се́мя Авра́амле раби́ Его́, сы́нове Иа́ковли избра́ннии Его́. Той Госпо́дь Бог наш, по всей земли́ судьбы́ Его́. Помяну́ в век заве́т Свой, сло́во, е́же запове́да в ты́сящы родо́в, е́же завеща́ Авраа́му, и кля́тву Свою́ Исаа́ку. И поста́ви ю́ Иа́кову в повеле́ние, и Изра́илю в заве́т ве́чен, глаго́ля: тебе́ дам зе́млю Ханаа́ню, у́же достоя́ния ва́шего, внегда́ бы́ти им ма́лым число́м, мале́йшым и прише́льцем в ней. И преидо́ша от язы́ка в язы́к, и от ца́рствия в лю́ди и́ны. Не оста́ви челове́ка оби́дети их, и обличи́ о них цари́. Не прикаса́йтеся пома́занным мои́м, и во проро́цех мои́х не лука́внуйте. И призва́ глад на зе́млю, вся́ко утверже́ние хле́бное сотры́. Посла́ пред ни́ми челове́ка: в раба́ про́дан бысть Ио́сиф. Смири́ша во око́вах но́зе eго́, желе́зо про́йде душа́ eго́, до́ндеже прии́де сло́во Его́, сло́во Госпо́дне разжже́ eго́. Посла́ царь и разреши́ eго́: князь люде́й, и оста́ви eго́. Поста́ви eго́ господи́на до́му своему́, и кня́зя всему́ стяжа́нию своему́, наказа́ти кня́зи eго́ я́ко себе́, и ста́рцы eго́ умудри́ти. И вни́де Изра́иль во Еги́пет, и Иа́ков прише́льствова в зе́млю Ха́мову. И возрасти́ лю́ди своя́ зело́, и укрепи́ я́ па́че враго́в их. Преврати́ се́рдце их возненави́дети лю́ди Его́, лесть сотвори́ти в рабе́х Его́. Посла́ Моисе́а раба́ Своего́, Ааро́на, eго́же избра́ Себе́. Положи́ в них словеса́ зна́мений Свои́х, и чуде́с Свои́х в земли́ Ха́мове. Посла́ тму и помрачи́, я́ко преогорчи́ша словеса́ Его́. Преложи́ во́ды их в кровь, и измори́ ры́бы их. Воскипе́ земля́ их жа́бами в сокро́вищницах царе́й их. Рече́, и приидо́ша пе́сия му́хи, и скни́пы во вся преде́лы их. Положи́ дожди́ их гра́ды, огнь попаля́ющ в земли́ их, и порази́ виногра́ды их и смо́квы их, и сотры́ вся́кое дре́во преде́л их. Рече́, и приидо́ша пру́зи и гу́сеницы, и́мже не бе числа́. И снедо́ша вся́ку траву́ в земли́ их, и поядо́ша всяк плод земли́ их. И порази́ вся́каго пе́рвенца в земли́ их, нача́ток вся́каго труда́ их, и изведе́ я́ с сребро́м и зла́том, и не бе в коле́нах их боля́й. Возвесели́ся Еги́пет во исхожде́нии их, я́ко нападе́ страх их на ня. Распростре́ о́блак в покро́в им и огнь, е́же просвети́ти им но́щию. Проси́ша и приидо́ша кра́стели, и хле́ба небе́снаго насы́ти я́, разве́рзе ка́мень и потеко́ша во́ды, потеко́ша в безво́дных ре́ки, я́ко помяну́ сло́во свято́е Свое́, е́же ко Авраа́му, рабу́ Своему́. И изведе́ лю́ди Своя́ в ра́дости, и избра́нныя Своя́ в весе́лии. И даде́ им страны́ язы́к, и труды́ люде́й насле́доваша, я́ко да сохраня́т оправда́ния Его́ и зако́на Его́ взы́щут.",
  ["текст_цс"] = "И҆сповѣ́дайтесѧ гдⷭ҇еви и҆ призыва́йте и҆́мѧ є҆гѡ̀, возвѣсти́те во ꙗ҆зы́цѣхъ дѣла̀ є҆гѡ̀: Воспо́йте є҆мꙋ̀ и҆ по́йте є҆мꙋ̀, повѣ́дите всѧ̑ чꙋдеса̀ є҆гѡ̀. Хвали́тесѧ ѡ҆ и҆́мени ст҃ѣ́мъ є҆гѡ̀: да возвесели́тсѧ се́рдце и҆́щꙋщихъ гдⷭ҇а: Взыщи́те гдⷭ҇а и҆ ᲂу҆тверди́тесѧ, взыщи́те лица̀ є҆гѡ̀ вы́нꙋ. Помѧни́те чꙋдеса̀ є҆гѡ̀, ꙗ҆̀же сотворѝ, чꙋдеса̀ є҆гѡ̀ и҆ сꙋдьбы̑ ᲂу҆́стъ є҆гѡ̀, Сѣ́мѧ а҆враа́мле рабѝ є҆гѡ̀, сы́нове і҆а̑кѡвли и҆збра́ннїи є҆гѡ̀. То́й гдⷭ҇ь бг҃ъ на́шъ: по все́й землѝ сꙋдьбы̑ є҆гѡ̀. Помѧнꙋ̀ въ вѣ́къ завѣ́тъ сво́й, сло́во, є҆́же заповѣ́да въ ты́сѧщы родѡ́въ, Є҆́же завѣща̀ а҆враа́мꙋ, и҆ клѧ́твꙋ свою̀ і҆саа́кꙋ: И҆ поста́ви ю҆̀ і҆а́кѡвꙋ въ повелѣ́нїе и҆ і҆и҃лю въ завѣ́тъ вѣ́ченъ, Гл҃ѧ: тебѣ̀ да́мъ зе́млю ханаа́ню, ᲂу҆́же достоѧ́нїѧ ва́шегѡ. Внегда̀ бы́ти и҆̀мъ ма̑лымъ число́мъ, малѣ́йшымъ и҆ прише́льцємъ въ не́й, И҆ преидо́ша ѿ ꙗ҆зы́ка въ ꙗ҆зы́къ и҆ ѿ ца́рствїѧ въ лю́ди и҆́ны: Не ѡ҆ста́ви человѣ́ка ѡ҆би́дѣти и҆̀хъ и҆ ѡ҆бличѝ ѡ҆ ни́хъ царѝ: Не прикаса́йтесѧ пома̑заннымъ мои̑мъ, и҆ во прⷪ҇ро́цѣхъ мои́хъ не лꙋка́внꙋйте. И҆ призва̀ гла́дъ на зе́млю: всѧ́ко ᲂу҆твержде́нїе хлѣ́бное сотры̀. Посла̀ пред̾ ни́ми человѣ́ка: въ раба̀ про́данъ бы́сть і҆ѡ́сифъ. Смири́ша во ѡ҆ко́вахъ но́зѣ є҆гѡ̀, желѣ́зо про́йде дꙋша̀ є҆гѡ̀, До́ндеже прїи́де сло́во є҆гѡ̀: сло́во гдⷭ҇не разжжѐ є҆го̀. Посла̀ ца́рь и҆ разрѣшѝ є҆го̀: кнѧ́зь люде́й, и҆ ѡ҆ста́ви є҆го̀. Поста́ви є҆го̀ господи́на до́мꙋ своемꙋ̀ и҆ кнѧ́зѧ всемꙋ̀ стѧжа́нїю своемꙋ̀, Наказа́ти кнѧ̑зи є҆гѡ̀ ꙗ҆́кѡ себѐ и҆ ста́рцы є҆гѡ̀ ᲂу҆мꙋдри́ти. И҆ вни́де і҆и҃ль во є҆гѵ́петъ, и҆ і҆а́кѡвъ прише́льствова въ зе́млю ха́мовꙋ. И҆ возрастѝ лю́ди своѧ̑ ѕѣлѡ̀ и҆ ᲂу҆крѣпѝ ѧ҆̀ па́че врагѡ́въ и҆́хъ. Превратѝ се́рдце и҆́хъ возненави́дѣти лю́ди є҆гѡ̀, ле́сть сотвори́ти въ рабѣ́хъ є҆гѡ̀. Посла̀ мѡѷсе́а раба̀ своего̀, а҆арѡ́на, є҆го́же и҆збра̀ себѣ̀: Положѝ въ ни́хъ словеса̀ зна́менїй свои́хъ и҆ чꙋде́съ свои́хъ въ землѝ ха́мовѣ. Посла̀ тмꙋ̀ и҆ помрачѝ, ꙗ҆́кѡ преѡгорчи́ша словеса̀ є҆гѡ̀. Преложѝ во́ды и҆́хъ въ кро́вь и҆ и҆зморѝ ры̑бы и҆́хъ. Воскипѣ̀ землѧ̀ и҆́хъ жа́бами въ сокро́вищницахъ царе́й и҆́хъ. Речѐ, и҆ прїидо́ша пє́сїѧ мꙋ̑хи и҆ скни̑пы во всѧ̑ предѣ́лы и҆́хъ. Положѝ дождѝ и҆́хъ гра́ды, ѻ҆́гнь попалѧ́ющь въ землѝ и҆́хъ: И҆ поразѝ вїногра́ды и҆́хъ и҆ смѡ́квы и҆́хъ, и҆ сотры̀ всѧ́кое дре́во предѣ̑лъ и҆́хъ. Речѐ, и҆ прїидо́ша прꙋ́зи и҆ гꙋ́сєницы, и҆̀мже не бѣ̀ числа̀, И҆ снѣдо́ша всѧ́кꙋ травꙋ̀ въ землѝ и҆́хъ, и҆ поѧдо́ша всѧ́къ пло́дъ землѝ и҆́хъ. И҆ поразѝ всѧ́каго пе́рвенца въ землѝ и҆́хъ, нача́токъ всѧ́кагѡ трꙋда̀ и҆́хъ: И҆ и҆зведѐ ѧ҆̀ съ сребро́мъ и҆ зла́томъ: и҆ не бѣ̀ въ колѣ́нѣхъ и҆́хъ болѧ́й. Возвесели́сѧ є҆гѵ́петъ во и҆схожде́нїи и҆́хъ: ꙗ҆́кѡ нападѐ стра́хъ и҆́хъ на нѧ̀. Распрострѐ ѻ҆́блакъ въ покро́въ и҆̀мъ, и҆ ѻ҆́гнь, є҆́же просвѣти́ти и҆̀мъ но́щїю. Проси́ша, и҆ прїидо́ша кра́стели, и҆ хлѣ́ба небе́снагѡ насы́ти ѧ҆̀: Разве́рзе ка́мень, и҆ потеко́ша во́ды, потеко́ша въ безво́дныхъ рѣ́ки: Ꙗ҆́кѡ помѧнꙋ̀ сло́во ст҃о́е своѐ, є҆́же ко а҆враа́мꙋ рабꙋ̀ своемꙋ̀. И҆ и҆зведѐ лю́ди своѧ̑ въ ра́дости и҆ и҆збра̑нныѧ своѧ̑ въ весе́лїи. И҆ дадѐ и҆̀мъ страны̑ ꙗ҆зы̑къ, и҆ трꙋды̀ люде́й наслѣ́доваша: Ꙗ҆́кѡ да сохранѧ́тъ ѡ҆правда̑нїѧ є҆гѡ̀ и҆ зако́на є҆гѡ̀ взы́щꙋтъ.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 105,
  ["часть"] = 1,
  ["кафизма"] = 15,
  ["слава"] = 1,
  ["текст_ру"] = "Испове́дайтеся Го́сподеви, я́ко благ, я́ко в век ми́лость Его́. Кто возглаго́лет си́лы Госпо́дни? Слы́шаны сотвори́т вся хвалы́ Его́? Блаже́ни храня́щии суд и творя́щии пра́вду во вся́кое вре́мя. Помяни́ нас, Го́споди, во благоволе́нии люде́й Твои́х, посети́ нас спасе́нием Твои́м. Ви́дети во бла́гости избра́нныя Твоя́, возвесели́тися в весе́лии язы́ка Твоего́, хвали́тися с достоя́нием Твои́м. Согреши́хом со отцы́ на́шими, беззако́нновахом, непра́вдовахом. Отцы́ на́ши во Еги́пте не разуме́ша чуде́с Твои́х, ни помяну́ша мно́жества ми́лости Твоея́ и преогорчи́ша восходя́ще в Чермно́е мо́ре. И спасе́ их и́мене Своего́ ра́ди, сказа́ти си́лу Свою́, и запрети́ Чермно́му мо́рю, и изся́че, и наста́ви я́ в бездне, я́ко в пусты́ни. И спасе́ я́ из руки́ ненави́дящих, и изба́ви я́ из руки́ враго́в. Покры́ вода́ стужа́ющыя им, ни еди́н от них избы́сть. И ве́роваша словеси́ Его́, и воспе́ша хвалу́ Его́. Ускори́ша, забы́ша дела́ Его́, не стерпе́ша сове́та Его́ и похоте́ша жела́нию в пусты́ни, и искуси́ша Бо́га в безво́дней. И даде́ им проше́ние их, посла́ сы́тость в ду́шы их. И прогне́ваша Моисе́а в стану́, Ааро́на свята́го Госпо́дня. Отве́рзеся земля́ и пожре́ Дафа́на, и покры́ на со́нмищи Авиро́на, и разжже́ся огнь в со́нме их, пла́мень попали́ гре́шники. И сотвори́ша тельца́ в Хори́ве, и поклони́шася истука́нному, и измени́ша сла́ву Его́ в подо́бие тельца́ яду́щаго траву́, и забы́ша Бо́га спаса́ющаго их, сотво́ршаго ве́лия во Еги́пте, чудеса́ в земли́ Ха́мове, стра́шная в мо́ри Чермне́м. И рече́ потреби́ти их, а́ще не бы Моисе́й, избра́нный Его́, стал в сокруше́нии пред Ним, возврати́ти я́рость Его́, да не погуби́т их. И уничижи́ша зе́млю жела́нную, не я́ша ве́ры словеси́ Его́, и поропта́ша в селе́ниих свои́х, не услы́шаша гла́са Госпо́дня. И воздви́же ру́ку Свою́ на ня, низложи́ти я́ в пусты́ни. И низложи́ти се́мя их во язы́цех, и расточи́ти я́ в страны́. И причасти́шася Веельфего́ру, и снедо́ша же́ртвы ме́ртвых. И раздражи́ша Eго́ в начина́ниих свои́х, и умно́жися в них паде́ние. И ста Финее́с, и уми́лостиви, и преста́ сечь. И вмени́ся eму́ в пра́вду, в род и род до ве́ка. И прогне́ваша Его́ на воде́ пререка́ния, и озло́блен бысть Моисе́й их ра́ди, я́ко преогорчи́ша дух eго́ и ра́знствова устна́ма свои́ма. Не потреби́ша язы́ки, я́же рече́ Госпо́дь им, и смеси́шася во язы́цех, и навыко́ша дело́м их. И порабо́таша истука́нным их, и бысть им в собла́зн, и пожро́ша сы́ны своя́ и дще́ри своя́ бесово́м, и пролия́ша кровь непови́нную, кровь сыно́в свои́х и дще́рей, я́же пожро́ша истука́нным ханаа́нским, и убие́на бысть земля́ их кровьми́, и оскверни́ся в де́лех их, и соблуди́ша в начина́ниих свои́х. И разгне́вася я́ростию Госпо́дь на лю́ди Своя́, и омерзи́ достоя́ние Свое́, и предаде́ я́ в ру́ки враго́в, и облада́ша и́ми ненави́дящии их. И стужи́ша им врази́ их, и смири́шася под рука́ми их. Мно́жицею изба́ви я́, ти́и же преогорчи́ша Его́ сове́том свои́м и смири́шася в беззако́ниих свои́х. И ви́де Госпо́дь, внегда́ скорбе́ти им, внегда́ услы́шаше моле́ние их. И помяну́ заве́т Свой, и раска́яся по мно́жеству ми́лости Своея́, и даде́ я́ в щедро́ты пред все́ми плени́вшими я́. Спаси́ ны, Го́споди Бо́же наш, и собери́ ны от язы́к испове́датися и́мени Твоему́ свято́му, хвали́тися во хвале́ Твое́й. Благослове́н Госпо́дь Бог Изра́илев от ве́ка и до ве́ка. И реку́т вси лю́дие: бу́ди, бу́ди.",
  ["текст_цс"] = "И҆сповѣ́дайтесѧ гдⷭ҇еви, ꙗ҆́кѡ бл҃гъ, ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Кто̀ возглаго́летъ си̑лы гдⷭ҇ни, слы̑шаны сотвори́тъ всѧ̑ хвалы̑ є҆гѡ̀; Бл҃же́ни хранѧ́щїи сꙋ́дъ и҆ творѧ́щїи пра́вдꙋ во всѧ́кое вре́мѧ. Помѧнѝ на́съ, гдⷭ҇и, во бл҃говоле́нїи люде́й твои́хъ, посѣтѝ на́съ сп҃се́нїемъ твои́мъ, Ви́дѣти во бла́гости и҆збра̑нныѧ твоѧ̑, возвесели́тисѧ въ весе́лїи ꙗ҆зы́ка твоегѡ̀, хвали́тисѧ съ достоѧ́нїемъ твои́мъ. Согрѣши́хомъ со ѻ҆тцы̀ на́шими, беззако́нновахомъ, непра́вдовахомъ: Ѻ҆тцы̀ на́ши во є҆гѵ́птѣ не разꙋмѣ́ша чꙋде́съ твои́хъ, ни помѧнꙋ́ша мно́жества млⷭ҇ти твоеѧ̀: и҆ преѡгорчи́ша восходѧ́ще въ чермно́е мо́ре. И҆ сп҃сѐ и҆̀хъ и҆́мене своегѡ̀ ра́ди, сказа́ти си́лꙋ свою̀: И҆ запретѝ чермно́мꙋ мо́рю, и҆ и҆зсѧ́че: и҆ наста́ви ѧ҆̀ въ бе́зднѣ ꙗ҆́кѡ въ пꙋсты́ни. И҆ сп҃сѐ ѧ҆̀ и҆з̾ рꙋкѝ ненави́дѧщихъ и҆ и҆зба́ви ѧ҆̀ и҆з̾ рꙋкѝ врагѡ́въ. Покры̀ вода̀ стꙋжа́ющыѧ и҆̀мъ: ни є҆ди́нъ ѿ ни́хъ и҆збы́сть. И҆ вѣ́роваша словесѝ є҆гѡ̀ и҆ воспѣ́ша хвалꙋ̀ є҆гѡ̀. Оу҆скори́ша, забы́ша дѣла̀ є҆гѡ̀, не стерпѣ́ша совѣ́та є҆гѡ̀: И҆ похотѣ́ша жела́нїю въ пꙋсты́ни и҆ и҆скꙋси́ша бг҃а въ безво́днѣй. И҆ дадѐ и҆̀мъ проше́нїе и҆́хъ, посла̀ сы́тость въ дꙋ́шы и҆́хъ. И҆ прогнѣ́ваша мѡѷсе́а въ станꙋ̀, а҆арѡ́на ст҃а́го гдⷭ҇нѧ. Ѿве́рзесѧ землѧ̀ и҆ пожрѐ даѳа́на и҆ покры̀ на со́нмищи а҆вїрѡ́на: И҆ разжже́сѧ ѻ҆́гнь въ со́нмѣ и҆́хъ, пла́мень попалѝ грѣ́шники. И҆ сотвори́ша тельца̀ въ хѡри́вѣ и҆ поклони́шасѧ и҆стꙋка́нномꙋ: И҆ и҆змѣни́ша сла́вꙋ є҆гѡ̀ въ подо́бїе тельца̀ ꙗ҆дꙋ́щагѡ травꙋ̀. И҆ забы́ша бг҃а сп҃са́ющаго и҆̀хъ, сотво́ршаго вє́лїѧ во є҆гѵ́птѣ, чꙋдеса̀ въ землѝ ха́мовѣ, стра̑шнаѧ въ мо́ри чермнѣ́мъ. И҆ речѐ потреби́ти и҆̀хъ, а҆́ще не бы̀ мѡѷсе́й и҆збра́нный є҆гѡ̀ ста́лъ въ сокрꙋше́нїи пред̾ ни́мъ, возврати́ти ꙗ҆́рость є҆гѡ̀, да не погꙋби́тъ и҆̀хъ. И҆ ᲂу҆ничижи́ша зе́млю жела́ннꙋю, не ꙗ҆́ша вѣ́ры словесѝ є҆гѡ̀: И҆ поропта́ша въ селе́нїихъ свои́хъ, не ᲂу҆слы́шаша гла́са гдⷭ҇нѧ. И҆ воздви́же рꙋ́кꙋ свою̀ на нѧ̀, низложи́ти ѧ҆̀ въ пꙋсты́ни, И҆ низложи́ти сѣ́мѧ и҆́хъ во ꙗ҆зы́цѣхъ, и҆ расточи́ти ѧ҆̀ въ страны̑. И҆ причасти́шасѧ веельфегѡ́рꙋ и҆ снѣдо́ша жє́ртвы ме́ртвыхъ: И҆ раздражи́ша є҆го̀ въ начина́нїихъ свои́хъ, и҆ ᲂу҆мно́жисѧ въ ни́хъ паде́нїе. И҆ ста̀ фїнее́съ и҆ ᲂу҆ми́лостиви, и҆ преста̀ сѣ́чь: И҆ вмѣни́сѧ є҆мꙋ̀ въ пра́вдꙋ, въ ро́дъ и҆ ро́дъ до вѣ́ка. И҆ прогнѣ́ваша є҆го̀ на водѣ̀ прерѣка́нїѧ, и҆ ѡ҆ѕло́бленъ бы́сть мѡѷсе́й и҆́хъ ра́ди: Ꙗ҆́кѡ преѡгорчи́ша дꙋ́хъ є҆гѡ̀ и҆ ра́знствова ᲂу҆стна́ма свои́ма. Не потреби́ша ꙗ҆зы́ки, ꙗ҆̀же речѐ гдⷭ҇ь и҆̀мъ. И҆ смѣси́шасѧ во ꙗ҆зы́цѣхъ и҆ навыко́ша дѣлѡ́мъ и҆́хъ: И҆ порабо́таша и҆стꙋка̑ннымъ и҆́хъ, и҆ бы́сть и҆̀мъ въ собла́знъ. И҆ пожро́ша сы́ны своѧ̑ и҆ дщє́ри своѧ̑ бѣсовѡ́мъ, И҆ пролїѧ́ша кро́вь непови́ннꙋю, кро́вь сынѡ́въ свои́хъ и҆ дще́рей, ꙗ҆̀же пожро́ша и҆стꙋка̑ннымъ ханаа̑нскимъ: и҆ ᲂу҆бїе́на бы́сть землѧ̀ и҆́хъ кровьмѝ И҆ ѡ҆скверни́сѧ въ дѣ́лѣхъ и҆́хъ: и҆ соблꙋди́ша въ начина́нїихъ свои́хъ. И҆ разгнѣ́васѧ ꙗ҆́ростїю гдⷭ҇ь на лю́ди своѧ̑ и҆ ѡ҆мерзѝ достоѧ́нїе своѐ: И҆ предадѐ ѧ҆̀ въ рꙋ́ки врагѡ́въ, и҆ ѡ҆блада́ша и҆́ми ненави́дѧщїи и҆̀хъ. И҆ стꙋжи́ша и҆̀мъ вразѝ и҆́хъ: и҆ смири́шасѧ под̾ рꙋка́ми и҆́хъ. Мно́жицею и҆зба́ви ѧ҆̀: ті́и же преѡгорчи́ша є҆го̀ совѣ́томъ свои́мъ, и҆ смири́шасѧ въ беззако́нїихъ свои́хъ. И҆ ви́дѣ гдⷭ҇ь, внегда̀ скорбѣ́ти и҆̀мъ, внегда̀ ᲂу҆слы́шаше моле́нїе и҆́хъ: И҆ помѧнꙋ̀ завѣ́тъ сво́й, и҆ раска́ѧсѧ по мно́жествꙋ млⷭ҇ти своеѧ̀: И҆ дадѐ ѧ҆̀ въ щедрѡ́ты пред̾ всѣ́ми плѣни́вшими ѧ҆̀. Сп҃си́ ны, гдⷭ҇и, бж҃е на́шъ, и҆ собери́ ны ѿ ꙗ҆зы̑къ, и҆сповѣ́датисѧ и҆́мени твоемꙋ̀ ст҃о́мꙋ, хвали́тисѧ во хвалѣ̀ твое́й. Бл҃гослове́нъ гдⷭ҇ь бг҃ъ і҆и҃левъ ѿ вѣ́ка и҆ до вѣ́ка. И҆ рекꙋ́тъ всѝ лю́дїе: бꙋ́ди, бꙋ́ди.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 106,
  ["часть"] = 1,
  ["кафизма"] = 15,
  ["слава"] = 2,
  ["текст_ру"] = "Испове́дайтеся Го́сподеви, я́ко благ, я́ко в век ми́лость Его́. Да реку́т изба́влении Го́сподем, и́хже изба́ви из руки́ врага́ и от стран собра́ их, от восто́к и за́пад, и се́вера, и мо́ря. Заблуди́ша в пусты́ни безво́дней, пути́ гра́да оби́тельнаго не обрето́ша. А́лчуще и жа́ждуще, душа́ их в них исчезе́. И воззва́ша ко Го́споду, внегда́ скорбе́ти им, и от нужд их изба́ви я́, и наста́ви я́ на путь прав, вни́ти во град оби́тельный. Да испове́дятся Го́сподеви ми́лости Его́, и чудеса́ Его́ сыново́м челове́ческим, я́ко насы́тил есть ду́шу тщу и ду́шу а́лчущу испо́лни благ. Седя́щыя во тьме и се́ни сме́ртней, окова́нныя нище́тою и желе́зом, я́ко преогорчи́ша словеса́ Бо́жия и сове́т Вы́шняго раздражи́ша. И смири́ся в труде́х се́рдце их, и изнемого́ша, и не бе помога́яй. И воззва́ша ко Го́споду, внегда́ скорбе́ти им, и от нужд их спасе́ я́, и изведе́ я́ из тьмы и се́ни сме́ртныя, и у́зы их растерза́. Да испове́дятся Го́сподеви ми́лости Его́, и чудеса́ Его́ сыново́м челове́ческим, я́ко сокруши́ врата́ ме́дная и вереи́ желе́зныя сломи́. Восприя́т я́ от пути́ беззако́ния их, беззако́ний бо ра́ди свои́х смири́шася. Вся́каго бра́шна возгнуша́ся душа́ их, и прибли́жишася до врат сме́ртных. И воззва́ша ко Го́споду, внегда́ скорбе́ти им, и от нужд их спасе́ я́, посла́ Сло́во Свое́ и исцели́ я́, и изба́ви я́ от растле́ний их. Да испове́дятся Го́сподеви ми́лости Его́, и чудеса́ Его́ сыново́м челове́ческим, и да пожру́т Ему́ же́ртву хвалы́, и да возвестя́т дела́ Его́ в ра́дости. Сходя́щии в мо́ре в корабля́х, творя́щии де́лания в вода́х мно́гих, ти́и ви́деша дела́ Госпо́дня и чудеса́ Его́ во глубине́. Рече́, и ста дух бу́рен, и вознесо́шася во́лны eго́, восхо́дят до небе́с и низхо́дят до бездн, душа́ их в злых та́яше: смято́шася, подвиго́шася, я́ко пия́ный, и вся му́дрость их поглощена́ бысть. И воззва́ша ко Го́споду, внегда́ скорбе́ти им, и от нужд их изведе́ я́, и повеле́ бу́ри, и ста в тишину́, и умолко́ша во́лны eго́. И возвесели́шася, я́ко умолко́ша, и наста́ви я́ в приста́нище хоте́ния своего́. Да испове́дятся Го́сподеви ми́лости Его́, и чудеса́ Его́ сыново́м челове́ческим: да вознесу́т Его́ в це́ркви людсте́й и на седа́лищи ста́рец восхва́лят Его́. Положи́л есть ре́ки в пусты́ню, и исхо́дища водна́я в жа́жду, зе́млю плодоно́сную в сла́ность, от зло́бы живу́щих на ней. Положи́л есть пусты́ню во езе́ра водна́я и зе́млю безво́дную во исхо́дища водна́я. И насели́ та́мо а́лчущыя, и соста́виша гра́ды оби́тельны, и насе́яша се́ла, и насади́ша виногра́ды, и сотвори́ша плод жи́тен. И благослови́ я́, и умно́жишася зело́, и скоты́ их не ума́ли. И ума́лишася, и озло́бишася от ско́рби зол и боле́зни. Излия́ся уничиже́ние на кня́зи их, и облазни́ я́ по непрохо́дней, а не по пути́. И помо́же убо́гу от нищеты́ и положи́ я́ко о́вцы оте́чествия. У́зрят пра́вии и возвеселя́тся, и вся́кое беззако́ние загради́т уста́ своя́. Кто прему́др и сохрани́т сия́? И уразуме́ют ми́лости Госпо́дни.",
  ["текст_цс"] = "И҆сповѣ́дайтесѧ гдⷭ҇еви, ꙗ҆́кѡ бл҃гъ, ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Да рекꙋ́тъ и҆зба́вленнїи гдⷭ҇емъ, и҆̀хже и҆зба́ви и҆з̾ рꙋкѝ врага̀, И҆ ѿ стра́нъ собра̀ и҆́хъ, ѿ востѡ́къ и҆ за̑падъ, и҆ сѣ́вера и҆ мо́рѧ: Заблꙋди́ша въ пꙋсты́ни безво́днѣй, пꙋтѝ гра́да ѻ҆би́тельнагѡ не ѡ҆брѣто́ша: А҆́лчꙋще и҆ жа́ждꙋще, дꙋша̀ и҆́хъ въ ни́хъ и҆счезѐ. И҆ воззва́ша ко гдⷭ҇ꙋ, внегда̀ скорбѣ́ти и҆̀мъ, и҆ ѿ нꙋ́ждъ и҆́хъ и҆зба́ви ѧ҆̀: И҆ наста́ви ѧ҆̀ на пꙋ́ть пра́въ, вни́ти во гра́дъ ѻ҆би́тельный. Да и҆сповѣ́дѧтсѧ гдⷭ҇еви млⷭ҇ти є҆гѡ̀ и҆ чꙋдеса̀ є҆гѡ̀ сыновѡ́мъ человѣ́чєскимъ: Ꙗ҆́кѡ насы́тилъ є҆́сть дꙋ́шꙋ тщꙋ̀, и҆ дꙋ́шꙋ а҆́лчꙋщꙋ и҆спо́лни бла̑гъ: Сѣдѧ́щыѧ во тмѣ̀ и҆ сѣ́ни сме́ртнѣй, ѡ҆кова̑нныѧ нището́ю и҆ желѣ́зомъ, Ꙗ҆́кѡ преѡгорчи́ша словеса̀ бж҃їѧ, и҆ совѣ́тъ вы́шнѧгѡ раздражи́ша. И҆ смири́сѧ въ трꙋдѣ́хъ се́рдце и҆́хъ, и҆ и҆знемого́ша, и҆ не бѣ̀ помога́ѧй. И҆ воззва́ша ко гдⷭ҇ꙋ, внегда̀ скорбѣ́ти и҆̀мъ, и҆ ѿ нꙋ́ждъ и҆́хъ сп҃сѐ ѧ҆̀: И҆ и҆зведѐ ѧ҆̀ и҆з̾ тмы̀ и҆ сѣ́ни сме́ртныѧ, и҆ ᲂу҆́зы и҆́хъ растерза̀. Да и҆сповѣ́дѧтсѧ гдⷭ҇еви млⷭ҇ти є҆гѡ̀ и҆ чꙋдеса̀ є҆гѡ̀ сыновѡ́мъ человѣ́чєскимъ: Ꙗ҆́кѡ сокрꙋшѝ врата̀ мѣ̑днаѧ, и҆ верєѝ желѣ̑зныѧ сломѝ. Воспрїѧ́тъ ѧ҆̀ ѿ пꙋтѝ беззако́нїѧ и҆́хъ: беззако́нїй бо ра́ди свои́хъ смири́шасѧ. Всѧ́кагѡ бра́шна возгнꙋша́сѧ дꙋша̀ и҆́хъ, и҆ прибли́жишасѧ до вра́тъ сме́ртныхъ. И҆ воззва́ша ко гдⷭ҇ꙋ, внегда̀ скорбѣ́ти и҆̀мъ, и҆ ѿ нꙋ́ждъ и҆́хъ сп҃сѐ ѧ҆̀: Посла̀ сло́во своѐ, и҆ и҆сцѣлѝ ѧ҆̀, и҆ и҆зба́ви ѧ҆̀ ѿ растлѣ́нїй и҆́хъ. ꙳Да и҆сповѣ́дѧтсѧ꙳ гдⷭ҇еви млⷭ҇ти є҆гѡ̀ и҆ чꙋдеса̀ є҆гѡ̀ сыновѡ́мъ человѣ́чєскимъ: И҆ да пожрꙋ́тъ є҆мꙋ̀ же́ртвꙋ хвалы̀ и҆ да возвѣстѧ́тъ дѣла̀ є҆гѡ̀ въ ра́дости. Сходѧ́щїи въ мо́ре въ корабле́хъ, творѧ́щїи дѣ̑ланїѧ въ вода́хъ мно́гихъ, Ті́и ви́дѣша дѣла̀ гдⷭ҇нѧ и҆ чꙋдеса̀ є҆гѡ̀ во глꙋбинѣ̀. Речѐ, и҆ ста̀ дꙋ́хъ бꙋ́ренъ, и҆ вознесо́шасѧ вѡ́лны є҆гѡ̀: Восхо́дѧтъ до небе́съ и҆ низхо́дѧтъ до бе́зднъ: дꙋша̀ и҆́хъ въ ѕлы́хъ та́ѧше: Смѧто́шасѧ, подвиго́шасѧ ꙗ҆́кѡ пїѧ́ный, и҆ всѧ̀ мꙋ́дрость и҆́хъ поглощена̀ бы́сть. И҆ воззва́ша ко гдⷭ҇ꙋ, внегда̀ скорбѣ́ти и҆̀мъ, и҆ ѿ нꙋ́ждъ и҆́хъ и҆зведѐ ѧ҆̀: И҆ повелѣ̀ бꙋ́ри, и҆ ста̀ въ тишинꙋ̀, и҆ ᲂу҆молко́ша вѡ́лны є҆гѡ̀. И҆ возвесели́шасѧ, ꙗ҆́кѡ ᲂу҆молко́ша, и҆ наста́ви ѧ҆̀ въ приста́нище хотѣ́нїѧ своегѡ̀. Да и҆сповѣ́дѧтсѧ гдⷭ҇еви млⷭ҇ти є҆гѡ̀ и҆ чꙋдеса̀ є҆гѡ̀ сыновѡ́мъ человѣ́чєскимъ: Да вознесꙋ́тъ є҆го̀ въ цр҃кви людстѣ́й, и҆ на сѣда́лищи ста́рєцъ восхва́лѧтъ є҆го̀. Положи́лъ є҆́сть рѣ́ки въ пꙋсты́ню и҆ и҆схѡ́дища вѡдна́ѧ въ жа́ждꙋ, Зе́млю плодоно́снꙋю въ сла́ность, ѿ ѕло́бы живꙋ́щихъ на не́й. Положи́лъ є҆́сть пꙋсты́ню во є҆зе́ра вѡдна́ѧ и҆ зе́млю безво́днꙋю во и҆схѡ́дища вѡдна́ѧ. И҆ населѝ та́мѡ а҆́лчꙋщыѧ, и҆ соста́виша гра́ды ѡ҆би́тєльны: И҆ насѣ́ѧша се́ла, и҆ насади́ша вїногра́ды, и҆ сотвори́ша пло́дъ жи́тенъ. И҆ блгⷭ҇вѝ ѧ҆̀, и҆ ᲂу҆мно́жишасѧ ѕѣлѡ̀: и҆ скоты̀ и҆́хъ не ᲂу҆ма́ли. И҆ ᲂу҆ма́лишасѧ и҆ ѡ҆ѕло́бишасѧ ѿ ско́рби ѕѡ́лъ и҆ болѣ́зни: И҆злїѧ́сѧ ᲂу҆ничиже́нїе на кнѧ̑зи и҆́хъ, и҆ ѡ҆блазнѝ ѧ҆̀ по непрохо́днѣй, а҆ не по пꙋтѝ. И҆ помо́же ᲂу҆бо́гꙋ ѿ нищеты̀ и҆ положѝ ꙗ҆́кѡ ѻ҆́вцы ѻ҆те́чєствїѧ. Оу҆́зрѧтъ пра́вїи и҆ возвеселѧ́тсѧ, и҆ всѧ́кое беззако́нїе загради́тъ ᲂу҆ста̀ своѧ̑. Кто̀ премꙋ́дръ и҆ сохрани́тъ сїѧ̑; и҆ ᲂу҆разꙋмѣ́ютъ млⷭ҇ти гдⷭ҇ни.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 107,
  ["часть"] = 1,
  ["кафизма"] = 15,
  ["слава"] = 3,
  ["текст_ру"] = "Гото́во се́рдце мое́, Бо́же, гото́во се́рдце мое́: воспою́ и пою́ во сла́ве мое́й. Воста́ни сла́ва моя́, воста́ни псалти́рю и гу́сли, воста́ну ра́но. Испове́мся Тебе́ в лю́дех, Го́споди, пою́ Тебе́ во язы́цех. Я́ко ве́лия верху́ небе́с ми́лость Твоя́ и до о́блак и́стина Твоя́. Вознеси́ся на небеса́, Бо́же, и пo всей земли́ сла́ва Твоя́, я́ко да изба́вятся возлю́бленнии Твои́: спаси́ десни́цею Твое́ю и услы́ши мя. Бог возглаго́ла во святе́м Свое́м: вознесу́ся и разделю́ Сики́му, и удо́ль селе́ний разме́рю. Мой есть Галаа́д и Мой есть Манасси́й, и Ефре́м заступле́ние главы́ Моея́, Иу́да царь Мой. Моа́в коно́б упова́ния Моего́, на Идуме́ю наложу́ сапо́г Мой: Мне иноплеме́нницы покори́шася. Кто введе́т мя во град огражде́ния? Или́ кто наста́вит мя до Идуме́и? Не Ты ли, Бо́же, отри́нувый нас? И не изы́деши, Бо́же, в си́лах на́ших? Даждь нам по́мощь от ско́рби, и су́етно спасе́ние челове́ческо. О Бо́зе сотвори́м си́лу, и Той уничижи́т враги́ на́ша.",
  ["текст_цс"] = "Гото́во се́рдце моѐ, бж҃е, гото́во се́рдце моѐ: воспою̀ и҆ пою̀ во сла́вѣ мое́й. Воста́ни, сла́ва моѧ̀, воста́ни, ѱалти́рю и҆ гꙋ́сли: воста́нꙋ ра́нѡ. И҆сповѣ́мсѧ тебѣ̀ въ лю́дехъ, гдⷭ҇и, пою̀ тебѣ̀ во ꙗ҆зы́цѣхъ: Ꙗ҆́кѡ ве́лїѧ верхꙋ̀ нб҃съ млⷭ҇ть твоѧ̀ и҆ до ѻ҆́блакъ и҆́стина твоѧ̀. Вознеси́сѧ на нб҃са̀, бж҃е, и҆ по все́й землѝ сла́ва твоѧ̀, Ꙗ҆́кѡ да и҆зба́вѧтсѧ возлю́бленнїи твоѝ: сп҃сѝ десни́цею твое́ю и҆ ᲂу҆слы́ши мѧ̀. Бг҃ъ возглаго́ла во ст҃ѣ́мъ свое́мъ: вознесꙋ́сѧ и҆ раздѣлю̀ сїки́мꙋ, и҆ ᲂу҆до́ль селе́нїй размѣ́рю. Мо́й є҆́сть галаа́дъ, и҆ мо́й є҆́сть манассі́й, и҆ є҆фре́мъ застꙋпле́нїе главы̀ моеѧ̀: і҆ꙋ́да ца́рь мо́й, Мѡа́въ коно́бъ ᲂу҆пова́нїѧ моегѡ̀: на і҆дꙋме́ю наложꙋ̀ сапо́гъ мо́й: мнѣ̀ и҆ноплемє́нницы покори́шасѧ. Кто̀ введе́тъ мѧ̀ во гра́дъ ѡ҆гражде́нїѧ; и҆лѝ кто̀ наста́витъ мѧ̀ до і҆дꙋме́и; Не ты́ ли, бж҃е, ѿри́нꙋвый на́съ, и҆ не и҆зы́деши, бж҃е, въ си́лахъ на́шихъ; Да́ждь на́мъ по́мощь ѿ ско́рби: и҆ сꙋ́етно спасе́нїе человѣ́ческо. Ѡ҆ бз҃ѣ сотвори́мъ си́лꙋ, и҆ то́й ᲂу҆ничижи́тъ врагѝ на́шѧ.",
  ["заголовок_ру"] = "Песнь, псало́м Дави́ду.",
  ["заголовок_цс"] = "Пѣ́снь, ѱало́мъ дв҃дꙋ."
}

