  ["текст_ру"] = "Бо́же, хвалы́ моея́ не премолчи́, я́ко уста́ гре́шнича и уста́ льсти́ваго на мя отверзо́шася, глаго́лаша на мя язы́ком льсти́вым, и словесы́ ненави́стными обыдо́ша мя, и бра́шася со мно́ю ту́не. Вме́сто е́же люби́ти мя, оболга́ху мя, аз же моля́хся, и положи́ша на мя зла́я за блага́я, и не́нависть за возлюбле́ние мое́. Поста́ви на него́ гре́шника, и диа́вол да ста́нет одесну́ю eго́. Внегда́ суди́тися eму́, да изы́дет осужде́н, и моли́тва eго́ да бу́дет в грех. Да бу́дут дни́е eго́ ма́ли, и епи́скопство eго́ да прии́мет ин: да бу́дут сы́нове eго́ си́ри, и жена́ eго́ вдова́: дви́жущеся да преселя́тся сы́нове eго́ и воспро́сят, да изгна́ни бу́дут из домо́в свои́х. Да взы́щет заимода́вец вся, ели́ка суть eго́, и да восхи́тят чужди́и труды́ eго́. Да не бу́дет eму́ засту́пника, ниже́ да бу́дет ущедря́яй сироты́ eго́. Да бу́дут ча́да eго́ в погубле́ние, в ро́де еди́ном да потреби́тся и́мя eго́. Да воспомяне́тся беззако́ние оте́ц eго́ пред Го́сподем, и грех ма́тере eго́ да не очи́стится. Да бу́дут пред Го́сподем вы́ну и да потреби́тся от земли́ па́мять их. Зане́же не помяну́ сотвори́ти ми́лость, и погна́ челове́ка ни́ща и убо́га, и умиле́на се́рдцем умертви́ти. И возлюби́ кля́тву, и прии́дет eму́, и не восхоте́ благослове́ния, и удали́тся от него́. И облече́ся в кля́тву я́ко в ри́зу, и вни́де я́ко вода́ во утро́бу eго́, и я́ко еле́й в ко́сти eго́. Да бу́дет eму́ я́ко ри́за, в ню́же облачи́тся, и я́ко по́яс, и́мже вы́ну опоясу́ется. Сие́ де́ло оболга́ющих мя у Го́спода и глаго́лющих лука́вая на ду́шу мою́. И ты, Го́споди, Го́споди, сотвори́ со мно́ю и́мене ра́ди Твоего́, я́ко бла́га ми́лость Твоя́. Изба́ви мя, я́ко нищ и убо́г есмь аз, и се́рдце мое́ смяте́ся внутрь мене́. Я́ко сень, внегда́ уклони́тися ей, отъя́хся, стрясо́хся я́ко пру́зи. Коле́на моя́ изнемого́ста от поста́, и плоть моя́ измени́ся еле́а ра́ди. И аз бых поноше́ние им, ви́деша мя, покива́ша глава́ми свои́ми. Помози́ ми, Го́споди Бо́же мой, и спаси́ мя по ми́лости Твое́й, и да разуме́ют, я́ко рука́ Твоя́ сия́, и Ты, Го́споди, сотвори́л еси́ ю́. Проклену́т ти́и, и Ты благослови́ши, востаю́щии на мя да постыдя́тся, раб же Твой возвесели́тся. Да облеку́тся оболга́ющии мя в срамоту́, и оде́ждутся, я́ко оде́ждею, студо́м свои́м. Испове́мся Го́сподеви зело́ усты́ мои́ми, и посреде́ мно́гих восхвалю́ Его́, я́ко предста́ одесну́ю убо́гаго, е́же спасти́ от гоня́щих ду́шу мою́.",
  ["текст_цс"] = "Бж҃е, хвалы̀ моеѧ̀ не премолчѝ: Ꙗ҆́кѡ ᲂу҆ста̀ грѣ̑шнича и҆ ᲂу҆ста̀ льсти́вагѡ на мѧ̀ ѿверзо́шасѧ, глаго́лаша на мѧ̀ ѧ҆зы́комъ льсти́вымъ, И҆ словесы̀ ненави́стными ѡ҆быдо́ша мѧ̀, и҆ бра́шасѧ со мно́ю тꙋ́не. Вмѣ́стѡ є҆́же люби́ти мѧ̀, ѡ҆болга́хꙋ мѧ̀, а҆́зъ же молѧ́хсѧ: И҆ положи́ша на мѧ̀ ѕла̑ѧ за бл҃га̑ѧ, и҆ не́нависть за возлюбле́нїе моѐ. Поста́ви на него̀ грѣ́шника, и҆ дїа́волъ да ста́нетъ ѡ҆деснꙋ́ю є҆гѡ̀: Внегда̀ сꙋди́тисѧ є҆мꙋ̀, да и҆зы́детъ ѡ҆сꙋжде́нъ, и҆ моли́тва є҆гѡ̀ да бꙋ́детъ въ грѣ́хъ. Да бꙋ́дꙋтъ дні́е є҆гѡ̀ ма́ли, и҆ є҆пі́скопство є҆гѡ̀ да прїи́метъ и҆́нъ: Да бꙋ́дꙋтъ сы́нове є҆гѡ̀ си́ри, и҆ жена̀ є҆гѡ̀ вдова̀: Дви́жꙋщесѧ да преселѧ́тсѧ сы́нове є҆гѡ̀ и҆ воспро́сѧтъ, да и҆згна́ни бꙋ́дꙋтъ и҆з̾ домѡ́въ свои́хъ. Да взы́щетъ заимода́вецъ всѧ̑, є҆ли̑ка сꙋ́ть є҆гѡ̀: и҆ да восхи́тѧтъ чꙋжді́и трꙋды̀ є҆гѡ̀. Да не бꙋ́детъ є҆мꙋ̀ застꙋ́пника, нижѐ да бꙋ́детъ ᲂу҆щедрѧ́ѧй сирѡты̀ є҆гѡ̀: Да бꙋ́дꙋтъ ча̑да є҆гѡ̀ въ погꙋбле́нїе, въ ро́дѣ є҆ди́нѣмъ да потреби́тсѧ и҆́мѧ є҆гѡ̀. Да воспомѧне́тсѧ беззако́нїе ѻ҆тє́цъ є҆гѡ̀ пред̾ гдⷭ҇емъ, и҆ грѣ́хъ ма́тере є҆гѡ̀ да не ѡ҆чи́ститсѧ: Да бꙋ́дꙋтъ пред̾ гдⷭ҇емъ вы́нꙋ, и҆ да потреби́тсѧ ѿ землѝ па́мѧть и҆́хъ: Зане́же не помѧнꙋ̀ сотвори́ти ми́лость, и҆ погна̀ человѣ́ка ни́ща и҆ ᲂу҆бо́га, и҆ ᲂу҆миле́на се́рдцемъ ᲂу҆мертви́ти. И҆ возлюбѝ клѧ́твꙋ, и҆ прїи́детъ є҆мꙋ̀: и҆ не восхотѣ̀ бл҃гослове́нїѧ, и҆ ᲂу҆дали́тсѧ ѿ негѡ̀. И҆ ѡ҆блече́сѧ въ клѧ́твꙋ ꙗ҆́кѡ въ ри́зꙋ, и҆ вни́де ꙗ҆́кѡ вода̀ во ᲂу҆тро́бꙋ є҆гѡ̀ и҆ ꙗ҆́кѡ є҆ле́й въ кѡ́сти є҆гѡ̀: Да бꙋ́детъ є҆мꙋ̀ ꙗ҆́кѡ ри́за, въ ню́же ѡ҆блачи́тсѧ, и҆ ꙗ҆́кѡ по́ѧсъ, и҆́мже вы́нꙋ ѡ҆поѧсꙋ́етсѧ. Сїѐ дѣ́ло ѡ҆болга́ющихъ мѧ̀ ᲂу҆ гдⷭ҇а и҆ глаго́лющихъ лꙋка̑ваѧ на дꙋ́шꙋ мою̀. И҆ ты̀, гдⷭ҇и, гдⷭ҇и, сотворѝ со мно́ю и҆́мене ра́ди твоегѡ̀, ꙗ҆́кѡ бл҃га млⷭ҇ть твоѧ̀: И҆зба́ви мѧ̀, ꙗ҆́кѡ ни́щъ и҆ ᲂу҆бо́гъ є҆́смь а҆́зъ, и҆ се́рдце моѐ смѧте́сѧ внꙋ́трь менѐ. Ꙗ҆́кѡ сѣ́нь, внегда̀ ᲂу҆клони́тисѧ є҆́й, ѿѧ́хсѧ: стрѧсо́хсѧ ꙗ҆́кѡ прꙋ́зи. Кѡлѣ́на моѧ̑ и҆знемого́ста ѿ поста̀, и҆ пло́ть моѧ̀ и҆змѣни́сѧ є҆ле́а ра́ди. И҆ а҆́зъ бы́хъ поноше́нїе и҆̀мъ: ви́дѣша мѧ̀, покива́ша глава́ми свои́ми. Помози́ ми, гдⷭ҇и бж҃е мо́й, и҆ сп҃си́ мѧ по млⷭ҇ти твое́й: И҆ да разꙋмѣ́ютъ, ꙗ҆́кѡ рꙋка̀ твоѧ̀ сїѧ̀, и҆ ты̀, гдⷭ҇и, сотвори́лъ є҆сѝ ю҆̀. Прокленꙋ́тъ ті́и, и҆ ты̀ бл҃гослови́ши: востаю́щїи на мѧ̀ да постыдѧ́тсѧ, ра́бъ же тво́й возвесели́тсѧ. Да ѡ҆блекꙋ́тсѧ ѡ҆болга́ющїи мѧ̀ въ срамотꙋ̀ и҆ ѡ҆де́ждꙋтсѧ ꙗ҆́кѡ ѻ҆де́ждою стꙋдо́мъ свои́мъ. И҆сповѣ́мсѧ гдⷭ҇еви ѕѣлѡ̀ ᲂу҆сты̑ мои́ми и҆ посредѣ̀ мно́гихъ восхвалю̀ є҆го̀: Ꙗ҆́кѡ предста̀ ѡ҆деснꙋ́ю ᲂу҆бо́гагѡ, є҆́же сп҃стѝ ѿ гонѧ́щихъ дꙋ́шꙋ мою̀.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 109,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 1,
  ["текст_ру"] = "Рече́ Госпо́дь Го́сподеви моему́: седи́ одесну́ю Мене́, до́ндеже положу́ враги́ Твоя́ подно́жие ног Твои́х. Жезл си́лы по́слет ти Госпо́дь от Сио́на, и госпо́дствуй посреде́ враго́в Твои́х. С Тобо́ю нача́ло в день си́лы Твоея́, во све́тлостех святы́х Твои́х, из чре́ва пре́жде денни́цы роди́х Тя. Кля́тся Госпо́дь и не раска́ется: Ты иере́й во век, по чи́ну Мелхиседе́кову. Госпо́дь одесну́ю Тебе́ сокруши́л есть в день гне́ва Своего́ цари́. Су́дит во язы́цех, испо́лнит паде́ния, сокруши́т главы́ на земли́ мно́гих. От пото́ка на пути́ пие́т, сего́ ра́ди вознесе́т главу́.",
  ["текст_цс"] = "Речѐ гдⷭ҇ь гдⷭ҇еви моемꙋ̀: сѣдѝ ѡ҆деснꙋ́ю менѐ, до́ндеже положꙋ̀ врагѝ твоѧ̑ подно́жїе но́гъ твои́хъ. Же́злъ си́лы по́слетъ тѝ гдⷭ҇ь ѿ сїѡ́на, и҆ гдⷭ҇ствꙋй посредѣ̀ врагѡ́въ твои́хъ. Съ тобо́ю нача́ло въ де́нь си́лы твоеѧ̀, во свѣ́тлостехъ ст҃ы́хъ твои́хъ: и҆з̾ чре́ва пре́жде денни́цы роди́хъ тѧ̀. Клѧ́тсѧ гдⷭ҇ь и҆ не раска́етсѧ: ты̀ і҆ере́й во вѣ́къ по чи́нꙋ мелхїседе́ковꙋ. Гдⷭ҇ь ѡ҆деснꙋ́ю тебє̀ сокрꙋши́лъ є҆́сть въ де́нь гнѣ́ва своегѡ̀ царѝ: Сꙋ́дитъ во ꙗ҆зы́цѣхъ, и҆спо́лнитъ падє́нїѧ, сокрꙋши́тъ главы̑ на землѝ мно́гихъ. Ѿ пото́ка на пꙋтѝ пїе́тъ: сегѡ̀ ра́ди вознесе́тъ главꙋ̀.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 110,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 1,
  ["текст_ру"] = "Испове́мся Тебе́, Го́споди, всем се́рдцем мои́м в сове́те пра́вых и со́нме. Ве́лия дела́ Госпо́дня, изы́скана во всех во́лях Его́. Испове́дание и великоле́пие де́ло Его́ и пра́вда Его́ пребыва́ет в век ве́ка. Па́мять сотвори́л есть чуде́с Свои́х, ми́лостив и щедр Госпо́дь. Пи́щу даде́ боя́щымся Его́, помяне́т в век заве́т Свой. Кре́пость дел Свои́х возвести́ лю́дем Свои́м, да́ти им достоя́ние язы́к. Дела́ рук Его́ и́стина и суд, ве́рны вся за́поведи Его́, утверже́ны в век ве́ка, сотворе́ны во и́стине и правоте́. Избавле́ние посла́ лю́дем Свои́м: запове́да в век заве́т Свой. Свя́то и стра́шно и́мя Его́. Нача́ло прему́дрости страх Госпо́день, ра́зум же благ всем творя́щым и́. Хвала́ Его́ пребыва́ет в век ве́ка.",
  ["текст_цс"] = "И҆сповѣ́мсѧ тебѣ̀, гдⷭ҇и, всѣ́мъ се́рдцемъ мои́мъ въ совѣ́тѣ пра́выхъ и҆ со́нмѣ. Вє́лїѧ дѣла̀ гдⷭ҇нѧ, и҆зы̑скана во всѣ́хъ во́лѧхъ є҆гѡ̀: И҆сповѣ́данїе и҆ великолѣ́пїе дѣ́ло є҆гѡ̀, и҆ пра́вда є҆гѡ̀ пребыва́етъ въ вѣ́къ вѣ́ка. Па́мѧть сотвори́лъ є҆́сть чꙋде́съ свои́хъ: млⷭ҇тивъ и҆ ще́дръ гдⷭ҇ь. Пи́щꙋ дадѐ боѧ́щымсѧ є҆гѡ̀: помѧне́тъ въ вѣ́къ завѣ́тъ сво́й. Крѣ́пость дѣ́лъ свои́хъ возвѣстѝ лю́демъ свои̑мъ, да́ти и҆̀мъ достоѧ́нїе ꙗ҆зы̑къ. Дѣла̀ рꙋ́къ є҆гѡ̀ и҆́стина и҆ сꙋ́дъ, вѣ̑рны всѧ̑ за́пѡвѣди є҆гѡ̀, Оу҆твержє́ны въ вѣ́къ вѣ́ка, сотворє́ны во и҆́стинѣ и҆ правотѣ̀. И҆збавле́нїе посла̀ лю́демъ свои̑мъ: заповѣ́да въ вѣ́къ завѣ́тъ сво́й: ст҃о и҆ стра́шно и҆́мѧ є҆гѡ̀. Нача́ло премⷣрости стра́хъ гдⷭ҇ень, ра́зꙋмъ же бл҃гъ всѣ̑мъ творѧ́щымъ и҆̀: хвала̀ є҆гѡ̀ пребыва́етъ въ вѣ́къ вѣ́ка.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 111,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 1,
  ["текст_ру"] = "Блаже́н муж, боя́йся Го́спода, в за́поведех Его́ восхо́щет зело́. Си́льно на земли́ бу́дет се́мя eго́, род пра́вых благослови́тся: сла́ва и бога́тство в дому́ eго́, и пра́вда eго́ пребыва́ет в век ве́ка. Возсия́ во тме свет пра́вым, ми́лостив и щедр, и пра́веден. Благ муж, ще́дря и дая́: устро́ит словеса́ своя́ на суде́, я́ко в век не подви́жится. В па́мять ве́чную бу́дет пра́ведник. От слу́ха зла не убои́тся, гото́во се́рдце eго́ упова́ти на Го́спода. Утверди́ся се́рдце eго́, не убои́тся, до́ндеже воззри́т на враги́ своя́. Расточи́, даде́ убо́гим, пра́вда eго́ пребыва́ет во век ве́ка, рог eго́ вознесе́тся в сла́ве. Гре́шник у́зрит и прогне́вается, зубы́ свои́ми поскреже́щет и раста́ет, жела́ние гре́шника поги́бнет.",
  ["текст_цс"] = "Бл҃же́нъ мꙋ́жъ боѧ́йсѧ гдⷭ҇а, въ за́повѣдехъ є҆гѡ̀ восхо́щетъ ѕѣлѡ̀. Си́льно на землѝ бꙋ́детъ сѣ́мѧ є҆гѡ̀, ро́дъ пра́выхъ бл҃гослови́тсѧ: Сла́ва и҆ бога́тство въ домꙋ̀ є҆гѡ̀, и҆ пра́вда є҆гѡ̀ пребыва́етъ въ вѣ́къ вѣ́ка. Возсїѧ̀ во тмѣ̀ свѣ́тъ пра̑вымъ: млⷭ҇тивъ и҆ ще́дръ и҆ првⷣнъ. Бл҃гъ мꙋ́жъ ще́дрѧ и҆ даѧ̀: ᲂу҆стро́итъ словеса̀ своѧ̑ на сꙋдѣ̀, ꙗ҆́кѡ въ вѣ́къ не подви́житсѧ. Въ па́мѧть вѣ́чнꙋю бꙋ́детъ првⷣникъ. Ѿ слꙋ́ха ѕла̀ не ᲂу҆бои́тсѧ: Гото́во се́рдце є҆гѡ̀ ᲂу҆пова́ти на гдⷭ҇а: ᲂу҆тверди́сѧ се́рдце є҆гѡ̀, не ᲂу҆бои́тсѧ, до́ндеже воззри́тъ на врагѝ своѧ̑. Расточѝ, дадѐ ᲂу҆бѡ́гимъ: пра́вда є҆гѡ̀ пребыва́етъ во вѣ́къ вѣ́ка: ро́гъ є҆гѡ̀ вознесе́тсѧ въ сла́вѣ. Грѣ́шникъ ᲂу҆́зритъ и҆ прогнѣ́ваетсѧ зꙋбы̀ свои́ми поскреже́щетъ и҆ раста́етъ: жела́нїе грѣ́шника поги́бнетъ.",
  ["заголовок_ру"] = "Аллилу́иа, Агге́ево и Заха́риино. Псало́м.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа, А҆гге́ево и҆ Заха́рїино. ѱало́мъ."
}

add_psalom {
  ["номер"] = 112,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 2,
  ["текст_ру"] = "Хвали́те, о́троцы, Го́спода, хвали́те и́мя Госпо́дне. Бу́ди и́мя Госпо́дне благослове́нно отны́не и до ве́ка. От восто́к со́лнца до за́пад хва́льно и́мя Госпо́дне. Высо́к над все́ми язы́ки Госпо́дь: над небесы́ сла́ва Его́. Кто я́ко Госпо́дь Бог наш? На высо́ких живы́й и на смире́нныя призира́яй на небеси́ и на земли́, воздвиза́яй от земли́ ни́ща и от гно́ища возвыша́яй убо́га, посади́ти eго́ с кня́зи, с кня́зи люде́й свои́х, вселя́я непло́довь в дом ма́терь о ча́дех веселя́щуся.",
  ["текст_цс"] = "Хвали́те, ѻ҆́троцы, гдⷭ҇а, хвали́те и҆́мѧ гдⷭ҇не. Бꙋ́ди и҆́мѧ гдⷭ҇не бл҃гослове́но ѿ ны́нѣ и҆ до вѣ́ка. Ѿ востѡ́къ со́лнца до за̑падъ хва́льно и҆́мѧ гдⷭ҇не. Высо́къ над̾ всѣ́ми ꙗ҆зы́ки гдⷭ҇ь: над̾ нб҃сы̀ сла́ва є҆гѡ̀. Кто̀ ꙗ҆́кѡ гдⷭ҇ь бг҃ъ на́шъ; на высо́кихъ живы́й, И҆ на смирє́нныѧ призира́ѧй на нб҃сѝ и҆ на землѝ: Воздвиза́ѧй ѿ землѝ ни́ща, и҆ ѿ гно́ища возвыша́ѧй ᲂу҆бо́га: Посади́ти є҆го̀ съ кнѧ̑зи, съ кнѧ̑зи люде́й свои́хъ: Вселѧ́ѧ непло́довь въ до́мъ, ма́терь ѡ҆ ча́дѣхъ веселѧ́щꙋсѧ.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 113,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 2,
  ["текст_ру"] = "Во исхо́де Изра́илеве от Еги́пта, до́му Иа́ковля из люде́й ва́рвар, бысть Иуде́а святы́ня Его́, Изра́иль о́бласть Eго́. Мо́ре ви́де и побе́же, Иорда́н возврати́ся вспять, го́ры взыгра́шася, я́ко овни́, и хо́лми, я́ко а́гнцы о́вчии. Что ти есть, мо́ре, я́ко побе́гло еси́? И тебe, Иорда́не, я́ко возврати́лся еси́ вспять? Го́ры, я́ко взыгра́стеся, я́ко овни́, и хо́лми, я́ко а́гнцы о́вчии? От лица́ Госпо́дня подви́жеся земля́, от лица́ Бо́га Иа́ковля, обра́щшаго ка́мень во езе́ра водна́я и несеко́мый во исто́чники водны́я. Не нам, Го́споди, не нам, но и́мени Твоему́ даждь сла́ву, о ми́лости Твое́й и и́стине Твое́й. Да не когда́ реку́т язы́цы: где есть Бог их? Бог же наш на небеси́ и на земли́, вся ели́ка восхоте́, сотвори́. И́доли язы́к сребро́ и зла́то, дела́ рук челове́ческих. Уста́ и́мут, и не возглаго́лют, о́чи и́мут и не у́зрят, у́ши и́мут, и не услы́шат, но́здри и́мут, и не обоня́ют, ру́це и́мут, и не ося́жут, но́зе и́мут, и не по́йдут, не возглася́т горта́нем свои́м. Подо́бни им да бу́дут творя́щии я́, и вси наде́ющиися на ня. Дом Изра́илев упова́ на Го́спода: Помо́щник и Защи́титель им есть. Дом Ааро́нь упова́ на Го́спода: Помо́щник и Защи́титель им есть. Боя́щиися Го́спода упова́ша на Го́спода: Помо́щник и Защи́титель им есть. Госпо́дь помяну́в ны благослови́л есть нас, благослови́л есть дом Изра́илев, благослови́л есть дом Ааро́нь, благослови́л есть боя́щыяся Го́спода, ма́лыя с вели́кими. Да приложи́т Госпо́дь на вы, на вы и на сы́ны ва́ша. Благослове́ни вы Го́сподеви, сотво́ршему не́бо и зе́млю. Не́бо небесе́ Го́сподеви, зе́млю же даде́ сыново́м челове́ческим. Не ме́ртвии восхва́лят Тя, Го́споди, ниже́ вси низходя́щии во ад, но мы, живи́и, благослови́м Го́спода отны́не и до ве́ка.",
  ["текст_цс"] = "Во и҆схо́дѣ і҆и҃левѣ ѿ є҆гѵ́пта, до́мꙋ і҆а́кѡвлѧ и҆з̾ люде́й ва̑рваръ, Бы́сть і҆ꙋде́а ст҃ы́нѧ є҆гѡ̀, і҆и҃ль ѻ҆́бласть є҆гѡ̀. Мо́ре ви́дѣ и҆ побѣжѐ, і҆ѻрда́нъ возврати́сѧ вспѧ́ть: Го́ры взыгра́шасѧ ꙗ҆́кѡ ѻ҆внѝ, и҆ хо́лми ꙗ҆́кѡ а҆́гнцы ѻ҆́вчїи. Что́ ти є҆́сть, мо́ре, ꙗ҆́кѡ побѣ́гло є҆сѝ, и҆ тебѣ̀, і҆ѻрда́не, ꙗ҆́кѡ возврати́лсѧ є҆сѝ вспѧ́ть: Го́ры, ꙗ҆́кѡ взыгра́стесѧ ꙗ҆́кѡ ѻ҆внѝ, и҆ хо́лми ꙗ҆́кѡ а҆́гнцы ѻ҆́вчїи. Ѿ лица̀ гдⷭ҇нѧ подви́жесѧ землѧ̀, ѿ лица̀ бг҃а і҆а́кѡвлѧ: Ѡ҆бра́щшагѡ ка́мень во є҆зе́ра вѡдна́ѧ и҆ несѣко́мый во и҆сто́чники вѡдны́ѧ. Не на́мъ, гдⷭ҇и, не на́мъ, но и҆́мени твоемꙋ̀ да́ждь сла́вꙋ ѡ҆ млⷭ҇ти твое́й и҆ и҆́стинѣ твое́й: Да не когда̀ рекꙋ́тъ ꙗ҆зы́цы: гдѣ̀ є҆́сть бг҃ъ и҆́хъ; Бг҃ъ же на́шъ на нб҃сѝ и҆ на землѝ, всѧ̑ є҆ли̑ка восхотѣ̀, сотворѝ. І҆́дѡли ꙗ҆зы̑къ сребро̀ и҆ зла́то, дѣла̀ рꙋ́къ человѣ́ческихъ: Оу҆ста̀ и҆́мꙋтъ, и҆ не возглаго́лютъ: ѻ҆́чи и҆́мꙋтъ, и҆ не ᲂу҆́зрѧтъ: Оу҆́ши и҆́мꙋтъ, и҆ не ᲂу҆слы́шатъ: нѡ́здри и҆́мꙋтъ, и҆ не ѡ҆бонѧ́ютъ: Рꙋ́цѣ и҆́мꙋтъ, и҆ не ѡ҆сѧ́жꙋтъ: но́зѣ и҆́мꙋтъ, и҆ не по́йдꙋтъ: не возгласѧ́тъ горта́немъ свои́мъ. Подо́бни и҆̀мъ да бꙋ́дꙋтъ творѧ́щїи ѧ҆̀ и҆ всѝ надѣ́ющїисѧ на нѧ̀. До́мъ і҆и҃левъ ᲂу҆пова̀ на гдⷭ҇а: помо́щникъ и҆ защи́титель и҆̀мъ є҆́сть. До́мъ а҆арѡ́нь ᲂу҆пова̀ на гдⷭ҇а: помо́щникъ и҆ защи́титель и҆̀мъ є҆́сть. Боѧ́щїисѧ гдⷭ҇а ᲂу҆пова́ша на гдⷭ҇а: помо́щникъ и҆ защи́титель и҆̀мъ є҆́сть. Гдⷭ҇ь помѧнꙋ́въ ны̀ бл҃гослови́лъ є҆́сть на́съ: бл҃гослови́лъ є҆́сть до́мъ і҆и҃левъ, бл҃гослови́лъ є҆́сть до́мъ а҆арѡ́нь, Бл҃гослови́лъ є҆́сть боѧ́щыѧсѧ гдⷭ҇а, ма̑лыѧ съ вели́кими. Да приложи́тъ гдⷭ҇ь на вы̀, на вы̀ и҆ на сы́ны ва́шѧ: Бл҃гослове́ни вы̀ гдⷭ҇еви, сотво́ршемꙋ нб҃о и҆ зе́млю. Нб҃о нб҃сѐ гдⷭ҇еви, зе́млю же дадѐ сыновѡ́мъ человѣ́чєскимъ. Не ме́ртвїи восхва́лѧтъ тѧ̀, гдⷭ҇и, нижѐ всѝ низходѧ́щїи во а҆́дъ: Но мы̀ живі́и бл҃гослови́мъ гдⷭ҇а ѿ ны́нѣ и҆ до вѣ́ка.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 114,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 2,
  ["текст_ру"] = "Возлюби́х, я́ко услы́шит Госпо́дь глас моле́ния моего́, я́ко приклони́ у́хо Свое́ мне, и во дни моя́ призову́. Объя́ша мя боле́зни сме́ртныя, беды́ а́довы обрето́ша мя, скорбь и боле́знь обрето́х, и и́мя Госпо́дне призва́х: о, Го́споди, изба́ви ду́шу мою́. Ми́лостив Госпо́дь и пра́веден, и Бог наш ми́лует. Храня́й младе́нцы Госпо́дь: смири́хся, и спасе́ мя. Обрати́ся, душе́ моя́, в поко́й твой, я́ко Госпо́дь благоде́йствова тя. Я́ко изъя́т ду́шу мою́ от сме́рти, о́чи мои́ от слез и но́зе мои́ от поползнове́ния. Благоугожду́ пред Го́сподем во стране́ живы́х.",
  ["текст_цс"] = "Возлюби́хъ, ꙗ҆́кѡ ᲂу҆слы́шитъ гдⷭ҇ь гла́съ моле́нїѧ моегѡ̀, Ꙗ҆́кѡ приклонѝ ᲂу҆́хо своѐ мнѣ̀: и҆ во дни̑ моѧ̑ призовꙋ̀. Ѡ҆б̾ѧ́ша мѧ̀ болѣ̑зни смє́ртныѧ, бѣды̑ а҆́дѡвы ѡ҆брѣто́ша мѧ̀: ско́рбь и҆ болѣ́знь ѡ҆брѣто́хъ и҆ и҆́мѧ гдⷭ҇не призва́хъ: Ѽ, гдⷭ҇и, и҆зба́ви дꙋ́шꙋ мою̀: млⷭ҇тивъ гдⷭ҇ь и҆ првⷣнъ, и҆ бг҃ъ на́шъ ми́лꙋетъ. Хранѧ́й младе́нцы гдⷭ҇ь: смири́хсѧ, и҆ сп҃се́ мѧ. Ѡ҆брати́сѧ, дꙋшѐ моѧ̀, въ поко́й тво́й, ꙗ҆́кѡ гдⷭ҇ь бл҃годѣ́йствова тѧ̀: Ꙗ҆́кѡ и҆з̾ѧ́тъ дꙋ́шꙋ мою̀ ѿ сме́рти, ѻ҆́чи моѝ ѿ сле́зъ и҆ но́зѣ моѝ ѿ поползнове́нїѧ. Бл҃гоꙋгождꙋ̀ пред̾ гдⷭ҇емъ во странѣ̀ живы́хъ.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 115,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 3,
  ["текст_ру"] = "Ве́ровах, те́мже возглаго́лах, аз же смири́хся зело́. Аз же рех во изступле́нии мое́м: всяк челове́к ложь. Что возда́м Го́сподеви о всех, я́же воздаде́ ми? Ча́шу спасе́ния прииму́ и и́мя Госпо́дне призову́, моли́твы моя́ Го́сподеви возда́м пред все́ми людьми́ Его́. Честна́ пред Го́сподем смерть преподо́бных Его́. О, Го́споди, аз раб Твой, аз раб Твой и сын рабы́ни Твоея́; растерза́л еси́ у́зы моя́. Тебе́ пожру́ же́ртву хвалы́, и во и́мя Госпо́дне призову́. Моли́твы моя́ Го́сподеви возда́м пред все́ми людьми́ Его́, во дво́рех до́му Госпо́дня, посреде́ тебе́, Иерусали́ме.",
  ["текст_цс"] = "Вѣ́ровахъ, тѣ́мже возглаго́лахъ: а҆́зъ же смири́хсѧ ѕѣлѡ̀. А҆́зъ же рѣ́хъ во и҆зстꙋпле́нїи мое́мъ: всѧ́къ человѣ́къ ло́жъ. Что̀ возда́мъ гдⷭ҇еви ѡ҆ всѣ́хъ, ꙗ҆̀же воздаде́ ми; Ча́шꙋ сп҃се́нїѧ прїимꙋ̀ и҆ и҆́мѧ гдⷭ҇не призовꙋ̀: Моли̑твы моѧ̑ гдⷭ҇еви возда́мъ пред̾ всѣ́ми людьмѝ є҆гѡ̀. Чтⷭ҇на̀ пред̾ гдⷭ҇емъ сме́рть прпⷣбныхъ є҆гѡ̀. Ѽ, гдⷭ҇и, а҆́зъ ра́бъ тво́й, а҆́зъ ра́бъ тво́й и҆ сы́нъ рабы́ни твоеѧ̀: растерза́лъ є҆сѝ ᲂу҆́зы моѧ̑. Тебѣ̀ пожрꙋ̀ же́ртвꙋ хвалы̀, и҆ во и҆́мѧ гдⷭ҇не призовꙋ̀. Моли̑твы моѧ̑ гдⷭ҇еви возда́мъ пред̾ всѣ́ми людьмѝ є҆гѡ̀, Во дво́рѣхъ до́мꙋ гдⷭ҇нѧ, посредѣ̀ тебє̀, і҆ерⷭ҇ли́ме.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 116,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 3,
