add_psalom {
  ["номер"] = 117,
  ["часть"] = 1,
  ["кафизма"] = 16,
  ["слава"] = 3,
  ["текст_ру"] = "Испове́дайтеся Го́сподеви, я́ко благ, я́ко в век ми́лость Его́. Да рече́т у́бо дом Изра́илев: я́ко благ, я́ко в век ми́лость Его́. Да рече́т у́бо дом Ааро́нь: я́ко благ, я́ко в век ми́лость Его́. Да реку́т у́бо вси боя́щиися Го́спода: я́ко благ, я́ко в век ми́лость Его́. От ско́рби призва́х Го́спода, и услы́ша мя в простра́нство. Госпо́дь мне помо́щник, и не убою́ся, что сотвори́т мне челове́к? Госпо́дь мне помо́щник, и аз воззрю́ на враги́ моя́. Бла́го есть наде́ятися на Го́спода, не́жели наде́ятися на челове́ка. Бла́го есть упова́ти на Го́спода, не́жели упова́ти на кня́зи. Вси язы́цы обыдо́ша мя, и и́менем Госпо́дним противля́хся им, обыше́дше обыдо́ша мя, и и́менем Госпо́дним противля́хся им, обыдо́ша мя, я́ко пче́лы сот, и разгоре́шася, я́ко огнь в те́рнии, и и́менем Госпо́дним противля́хся им. Отринове́н преврати́хся па́сти, и Госпо́дь прия́т мя. Кре́пость моя́ и пе́ние мое́ Госпо́дь, и бысть ми во спасе́ние. Глас ра́дости и спасе́ния в селе́ниих пра́ведных: десни́ца Госпо́дня сотвори́ си́лу. Десни́ца Госпо́дня вознесе́ мя, десни́ца Госпо́дня сотвори́ си́лу. Не умру́, но жив бу́ду, и пове́м дела́ Госпо́дня. Наказу́я наказа́ мя Госпо́дь, сме́рти же не предаде́ мя. Отве́рзите мне врата́ пра́вды, вшед в ня испове́мся Го́сподеви. Сия́ врата́ Госпо́дня, пра́веднии вни́дут в ня. Испове́мся Тебе́, я́ко услы́шал мя еси́, и был еси́ мне во спасе́ние. Ка́мень, eго́же небрего́ша зи́ждущии, сей бысть во главу́ у́гла: от Го́спода бысть сей, и есть ди́вен во очесе́х на́ших. Сей день, eго́же сотвори́ Госпо́дь, возра́дуемся и возвесели́мся в онь. О, Го́споди, спаси́ же, о Го́споди, поспеши́ же. Благослове́н Гряды́й во и́мя Госпо́дне, благослови́хом вы из до́му Госпо́дня. Бог Госпо́дь, и яви́ся нам: соста́вите пра́здник во учаща́ющих до рог олтаре́вых. Бог мой еси́ Ты, и испове́мся Тебе́, Бог мой еси́ Ты, и вознесу́ Тя. Испове́мся Тебе́, я́ко услы́шал мя еси́, и был еси́ мне во спасе́ние. Испове́дайтеся Го́сподеви, я́ко Благ, я́ко в век ми́лость Его́.",
  ["текст_цс"] = "И҆сповѣ́дайтесѧ гдⷭ҇еви, ꙗ҆́кѡ бл҃гъ, ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Да рече́тъ ᲂу҆́бѡ до́мъ і҆и҃левъ: ꙗ҆́кѡ бл҃гъ, ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Да рече́тъ ᲂу҆́бѡ до́мъ а҆арѡ́нь: ꙗ҆́кѡ бл҃гъ, ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Да рекꙋ́тъ ᲂу҆́бѡ всѝ боѧ́щїисѧ гдⷭ҇а: ꙗ҆́кѡ бл҃гъ, ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Ѿ ско́рби призва́хъ гдⷭ҇а, и҆ ᲂу҆слы́ша мѧ̀ въ простра́нство. Гдⷭ҇ь мнѣ̀ помо́щникъ, и҆ не ᲂу҆бою́сѧ: что̀ сотвори́тъ мнѣ̀ человѣ́къ; Гдⷭ҇ь мнѣ̀ помо́щникъ, и҆ а҆́зъ воззрю̀ на врагѝ моѧ̑. Бл҃го є҆́сть надѣ́ѧтисѧ на гдⷭ҇а, не́жели надѣ́ѧтисѧ на человѣ́ка: Бл҃го є҆́сть ᲂу҆пова́ти на гдⷭ҇а, не́жели ᲂу҆пова́ти на кнѧ̑зи. Всѝ ꙗ҆зы́цы ѡ҆быдо́ша мѧ̀, и҆ и҆́менемъ гдⷭ҇нимъ противлѧ́хсѧ и҆̀мъ: Ѡ҆быше́дше ѡ҆быдо́ша мѧ̀, и҆ и҆́менемъ гдⷭ҇нимъ противлѧ́хсѧ и҆̀мъ: Ѡ҆быдо́ша мѧ̀ ꙗ҆́кѡ пче́лы со́тъ, и҆ разгорѣ́шасѧ ꙗ҆́кѡ ѻ҆́гнь въ те́рнїи: и҆ и҆́менемъ гдⷭ҇нимъ противлѧ́хсѧ и҆̀мъ. Ѿринове́нъ преврати́хсѧ па́сти, и҆ гдⷭ҇ь прїѧ́тъ мѧ̀. Крѣ́пость моѧ̀ и҆ пѣ́нїе моѐ гдⷭ҇ь, и҆ бы́сть мѝ во сп҃се́нїе. Гла́съ ра́дости и҆ сп҃се́нїѧ въ селе́нїихъ првⷣныхъ: десни́ца гдⷭ҇нѧ сотворѝ си́лꙋ. Десни́ца гдⷭ҇нѧ вознесе́ мѧ, десни́ца гдⷭ҇нѧ сотворѝ си́лꙋ. Не ᲂу҆мрꙋ̀, но жи́въ бꙋ́дꙋ и҆ повѣ́мъ дѣла̀ гдⷭ҇нѧ. Наказꙋ́ѧ наказа́ мѧ гдⷭ҇ь, сме́рти же не предаде́ мѧ. Ѿве́рзите мнѣ̀ врата̀ пра́вды: вше́дъ въ нѧ̀, и҆сповѣ́мсѧ гдⷭ҇еви. Сїѧ̑ врата̀ гдⷭ҇нѧ: првⷣнїи вни́дꙋтъ въ нѧ̀. И҆сповѣ́мсѧ тебѣ̀, ꙗ҆́кѡ ᲂу҆слы́шалъ мѧ̀ є҆сѝ и҆ бы́лъ є҆сѝ мнѣ̀ во сп҃се́нїе. Ка́мень, є҆го́же небрего́ша зи́ждꙋщїи, се́й бы́сть во главꙋ̀ ᲂу҆́гла: Ѿ гдⷭ҇а бы́сть се́й, и҆ є҆́сть ди́венъ во ѻ҆чесѣ́хъ на́шихъ. Се́й де́нь, є҆го́же сотворѝ гдⷭ҇ь, возра́дꙋемсѧ и҆ возвесели́мсѧ въ ѻ҆́нь. Ѽ, гдⷭ҇и, сп҃си́ же, ѽ, гдⷭ҇и, поспѣши́ же. Бл҃гослове́нъ грѧды́й во и҆́мѧ гдⷭ҇не: бл҃гослови́хомъ вы̀ и҆з̾ до́мꙋ гдⷭ҇нѧ. Бг҃ъ гдⷭ҇ь, и҆ ꙗ҆ви́сѧ на́мъ: соста́вите пра́здникъ во ᲂу҆чаща́ющихъ до рѡ́гъ ѻ҆лтаре́выхъ. Бг҃ъ мо́й є҆сѝ ты̀, и҆ и҆сповѣ́мсѧ тебѣ̀: бг҃ъ мо́й є҆сѝ ты̀, и҆ вознесꙋ́ тѧ: и҆сповѣ́мсѧ тебѣ̀, ꙗ҆́кѡ ᲂу҆слы́шалъ мѧ̀ є҆сѝ и҆ бы́лъ є҆сѝ мнѣ̀ во сп҃се́нїе. И҆сповѣ́дайтесѧ гдⷭ҇еви, ꙗ҆́кѡ бл҃гъ, ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 118,
  ["часть"] = 1,
  ["кафизма"] = 17,
  ["слава"] = 1,
  ["текст_ру"] = "Блаже́ни непоро́чнии в путь, ходя́щии в зако́не Госпо́дни. Блаже́ни испыта́ющии свиде́ния Его́, всем се́рдцем взы́щут Его́, не де́лающии бо беззако́ния, в путе́х Его́ ходи́ша. Ты запове́дал еси́ за́поведи Твоя́ сохрани́ти зело́. Дабы́ испра́вилися путие́ мои́, сохрани́ти оправда́ния Твоя́. Тогда́ не постыжу́ся, внегда́ призре́ти ми на вся за́поведи Твоя́. Испове́мся Тебе́ в пра́вости се́рдца, внегда́ научи́ти ми ся судьба́м пра́вды Твоея́. Оправда́ния Твоя́ сохраню́, не оста́ви мене́ до зела́. В чесо́м испра́вит юне́йший путь свой? Внегда́ сохрани́ти словеса́ Твоя́. Всем се́рдцем мои́м взыска́х Тебе́, не отри́ни мене́ от за́поведей Твои́х. В се́рдце мое́м скрых словеса́ Твоя́, я́ко да не согрешу́ Тебе́. Благослове́н еси́, Го́споди: научи́ мя оправда́нием Твои́м. Устна́ма мои́ма возвести́х вся судьбы́ уст Твои́х. На пути́ свиде́ний Твои́х наслади́хся, я́ко о вся́ком бога́тстве. В за́поведех Твои́х поглумлю́ся, и уразуме́ю пути́ Твоя́. Во оправда́ниих Твои́х поучу́ся, не забу́ду слове́с Твои́х. Возда́ждь рабу́ Твоему́: живи́ мя, и сохраню́ словеса́ Твоя́. Откры́й о́чи мои́, и уразуме́ю чудеса́ от зако́на Твоего́. Пришле́ц аз есмь на земли́: не скрый от мене́ за́поведи Твоя́. Возлюби́ душа́ моя́ возжела́ти судьбы́ Твоя́ на вся́кое вре́мя. Запрети́л еси́ го́рдым: про́кляти уклоня́ющиися от за́поведей Твои́х. Отьими́ от мене́ поно́с и уничиже́ние, я́ко свиде́ний Твои́х взыска́х. И́бо седо́ша кня́зи, и на мя клевета́ху, раб же Твой глумля́шеся во оправда́ниих Твои́х: И́бо свиде́ния Твоя́ поуче́ние мое́ есть, и сове́ти мои́ оправда́ния Твоя́. Прильпе́ земли́ душа́ моя́: живи́ мя по словеси́ Твоему́. Пути́ моя́ возвести́х, и услы́шал мя еси́: научи́ мя оправда́нием Твои́м: Путь оправда́ний Твои́х вразуми́ ми, и поглумлю́ся в чудесе́х Твои́х. Воздрема́ душа́ моя́ от уны́ния: утверди́ мя в словесе́х Твои́х. Путь непра́вды отста́ви от мене́, и зако́ном Твои́м поми́луй мя. Путь и́стины изво́лих, и судьбы́ Твоя́ не забы́х. Прилепи́хся свиде́нием Твои́м, Го́споди, не посрами́ мене́. Путь за́поведей Твои́х теко́х, егда́ расшири́л еси́ се́рдце мое́. Законоположи́ мне, Го́споди, путь оправда́ний Твои́х, и взыщу́ и́ вы́ну: Вразуми́ мя, и испыта́ю зако́н Твой, и сохраню́ и́ всем се́рдцем мои́м. Наста́ви мя на стезю́ за́поведей Твои́х, я́ко ту́ю восхоте́х. Приклони́ се́рдце мое́ во свиде́ния Твоя́, а не в лихои́мство. Отврати́ о́чи мои́, е́же не ви́дети суеты́, в пути́ Твое́м живи́ мя. Поста́ви рабу́ Твоему́ сло́во Твое́ в страх Твой. Отьими́ поноше́ние мое́, е́же непщева́х: я́ко судьбы́ Твоя́ бла́ги. Се возжела́х за́поведи Твоя́, в пра́вде Твое́й живи́ мя. И да прии́дет на мя ми́лость Твоя́, Го́споди, спасе́ние Твое́ по словеси́ Твоему́. И отвеща́ю поноша́ющым ми сло́во: я́ко упова́х на словеса́ Твоя́. И не отъими́ от уст мои́х словесе́ и́стинна до зела́, я́ко на судьбы́ Твоя́ упова́х. И сохраню́ зако́н Твой вы́ну, в век и в век ве́ка. И хожда́х в широте́, я́ко за́поведи Твоя́ взыска́х. И глаго́лах о свиде́ниих Твои́х пред цари́, и не стыдя́хся: И поуча́хся в за́поведех Твои́х, я́же возлюби́х зело́: И воздвиго́х ру́це мои́ к за́поведем Твои́м, я́же возлюби́х, и глумля́хся во оправда́ниих Твои́х. Помяни́ словеса́ Твоя́ рабу́ Твоему́, и́хже упова́ние дал ми еси́. То мя уте́ши во смире́нии мое́м, я́ко сло́во Твое́ живи́ мя. Го́рдии законопреступова́ху до зела́: от зако́на же Твоего́ не уклони́хся. Помяну́х судьбы́ Твоя́ от ве́ка, Го́споди, и уте́шихся. Печа́ль прия́т мя от гре́шник, оставля́ющих зако́н Твой. Пе́та бя́ху мне оправда́ния Твоя́, на ме́сте прише́льствия моего́. Помяну́х в нощи́ и́мя Твое́, Го́споди, и сохрани́х зако́н Твой. Сей бысть мне, я́ко оправда́ний Твои́х взыска́х. Часть моя́ еси́, Го́споди, рех сохрани́ти зако́н Твой. Помоли́хся лицу́ Твоему́ всем се́рдцем мои́м: поми́луй мя по словеси́ Твоему́. Помы́слих пути́ Твоя́, и возврати́х но́зе мои́ во свиде́ния Твоя́. Угото́вихся и не смути́хся сохрани́ти за́поведи Твоя́. У́жя гре́шник обяза́шася мне, и зако́на Твоего́ не забы́х. Полу́нощи воста́х испове́датися Тебе́ о судьба́х пра́вды Твоея́. Прича́стник аз есмь всем боя́щымся Тебе́, и храня́щым за́поведи Твоя́. Ми́лости Твоея́, Го́споди, испо́лнь земля́: оправда́нием Твои́м научи́ мя. Бла́гость сотвори́л еси́ с рабо́м Твои́м, Го́споди, по словеси́ Твоему́. Бла́гости, и наказа́нию и ра́зуму научи́ мя, я́ко за́поведем Твои́м ве́ровах. Пре́жде да́же не смири́ти ми ся, аз прегреши́х: сего́ ра́ди сло́во Твое́ сохрани́х. Благ еси́ Ты, Го́споди, и бла́гостию Твое́ю научи́ мя оправда́нием Твои́м. Умно́жися на мя непра́вда го́рдых, аз же всем се́рдцем мои́м испыта́ю за́поведи Твоя́. Усыри́ся я́ко млеко́ се́рдце их, аз же зако́ну Твоему́ поучи́хся. Бла́го мне, я́ко смири́л мя еси́, я́ко да научу́ся оправда́нием Твои́м. Благ мне зако́н уст Твои́х, па́че ты́сящ зла́та и сребра́.",
  ["текст_цс"] = "Бл҃же́ни непоро́чнїи въ пꙋ́ть, ходѧ́щїи въ зако́нѣ гдⷭ҇ни. Бл҃же́ни и҆спыта́ющїи свидѣ̑нїѧ є҆гѡ̀, всѣ́мъ срⷣцемъ взы́щꙋтъ є҆го̀. Не дѣ́лающїи бо беззако́нїѧ въ пꙋте́хъ є҆гѡ̀ ходи́ша. Ты̀ заповѣ́далъ є҆сѝ за́пѡвѣди твоѧ̑ сохрани́ти ѕѣлѡ̀: Дабы̀ и҆спра́вилисѧ пꙋтїѐ моѝ, сохрани́ти ѡ҆правда̑нїѧ твоѧ̑. Тогда̀ не постыжꙋ́сѧ, внегда̀ призрѣ́ти мѝ на всѧ̑ за́пѡвѣди твоѧ̑. И҆сповѣ́мсѧ тебѣ̀ въ пра́вости се́рдца, внегда̀ наꙋчи́ти ми сѧ сꙋдьба́мъ пра́вды твоеѧ̀. Ѡ҆правда̑нїѧ твоѧ̑ сохраню̀: не ѡ҆ста́ви менѐ до ѕѣла̀. Въ чесо́мъ и҆спра́витъ ю҆нѣ́йшїй пꙋ́ть сво́й; внегда̀ сохрани́ти словеса̀ твоѧ̑. Всѣ́мъ се́рдцемъ мои́мъ взыска́хъ тебѐ: не ѿри́ни менѐ ѿ за́повѣдїй твои́хъ. Въ се́рдцы мое́мъ скры́хъ словеса̀ твоѧ̑, ꙗ҆́кѡ да не согрѣшꙋ̀ тебѣ̀. Бл҃гослове́нъ є҆сѝ, гдⷭ҇и: наꙋчи́ мѧ ѡ҆правда́нїємъ твои̑мъ. Оу҆стна́ма мои́ма возвѣсти́хъ всѧ̑ сꙋдьбы̑ ᲂу҆́стъ твои́хъ. На пꙋтѝ свидѣ́нїй твои́хъ наслади́хсѧ, ꙗ҆́кѡ ѡ҆ всѧ́комъ бога́тствѣ. Въ за́повѣдехъ твои́хъ поглꙋмлю́сѧ, и҆ ᲂу҆разꙋмѣ́ю пꙋти̑ твоѧ̑. Во ѡ҆правда́нїихъ твои́хъ поꙋчꙋ́сѧ: не забꙋ́дꙋ слове́съ твои́хъ. Возда́ждь рабꙋ̀ твоемꙋ̀: живи́ мѧ, и҆ сохраню̀ словеса̀ твоѧ̑. Ѿкры́й ѻ҆́чи моѝ, и҆ ᲂу҆разꙋмѣ́ю чꙋдеса̀ ѿ зако́на твоегѡ̀. Пришле́цъ а҆́зъ є҆́смь на землѝ: не скры́й ѿ менѐ за́пѡвѣди твоѧ̑. Возлюбѝ дꙋша̀ моѧ̀ возжела́ти сꙋдьбы̑ твоѧ̑ на всѧ́кое вре́мѧ. Запрети́лъ є҆сѝ гѡ́рдымъ: про́клѧти ᲂу҆клонѧ́ющїисѧ ѿ за́повѣдїй твои́хъ. Ѿимѝ ѿ менѐ поно́съ поноше́нїе и҆ ᲂу҆ничиже́нїе, ꙗ҆́кѡ свидѣ́нїй твои́хъ взыска́хъ. И҆́бо сѣдо́ша кнѧ̑зи и҆ на мѧ̀ клевета́хꙋ, ра́бъ же тво́й глꙋмлѧ́шесѧ во ѡ҆правда́нїихъ твои́хъ: И҆́бо свидѣ̑нїѧ твоѧ̑ поꙋче́нїе моѐ є҆́сть, и҆ совѣ́ти моѝ ѡ҆правда̑нїѧ твоѧ̑. Прильпѐ землѝ дꙋша̀ моѧ̀: живи́ мѧ по словесѝ твоемꙋ̀. Пꙋти̑ моѧ̑ возвѣсти́хъ, и҆ ᲂу҆слы́шалъ мѧ̀ є҆сѝ: наꙋчи́ мѧ ѡ҆правда́нїємъ твои̑мъ. Пꙋ́ть ѡ҆правда́нїй твои́хъ вразꙋми́ ми, и҆ поглꙋмлю́сѧ въ чꙋдесѣ́хъ твои́хъ. Воздрема̀ дꙋша̀ моѧ̀ ѿ ᲂу҆ны́нїѧ: ᲂу҆тверди́ мѧ въ словесѣ́хъ твои́хъ. Пꙋ́ть непра́вды ѿста́ви ѿ менѐ и҆ зако́номъ твои́мъ поми́лꙋй мѧ̀. Пꙋ́ть и҆́стины и҆зво́лихъ и҆ сꙋдьбы̑ твоѧ̑ не забы́хъ. Прилѣпи́хсѧ свидѣ́нїємъ твои̑мъ, гдⷭ҇и, не посрамѝ менѐ. Пꙋ́ть за́повѣдїй твои́хъ теко́хъ, є҆гда̀ разшири́лъ є҆сѝ се́рдце моѐ. Законоположѝ мнѣ̀, гдⷭ҇и, пꙋ́ть ѡ҆правда́нїй твои́хъ, и҆ взыщꙋ̀ и҆̀ вы́нꙋ: Вразꙋми́ мѧ, и҆ и҆спыта́ю зако́нъ тво́й и҆ сохраню̀ и҆̀ всѣ́мъ се́рдцемъ мои́мъ. Наста́ви мѧ̀ на стезю̀ за́повѣдїй твои́хъ, ꙗ҆́кѡ тꙋ́ю восхотѣ́хъ. Приклонѝ се́рдце моѐ во свидѣ̑нїѧ твоѧ̑, а҆ не въ лихои́мство. Ѿвратѝ ѻ҆́чи моѝ є҆́же не ви́дѣти сꙋеты̀: въ пꙋтѝ твое́мъ живи́ мѧ. Поста́ви рабꙋ̀ твоемꙋ̀ сло́во твоѐ въ стра́хъ тво́й. Ѿимѝ поноше́нїе моѐ, є҆́же непщева́хъ: ꙗ҆́кѡ сꙋдьбы̑ твоѧ̑ бл҃ги. Сѐ, возжела́хъ за́пѡвѣди твоѧ̑: въ пра́вдѣ твое́й живи́ мѧ. И҆ да прїи́детъ на мѧ̀ млⷭ҇ть твоѧ̀, гдⷭ҇и, сп҃се́нїе твоѐ по словесѝ твоемꙋ̀: И҆ ѿвѣща́ю поноша́ющымъ мѝ сло́во, ꙗ҆́кѡ ᲂу҆пова́хъ на словеса̀ твоѧ̑. И҆ не ѿимѝ ѿ ᲂу҆́стъ мои́хъ словесѐ и҆́стинна до ѕѣла̀, ꙗ҆́кѡ на сꙋдьбы̑ твоѧ̑ ᲂу҆пова́хъ: И҆ сохраню̀ зако́нъ тво́й вы́нꙋ, въ вѣ́къ и҆ въ вѣ́къ вѣ́ка. И҆ хожда́хъ въ широтѣ̀, ꙗ҆́кѡ за́пѡвѣди твоѧ̑ взыска́хъ: И҆ глаго́лахъ ѡ҆ свидѣ́нїихъ твои́хъ пред̾ царѝ и҆ не стыдѧ́хсѧ: И҆ поꙋча́хсѧ въ за́повѣдехъ твои́хъ, ꙗ҆̀же возлюби́хъ ѕѣлѡ̀: И҆ воздвиго́хъ рꙋ́цѣ моѝ къ за́повѣдемъ твои̑мъ, ꙗ҆̀же возлюби́хъ, и҆ глꙋмлѧ́хсѧ во ѡ҆правда́нїихъ твои́хъ. Помѧнѝ словеса̀ твоѧ̑ рабꙋ̀ твоемꙋ̀, и҆́хже ᲂу҆пова́нїе да́лъ мѝ є҆сѝ. То́ мѧ ᲂу҆тѣ́ши во смире́нїи мое́мъ, ꙗ҆́кѡ сло́во твоѐ живи́ мѧ. Го́рдїи законопрестꙋпова́хꙋ до ѕѣла̀: ѿ зако́на же твоегѡ̀ не ᲂу҆клони́хсѧ. Помѧнꙋ́хъ сꙋдьбы̑ твоѧ̑ ѿ вѣ́ка, гдⷭ҇и, и҆ ᲂу҆тѣ́шихсѧ. Печа́ль прїѧ́тъ мѧ̀ ѿ грѣ̑шникъ, ѡ҆ставлѧ́ющихъ зако́нъ тво́й. Пѣ̑та бѧ́хꙋ мнѣ̀ ѡ҆правда̑нїѧ твоѧ̑ на мѣ́стѣ прише́льствїѧ моегѡ̀. Помѧнꙋ́хъ въ нощѝ и҆́мѧ твоѐ, гдⷭ҇и, и҆ сохрани́хъ зако́нъ тво́й. Се́й бы́сть мнѣ̀, ꙗ҆́кѡ ѡ҆правда́нїй твои́хъ взыска́хъ. Ча́сть моѧ̀ є҆сѝ, гдⷭ҇и: рѣ́хъ сохрани́ти зако́нъ тво́й. Помоли́хсѧ лицꙋ̀ твоемꙋ̀ всѣ́мъ се́рдцемъ мои́мъ: поми́лꙋй мѧ̀ по словесѝ твоемꙋ̀. Помы́слихъ пꙋти̑ твоѧ̑ и҆ возврати́хъ но́зѣ моѝ во свидѣ̑нїѧ твоѧ̑. Оу҆гото́вихсѧ и҆ не смꙋти́хсѧ сохрани́ти за́пѡвѣди твоѧ̑. Оу҆́жѧ грѣ̑шникъ ѡ҆бѧза́шасѧ мнѣ̀, и҆ зако́на твоегѡ̀ не забы́хъ. Полꙋ́нощи воста́хъ и҆сповѣ́датисѧ тебѣ̀ ѡ҆ сꙋдьба́хъ пра́вды твоеѧ̀. Прича́стникъ а҆́зъ є҆́смь всѣ̑мъ боѧ́щымсѧ тебє̀ и҆ хранѧ́щымъ за́пѡвѣди твоѧ̑. Млⷭ҇ти твоеѧ̀, гдⷭ҇и, и҆спо́лнь землѧ̀: ѡ҆правда́нїємъ твои̑мъ наꙋчи́ мѧ. Бл҃гость сотвори́лъ є҆сѝ съ рабо́мъ твои́мъ, гдⷭ҇и, по словесѝ твоемꙋ̀: Бл҃гости и҆ наказа́нїю и҆ ра́зꙋмꙋ наꙋчи́ мѧ, ꙗ҆́кѡ за́повѣдемъ твои̑мъ вѣ́ровахъ. Пре́жде да́же не смири́ти ми сѧ, а҆́зъ прегрѣши́хъ: сегѡ̀ ра́ди сло́во твоѐ сохрани́хъ. Бл҃гъ є҆сѝ ты̀, гдⷭ҇и: и҆ бл҃гостїю твое́ю наꙋчи́ мѧ ѡ҆правда́нїємъ твои̑мъ. Оу҆мно́жисѧ на мѧ̀ непра́вда го́рдыхъ: а҆́зъ же всѣ́мъ се́рдцемъ мои́мъ и҆спыта́ю за́пѡвѣди твоѧ̑. Оу҆сыри́сѧ ꙗ҆́кѡ млеко̀ се́рдце и҆́хъ: а҆́зъ же зако́нꙋ твоемꙋ̀ поꙋчи́хсѧ. Бл҃го мнѣ̀, ꙗ҆́кѡ смири́лъ мѧ̀ є҆сѝ, ꙗ҆́кѡ да наꙋчꙋ́сѧ ѡ҆правда́нїємъ твои̑мъ. Бл҃гъ мнѣ̀ зако́нъ ᲂу҆́стъ твои́хъ па́че ты́сѧщъ зла́та и҆ сребра̀.",
