  ["текст_ру"] = "При́зри на мя и поми́луй мя, по суду́ лю́бящих и́мя Твое́. Стопы́ моя́ напра́ви по словеси́ Твоему́, и да не облада́ет мно́ю вся́кое беззако́ние. Изба́ви мя от клеветы́ челове́ческия, и сохраню́ за́поведи Твоя́. Лице́ Твое́ просвети́ на раба́ Твоего́, и научи́ мя оправда́нием Твои́м. Исхо́дища водна́я изведо́сте о́чи мои́, поне́же не сохрани́х зако́на Твоего́. Пра́веден еси́, Го́споди, и пра́ви суди́ Твои́. Запове́дал еси́ пра́вду свиде́ния Твоя́, и и́стину зело́. Иста́яла мя есть ре́вность Твоя́, я́ко забы́ша словеса́ Твоя́ врази́ мои́. Разжже́но сло́во Твое́ зело́, и раб Твой возлюби́ е́. Юне́йший аз есмь и уничиже́н, оправда́ний Твои́х не забы́х. Пра́вда Твоя́ пра́вда во век, и зако́н Твой и́стина. Ско́рби и ну́жды обрето́ша мя, за́поведи Твоя́ поуче́ние мое́. Пра́вда свиде́ния Твоя́ в век, вразуми́ мя, и жив бу́ду. Воззва́х всем се́рдцем мои́м, услы́ши мя, Го́споди, оправда́ния Твоя́ взыщу́. Воззва́х Ти, спаси́ мя, и сохраню́ свиде́ния Твоя́. Предвари́х в безго́дии и воззва́х, на словеса́ Твоя́ упова́х. Предвари́сте о́чи мои́ ко у́тру, поучи́тися словесе́м Твои́м. Глас мой услы́ши, Го́споди, по ми́лости Твое́й: по судьбе́ Твое́й живи́ мя. Прибли́жишася гоня́щии мя беззако́нием, от зако́на же Твоего́ удали́шася. Близ еси́ Ты, Го́споди, и вси путие́ Твои́ и́стина. Испе́рва позна́х от свиде́ний Твои́х, я́ко в век основа́л я́ еси́. Виждь смире́ние мое́ и изми́ мя, я́ко зако́на Твоего́ не забы́х. Суди́ суд мой и изба́ви мя, словесе́ ра́ди Твоего́ живи́ мя. Дале́че от гре́шник спасе́ние, я́ко оправда́ний Твои́х не взыска́ша. Щедро́ты Твоя́ мно́ги, Го́споди, по судьбе́ Твое́й живи́ мя. Мно́зи изгоня́щии мя и стужа́ющии ми, от свиде́ний Твои́х не уклони́хся. Ви́дех неразумева́ющия и иста́ях, я́ко слове́с Твои́х не сохрани́ша. Виждь, я́ко за́поведи Твоя́ возлюби́х, Го́споди, по ми́лости Твое́й живи́ мя. Нача́ло слове́с Твои́х и́стина, и во век вся судьбы́ пра́вды Твоея́. Кня́зи погна́ша мя ту́не, и от слове́с Твои́х убоя́ся се́рдце мое́. Возра́дуюся аз о словесе́х Твои́х, я́ко обрета́яй коры́сть мно́гу. Непра́вду возненави́дех и омерзи́х, зако́н же Твой возлюби́х. Седмери́цею днем хвали́х Тя о судьба́х пра́вды Твоея́. Мир мног лю́бящым зако́н Твой, и несть им собла́зна. Ча́ях спасе́ния Твоего́, Го́споди, и за́поведи Твоя́ возлюби́х. Сохрани́ душа́ моя́ свиде́ния Твоя́ и возлюби́ я́ зело́. Сохрани́х за́поведи Твоя́ и свиде́ния Твоя́, я́ко вси путие́ мои́ пред Тобо́ю, Го́споди. Да прибли́жится моле́ние мое́ пред Тя, Го́споди, по словеси́ Твоему́ вразуми́ мя. Да вни́дет проше́ние мое́ пред Тя, Го́споди, по словеси́ Твоему́ изба́ви мя. Отры́гнут устне́ мои́ пе́ние, егда́ научи́ши мя оправда́нием Твои́м. Провеща́ет язы́к мой словеса́ Твоя́, я́ко вся за́поведи Твоя́ пра́вда. Да бу́дет рука́ Твоя́ е́же спасти́ мя, я́ко за́поведи Твоя́ изво́лих. Возжела́х спасе́ние Твое́, Го́споди, и зако́н Твой поуче́ние мое́ есть. Жива́ бу́дет душа́ моя́ и восхва́лит Тя, и судьбы́ Твоя́ помо́гут мне. Заблуди́х, я́ко овча́ поги́бшее, взыщи́ раба́ Твоего́, я́ко за́поведей Твои́х не забы́х.",
  ["текст_цс"] = "При́зри на мѧ̀ и҆ поми́лꙋй мѧ̀, по сꙋдꙋ̀ лю́бѧщихъ и҆́мѧ твоѐ. Стѡпы̀ моѧ̑ напра́ви по словесѝ твоемꙋ̀, и҆ да не ѡ҆блада́етъ мно́ю всѧ́кое беззако́нїе: И҆зба́ви мѧ̀ ѿ клеветы̀ человѣ́ческїѧ, и҆ сохраню̀ за́пѡвѣди твоѧ̑. Лицѐ твоѐ просвѣтѝ на раба̀ твоего̀ и҆ наꙋчи́ мѧ ѡ҆правда́нїємъ твои̑мъ. И҆схѡ́дища водна̑ѧ и҆зведо́стѣ ѻ҆́чи моѝ, поне́же не сохрани́хъ зако́на твоегѡ̀. Првⷣнъ є҆сѝ, гдⷭ҇и, и҆ пра́ви сꙋдѝ твоѝ: Заповѣ́далъ є҆сѝ пра́вдꙋ свидѣ̑нїѧ твоѧ̑, и҆ и҆́стинꙋ ѕѣлѡ̀. И҆ста́ѧла мѧ̀ є҆́сть ре́вность твоѧ̀: ꙗ҆́кѡ забы́ша словеса̀ твоѧ̑ вразѝ моѝ. Разжже́но сло́во твоѐ ѕѣлѡ̀, и҆ ра́бъ тво́й возлюбѝ є҆̀. Ю҆нѣ́йшїй а҆́зъ є҆́смь и҆ ᲂу҆ничиже́нъ: ѡ҆правда́нїй твои́хъ не забы́хъ. Пра́вда твоѧ̀ пра́вда во вѣ́къ, и҆ зако́нъ тво́й и҆́стина. Скѡ́рби и҆ нꙋ́жди ѡ҆брѣто́ша мѧ̀: за́пѡвѣди твоѧ̑ поꙋче́нїе моѐ. Пра́вда свидѣ̑нїѧ твоѧ̑ въ вѣ́къ: вразꙋми́ мѧ, и҆ жи́въ бꙋ́дꙋ. Воззва́хъ всѣ́мъ се́рдцемъ мои́мъ, ᲂу҆слы́ши мѧ̀, гдⷭ҇и: ѡ҆правда̑нїѧ твоѧ̑ взыщꙋ̀. Воззва́хъ тѝ, сп҃си́ мѧ, и҆ сохраню̀ свидѣ̑нїѧ твоѧ̑. Предвари́хъ въ безго́дїи и҆ воззва́хъ: на словеса̀ твоѧ̑ ᲂу҆пова́хъ. Предвари́стѣ ѻ҆́чи моѝ ко ᲂу҆́трꙋ, поꙋчи́тисѧ словесє́мъ твои̑мъ. Гла́съ мо́й ᲂу҆слы́ши, гдⷭ҇и, по млⷭ҇ти твое́й: по сꙋдьбѣ̀ твое́й живи́ мѧ. Прибли́жишасѧ гонѧ́щїи мѧ̀ беззако́нїемъ: ѿ зако́на же твоегѡ̀ ᲂу҆дали́шасѧ. Бли́з̾ є҆сѝ ты̀, гдⷭ҇и, и҆ всѝ пꙋтїѐ твоѝ и҆́стина. И҆спе́рва позна́хъ ѿ свидѣ́нїй твои́хъ, ꙗ҆́кѡ въ вѣ́къ ѡ҆снова́лъ ѧ҆̀ є҆сѝ. Ви́ждь смире́нїе моѐ и҆ и҆зми́ мѧ: ꙗ҆́кѡ зако́на твоегѡ̀ не забы́хъ. Сꙋдѝ сꙋ́дъ мо́й и҆ и҆зба́ви мѧ̀: словесѐ ра́ди твоегѡ̀ живи́ мѧ. Дале́че ѿ грѣ̑шникъ сп҃се́нїе, ꙗ҆́кѡ ѡ҆правда́нїй твои́хъ не взыска́ша. Щедрѡ́ты твоѧ̑ мнѡ́ги, гдⷭ҇и: по сꙋдьбѣ̀ твое́й живи́ мѧ. Мно́зи и҆згонѧ́щїи мѧ̀ и҆ стꙋжа́ющїи мѝ: ѿ свидѣ́нїй твои́хъ не ᲂу҆клони́хсѧ. Ви́дѣхъ неразꙋмѣва́ющыѧ и҆ и҆ста́ѧхъ: ꙗ҆́кѡ слове́съ твои́хъ не сохрани́ша. Ви́ждь, ꙗ҆́кѡ за́пѡвѣди твоѧ̑ возлюби́хъ: гдⷭ҇и, по млⷭ҇ти твое́й живи́ мѧ. Нача́ло слове́съ твои́хъ и҆́стина, и҆ во вѣ́къ всѧ̑ сꙋдьбы̑ пра́вды твоеѧ̀. Кнѧ̑зи погна́ша мѧ̀ тꙋ́не: и҆ ѿ слове́съ твои́хъ ᲂу҆боѧ́сѧ се́рдце моѐ. Возра́дꙋюсѧ а҆́зъ ѡ҆ словесѣ́хъ твои́хъ, ꙗ҆́кѡ ѡ҆брѣта́ѧй коры́сть мно́гꙋ. Непра́вдꙋ возненави́дѣхъ и҆ ѡ҆мерзи́хъ: зако́нъ же тво́й возлюби́хъ. Седмери́цею дне́мъ хвали́хъ тѧ̀ ѡ҆ сꙋдьба́хъ пра́вды твоеѧ̀. Ми́ръ мно́гъ лю́бѧщымъ зако́нъ тво́й, и҆ нѣ́сть и҆̀мъ собла́зна. Ча́ѧхъ сп҃се́нїѧ твоегѡ̀, гдⷭ҇и, и҆ за́пѡвѣди твоѧ̑ возлюби́хъ. Сохранѝ дꙋша̀ моѧ̀ свидѣ̑нїѧ твоѧ̑ и҆ возлюбѝ ѧ҆̀ ѕѣлѡ̀. Сохрани́хъ за́пѡвѣди твоѧ̑ и҆ свидѣ̑нїѧ твоѧ̑, ꙗ҆́кѡ всѝ пꙋтїѐ моѝ пред̾ тобо́ю, гдⷭ҇и. Да прибли́житсѧ моле́нїе моѐ пред̾ тѧ̀, гдⷭ҇и: по словесѝ твоемꙋ̀ вразꙋми́ мѧ. Да вни́детъ проше́нїе моѐ пред̾ тѧ̀: гдⷭ҇и, по словесѝ твоемꙋ̀ и҆зба́ви мѧ̀. Ѿры́гнꙋтъ ᲂу҆стнѣ̀ моѝ пѣ́нїе, є҆гда̀ наꙋчи́ши мѧ̀ ѡ҆правда́нїємъ твои̑мъ. Провѣща́етъ ѧ҆зы́къ мо́й словеса̀ твоѧ̑, ꙗ҆́кѡ всѧ̑ за́пѡвѣди твоѧ̑ пра́вда. Да бꙋ́детъ рꙋка̀ твоѧ̀ є҆́же сп҃сти́ мѧ, ꙗ҆́кѡ за́пѡвѣди твоѧ̑ и҆зво́лихъ. Возжела́хъ сп҃се́нїе твоѐ, гдⷭ҇и, и҆ зако́нъ тво́й поꙋче́нїе моѐ є҆́сть. Жива̀ бꙋ́детъ дꙋша̀ моѧ̀ и҆ восхва́литъ тѧ̀: и҆ сꙋдьбы̑ твоѧ̑ помо́гꙋтъ мнѣ̀. Заблꙋди́хъ ꙗ҆́кѡ ѻ҆вча̀ поги́бшее: взыщѝ раба̀ твоего̀, ꙗ҆́кѡ за́повѣдей твои́хъ не забы́хъ.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 119,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 1,
  ["текст_ру"] = "Ко Го́споду, внегда́ скорбе́ти ми, воззва́х, и услы́ша мя. Го́споди, изба́ви ду́шу мою́ от усте́н непра́ведных и от язы́ка льсти́ва. Что да́стся тебе́, или́ что приложи́тся тебе́ к язы́ку льсти́ву? Стре́лы си́льнаго изощре́ны, со у́гльми пусты́нными. Увы́ мне, я́ко прише́льствие мое́ продолжи́ся, всели́хся с селе́нии Кида́рскими. Мно́го прише́льствова душа́ моя́, с ненави́дящими ми́ра бех ми́рен: егда́ глаго́лах им, боря́ху мя ту́не.",
  ["текст_цс"] = "Ко гдⷭ҇ꙋ, внегда̀ скорбѣ́ти мѝ, воззва́хъ, и҆ ᲂу҆слы́ша мѧ̀. Гдⷭ҇и, и҆зба́ви дꙋ́шꙋ мою̀ ѿ ᲂу҆сте́нъ непра́ведныхъ и҆ ѿ ѧ҆зы́ка льсти́ва. Что̀ да́стсѧ тебѣ̀, и҆лѝ что̀ приложи́тсѧ тебѣ̀ къ ѧ҆зы́кꙋ льсти́вꙋ; Стрѣ́лы си́льнагѡ и҆з̾ѡщрє́ны, со ᲂу҆́гльми пꙋсты́нными. Оу҆вы̀ мнѣ̀, ꙗ҆́кѡ прише́льствїе моѐ продолжи́сѧ, всели́хсѧ съ селє́нїи кида́рскими: Мно́гѡ прише́льствова дꙋша̀ моѧ̀: съ ненави́дѧщими ми́ра бѣ́хъ ми́ренъ: Є҆гда̀ глаго́лахъ и҆̀мъ, борѧ́хꙋ мѧ̀ тꙋ́не.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 120,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 1,
  ["текст_ру"] = "Возведо́х о́чи мои́ в го́ры, отню́дуже прии́дет по́мощь моя́. По́мощь моя́ от Го́спода, сотво́ршаго не́бо и зе́млю. Не даждь во смяте́ние ноги́ твоея́, ниже́ воздре́млет храня́й тя, се не воздре́млет, ниже́ у́снет храня́й Изра́иля. Госпо́дь сохрани́т тя, Госпо́дь покро́в твой на руку́ десну́ю твою́. Во дни со́лнце не ожже́т тебе́, ниже́ луна́ но́щию. Госпо́дь сохрани́т тя от вся́каго зла, сохрани́т ду́шу твою́ Госпо́дь. Госпо́дь сохрани́т вхожде́ние твое́ и исхожде́ние твое́, отны́не и до ве́ка.",
  ["текст_цс"] = "Возведо́хъ ѻ҆́чи моѝ въ го́ры, ѿню́дꙋже прїи́детъ по́мощь моѧ̀. По́мощь моѧ̀ ѿ гдⷭ҇а, сотво́ршагѡ не́бо и҆ зе́млю. Не да́ждь во смѧте́нїе ногѝ твоеѧ̀, нижѐ воздре́млетъ хранѧ́й тѧ̀: Сѐ, не воздре́млетъ, нижѐ ᲂу҆́снетъ хранѧ́й і҆и҃лѧ. Гдⷭ҇ь сохрани́тъ тѧ̀, гдⷭ҇ь покро́въ тво́й на рꙋ́кꙋ деснꙋ́ю твою̀. Во днѝ со́лнце не ѡ҆жже́тъ тебѐ, нижѐ лꙋна̀ но́щїю. Гдⷭ҇ь сохрани́тъ тѧ̀ ѿ всѧ́кагѡ ѕла̀, сохрани́тъ дꙋ́шꙋ твою̀ гдⷭ҇ь: Гдⷭ҇ь сохрани́тъ вхожде́нїе твоѐ и҆ и҆схожде́нїе твоѐ, ѿ ны́нѣ и҆ до вѣ́ка.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 121,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 1,
  ["текст_ру"] = "Возвесели́хся о ре́кших мне: в дом Госпо́день по́йдем. Стоя́ще бя́ху но́ги на́ша во дво́рех твои́х, Иерусали́ме. Иерусали́м зи́ждемый я́ко град, eму́же прича́стие eго́ вку́пе. Та́мо бо взыдо́ша коле́на, коле́на Госпо́дня, свиде́ние Изра́илево, испове́датися и́мени Госпо́дню, я́ко та́мо седо́ша престо́ли на суд, престо́ли в дому́ Дави́дове. Вопроси́те же я́же о ми́ре Иерусали́ма: и оби́лие лю́бящым тя. Бу́ди же мир в си́ле твое́й и оби́лие в столпостена́х твои́х. Ра́ди бра́тий мои́х и бли́жних мои́х глаго́лах у́бо мир о тебе́. До́му ра́ди Го́спода Бо́га на́шего взыска́х блага́я тебе́.",
  ["текст_цс"] = "Возвесели́хсѧ ѡ҆ ре́кшихъ мнѣ̀: въ до́мъ гдⷭ҇ень по́йдемъ. Стоѧ́ще бѧ́хꙋ но́ги на́шѧ во дво́рѣхъ твои́хъ, і҆ерⷭ҇ли́ме. І҆ерⷭ҇ли́мъ зи́ждемый ꙗ҆́кѡ гра́дъ, є҆мꙋ́же прича́стїе є҆гѡ̀ вкꙋ́пѣ. Та́мѡ бо взыдо́ша кѡлѣ́на, кѡлѣ́на гдⷭ҇нѧ, свидѣ́нїе і҆и҃лево, и҆сповѣ́датисѧ и҆́мени гдⷭ҇ню: Ꙗ҆́кѡ та́мѡ сѣдо́ша престо́ли на сꙋ́дъ, престо́ли въ домꙋ̀ дв҃довѣ. Вопроси́те же ꙗ҆̀же ѡ҆ ми́рѣ і҆ерⷭ҇ли́ма: и҆ ѻ҆би́лїе лю́бѧщымъ тѧ̀. Бꙋ́ди же ми́ръ въ си́лѣ твое́й, и҆ ѻ҆би́лїе въ столпостѣна́хъ твои́хъ. Ра́ди бра́тїй мои́хъ и҆ бли́жнихъ мои́хъ глаго́лахъ ᲂу҆́бѡ ми́ръ ѡ҆ тебѣ̀. До́мꙋ ра́ди гдⷭ҇а бг҃а на́шегѡ взыска́хъ бл҃га̑ѧ тебѣ̀.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 122,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 1,
  ["текст_ру"] = "К Тебе́ возведо́х о́чи мои́, живу́щему на небеси́. Се я́ко о́чи раб в руку́ госпо́дий свои́х, я́ко о́чи рабы́ни в руку́ госпожи́ своея́, та́ко о́чи на́ши ко Го́споду Бо́гу на́шему, до́ндеже уще́дрит ны. Поми́луй нас, Го́споди, поми́луй нас, я́ко по мно́гу испо́лнихомся уничиже́ния, наипа́че напо́лнися душа́ на́ша поноше́ния гобзу́ющих и уничиже́ния го́рдых.",
  ["текст_цс"] = "Къ тебѣ̀ возведо́хъ ѻ҆́чи моѝ, живꙋ́щемꙋ на нб҃сѝ. Сѐ, ꙗ҆́кѡ ѻ҆́чи ра̑бъ въ рꙋкꙋ̀ госпо́дїй свои́хъ, ꙗ҆́кѡ ѻ҆́чи рабы́ни въ рꙋкꙋ̀ госпожѝ своеѧ̀: та́кѡ ѻ҆́чи на́ши ко гдⷭ҇ꙋ бг҃ꙋ на́шемꙋ, до́ндеже ᲂу҆ще́дритъ ны̀. Поми́лꙋй на́съ, гдⷭ҇и, поми́лꙋй на́съ, ꙗ҆́кѡ помно́гꙋ и҆спо́лнихомсѧ ᲂу҆ничиже́нїѧ: Наипа́че напо́лнисѧ дꙋша̀ на́ша поноше́нїѧ гобзꙋ́ющихъ и҆ ᲂу҆ничиже́нїѧ го́рдыхъ.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 123,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 1,
  ["текст_ру"] = "Я́ко а́ще не Госпо́дь бы был в нас, да рече́т у́бо Изра́иль, я́ко а́ще не Госпо́дь бы был в нас, внегда́ воста́ти челове́ком на ны, у́бо живы́х поже́рли бы́ша нас, внегда́ прогне́ватися я́рости их на ны, у́бо вода́ потопи́ла бы нас. Пото́к пре́йде душа́ на́ша, у́бо пре́йде душа́ на́ша во́ду непостоя́нную. Благослове́н Госпо́дь, И́же не даде́ нас в лови́тву зубо́м их. Душа́ на́ша, я́ко пти́ца изба́вися от се́ти ловя́щих: сеть сокруши́ся, и мы изба́влени бы́хом. По́мощь на́ша во и́мя Го́спода, сотво́ршаго не́бо и зе́млю.",
  ["текст_цс"] = "Ꙗ҆́кѡ а҆́ще не гдⷭ҇ь бы бы́лъ въ на́съ, да рече́тъ ᲂу҆́бѡ і҆и҃ль: Ꙗ҆́кѡ а҆́ще не гдⷭ҇ь бы бы́лъ въ на́съ, внегда̀ воста́ти человѣ́кѡмъ на ны̀, ᲂу҆̀бо живы́хъ поже́рли бы́ша на́съ: Внегда̀ прогнѣ́ватисѧ ꙗ҆́рости и҆́хъ на ны̀, ᲂу҆̀бо вода̀ потопи́ла бы на́съ. Пото́къ пре́йде дꙋша̀ на́ша: Оу҆̀бо пре́йде дꙋша̀ на́ша во́дꙋ непостоѧ́ннꙋю. Бл҃гослове́нъ гдⷭ҇ь, и҆́же не дадѐ на́съ въ лови́твꙋ зꙋбѡ́мъ и҆́хъ. Дꙋша̀ на́ша ꙗ҆́кѡ пти́ца и҆зба́висѧ ѿ сѣ́ти ловѧ́щихъ: сѣ́ть сокрꙋши́сѧ, и҆ мы̀ и҆зба́влени бы́хомъ. По́мощь на́ша во и҆́мѧ гдⷭ҇а, сотво́ршагѡ не́бо и҆ зе́млю.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
