  ["кафизма"] = 18,
  ["слава"] = 3,
  ["текст_ру"] = "Из глубины́ воззва́х к Тебе́, Го́споди, Го́споди, услы́ши глас мой. Да бу́дут у́ши Твои́ вне́млюще гла́су моле́ния моего́. А́ще беззако́ния на́зриши, Го́споди, Го́споди, кто постои́т? Я́ко у Тебе́ очище́ние есть. И́мене ра́ди Твоего́ потерпе́х Тя, Го́споди, потерпе́ душа́ моя́ в сло́во Твое́, упова́ душа́ моя́ на Го́спода. От стра́жи у́тренния до но́щи, от стра́жи у́тренния да упова́ет Изра́иль на Го́спода. Я́ко у Го́спода ми́лость, и мно́гое у Него́ избавле́ние, и Той изба́вит Изра́иля от всех беззако́ний eго́.",
  ["текст_цс"] = "И҆з̾ глꙋбины̀ воззва́хъ къ тебѣ̀, гдⷭ҇и: гдⷭ҇и, ᲂу҆слы́ши гла́съ мо́й. Да бꙋ́дꙋтъ ᲂу҆́ши твоѝ вне́млющѣ гла́сꙋ моле́нїѧ моегѡ̀. А҆́ще беззакѡ́нїѧ на́зриши, гдⷭ҇и, гдⷭ҇и, кто̀ постои́тъ; ꙗ҆́кѡ ᲂу҆ тебє̀ ѡ҆чище́нїе є҆́сть. И҆́мене ра́ди твоегѡ̀ потерпѣ́хъ тѧ̀, гдⷭ҇и, потерпѣ̀ дꙋша̀ моѧ̀ въ сло́во твоѐ: ᲂу҆пова̀ дꙋша̀ моѧ̀ на гдⷭ҇а. Ѿ стра́жи ᲂу҆́треннїѧ до но́щи, ѿ стра́жи ᲂу҆́треннїѧ да ᲂу҆пова́етъ і҆и҃ль на гдⷭ҇а: Ꙗ҆́кѡ ᲂу҆ гдⷭ҇а млⷭ҇ть, и҆ мно́гое ᲂу҆ негѡ̀ и҆збавле́нїе: и҆ то́й и҆зба́витъ і҆и҃лѧ ѿ всѣ́хъ беззако́нїй є҆гѡ̀.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 130,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 3,
  ["текст_ру"] = "Го́споди, не вознесе́ся се́рдце мое́, ниже́ вознесо́стеся о́чи мои́, ниже́ ходи́х в вели́ких, ниже́ в ди́вных па́че мене́. А́ще не смиреному́дрствовах, но вознесо́х ду́шу мою́, я́ко отдое́ное на ма́терь свою́, та́ко возда́си на ду́шу мою́. Да упова́ет Изра́иль на Го́спода, отны́не и до ве́ка.",
  ["текст_цс"] = "Гдⷭ҇и, не вознесе́сѧ се́рдце моѐ, нижѐ вознесо́стѣсѧ ѻ҆́чи моѝ: нижѐ ходи́хъ въ вели́кихъ, нижѐ въ ди́вныхъ па́че менѐ. А҆́ще не смиреномꙋ́дрствовахъ, но вознесо́хъ дꙋ́шꙋ мою̀, ꙗ҆́кѡ ѿдое́ное на ма́терь свою̀, та́кѡ возда́си на дꙋ́шꙋ мою̀. Да ᲂу҆пова́етъ і҆и҃ль на гдⷭ҇а ѿ ны́нѣ и҆ до вѣ́ка.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 131,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 3,
  ["текст_ру"] = "Помяни́, Го́споди, Дави́да и всю кро́тость eго́: я́ко кля́тся Го́сподеви, обеща́ся Бо́гу Иа́ковлю: а́ще вни́ду в селе́ние до́му моего́, или́ взы́ду на одр посте́ли моея́, а́ще дам сон очи́ма мои́ма и ве́ждома мои́ма дрема́ние, и поко́й скраниа́ма мои́ма, до́ндеже обря́щу ме́сто Го́сподеви, селе́ние Бо́гу Иа́ковлю. Се слы́шахом я́ во Евфра́фе, обрето́хом я́ в поля́х дубра́вы. Вни́дем в селе́ния Его́, поклони́мся на ме́сто, иде́же стоя́сте но́зе Его́. Воскресни́, Го́споди, в поко́й Твой, Ты и киво́т святы́ни Твоея́. Свяще́нницы Твои́ облеку́тся пра́вдою, и преподо́бнии Твои́ возра́дуются. Дави́да ра́ди раба́ Твоего́ не отврати́ лице́ пома́заннаго Твоего́. Кля́тся Госпо́дь Дави́ду и́стиною и не отве́ржется ея́: от плода́ чре́ва твоего́ посажду́ на престо́ле твое́м. А́ще сохраня́т сы́нове твои́ заве́т Мой, и свиде́ния Моя́ сия́, и́мже научу́ я́, и сы́нове их до ве́ка ся́дут на престо́ле твое́м. Я́ко избра́ Госпо́дь Сио́на, изво́ли и́ в жили́ще Себе́. Сей поко́й Мой во век ве́ка, зде вселю́ся, я́ко изво́лих и́. Лови́тву eго́ благословля́яй благословлю́, ни́щыя eго́ насы́щу хле́бы, свяще́нники eго́ облеку́ во спасе́ние, и преподо́бнии eго́ ра́достию возра́дуются. Та́мо возращу́ рог Дави́дови, угото́вах свети́льник пома́занному Моему́. Враги́ eго́ облеку́ студо́м, на не́мже процвете́т святы́ня Моя́.",
  ["текст_цс"] = "Помѧнѝ, гдⷭ҇и, дв҃да и҆ всю̀ кро́тость є҆гѡ̀: Ꙗ҆́кѡ клѧ́тсѧ гдⷭ҇еви, ѡ҆бѣща́сѧ бг҃ꙋ і҆а́кѡвлю: А҆́ще вни́дꙋ въ селе́нїе до́мꙋ моегѡ̀, и҆лѝ взы́дꙋ на ѻ҆́дръ посте́ли моеѧ̀: А҆́ще да́мъ со́нъ ѻ҆чи́ма мои́ма, и҆ вѣ́ждома мои́ма дрема́нїе, и҆ поко́й скранїа́ма мои́ма: До́ндеже ѡ҆брѧ́щꙋ мѣ́сто гдⷭ҇еви, селе́нїе бг҃ꙋ і҆а́кѡвлю. Сѐ, слы́шахомъ ѧ҆̀ во є҆ѵфра́ѳѣ, ѡ҆брѣто́хомъ ѧ҆̀ въ полѧ́хъ дꙋбра́вы: Вни́демъ въ селє́нїѧ є҆гѡ̀, поклони́мсѧ на мѣ́сто, и҆дѣ́же стоѧ́стѣ но́зѣ є҆гѡ̀. Воскрⷭ҇нѝ, гдⷭ҇и, въ поко́й тво́й, ты̀ и҆ кївѡ́тъ ст҃ы́ни твоеѧ̀. Сщ҃е́нницы твоѝ ѡ҆блекꙋ́тсѧ пра́вдою, и҆ прпⷣбнїи твоѝ возра́дꙋютсѧ. Дв҃да ра́ди раба̀ твоегѡ̀, не ѿвратѝ лицѐ пома́заннагѡ твоегѡ̀. Клѧ́тсѧ гдⷭ҇ь дв҃дꙋ и҆́стиною, и҆ не ѿве́ржетсѧ є҆ѧ̀: ѿ плода̀ чре́ва твоегѡ̀ посаждꙋ̀ на престо́лѣ твое́мъ. А҆́ще сохранѧ́тъ сы́нове твоѝ завѣ́тъ мо́й и҆ свидѣ̑нїѧ моѧ̑ сїѧ̑, и҆̀мже наꙋчꙋ̀ ѧ҆̀, и҆ сы́нове и҆́хъ до вѣ́ка сѧ́дꙋтъ на престо́лѣ твое́мъ. Ꙗ҆́кѡ и҆збра̀ гдⷭ҇ь сїѡ́на, и҆зво́ли и҆̀ въ жили́ще себѣ̀. Се́й поко́й мо́й во вѣ́къ вѣ́ка, здѣ̀ вселю́сѧ, ꙗ҆́кѡ и҆зво́лихъ и҆̀. Лови́твꙋ є҆гѡ̀ бл҃гословлѧ́ѧй бл҃гословлю̀, ни́щыѧ є҆гѡ̀ насы́щꙋ хлѣ́бы: Сщ҃е́нники є҆гѡ̀ ѡ҆блекꙋ̀ во сп҃се́нїе, и҆ прпⷣбнїи є҆гѡ̀ ра́достїю возра́дꙋютсѧ. Та́мѡ возращꙋ̀ ро́гъ дв҃дови, ᲂу҆гото́вахъ свѣти́льникъ пома́занномꙋ моемꙋ̀. Врагѝ є҆гѡ̀ ѡ҆блекꙋ̀ стꙋдо́мъ, на не́мъ же процвѣте́тъ ст҃ы́нѧ моѧ̀.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 132,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 3,
  ["текст_ру"] = "Се что́ добро́, или́ что́ красно́? Но е́же жи́ти бра́тии вку́пе. Я́ко мvро на главе́, сходя́щее на браду́, браду́ Ааро́ню, сходя́щее на оме́ты оде́жды eго́, я́ко роса́ Аермо́нская сходя́щая на го́ры Сио́нския, я́ко та́мо запове́да Госпо́дь благослове́ние и живо́т до ве́ка.",
  ["текст_цс"] = "Сѐ, что̀ добро̀, и҆лѝ что̀ красно̀, но є҆́же жи́ти бра́тїи вкꙋ́пѣ; Ꙗ҆́кѡ мѵ́ро на главѣ̀, сходѧ́щее на брадꙋ̀, брадꙋ̀ а҆арѡ́ню, сходѧ́щее на ѻ҆ме́ты ѻ҆де́жды є҆гѡ̀: Ꙗ҆́кѡ роса̀ а҆ермѡ́нскаѧ сходѧ́щаѧ на го́ры сїѡ̑нскїѧ: ꙗ҆́кѡ та́мѡ заповѣ́да гдⷭ҇ь бл҃гослове́нїе и҆ живо́тъ до вѣ́ка.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 133,
  ["часть"] = 1,
  ["кафизма"] = 18,
  ["слава"] = 3,
  ["текст_ру"] = "Се ны́не благослови́те Го́спода вси раби́ Госпо́дни, стоя́щии в хра́ме Госпо́дни, во дво́рех до́му Бо́га на́шего, В но́щех воздежи́те ру́ки ва́ша во свята́я, и благослови́те Го́спода. Благослови́т тя Госпо́дь от Сио́на, сотвори́вый не́бо и зе́млю.",
  ["текст_цс"] = "Сѐ, ны́нѣ бл҃гослови́те гдⷭ҇а, всѝ рабѝ гдⷭ҇ни, стоѧ́щїи въ хра́мѣ гдⷭ҇ни, во дво́рѣхъ до́мꙋ бг҃а на́шегѡ. Въ но́щехъ воздѣжи́те рꙋ́ки ва́шѧ во ст҃а̑ѧ и҆ бл҃гослови́те гдⷭ҇а. Бл҃гослови́тъ тѧ̀ гдⷭ҇ь ѿ сїѡ́на, сотвори́вый не́бо и҆ зе́млю.",
  ["заголовок_ру"] = "Песнь степе́ней.",
  ["заголовок_цс"] = "Пѣ́снь степе́ней."
}

add_psalom {
  ["номер"] = 134,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 1,
  ["текст_ру"] = "Хвали́те и́мя Госпо́дне, хвали́те, раби́ Го́спода, стоя́щии во хра́ме Госпо́дни, во дво́рех до́му Бо́га на́шего. Хвали́те Го́спода, я́ко благ Госпо́дь, по́йте и́мени Его́, я́ко добро́: я́ко Иа́кова избра́ Себе́ Госпо́дь, Изра́иля в достоя́ние Себе́. Я́ко аз позна́х, я́ко ве́лий Госпо́дь, и Госпо́дь наш над все́ми бо́ги. Вся ели́ка восхоте́ Госпо́дь, сотвори́ на небеси́ и на земли́, в моря́х и во всех бе́зднах. Возводя́ о́блаки от после́дних земли́, мо́лнии в дождь сотвори́, изводя́й ве́тры от сокро́вищ Свои́х. И́же порази́ пе́рвенцы Еги́петския, от челове́ка до скота́. Посла́ зна́мения и чудеса́ посреде́ Тебе́, Еги́пте, на фарао́на и на вся рабы́ eго́. И́же порази́ язы́ки мно́ги и изби́ цари́ кре́пки: Сио́на, царя́ Аморре́йска, и Ога, царя́ Васа́нска, и вся ца́рствия Ханаа́нска, и даде́ зе́млю их достоя́ние, достоя́ние Изра́илю, лю́дем Свои́м. Го́споди, и́мя Твое́ в век и па́мять Твоя́ в род и род: я́ко суди́ти и́мать Госпо́дь лю́дем Свои́м, и о рабе́х Свои́х умо́лится. И́доли язы́к, сребро́ и зла́то, дела́ рук челове́ческих. Уста́ и́мут, и не возлаго́лют, о́чи и́мут, и не у́зрят, у́ши и́мут, и не услы́шат, ниже́ бо есть дух во усте́х их. Подо́бни им да бу́дут творя́щии я́, и вси наде́ющиися на ня. До́ме Изра́илев, благослови́те Го́спода, до́ме Ааро́нь, благослови́те Го́спода, до́ме Леви́ин, благослови́те Го́спода. Боя́щиися Го́спода, благослови́те Го́спода. Благослове́н Госпо́дь от Сио́на, живы́й во Иерусали́ме.",
  ["текст_цс"] = "Хвали́те и҆́мѧ гдⷭ҇не, хвали́те, рабѝ гдⷭ҇а, Стоѧ́щїи во хра́мѣ гдⷭ҇ни, во дво́рѣхъ до́мꙋ бг҃а на́шегѡ. Хвали́те гдⷭ҇а, ꙗ҆́кѡ бла́гъ гдⷭ҇ь: по́йте и҆́мени є҆гѡ̀, ꙗ҆́кѡ добро̀: Ꙗ҆́кѡ і҆а́кѡва и҆збра̀ себѣ̀ гдⷭ҇ь, і҆и҃лѧ въ достоѧ́нїе себѣ̀: Ꙗ҆́кѡ а҆́зъ позна́хъ, ꙗ҆́кѡ ве́лїй гдⷭ҇ь, и҆ гдⷭ҇ь на́шъ над̾ всѣ́ми бо́ги: Всѧ̑, є҆ли̑ка восхотѣ̀ гдⷭ҇ь, сотворѝ на нб҃сѝ и҆ на землѝ, въ морѧ́хъ и҆ во всѣ́хъ бе́зднахъ. Возводѧ̀ ѻ҆́блаки ѿ послѣ́днихъ землѝ, мѡ́лнїи въ до́ждь сотворѝ, и҆зводѧ́й вѣ́тры ѿ сокро́вищъ свои́хъ. И҆́же поразѝ пе́рвенцы є҆гѵ́пєтскїѧ ѿ человѣ́ка до скота̀: Посла̀ зна́мєнїѧ и҆ чꙋдеса̀ посредѣ̀ тебє̀, є҆гѵ́пте, на фараѡ́на и҆ на всѧ̑ рабы̑ є҆гѡ̀. И҆́же поразѝ ꙗ҆зы́ки мнѡ́ги и҆ и҆збѝ царѝ крѣ́пки: Сиѡ́на царѧ̀ а҆морре́йска и҆ ѡ҆́га царѧ̀ васа́нска, и҆ всѧ̑ ца̑рствїѧ ханаа̑нска: И҆ дадѐ зе́млю и҆́хъ достоѧ́нїе, достоѧ́нїе і҆и҃лю лю́демъ свои̑мъ. Гдⷭ҇и, и҆́мѧ твоѐ въ вѣ́къ, и҆ па́мѧть твоѧ̀ въ ро́дъ и҆ ро́дъ: Ꙗ҆́кѡ сꙋди́ти и҆́мать гдⷭ҇ь лю́демъ свои̑мъ, и҆ ѡ҆ рабѣ́хъ свои́хъ ᲂу҆мо́литсѧ. І҆́дѡли ꙗ҆зы̑къ сребро̀ и҆ зла́то, дѣла̀ рꙋ́къ человѣ́ческихъ: Оу҆ста̀ и҆́мꙋтъ, и҆ не возглаго́лютъ: ѻ҆́чи и҆́мꙋтъ, и҆ не ᲂу҆́зрѧтъ: Оу҆́ши и҆́мꙋтъ, и҆ не ᲂу҆слы́шатъ: ниже́ бо є҆́сть дꙋ́хъ во ᲂу҆стѣ́хъ и҆́хъ. Подо́бни и҆̀мъ да бꙋ́дꙋтъ творѧ́щїи ѧ҆̀ и҆ всѝ надѣ́ющїисѧ на нѧ̀. До́ме і҆и҃левъ, бл҃гослови́те гдⷭ҇а: до́ме а҆арѡ́нь, бл҃гослови́те гдⷭ҇а: до́ме леѵі́инъ, бл҃гослови́те гдⷭ҇а: Боѧ́щїисѧ гдⷭ҇а, бл҃гослови́те гдⷭ҇а. Бл҃гослове́нъ гдⷭ҇ь ѿ сїѡ́на, живы́й во і҆ерⷭ҇ли́мѣ.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 135,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 1,
  ["текст_ру"] = "Испове́дайтеся Го́сподеви, я́ко благ, я́ко в век ми́лость Его́. Испове́дайтеся Бо́гу бого́в, я́ко в век ми́лость Его́. Испове́дайтеся Го́сподеви господе́й, я́ко в век ми́лость Его́. Сотво́ршему чудеса́ ве́лия еди́ному, я́ко в век ми́лость Его́. Сотво́ршему небеса́ ра́зумом, я́ко в век ми́лость Его́. Утверди́вшему зе́млю на вода́х, я́ко в век ми́лость Его́. Сотво́ршему свети́ла ве́лия еди́ному, я́ко в век ми́лость Его́. Со́лнце во о́бласть дне, я́ко в век ми́лость Его́. Луну́ и зве́зды во о́бласть но́щи, я́ко в век ми́лость Его́. Порази́вшему Еги́пта с пе́рвенцы eго́, я́ко в век ми́лость Его́, и изве́дшему Изра́иля от среды́ их, я́ко в век ми́лость Его́. Руко́ю кре́пкою и мы́шцею высо́кою, я́ко в век ми́лость Его́. Разде́льшему Чермно́е мо́ре в разделе́ния, я́ко в век ми́лость Его́. И прове́дшему Изра́иля посреде́ eго́, я́ко в век ми́лость Его́. И истря́сшему фарао́на и си́лу eго́ в мо́ре Чермно́е, я́ко в век ми́лость Его́. Прове́дшему лю́ди Своя́ в пусты́ни, я́ко в век ми́лость Его́. Порази́вшему цари́ ве́лия, я́ко в век ми́лость Его́, и уби́вшему цари́ кре́пкия, я́ко в век ми́лость Его́: Сио́на, царя́ Аморре́йска, я́ко в век ми́лость Его́, и Ога, царя́ Васа́нска, я́ко в век ми́лость Его́. И да́вшему зе́млю их достоя́ние, я́ко в век ми́лость Его́. Достоя́ние Изра́илю, рабу́ Своему́, я́ко в век ми́лость Его́. Я́ко во смире́нии на́шем помяну́ ны Госпо́дь, я́ко в век ми́лость Его́. И изба́вил ны есть от враго́в на́ших, я́ко в век ми́лость Его́. Дая́й пи́щу вся́кой пло́ти, я́ко в век ми́лость Его́. Испове́дайтеся Бо́гу небе́сному, я́ко в век ми́лость Его́.",
  ["текст_цс"] = "И҆сповѣ́дайтесѧ гдⷭ҇еви, ꙗ҆́кѡ бл҃гъ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. И҆сповѣ́дайтесѧ бг҃ꙋ богѡ́въ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. И҆сповѣ́дайтесѧ гдⷭ҇еви господе́й: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Сотво́ршемꙋ чꙋдеса̀ вє́лїѧ є҆ди́номꙋ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Сотво́ршемꙋ небеса̀ ра́зꙋмомъ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Оу҆тверди́вшемꙋ зе́млю на вода́хъ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Сотво́ршемꙋ свѣти̑ла вє́лїѧ є҆ди́номꙋ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: Со́лнце во ѻ҆́бласть днѐ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: Лꙋнꙋ̀ и҆ ѕвѣ́зды во ѻ҆́бласть но́щи: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Порази́вшемꙋ є҆гѵ́пта съ пе́рвенцы є҆гѡ̀: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: И҆ и҆зве́дшемꙋ і҆и҃лѧ ѿ среды̀ и҆́хъ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: Рꙋко́ю крѣ́пкою и҆ мы́шцею высо́кою: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Раздѣ́льшемꙋ чермно́е мо́ре въ раздѣлє́нїѧ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: И҆ прове́дшемꙋ і҆и҃лѧ посредѣ̀ є҆гѡ̀: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: И҆ и҆стрѧ́сшемꙋ фараѡ́на и҆ си́лꙋ є҆гѡ̀ въ мо́ре чермно́е: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Прове́дшемꙋ лю́ди своѧ̑ въ пꙋсты́ни: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Порази́вшемꙋ царѝ вє́лїѧ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. И҆ ᲂу҆би́вшемꙋ царѝ крѣ̑пкїѧ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: Сиѡ́на царѧ̀ а҆морре́йска: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: И҆ ѡ҆́га царѧ̀ васа́нска: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. И҆ да́вшемꙋ зе́млю и҆́хъ достоѧ́нїе: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: Достоѧ́нїе і҆и҃лю рабꙋ̀ своемꙋ̀: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. Ꙗ҆́кѡ во смире́нїи на́шемъ помѧнꙋ́ ны гдⷭ҇ь: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. И҆ и҆зба́вилъ ны̀ є҆́сть ѿ врагѡ́въ на́шихъ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀: Даѧ́й пи́щꙋ всѧ́кой пло́ти: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀. И҆сповѣ́дайтесѧ бг҃ꙋ нбⷭ҇номꙋ: ꙗ҆́кѡ въ вѣ́къ млⷭ҇ть є҆гѡ̀.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 136,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 1,
  ["текст_ру"] = "На река́х Вавило́нских, та́мо седо́хом и пла́кахом, внегда́ помяну́ти нам Сио́на. На ве́рбиих посреде́ eго́ обе́сихом орга́ны на́ша. Я́ко та́мо вопроси́ша ны пле́ншии нас о словесе́х пе́сней и ве́дшии нас о пе́нии: воспо́йте нам от пе́сней Сио́нских. Ка́ко воспое́м песнь Госпо́дню на земли́ чужде́й? А́ще забу́ду тебе́, Иерусали́ме, забве́на бу́ди десни́ца моя́. Прильпни́ язы́к мой горта́ни моему́, а́ще не помяну́ тебе́, а́ще не предложу́ Иерусали́ма, я́ко в нача́ле весе́лия моего́. Помяни́, Го́споди, сы́ны Едо́мския, в день Иерусали́мль глаго́лющыя: истоща́йте, истоща́йте до основа́ний eго́. Дщи Вавило́ня окая́нная, блаже́н и́же возда́ст тебе́ воздая́ние твое́, е́же воздала́ еси́ нам. Блаже́н и́же и́мет и разбие́т младе́нцы твоя́ о ка́мень.",
  ["текст_цс"] = "На рѣка́хъ вавѷлѡ́нскихъ, та́мѡ сѣдо́хомъ и҆ пла́кахомъ, внегда̀ помѧнꙋ́ти на́мъ сїѡ́на: На ве́рбїихъ посредѣ̀ є҆гѡ̀ ѡ҆бѣ́сихомъ ѻ҆рга́ны на́шѧ. Ꙗ҆́кѡ та́мѡ вопроси́ша ны̀ плѣ́ншїи на́съ ѡ҆ словесѣ́хъ пѣ́сней, и҆ ве́дшїи на́съ ѡ҆ пѣ́нїи: воспо́йте на́мъ ѿ пѣ́сней сїѡ́нскихъ. Ка́кѡ воспое́мъ пѣ́снь гдⷭ҇ню на землѝ чꙋжде́й; А҆́ще забꙋ́дꙋ тебѐ, і҆ерⷭ҇ли́ме, забве́на бꙋ́ди десни́ца моѧ̀. Прильпнѝ ѧ҆зы́къ мо́й горта́ни моемꙋ̀, а҆́ще не помѧнꙋ̀ тебє̀, а҆́ще не предложꙋ̀ і҆ерⷭ҇ли́ма, ꙗ҆́кѡ въ нача́лѣ весе́лїѧ моегѡ̀. Помѧнѝ, гдⷭ҇и, сы́ны є҆дѡ̑мскїѧ въ де́нь і҆ерⷭ҇ли́мль глаго́лющыѧ: и҆стоща́йте, и҆стоща́йте до ѡ҆снова́нїй є҆гѡ̀. Дщѝ вавѷлѡ́нѧ ѡ҆каѧ́ннаѧ, бл҃же́нъ, и҆́же возда́стъ тебѣ̀ воздаѧ́нїе твоѐ, є҆́же воздала̀ є҆сѝ на́мъ: Бл҃же́нъ, и҆́же и҆́метъ и҆ разбїе́тъ младе́нцы твоѧ̑ ѡ҆ ка́мень.",
  ["заголовок_ру"] = "Дави́ду Иереми́ем.",
  ["заголовок_цс"] = "Дв҃дꙋ і҆еремі́емъ."
}

add_psalom {
  ["номер"] = 137,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 2,
  ["текст_ру"] = "Испове́мся Тебе́, Го́споди, всем се́рдцем мои́м, и пред А́нгелы воспою́ Тебе́, я́ко услы́шал еси́ вся глаго́лы уст мои́х. Поклоню́ся ко хра́му свято́му Твоему́ и испове́мся и́мени Твоему́ о ми́лости Твое́й и и́стине Твое́й, я́ко возвели́чил еси́ над всем и́мя Твое́ свято́е. Во́ньже а́ще день призову́ Тя, ско́ро услы́ши мя: умно́жиши мя в души́ мое́й си́лою Твое́ю. Да испове́дятся Тебе́, Го́споди, вси ца́рие зе́мстии, я́ко услы́шаша вся глаго́лы уст Твои́х, и да воспою́т в путе́х Госпо́дних, я́ко ве́лия сла́ва Госпо́дня, я́ко высо́к Госпо́дь, и смире́нныя призира́ет, и высо́кая издале́ча весть. А́ще пойду́ посреде́ ско́рби, живи́ши мя, на гнев враг мои́х просте́рл еси́ руку́ Твою́, и спасе́ мя десни́ца Твоя́. Госпо́дь возда́ст за мя. Го́споди, ми́лость Твоя́ во век, дел руку́ Твое́ю не пре́зри.",
  ["текст_цс"] = "И҆сповѣ́мсѧ тебѣ̀, гдⷭ҇и, всѣ́мъ се́рдцемъ мои́мъ, и҆ пред̾ а҆́гг҃лы воспою̀ тебѣ̀, ꙗ҆́кѡ ᲂу҆слы́шалъ є҆сѝ всѧ̑ глаго́лы ᲂу҆́стъ мои́хъ: Поклоню́сѧ ко хра́мꙋ ст҃о́мꙋ твоемꙋ̀ и҆ и҆сповѣ́мсѧ и҆́мени твоемꙋ̀ ѡ҆ млⷭ҇ти твое́й и҆ и҆́стинѣ твое́й, ꙗ҆́кѡ возвели́чилъ є҆сѝ над̾ всѣ́мъ и҆́мѧ твоѐ ст҃о́е. Во́ньже а҆́ще де́нь призовꙋ́ тѧ, ско́рѡ ᲂу҆слы́ши мѧ̀: ᲂу҆мно́жиши мѧ̀ въ дꙋшѝ мое́й си́лою твое́ю. Да и҆сповѣ́дѧтсѧ тебѣ̀, гдⷭ҇и, всѝ ца́рїе зе́мстїи, ꙗ҆́кѡ ᲂу҆слы́шаша всѧ̑ глаго́лы ᲂу҆́стъ твои́хъ: И҆ да воспою́тъ въ пꙋте́хъ гдⷭ҇нихъ, ꙗ҆́кѡ ве́лїѧ сла́ва гдⷭ҇нѧ: Ꙗ҆́кѡ высо́къ гдⷭ҇ь, и҆ смирє́нныѧ призира́етъ, и҆ высѡ́каѧ и҆здале́ча вѣ́сть. А҆́ще пойдꙋ̀ посредѣ̀ ско́рби, живи́ши мѧ̀: на гнѣ́въ вра̑гъ мои́хъ просте́рлъ є҆сѝ рꙋ́кꙋ твою̀, и҆ сп҃се́ мѧ десни́ца твоѧ̀. Гдⷭ҇ь возда́стъ за мѧ̀: гдⷭ҇и, млⷭ҇ть твоѧ̀ во вѣ́къ: дѣ́лъ рꙋкꙋ̀ твоє́ю не пре́зри.",
  ["заголовок_ру"] = "Псало́м Дави́ду, Агге́а и Заха́рии.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ, а҆гге́а и҆ заха́рїи."
}

add_psalom {
  ["номер"] = 138,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 2,
  ["текст_ру"] = "Го́споди, искуси́л мя еси́ и позна́л мя еси́. Ты позна́л еси́ седа́ние мое́ и воста́ние мое́. Ты разуме́л еси́ помышле́ния моя́ издале́ча: стезю́ мою́ и у́же мое́ Ты еси́ изсле́довал, и вся пути́ моя́ прови́дел еси́. Я́ко несть льсти в язы́це мое́м: се, Го́споди, Ты позна́л еси́. Вся после́дняя и дре́вняя: Ты созда́л еси́ мя, и положи́л еси́ на мне ру́ку Твою́. Удиви́ся ра́зум Твой от мене́, утверди́ся, не возмогу́ к нему́. Ка́мо пойду́ от Ду́ха Твоего́? И от лица́ Твоего́ ка́мо бежу́? А́ще взы́ду на не́бо – Ты та́мо еси́, а́ще сни́ду во ад – та́мо еси́. А́ще возму́ криле́ мои́ ра́но и вселю́ся в после́дних мо́ря – и та́мо бо рука́ Твоя́ наста́вит мя и удержи́т мя десни́ца Твоя́. И рех: еда́ тма попере́т мя, и нощь просвеще́ние в сла́дости мое́й? Я́ко тма не помрачи́тся от Тебе́, и нощь, я́ко день, просвети́тся, я́ко тма ея́, та́ко и свет ея́. Я́ко Ты созда́л еси́ утро́бы моя́, восприя́л мя еси́ из чре́ва ма́тере моея́. Испове́мся Тебе́, я́ко стра́шно удиви́лся еси́: чу́дна дела́ Твоя́, и душа́ моя́ зна́ет зело́. Не утаи́ся кость моя́ от Тебе́, ю́же сотвори́л еси́ в та́йне, и соста́в мой в преиспо́дних земли́. Несоде́ланное мое́ ви́десте о́чи Твои́, и в кни́зе Твое́й вси напи́шутся, во днех сози́ждутся и никто́же в них. Мне же зело́ че́стни бы́ша дру́зи Твои́, Бо́же, зело́ утверди́шася влады́чествия их. Изочту́ их, и па́че песка́ умно́жатся; воста́х, и еще́ есмь с Тобо́ю. А́ще избие́ши гре́шники, Бо́же, му́жие крове́й, уклони́теся от мене́. Я́ко ревни́ви есте́ в помышле́ниих, прии́мут в суету́ гра́ды Твоя́. Не ненави́дящыя ли Тя, Го́споди, возненави́дех, и о вразе́х Твои́х иста́ях? Соверше́нною не́навистию возненави́дех я́, во враги́ бы́ша ми. Искуси́ мя, Бо́же, и уве́ждь се́рдце мое́, истяжи́ мя и разуме́й стези́ моя́, и виждь, а́ще путь беззако́ния во мне, и наста́ви мя на путь ве́чен.",
  ["текст_цс"] = "Гдⷭ҇и, и҆скꙋси́лъ мѧ̀ є҆сѝ и҆ позна́лъ мѧ̀ є҆сѝ: ты̀ позна́лъ є҆сѝ сѣда́нїе моѐ и҆ воста́нїе моѐ. Ты̀ разꙋмѣ́лъ є҆сѝ помышлє́нїѧ моѧ̑ и҆здале́ча: Стезю̀ мою̀ и҆ ᲂу҆́же моѐ ты̀ є҆сѝ и҆зслѣ́довалъ и҆ всѧ̑ пꙋти̑ моѧ̑ прови́дѣлъ є҆сѝ. Ꙗ҆́кѡ нѣ́сть льстѝ въ ѧ҆зы́цѣ мое́мъ: сѐ, гдⷭ҇и, ты̀ позна́лъ є҆сѝ Всѧ̑ послѣ̑днѧѧ и҆ дрє́внѧѧ: ты̀ созда́лъ є҆сѝ мѧ̀ и҆ положи́лъ є҆сѝ на мнѣ̀ рꙋ́кꙋ твою̀. Оу҆диви́сѧ ра́зꙋмъ тво́й ѿ менѐ, ᲂу҆тверди́сѧ, не возмогꙋ̀ къ немꙋ̀. Ка́мѡ пойдꙋ̀ ѿ дх҃а твоегѡ̀; и҆ ѿ лица̀ твоегѡ̀ ка́мѡ бѣжꙋ̀; А҆́ще взы́дꙋ на нб҃о, ты̀ та́мѡ є҆сѝ: а҆́ще сни́дꙋ во а҆́дъ, та́мѡ є҆сѝ. А҆́ще возмꙋ̀ крилѣ̑ моѝ ра́нѡ и҆ вселю́сѧ въ послѣ́днихъ мо́рѧ, И҆ та́мѡ бо рꙋка̀ твоѧ̀ наста́витъ мѧ̀, и҆ ᲂу҆держи́тъ мѧ̀ десни́ца твоѧ̀. И҆ рѣ́хъ: є҆да̀ тма̀ попере́тъ мѧ̀; и҆ но́щь просвѣще́нїе въ сла́дости мое́й. Ꙗ҆́кѡ тма̀ не помрачи́тсѧ ѿ тебє̀, и҆ но́щь ꙗ҆́кѡ де́нь просвѣти́тсѧ: ꙗ҆́кѡ тма̀ є҆ѧ̀, та́кѡ и҆ свѣ́тъ є҆ѧ̀. Ꙗ҆́кѡ ты̀ созда́лъ є҆сѝ ᲂу҆трѡ́бы моѧ̑, воспрїѧ́лъ мѧ̀ є҆сѝ и҆з̾ чре́ва ма́тере моеѧ̀. И҆сповѣ́мсѧ тебѣ̀, ꙗ҆́кѡ стра́шнѡ ᲂу҆диви́лсѧ є҆сѝ: чꙋ̑дна дѣла̀ твоѧ̑, и҆ дꙋша̀ моѧ̀ зна́етъ ѕѣлѡ̀. Не ᲂу҆таи́сѧ ко́сть моѧ̀ ѿ тебє̀, ю҆́же сотвори́лъ є҆сѝ въ та́йнѣ, и҆ соста́въ мо́й въ преиспо́днихъ землѝ. Несодѣ́ланное моѐ ви́дѣстѣ ѻ҆́чи твоѝ, и҆ въ кни́зѣ твое́й всѝ напи́шꙋтсѧ: во дне́хъ сози́ждꙋтсѧ, и҆ никто́же въ ни́хъ. Мнѣ́ же ѕѣлѡ̀ че́стни бы́ша дрꙋ́зи твоѝ, бж҃е, ѕѣлѡ̀ ᲂу҆тверди́шасѧ влады́чєствїѧ и҆́хъ: И҆зочтꙋ̀ и҆̀хъ, и҆ па́че песка̀ ᲂу҆мно́жатсѧ: воста́хъ, и҆ є҆щѐ є҆́смь съ тобо́ю. А҆́ще и҆збїе́ши грѣ́шники, бж҃е: мꙋ́жїе крове́й, ᲂу҆клони́тесѧ ѿ менѐ. Ꙗ҆́кѡ ревни́ви є҆стѐ въ помышле́нїихъ, прїи́мꙋтъ въ сꙋетꙋ̀ гра́ды твоѧ̑. Не ненави́дѧщыѧ ли тѧ̀, гдⷭ҇и, возненави́дѣхъ, и҆ ѡ҆ вразѣ́хъ твои́хъ и҆ста́ѧхъ; Соверше́нною не́навистїю возненави́дѣхъ ѧ҆̀: во врагѝ бы́ша мѝ. И҆скꙋси́ мѧ, бж҃е, и҆ ᲂу҆вѣ́ждь се́рдце моѐ: и҆стѧжи́ мѧ и҆ разꙋмѣ́й стєзѝ моѧ̑: И҆ ви́ждь, а҆́ще пꙋ́ть беззако́нїѧ во мнѣ̀, и҆ наста́ви мѧ̀ на пꙋ́ть вѣ́ченъ.",
  ["заголовок_ру"] = "В коне́ц Дави́ду, псало́м Заха́риин в разсе́янии.",
  ["заголовок_цс"] = "Въ коне́цъ дв҃дꙋ, ѱало́мъ заха́рїинъ, въ разсѣ́ѧнїи."
}

add_psalom {
  ["номер"] = 139,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 2,
  ["текст_ру"] = "Изми́ мя, Го́споди, от челове́ка лука́ва, от му́жа непра́ведна изба́ви мя, и́же помы́слиша непра́вду в се́рдце, весь день ополча́ху бра́ни, изостри́ша язы́к свой, я́ко змии́н, яд а́спидов под устна́ми их. Сохрани́ мя, Го́споди, из руки́ гре́шничи, от челове́к непра́ведных изми́ мя, и́же помы́слиша запя́ти стопы́ моя́. Скры́ша го́рдии сеть мне, и у́жы препя́ша сеть нога́ма мои́ма. При стези́ собла́зны положи́ша ми. Рех Го́сподеви: Бог мой еси́ Ты, внуши́, Го́споди, глас моле́ния моего́. Го́споди, Го́споди, си́ло спасе́ния моего́, осени́л еси́ над главо́ю мое́ю в день бра́ни. Не преда́ждь мене́, Го́споди, от жела́ния моего́ гре́шнику: помы́слиша на мя, не оста́ви мене́, да не когда́ вознесу́тся. Глава́ окруже́ния их, труд усте́н их покры́ет я́. Паду́т на них у́глия о́гненная, низложи́ши я́ в страсте́х, и не постоя́т. Муж язы́чен не испра́вится на земли́: му́жа непра́ведна зла́я уловя́т во истле́ние. Позна́х, я́ко сотвори́т Госпо́дь суд ни́щым и месть убо́гим. Оба́че пра́веднии испове́дятся и́мени Твоему́, и вселя́тся пра́вии с лице́м Твои́м.",
  ["текст_цс"] = "И҆зми́ мѧ, гдⷭ҇и, ѿ человѣ́ка лꙋка́ва, ѿ мꙋ́жа непра́ведна и҆зба́ви мѧ̀: И҆̀же помы́слиша непра́вдꙋ въ се́рдцы, ве́сь де́нь ѡ҆полча́хꙋ бра̑ни: И҆з̾ѡстри́ша ѧ҆зы́къ сво́й ꙗ҆́кѡ ѕмїи́нъ: ꙗ҆́дъ а҆́спїдовъ под̾ ᲂу҆стна́ми и҆́хъ. Сохрани́ мѧ, гдⷭ҇и, и҆з̾ рꙋкѝ грѣ́шничи, ѿ человѣ̑къ непра́ведныхъ и҆зми́ мѧ, и҆̀же помы́слиша запѧ́ти стѡпы̀ моѧ̑. Скры́ша го́рдїи сѣ́ть мнѣ̀ и҆ ᲂу҆́жы, препѧ́ша сѣ́ть нога́ма мои́ма: При стезѝ собла́зны положи́ша мѝ. Рѣ́хъ гдⷭ҇еви: бг҃ъ мо́й є҆сѝ ты̀, внꙋшѝ, гдⷭ҇и, гла́съ моле́нїѧ моегѡ̀. Гдⷭ҇и, гдⷭ҇и, си́ло сп҃се́нїѧ моегѡ̀, ѡ҆сѣни́лъ є҆сѝ над̾ главо́ю мое́ю въ де́нь бра́ни. Не преда́ждь менѐ, гдⷭ҇и, ѿ жела́нїѧ моегѡ̀ грѣ́шникꙋ: помы́слиша на мѧ̀, не ѡ҆ста́ви менѐ, да не когда̀ вознесꙋ́тсѧ. Глава̀ ѡ҆крꙋже́нїѧ и҆́хъ, трꙋ́дъ ᲂу҆сте́нъ и҆́хъ покры́етъ ѧ҆̀. Падꙋ́тъ на ни́хъ ᲂу҆́глїѧ ѻ҆́гнєннаѧ, низложи́ши ѧ҆̀ во страсте́хъ, и҆ не постоѧ́тъ. Мꙋ́жъ ѧ҆зы́ченъ не и҆спра́витсѧ на землѝ: мꙋ́жа непра́ведна ѕла̑ѧ ᲂу҆ловѧ́тъ во и҆стлѣ́нїе. Позна́хъ, ꙗ҆́кѡ сотвори́тъ гдⷭ҇ь сꙋ́дъ ни́щымъ и҆ ме́сть ᲂу҆бѡ́гимъ. Ѻ҆ба́че првⷣнїи и҆сповѣ́дѧтсѧ и҆́мени твоемꙋ̀, и҆ вселѧ́тсѧ пра́вїи съ лице́мъ твои́мъ.",
  ["заголовок_ру"] = "В коне́ц, псало́м Дави́ду.",
  ["заголовок_цс"] = "Въ коне́цъ, ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 140,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 3,
  ["текст_ру"] = "Го́споди, воззва́х к Тебе́, услы́ши мя: вонми́ гла́су моле́ния моего́, внегда́ воззва́ти ми к Тебе́. Да испра́вится моли́тва моя́, я́ко кади́ло пред Тобо́ю, воздея́ние руку́ мое́ю – же́ртва вече́рняя. Положи́, Го́споди, хране́ние усто́м мои́м, и дверь огражде́ния о устна́х мои́х. Не уклони́ се́рдце мое́ в словеса́ лука́вствия, непщева́ти вины́ о гресе́х, с челове́ки де́лающими беззако́ние, и не сочту́ся со избра́нными их. Нака́жет мя пра́ведник ми́лостию и обличи́т мя, еле́й же гре́шнаго да не нама́стит главы́ моея́, я́ко еще́ и моли́тва моя́ во благоволе́ниих их. Поже́рты бы́ша при ка́мени судии́ их: услы́шатся глаго́ли мои́, я́ко возмого́ша. Я́ко то́лща земли́ просе́деся на земли́, расточи́шася ко́сти их при а́де. Я́ко к Тебе́, Го́споди, Го́споди, о́чи мои́: на Тя упова́х, не отыми́ ду́шу мою́. Сохрани́ мя от се́ти, ю́же соста́виша ми, и от собла́зн де́лающих беззако́ние. Паду́т во мре́жу свою́ гре́шницы: еди́н есмь аз, до́ндеже прейду́.",
  ["текст_цс"] = "Гдⷭ҇и, воззва́хъ къ тебѣ̀, ᲂу҆слы́ши мѧ̀: вонмѝ гла́сꙋ моле́нїѧ моегѡ̀, внегда̀ воззва́ти мѝ къ тебѣ̀. Да и҆спра́витсѧ моли́тва моѧ̀ ꙗ҆́кѡ кади́ло пред̾ тобо́ю: воздѣѧ́нїе рꙋкꙋ̀ моє́ю, же́ртва вече́рнѧѧ. Положѝ, гдⷭ҇и, хране́нїе ᲂу҆стѡ́мъ мои̑мъ и҆ две́рь ѡ҆гражде́нїѧ ѡ҆ ᲂу҆стна́хъ мои́хъ. Не ᲂу҆клонѝ се́рдце моѐ въ словеса̀ лꙋка́вствїѧ, непщева́ти вины̀ ѡ҆ грѣсѣ́хъ съ человѣ́ки дѣ́лающими беззако́нїе: и҆ не сочтꙋ́сѧ со и҆збра́нными и҆́хъ. Нака́жетъ мѧ̀ првⷣникъ ми́лостїю и҆ ѡ҆бличи́тъ мѧ̀, є҆ле́й же грѣ́шнагѡ да не нама́ститъ главы̀ моеѧ̀: ꙗ҆́кѡ є҆щѐ и҆ моли́тва моѧ̀ во бл҃говоле́нїихъ и҆́хъ. Пожє́рты бы́ша при ка́мени сꙋдїи̑ и҆́хъ: ᲂу҆слы́шатсѧ глаго́ли моѝ, ꙗ҆́кѡ возмого́ша. Ꙗ҆́кѡ то́лща землѝ просѣ́десѧ на землѝ, расточи́шасѧ кѡ́сти и҆́хъ при а҆́дѣ. Ꙗ҆́кѡ къ тебѣ̀, гдⷭ҇и, гдⷭ҇и, ѻ҆́чи моѝ: на тѧ̀ ᲂу҆пова́хъ, не ѿимѝ дꙋ́шꙋ мою̀: Сохрани́ мѧ ѿ сѣ́ти, ю҆́же соста́виша мѝ, и҆ ѿ собла̑знъ дѣ́лающихъ беззако́нїе. Падꙋ́тъ во мре́жꙋ свою̀ грѣ̑шницы: є҆ди́нъ є҆́смь а҆́зъ, до́ндеже прейдꙋ̀.",
  ["заголовок_ру"] = "Псало́м Дави́ду.",
  ["заголовок_цс"] = "Ѱало́мъ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 141,
  ["часть"] = 1,
  ["кафизма"] = 19,
  ["слава"] = 3,
  ["текст_ру"] = "Гла́сом мои́м ко Го́споду воззва́х, гла́сом мои́м ко Го́споду помоли́хся. Пролию́ пред Ним моле́ние мое́, печа́ль мою́ пред Ним возвещу́. Внегда́ исчеза́ти от мене́ ду́ху моему́: и Ты позна́л еси́ стези́ моя́: на пути́ сем, по нему́же хожда́х, скры́ша сеть мне. Смотря́х одесну́ю и возгля́дах, и не бе зна́яй мене́: поги́бе бе́гство от мене́, и несть взыска́яй ду́шу мою́. Воззва́х к Тебе́, Го́споди, рех: Ты еси́ упова́ние мое́, часть моя́ еси́ на земли́ живы́х. Вонми́ моле́нию моему́, я́ко смири́хся зело́, изба́ви мя от гоня́щих мя, я́ко укрепи́шася па́че мене́. Изведи́ из темни́цы ду́шу мою́, испове́датися и́мени Твоему́. Мене́ ждут пра́ведницы, до́ндеже возда́си мне.",
  ["текст_цс"] = "Гла́сомъ мои́мъ ко гдⷭ҇ꙋ воззва́хъ, гла́сомъ мои́мъ ко гдⷭ҇ꙋ помоли́хсѧ. Пролїю̀ пред̾ ни́мъ моле́нїе моѐ, печа́ль мою̀ пред̾ ни́мъ возвѣщꙋ̀. Внегда̀ и҆счеза́ти ѿ менѐ дꙋ́хꙋ моемꙋ̀, и҆ ты̀ позна́лъ є҆сѝ стєзѝ моѧ̑: на пꙋтѝ се́мъ, по немꙋ́же хожда́хъ, скры́ша сѣ́ть мнѣ̀. Сматрѧ́хъ ѡ҆деснꙋ́ю и҆ возглѧ́дахъ, и҆ не бѣ̀ зна́ѧй менѐ: поги́бе бѣ́гство ѿ менѐ, и҆ нѣ́сть взыска́ѧй дꙋ́шꙋ мою̀. Воззва́хъ къ тебѣ̀, гдⷭ҇и, рѣ́хъ: ты̀ є҆сѝ ᲂу҆пова́нїе моѐ, ча́сть моѧ̀ є҆сѝ на землѝ живы́хъ. Вонмѝ моле́нїю моемꙋ̀, ꙗ҆́кѡ смири́хсѧ ѕѣлѡ̀: и҆зба́ви мѧ̀ ѿ гонѧ́щихъ мѧ̀, ꙗ҆́кѡ ᲂу҆крѣпи́шасѧ па́че менѐ. И҆зведѝ и҆з̾ темни́цы дꙋ́шꙋ мою̀, и҆сповѣ́датисѧ и҆́мени твоемꙋ̀: менѐ ждꙋ́тъ првⷣницы, до́ндеже возда́си мнѣ̀.",
  ["заголовок_ру"] = "Ра́зума Дави́ду, внегда́ бы́ти ему́ в ве́ртпе моля́щемуся.",
  ["заголовок_цс"] = "Ра́зꙋма дв҃дꙋ, внегда̀ бы́ти є҆мꙋ̀ въ верте́пѣ молѧ́щемꙋсѧ."
}

