}

add_psalom {
  ["номер"] = 144,
  ["часть"] = 1,
  ["кафизма"] = 20,
  ["слава"] = 1,
  ["текст_ру"] = "Вознесу́ Тя, Бо́же мой, Царю́ мой, и благословлю́ и́мя Твое́ в век и в век ве́ка. На всяк день благословлю́ Тя и восхвалю́ и́мя Твое́ в век и в век ве́ка. Ве́лий Госпо́дь и хва́лен зело́, и вели́чию Его́ несть конца́. Род и род восхва́лят дела́ Твоя́ и си́лу Твою́ возвестя́т. Великоле́пие сла́вы святы́ни Твоея́ возглаго́лют и чудеса́ Твоя́ пове́дят. И си́лу стра́шных Твои́х реку́т и вели́чие Твое́ пове́дят. Па́мять мно́жества бла́гости Твоея́ отры́гнут и пра́вдою Твое́ю возра́дуются. Щедр и ми́лостив Госпо́дь, Долготерпели́в и Многоми́лостив. Благ Госпо́дь вся́ческим, и щедро́ты Его́ на всех де́лех Его́. Да испове́дятся Тебе́, Го́споди, вся дела́ Твоя́, и преподо́бнии Твои́ да благословя́т Тя. Сла́ву Ца́рствия Твоего́ реку́т, и силу Твою́ возглаго́лют, сказа́ти сыново́м челове́ческим си́лу Твою́, и сла́ву великоле́пия Ца́рствия Твоего́. Ца́рство Твое́, Ца́рство всех веко́в, и влады́чество Твое́ во вся́ком ро́де и ро́де. Ве́рен Госпо́дь во всех словесе́х Свои́х и преподо́бен во всех де́лех Свои́х. Утвержда́ет Госпо́дь вся низпа́дающыя и возставля́ет вся низве́рженныя. О́чи всех на Тя упова́ют, и Ты дае́ши им пи́щу во благовре́мении. Отверза́еши Ты ру́ку Твою́ и исполня́еши вся́кое живо́тно благоволе́ния. Пра́веден Госпо́дь во всех путе́х Свои́х и преподо́бен во всех де́лех Свои́х. Близ Госпо́дь всем призыва́ющым Его́, всем призыва́ющым Его́ во и́стине. Во́лю боя́щихся Его́ сотвори́т и моли́тву их услы́шит и спасе́т я́. Храни́т Госпо́дь вся лю́бящыя Его́ и вся гре́шники потреби́т. Хвалу́ Госпо́дню возглаго́лют уста́ моя́, и да благослови́т вся́ка плоть и́мя свято́е Его́ в век и в век ве́ка.",
  ["текст_цс"] = "Вознесꙋ́ тѧ, бж҃е мо́й, цр҃ю̀ мо́й, и҆ бл҃гословлю̀ и҆́мѧ твоѐ въ вѣ́къ и҆ въ вѣ́къ вѣ́ка. На всѧ́къ де́нь бл҃гословлю́ тѧ, и҆ восхвалю̀ и҆́мѧ твоѐ въ вѣ́къ и҆ въ вѣ́къ вѣ́ка. Ве́лїй гдⷭ҇ь и҆ хва́ленъ ѕѣлѡ̀, и҆ вели́чїю є҆гѡ̀ нѣ́сть конца̀. Ро́дъ и҆ ро́дъ восхва́лѧтъ дѣла̀ твоѧ̑ и҆ си́лꙋ твою̀ возвѣстѧ́тъ: Великолѣ́пїе сла́вы ст҃ы́ни твоеѧ̀ возглаго́лютъ и҆ чꙋдеса̀ твоѧ̑ повѣ́дѧтъ: И҆ си́лꙋ стра́шныхъ твои́хъ рекꙋ́тъ и҆ вели́чїе твоѐ повѣ́дѧтъ: Па́мѧть мно́жества бл҃гости твоеѧ̀ ѿры́гнꙋтъ и҆ пра́вдою твое́ю возра́дꙋютсѧ. Ще́дръ и҆ млⷭ҇тивъ гдⷭ҇ь, долготерпѣли́въ и҆ многомлⷭ҇тивъ. Бл҃гъ гдⷭ҇ь всѧ́чєскимъ, и҆ щедрѡ́ты є҆гѡ̀ на всѣ́хъ дѣ́лѣхъ є҆гѡ̀. Да и҆сповѣ́дѧтсѧ тебѣ̀, гдⷭ҇и, всѧ̑ дѣла̀ твоѧ̑, и҆ прпⷣбнїи твоѝ да бл҃гословѧ́тъ тѧ̀: Сла́вꙋ црⷭ҇твїѧ твоегѡ̀ рекꙋ́тъ и҆ си́лꙋ твою̀ возглаго́лютъ, Сказа́ти сыновѡ́мъ человѣ́чєскимъ си́лꙋ твою̀ и҆ сла́вꙋ великолѣ́пїѧ црⷭ҇твїѧ твоегѡ̀. Црⷭ҇тво твоѐ црⷭ҇тво всѣ́хъ вѣкѡ́въ, и҆ влⷣчество твоѐ во всѧ́комъ ро́дѣ и҆ ро́дѣ. Вѣ́ренъ гдⷭ҇ь во всѣ́хъ словесѣ́хъ свои́хъ и҆ прпⷣбенъ во всѣ́хъ дѣ́лѣхъ свои́хъ. Оу҆твержда́етъ гдⷭ҇ь всѧ̑ низпа́дающыѧ и҆ возставлѧ́етъ всѧ̑ низве́ржєнныѧ. Ѻ҆́чи всѣ́хъ на тѧ̀ ᲂу҆пова́ютъ, и҆ ты̀ дае́ши и҆̀мъ пи́щꙋ во бл҃говре́менїи: Ѿверза́еши ты̀ рꙋ́кꙋ твою̀ и҆ и҆сполнѧ́еши всѧ́кое живо́тно бл҃говоле́нїѧ. Првⷣнъ гдⷭ҇ь во всѣ́хъ пꙋте́хъ свои́хъ и҆ прпⷣбенъ во всѣ́хъ дѣ́лѣхъ свои́хъ. Бли́з̾ гдⷭ҇ь всѣ̑мъ призыва́ющымъ є҆го̀, всѣ̑мъ призыва́ющымъ є҆го̀ во и҆́стинѣ: Во́лю боѧ́щихсѧ є҆гѡ̀ сотвори́тъ, и҆ моли́твꙋ и҆́хъ ᲂу҆слы́шитъ, и҆ сп҃се́тъ ѧ҆̀. Храни́тъ гдⷭ҇ь всѧ̑ лю́бѧщыѧ є҆го̀, и҆ всѧ̑ грѣ́шники потреби́тъ. Хвалꙋ̀ гдⷭ҇ню возглаго́лютъ ᲂу҆ста̀ моѧ̑: и҆ да бл҃гослови́тъ всѧ́ка пло́ть и҆́мѧ ст҃о́е є҆гѡ̀ въ вѣ́къ и҆ въ вѣ́къ вѣ́ка.",
  ["заголовок_ру"] = "Хвала́ Дави́ду.",
  ["заголовок_цс"] = "Хвала̀ дв҃дꙋ."
}

add_psalom {
  ["номер"] = 145,
  ["часть"] = 1,
  ["кафизма"] = 20,
  ["слава"] = 2,
  ["текст_ру"] = "Хвали́, душе́ моя́, Го́спода. Восхвалю́ Го́спода в животе́ мое́м, пою́ Бо́гу моему́, до́ндеже есмь. Не наде́йтеся на кня́зи, на сы́ны челове́ческия, в ни́хже несть спасе́ния. Изы́дет дух eго́ и возврати́тся в зе́млю свою́. В той день поги́бнут вся помышле́ния eго́. Блаже́н, eму́же Бог Иа́ковль помо́щник его́, упова́ние eго́ на Го́спода Бо́га своего́, сотво́ршаго не́бо и зе́млю, мо́ре и вся, я́же в них, храня́щаго и́стину в век, творя́щаго суд оби́димым, даю́щаго пи́щу а́лчушым. Госпо́дь реши́т окова́нныя. Госпо́дь умудря́ет слепцы́. Госпо́дь возво́дит низве́рженныя. Госпо́дь лю́бит пра́ведники. Госпо́дь храни́т прише́льцы, си́ра и вдову́ прии́мет и путь гре́шных погуби́т. Воцари́тся Госпо́дь во век, Бог твой, Сио́не, в род и род.",
  ["текст_цс"] = "Хвалѝ, дꙋшѐ моѧ̀, гдⷭ҇а: Восхвалю̀ гдⷭ҇а въ животѣ̀ мое́мъ, пою̀ бг҃ꙋ моемꙋ̀, до́ндеже є҆́смь. Не надѣ́йтесѧ на кнѧ̑зи, на сы́ны человѣ́чєскїѧ, въ ни́хже нѣ́сть сп҃се́нїѧ. И҆зы́детъ дꙋ́хъ є҆гѡ̀, и҆ возврати́тсѧ въ зе́млю свою̀: въ то́й де́нь поги́бнꙋтъ всѧ̑ помышлє́нїѧ є҆гѡ̀. Бл҃же́нъ, є҆мꙋ́же бг҃ъ і҆а́кѡвль помо́щникъ є҆гѡ̀, ᲂу҆пова́нїе є҆гѡ̀ на гдⷭ҇а бг҃а своего̀, Сотво́ршаго не́бо и҆ зе́млю, мо́ре, и҆ всѧ̑, ꙗ҆̀же въ ни́хъ: хранѧ́щаго и҆́стинꙋ въ вѣ́къ, Творѧ́щаго сꙋ́дъ ѡ҆би̑димымъ, даю́щаго пи́щꙋ а҆́лчꙋщымъ. Гдⷭ҇ь рѣши́тъ ѡ҆кова̑нныѧ: Гдⷭ҇ь ᲂу҆мꙋдрѧ́етъ слѣпцы̀: гдⷭ҇ь возво́дитъ низве́ржєнныѧ: гдⷭ҇ь лю́битъ првⷣники. Гдⷭ҇ь храни́тъ прише́льцы, си́ра и҆ вдовꙋ̀ прїи́метъ, и҆ пꙋ́ть грѣ́шныхъ погꙋби́тъ. Воцр҃и́тсѧ гдⷭ҇ь во вѣ́къ, бг҃ъ тво́й, сїѡ́не, въ ро́дъ и҆ ро́дъ.",
  ["заголовок_ру"] = "Аллилу́иа, Агге́а и Заха́рии.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа, а҆гге́а и҆ заха́рїи."
}

add_psalom {
  ["номер"] = 146,
  ["часть"] = 1,
  ["кафизма"] = 20,
  ["слава"] = 2,
  ["текст_ру"] = "Хвали́те Го́спода, я́ко благ псало́м. Бо́гови на́шему да услади́тся хвале́ние. Зи́ждай Иерусали́ма Госпо́дь, разсе́яния Изра́илева собере́т. Исцеля́яй сокруше́нныя се́рдцем и обязу́яй сокруше́ния их. Исчита́яй мно́жество звезд и всем им имена́ нарица́яй. Ве́лий Госпо́дь наш, и ве́лия кре́пость Его́, и ра́зума Его́ несть числа́, Прие́мляй кро́ткия Госпо́дь, смиря́яй же гре́шники до земли́. Начни́те Го́сподеви во испове́дании, по́йте Бо́гови на́шему в гу́слех. Одева́ющему не́бо о́блаки, уготовля́ющему земли́ дождь, прозяба́ющему на гора́х траву́ и злак на слу́жбу челове́ком, даю́щему ското́м пи́щу их, и птенце́м вра́новым призыва́ющым Его́. Не в си́ле ко́нстей восхо́щет, ниже́ в лы́стех му́жеских благоволи́т. Благоволи́т Госпо́дь в боя́щихся Его́ и во упова́ющих на ми́лость Его́.",
  ["текст_цс"] = "Хвали́те гдⷭ҇а, ꙗ҆́кѡ бл҃гъ ѱало́мъ: бг҃ови на́шемꙋ да ᲂу҆слади́тсѧ хвале́нїе. Зи́ждай і҆ерⷭ҇ли́ма гдⷭ҇ь: разсѣ̑ѧнїѧ і҆и҃лєва собере́тъ: И҆сцѣлѧ́ѧй сокрꙋшє́нныѧ се́рдцемъ и҆ ѡ҆бѧзꙋ́ѧй сокрꙋшє́нїѧ и҆́хъ: И҆счита́ѧй мно́жество ѕвѣ́здъ, и҆ всѣ̑мъ и҆̀мъ и҆мена̀ нарица́ѧй. Ве́лїй гдⷭ҇ь на́шъ, и҆ ве́лїѧ крѣ́пость є҆гѡ̀, и҆ ра́зꙋма є҆гѡ̀ нѣ́сть числа̀. Прїе́млѧй крѡ́ткїѧ гдⷭ҇ь, смирѧ́ѧй же грѣ́шники до землѝ. Начни́те гдⷭ҇еви во и҆сповѣ́данїи, по́йте бг҃ови на́шемꙋ въ гꙋ́слехъ: Ѡ҆дѣва́ющемꙋ не́бо ѻ҆́блаки, ᲂу҆готовлѧ́ющемꙋ землѝ до́ждь: прозѧба́ющемꙋ на гора́хъ травꙋ̀ и҆ ѕла́къ на слꙋ́жбꙋ человѣ́кѡмъ: Даю́щемꙋ скотѡ́мъ пи́щꙋ и҆́хъ, и҆ птенцє́мъ вра́нѡвымъ призыва́ющымъ є҆го̀. Не въ си́лѣ ко́нстѣй восхо́щетъ, нижѐ въ лы́стѣхъ мꙋ́жескихъ бл҃говоли́тъ: Бл҃говоли́тъ гдⷭ҇ь въ боѧ́щихсѧ є҆гѡ̀ и҆ во ᲂу҆пова́ющихъ на млⷭ҇ть є҆гѡ̀.",
  ["заголовок_ру"] = "Аллилу́иа.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа."
}

add_psalom {
  ["номер"] = 147,
  ["часть"] = 1,
  ["кафизма"] = 20,
  ["слава"] = 2,
  ["текст_ру"] = "Похвали́, Иерусали́ме, Го́спода, хвали́ Бо́га Твоего́, Сио́не, я́ко укрепи́ вереи́ врат Твои́х, благослови́ сы́ны твоя́ в тебе́. Полага́яй преде́лы Твоя́ мир, и ту́ка пшени́чна насыща́яй тя. Посыла́яй сло́во Свое́ земли́, до ско́рости тече́т сло́во Его́, даю́щаго снег Свой, я́ко во́лну, мглу, я́ко пе́пел, посыпа́ющаго, мета́ющаго го́лоть Свой, я́ко хле́бы. Проти́ву лица́ мра́за Его́ кто постои́т? По́слет Сло́во Свое́, и иста́ет я́, дхнет Дух Его́, и потеку́т во́ды. Возвеща́яй сло́во Свое́ Иа́кову, оправда́ния и судьбы́ Своя́ Изра́илеви. Не сотвори́ та́ко вся́кому язы́ку, и судьбы́ Своя́ не яви́ им.",
  ["текст_цс"] = "Похвалѝ, і҆ерⷭ҇ли́ме, гдⷭ҇а, хвалѝ бг҃а твоего̀, сїѡ́не: Ꙗ҆́кѡ ᲂу҆крѣпѝ верєѝ вра́тъ твои́хъ, блгⷭ҇вѝ сы́ны твоѧ̑ въ тебѣ̀. Полага́ѧй предѣ́лы твоѧ̑ ми́ръ, и҆ тꙋ́ка пшени́чна насыща́ѧй тѧ̀: Посыла́ѧй сло́во своѐ землѝ, до ско́рости тече́тъ сло́во є҆гѡ̀, Даю́щагѡ снѣ́гъ сво́й ꙗ҆́кѡ во́лнꙋ, мглꙋ̀ ꙗ҆́кѡ пе́пелъ посыпа́ющагѡ, Мета́ющагѡ го́лоть сво́й ꙗ҆́кѡ хлѣ́бы: проти́вꙋ лица̀ мра́за є҆гѡ̀ кто̀ постои́тъ; По́слетъ сло́во своѐ, и҆ и҆ста́етъ ѧ҆̀: дхне́тъ дꙋ́хъ є҆гѡ̀, и҆ потекꙋ́тъ во́ды. Возвѣща́ѧй сло́во своѐ і҆а́кѡвꙋ, ѡ҆правда̑нїѧ и҆ сꙋдьбы̑ своѧ̑ і҆и҃леви: Не сотворѝ та́кѡ всѧ́комꙋ ꙗ҆зы́кꙋ, и҆ сꙋдьбы̑ своѧ̑ не ꙗ҆вѝ и҆̀мъ.",
  ["заголовок_ру"] = "Аллилу́иа, Агге́а и Заха́рии.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа, а҆гге́а и҆ заха́рїи."
}

