  ["кафизма"] = 20,
  ["слава"] = 3,
  ["текст_ру"] = "Хвали́те Го́спода с небе́с, хвали́те Его́ в вы́шних. Хвали́те Его́, вси А́нгели Его́, хвали́те Его́, вся си́лы Его́. Хвали́те Его́, со́лнце и луна́, хвали́те Его́, вся зве́зды и свет. Хвали́те Его́ небеса́ небе́с и вода́, я́же превы́ше небе́с. Да восхва́лят и́мя Госпо́дне: я́ко Той рече́, и бы́ша, Той повеле́, и созда́шася. Поста́ви я́ в век и в век ве́ка, повеле́ние положи́, и не ми́мо и́дет. Хвали́те Го́спода от земли́, зми́еве и вся бе́здны: огнь, град, снег, го́лоть, дух бу́рен, творя́щая сло́во Его́, го́ры и вси хо́лми, древа́ плодоно́сна и вси ке́дри, зве́рие и вси ско́ти, га́ди и пти́цы перна́ты. Ца́рие зе́мстии и вси лю́дие, кня́зи и вси судии́ зе́мстии, ю́ноши и де́вы, ста́рцы с ю́нотами да восхва́лят и́мя Госпо́дне, я́ко вознесе́ся и́мя Того́ еди́наго, испове́дание Его́ на земли́ и на небеси́. И вознесе́т рог люде́й Свои́х, песнь всем преподо́бным Его́, сыново́м Изра́илевым, лю́дем, приближа́ющымся Ему́.",
  ["текст_цс"] = "Хвали́те гдⷭ҇а съ нб҃съ, хвали́те є҆го̀ въ вы́шнихъ. Хвали́те є҆го̀ всѝ а҆́гг҃ли є҆гѡ̀: хвали́те є҆го̀, всѧ̑ си̑лы є҆гѡ̀. Хвали́те є҆го̀, со́лнце и҆ лꙋна̀: хвали́те є҆го̀ всѧ̑ ѕвѣ́зды и҆ свѣ́тъ. Хвали́те є҆го̀, нб҃са̀ нб҃съ и҆ вода̀, ꙗ҆́же превы́ше небе́съ. Да восхва́лѧтъ и҆́мѧ гдⷭ҇не: ꙗ҆́кѡ то́й речѐ, и҆ бы́ша: то́й повелѣ̀, и҆ созда́шасѧ. Поста́ви ѧ҆̀ въ вѣ́къ и҆ въ вѣ́къ вѣ́ка: повелѣ́нїе положѝ, и҆ не ми́мѡ и҆́детъ. Хвали́те гдⷭ҇а ѿ землѝ, ѕмі́евє и҆ всѧ̑ бє́здны: Ѻ҆́гнь, гра́дъ, снѣ́гъ, го́лоть, дꙋ́хъ бꙋ́ренъ, творѧ̑щаѧ сло́во є҆гѡ̀: Го́ры и҆ всѝ хо́лми, древа̀ плодонѡ́сна и҆ всѝ ке́дри: Ѕвѣ́рїе и҆ всѝ ско́ти, га́ди и҆ пти̑цы перна̑ты: Ца́рїе зе́мстїи и҆ всѝ лю́дїе, кнѧ̑зи и҆ всѝ сꙋдїи̑ зе́мстїи: Ю҆́нѡши и҆ дѣ̑вы, ста́рцы съ ю҆́нотами. Да восхва́лѧтъ и҆́мѧ гдⷭ҇не: ꙗ҆́кѡ вознесе́сѧ и҆́мѧ тогѡ̀ є҆ди́нагѡ, и҆сповѣ́данїе є҆гѡ̀ на землѝ и҆ на нб҃сѝ. И҆ вознесе́тъ ро́гъ люде́й свои́хъ: пѣ́снь всѣ̑мъ прпⷣбнымъ є҆гѡ̀, сыновѡ́мъ і҆и҃лєвымъ, лю́демъ приближа́ющымсѧ є҆мꙋ̀.",
  ["заголовок_ру"] = "Аллилу́иа, Агге́а и Заха́рии.",
  ["заголовок_цс"] = "А҆ллилꙋ́їа, а҆гге́а и҆ заха́рїи."
}

add_psalom {
  ["номер"] = 149,
